'use client';

import React, { useEffect, useMemo, useRef, useState } from 'react';

import type { CssAnimationConfig } from '@/shared/contracts/cms';
import { DEFAULT_CSS_ANIMATION_CONFIG } from '@/shared/contracts/cms';
import { cn } from '@/shared/utils/ui-utils';

import { useBlockSettings } from './sections/FrontendBlockRenderer';

interface CssAnimationWrapperProps {
  config?: CssAnimationConfig | undefined;
  children: React.ReactNode;
  className?: string;
}

const resolveIterationCount = (
  loop: boolean | undefined,
  iterations: string | number | undefined
): string => {
  if (loop === true || iterations === 'infinite') return 'infinite';
  return String(typeof iterations === 'number' ? Math.max(1, iterations) : 1);
};

const resolveTriggerClass = (trigger: string): string => {
  if (trigger === 'inView') return 'cms-css-anim--in-view';
  if (trigger === 'hover') return 'cms-css-anim--hover';
  return 'cms-css-anim--load';
};

const buildCssAnimationName = (effect: string | undefined): string => `cms-anim-${effect ?? 'none'}`;

const buildStyleVars = (merged: CssAnimationConfig): React.CSSProperties => {
  const iterationCount = resolveIterationCount(merged.loop, merged.iterations);
  const name = buildCssAnimationName(merged.effect);
  return {
    ['--cms-css-anim-name' as string]: name,
    ['--cms-css-anim-duration' as string]: `${merged.duration ?? 700}ms`,
    ['--cms-css-anim-delay' as string]: `${merged.delay ?? 0}ms`,
    ['--cms-css-anim-ease' as string]: merged.easing ?? 'ease-out',
    ['--cms-css-anim-iter' as string]: iterationCount,
    ['--cms-css-anim-direction' as string]: merged.direction ?? 'normal',
    ['--cms-css-anim-fill' as string]: merged.fillMode ?? 'both',
    ['--cms-css-anim-distance' as string]: `${merged.distance ?? 40}px`,
    ['--cms-css-anim-scale' as string]: merged.scale ?? 0.9,
    ['--cms-css-anim-rotate' as string]: `${merged.rotate ?? 12}deg`,
    ['--cms-css-anim-blur' as string]: `${merged.blur ?? 6}px`,
  };
};

export function CssAnimationWrapper({
  config: propConfig,
  children,
  className,
}: CssAnimationWrapperProps): React.ReactNode {
  const blockSettings = useBlockSettings();

  const config = useMemo((): CssAnimationConfig | undefined => {
    if (propConfig) return propConfig;
    const blockAnim = blockSettings?.['cssAnimation'];
    if (blockAnim !== undefined && blockAnim !== null) {
      return blockAnim as CssAnimationConfig;
    }
    return undefined;
  }, [propConfig, blockSettings]);

  const merged = useMemo((): CssAnimationConfig => ({ ...DEFAULT_CSS_ANIMATION_CONFIG, ...(config ?? {}) }), [config]);
  const enabled = Boolean(merged.enabled) && merged.effect !== 'none';
  const trigger = merged.trigger ?? 'load';
  const ref = useRef<HTMLDivElement | null>(null);
  const [active, setActive] = useState<boolean>(trigger !== 'inView');

  useEffect(() => {
    if (trigger !== 'inView') return;
    const node = ref.current;
    if (!node || typeof IntersectionObserver === 'undefined') return;
    const observer = new IntersectionObserver(
      (entries: IntersectionObserverEntry[]) => {
        entries.forEach((entry: IntersectionObserverEntry) => {
          if (entry.isIntersecting) {
            setActive(true);
          } else if (merged.replayOnExit === true) {
            setActive(false);
          }
        });
      },
      { threshold: 0.25 }
    );
    observer.observe(node);
    return (): void => {
      observer.disconnect();
    };
  }, [merged.replayOnExit, trigger]);

  if (!enabled) {
    return <>{children}</>;
  }

  const styleVars = buildStyleVars(merged);
  const triggerClass = resolveTriggerClass(trigger);

  return (
    <div
      ref={ref}
      className={cn('cms-css-anim', triggerClass, active ? 'is-active' : '', className)}
      style={styleVars}
    >
      {children}
    </div>
  );
}

'use client';

import React, { useMemo, useRef, useEffect } from 'react';
import type { GsapAnimationConfig } from '@/features/gsap/public';
import { DEFAULT_ANIMATION_CONFIG } from '@/features/gsap/public';
import { useBlockSettings } from './sections/FrontendBlockRenderer';
import { buildEase, buildStagger, buildTargets } from './gsap-wrapper/animation-builders';
import { buildScrollTrigger } from './gsap-wrapper/animation-triggers';
import {
  buildKeyframes,
  buildMotionPathVars,
  resolveMotionPath,
} from './gsap-wrapper/animation-presets';
import { getGsapFromVars } from '@/features/gsap/public';

interface GsapAnimationWrapperProps {
  config?: Partial<GsapAnimationConfig> | undefined;
  children: React.ReactNode;
  className?: string | undefined;
}

const handleMotionPath = (
  gsap: any,
  targets: Element[],
  config: GsapAnimationConfig,
  root: HTMLElement,
  baseVars: Record<string, unknown>
): void => {
  if (config.motionPathEnabled === true) {
    const path = resolveMotionPath(config, root);
    if (path !== null) {
      const motionPathVars = buildMotionPathVars(config, path);
      gsap.to(targets, { ...baseVars, motionPath: motionPathVars });
    }
  }
};

export function GsapAnimationWrapper({
  config: propConfig,
  children,
  className,
}: GsapAnimationWrapperProps): React.ReactNode {
  const ref = useRef<HTMLDivElement>(null);
  const blockSettings = useBlockSettings();

  const config = useMemo((): Partial<GsapAnimationConfig> | undefined => {
    if (propConfig) return propConfig;
    const blockGsap = blockSettings?.['gsapAnimation'];
    if (blockGsap !== undefined && blockGsap !== null) {
      return blockGsap as Partial<GsapAnimationConfig>;
    }
    return undefined;
  }, [propConfig, blockSettings]);

  const configSignature = useMemo(() => JSON.stringify(config ?? null), [config]);
  const mergedConfig: GsapAnimationConfig | null = useMemo(() => {
    if (!config) return null;
    return { ...DEFAULT_ANIMATION_CONFIG, ...config };
  }, [config]);

  useEffect(() => {
    if (!mergedConfig || (mergedConfig.preset === 'none' && !mergedConfig.motionPathEnabled) || !ref.current) {
      return undefined;
    }
    let ctx: any = null;
    let cancelled = false;

    const loadGsap = async (): Promise<void> => {
      const { gsap } = await import('gsap');
      const { ScrollTrigger } = await import('gsap/ScrollTrigger');
      const { CustomEase } = await import('gsap/CustomEase');
      const { MotionPathPlugin } = await import('gsap/MotionPathPlugin');
      gsap.registerPlugin(ScrollTrigger, CustomEase, MotionPathPlugin);

      if (cancelled || !ref.current) return;
      const root = ref.current;

      ctx = gsap.context(() => {
        const targets = buildTargets(root, mergedConfig.selector);
        if (!targets.length) return;
        const ease = buildEase(mergedConfig, CustomEase);
        const stagger = buildStagger(mergedConfig, targets.length);
        const scrollTrigger = buildScrollTrigger(mergedConfig, root, targets.length);
        const baseVars = {
          duration: mergedConfig.duration ?? DEFAULT_ANIMATION_CONFIG.duration ?? 0.6,
          delay: mergedConfig.delay ?? DEFAULT_ANIMATION_CONFIG.delay ?? 0,
          ease,
          ...(stagger ? { stagger } : {}),
          ...(scrollTrigger ? { scrollTrigger } : {}),
        };

        handleMotionPath(gsap, targets, mergedConfig, root, baseVars);
        const keyframes = buildKeyframes(mergedConfig.preset);
        if (keyframes) {
          gsap.to(targets, { ...baseVars, ...keyframes });
        } else {
          const fromVars = getGsapFromVars(mergedConfig.preset);
          gsap.from(targets, { ...fromVars, ...baseVars });
        }
      }, root);

      ScrollTrigger?.refresh?.();
    };

    void loadGsap();

    return (): void => {
      cancelled = true;
      if (ctx && typeof ctx.revert === 'function') ctx.revert();
    };
  }, [mergedConfig, configSignature]);

  if (!mergedConfig || mergedConfig.preset === 'none') {
    return <>{children}</>;
  }

  return (
    <div ref={ref} className={className}>
      {children}
    </div>
  );
}

'use client';

import dynamic from 'next/dynamic';
import { usePathname, useSearchParams } from 'next/navigation';
import type { Session } from 'next-auth';
import React from 'react';

import {
  DEFAULT_APP_EMBED_BASE_PATH,
  DEFAULT_APP_EMBED_ENTRY_PAGE,
  DEFAULT_APP_EMBED_HEIGHT,
  DEFAULT_APP_EMBED_ID,
  getAppEmbedOption,
} from '@/shared/lib/app-embeds';
import { isSuperAdminSession } from '@/shared/lib/auth/elevated-session-user';
import { useOptionalNextAuthSession } from '@/shared/lib/auth/useOptionalNextAuthSession';
import {
  buildKangurEmbeddedBasePath,
  getKangurPageSlug,
  getKangurInternalQueryParamKeys,
  KANGUR_MAIN_PAGE_KEY,
  KANGUR_PAGE_TO_SLUG,
  readKangurUrlParam,
  KANGUR_EMBED_QUERY_PARAM,
  resolveKangurPageKeyFromSlug,
} from '@/shared/lib/kangur-cms-bridge';
import { Card } from '@/shared/ui/primitives.public';

import { useRequiredBlockRenderContext, useRequiredBlockSettings } from './BlockContext';

const LazyKangurFeaturePage = dynamic(
  () => import('@/features/kangur/ui/KangurFeaturePage').then((mod) => mod.KangurFeaturePage),
  {
    ssr: false,
    loading: () => null,
  }
);

const resolveAppEmbedHeight = (value: unknown): number => {
  if (typeof value !== 'number' || !Number.isFinite(value)) {
    return DEFAULT_APP_EMBED_HEIGHT;
  }
  return Math.max(240, value);
};

const resolveKangurSlug = (value: unknown): string | null => {
  if (typeof value !== 'string' || value.trim().length === 0) {
    return null;
  }

  const trimmed = value.trim();
  const directPageSlug = KANGUR_PAGE_TO_SLUG[trimmed];
  if (directPageSlug) {
    return directPageSlug;
  }

  const directMatch = Object.entries(KANGUR_PAGE_TO_SLUG).find(
    ([, slug]) => slug.toLowerCase() === trimmed.toLowerCase()
  );
  if (directMatch) {
    return directMatch[1];
  }

  return null;
};

const resolveKangurEntrySlug = (entryPage: unknown): string[] => {
  const resolvedSlug = resolveKangurSlug(entryPage);
  if (!resolvedSlug) {
    return [];
  }

  if (resolvedSlug === getKangurPageSlug(KANGUR_MAIN_PAGE_KEY)) {
    return [];
  }

  return [resolvedSlug];
};

const SUPER_ADMIN_ONLY_KANGUR_PAGE_KEYS = new Set(['GamesLibrary']);

const canAccessKangurPage = (
  pageKey: string | null | undefined,
  session: Session | null | undefined
): boolean => {
  const normalizedPageKey = pageKey?.trim();
  return !normalizedPageKey ||
    !SUPER_ADMIN_ONLY_KANGUR_PAGE_KEYS.has(normalizedPageKey) ||
    isSuperAdminSession(session);
};

const canAccessKangurSlugSegments = (
  slugSegments: readonly string[] = [],
  session: Session | null | undefined
): boolean => {
  const leadSlug = slugSegments[0]?.trim() || null;
  const pageKey = resolveKangurPageKeyFromSlug(leadSlug);
  return canAccessKangurPage(pageKey, session);
};

const resolveAccessibleKangurEmbedSlug = (input: {
  requestedSlug: string | null;
  entryPage: unknown;
  session: import('next-auth').Session | null | undefined;
}): string[] => {
  const { requestedSlug, entryPage, session } = input;
  const fallbackSlug = resolveKangurEntrySlug(entryPage);
  const requestedActiveSlug =
    requestedSlug === null ? fallbackSlug : requestedSlug ? [requestedSlug] : [];

  if (canAccessKangurSlugSegments(requestedActiveSlug, session)) {
    return requestedActiveSlug;
  }

  return canAccessKangurSlugSegments(fallbackSlug, session) ? fallbackSlug : [];
};

export function AppEmbedBlock(): React.ReactNode {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const settings = useRequiredBlockSettings();
  const { block } = useRequiredBlockRenderContext();
  const { data: session } = useOptionalNextAuthSession();
  const rawAppId = settings['appId'];
  const appOption = getAppEmbedOption(
    typeof rawAppId === 'string' ? rawAppId : DEFAULT_APP_EMBED_ID
  );
  const title = (settings['title'] as string) || '';
  const embedUrl = (settings['embedUrl'] as string) || '';
  const height = resolveAppEmbedHeight(settings['height']);
  const configuredBasePath = (settings['basePath'] as string) || DEFAULT_APP_EMBED_BASE_PATH;
  const entryPage = (settings['entryPage'] as string) || DEFAULT_APP_EMBED_ENTRY_PAGE;
  const appLabel = appOption?.label ?? 'App';
  const heading = title || appLabel;
  const hostPageSearchParams = new URLSearchParams(searchParams.toString());
  const currentBlockEmbeddedBasePath = buildKangurEmbeddedBasePath('/', block.id);

  getKangurInternalQueryParamKeys(currentBlockEmbeddedBasePath).forEach((key) => {
    hostPageSearchParams.delete(key);
  });
  getKangurInternalQueryParamKeys().forEach((key) => {
    hostPageSearchParams.delete(key);
  });

  const currentHostHref = `${pathname || '/'}${
    hostPageSearchParams.toString().length > 0 ? `?${hostPageSearchParams.toString()}` : ''
  }`;
  const hostPath = configuredBasePath.trim().length > 0 ? configuredBasePath : currentHostHref;
  const embeddedBasePath = buildKangurEmbeddedBasePath(hostPath, block.id);
  const requestedSlug = readKangurUrlParam(
    searchParams,
    KANGUR_EMBED_QUERY_PARAM,
    embeddedBasePath
  );
  const activeSlug = resolveAccessibleKangurEmbedSlug({
    requestedSlug,
    entryPage,
    session,
  });

  return (
    <Card
      variant='subtle'
      padding='md'
      className='cms-hover-card w-full border-border/40 bg-card/40'
    >
      <div className='mb-3 flex items-start justify-between gap-3'>
        <div>
          <div className='text-sm font-semibold text-[var(--cms-appearance-page-text)]'>
            {heading}
          </div>
          <div className='cms-appearance-muted-text text-[10px] uppercase tracking-wide'>
            {appOption?.renderMode === 'internal-app'
              ? `Internal app mount${hostPath ? ` · ${hostPath}` : ''}`
              : 'App embed'}
          </div>
        </div>
      </div>
      {appOption?.id === 'kangur' && appOption.renderMode === 'internal-app' ? (
        <div
          className='cms-appearance-surface relative overflow-hidden rounded-[28px] border'
          style={{ minHeight: height }}
        >
          <LazyKangurFeaturePage slug={activeSlug} basePath={embeddedBasePath} embedded />
        </div>
      ) : embedUrl ? (
        <iframe
          src={embedUrl}
          title={heading}
          className='w-full rounded-md border border-border/40 bg-black'
          style={{ height }}
        />
      ) : (
        <Card
          variant='subtle-compact'
          padding='none'
          className='cms-appearance-subtle-surface cms-appearance-muted-text flex items-center justify-center border-dashed px-4 text-center text-xs'
          style={{ minHeight: height }}
        >
          {appOption?.renderMode === 'internal-app'
            ? `This ${appLabel} block is configured for an internal app mount.`
            : `Provide an embed URL to render the ${appLabel} app here.`}
        </Card>
      )}
    </Card>
  );
}

'use client';

import React, { useMemo } from 'react';

import {
  resolveCmsRuntimeValue,
  resolveCmsRuntimeAction,
  useOptionalCmsRuntime,
} from '../CmsRuntimeContext';
import { useRequiredBlockSettings } from './BlockContext';
import {
  isRuntimeTruthyValue,
  parseBoolean,
  parseRuntimeActionArgs,
} from './ButtonBlock.helpers';

const BASE_CLASSES = 'cms-hover-button inline-block rounded-md px-6 py-2.5 text-sm font-semibold transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-55';

function getButtonStyles(settings: Record<string, unknown>): React.CSSProperties {
  const customStyles: React.CSSProperties = {};
  const fontFamily = settings['fontFamily'] as string | undefined;
  const fontSize = settings['fontSize'] as number | undefined;
  const fontWeight = settings['fontWeight'] as string | undefined;
  const textColor = settings['textColor'] as string | undefined;
  const bgColor = settings['bgColor'] as string | undefined;
  const borderColor = settings['borderColor'] as string | undefined;
  const borderRadius = settings['borderRadius'] as number | undefined;
  const borderWidth = settings['borderWidth'] as number | undefined;

  if (fontFamily !== undefined) customStyles.fontFamily = fontFamily;
  if (fontSize !== undefined && fontSize > 0) customStyles.fontSize = `${fontSize}px`;
  if (fontWeight !== undefined) customStyles.fontWeight = fontWeight;
  if (textColor !== undefined) customStyles.color = textColor;
  if (bgColor !== undefined) customStyles.backgroundColor = bgColor;
  if (borderColor !== undefined) customStyles.borderColor = borderColor;
  if (borderRadius !== undefined && borderRadius > 0) customStyles.borderRadius = `${borderRadius}px`;
  if (borderWidth !== undefined && borderWidth > 0) customStyles.borderWidth = `${borderWidth}px`;

  return customStyles;
}

export function ButtonBlock(): React.JSX.Element {
  const settings = useRequiredBlockSettings();
  const runtime = useOptionalCmsRuntime();

  const label = (settings['buttonLabel'] as string) || 'Button';
  const link = (settings['buttonLink'] as string) || '#';
  const style = (settings['buttonStyle'] as string) || 'solid';

  const runtimeActionArgs = useMemo(() => parseRuntimeActionArgs(settings['runtimeActionArgs']), [settings]);
  const runtimeAction = useMemo(() => resolveCmsRuntimeAction(runtime, settings['buttonDisabledSource'] as string, settings['buttonDisabledPath'] as string), [runtime, settings]);
  const runtimeDisabledValue = useMemo(() => resolveCmsRuntimeValue(runtime, settings['buttonDisabledSource'] as string, settings['buttonDisabledPath'] as string), [runtime, settings]);

  const isDisabled = useMemo(() => {
    const hasRuntimeBinding =
      typeof settings['buttonDisabledSource'] === 'string' &&
      (settings['buttonDisabledSource']).trim().length > 0 &&
      typeof settings['buttonDisabledPath'] === 'string' &&
      (settings['buttonDisabledPath']).trim().length > 0;

    if (!hasRuntimeBinding) {
      return parseBoolean(settings['buttonDisabled']);
    }

    const disabledWhen = settings['buttonDisabledWhen'] === 'falsy' ? 'falsy' : 'truthy';
    const resolvedTruthy = isRuntimeTruthyValue(runtimeDisabledValue);
    return disabledWhen === 'truthy' ? resolvedTruthy : !resolvedTruthy;
  }, [runtimeDisabledValue, settings]);

  const customStyles = getButtonStyles(settings);

  const className = `${BASE_CLASSES} ${style === 'outline' ? 'cms-appearance-button-outline border-2 hover:text-current' : 'cms-appearance-button-primary border'} focus-visible:ring-white`.trim();

  if (runtimeAction !== null || isDisabled) {
    return (
      <button
        type='button'
        onClick={() => runtimeAction?.(...runtimeActionArgs)}
        disabled={Boolean(isDisabled)}
        className={className}
        style={customStyles}
        aria-label={label}
        title={label}
      >
        {label}
      </button>
    );
  }

  return (
    <a
      href={link}
      className={className}
      style={customStyles}
      aria-label={label}
      title={label}
    >
      {label}
    </a>
  );
}

'use client';

import React, { useMemo } from 'react';

import { getBlockTypographyStyles } from '../theme-styles';
import { useRequiredBlockSettings } from './BlockContext';

function Heading({ size, text, typoStyles }: { size: string, text: string, typoStyles: React.CSSProperties }): React.JSX.Element {
  if (size === 'small') {
    return (
      <h3 className='text-xl font-bold leading-tight tracking-tight md:text-2xl' style={typoStyles}>
        {text}
      </h3>
    );
  }
  if (size === 'large') {
    return (
      <h2 className='text-3xl font-bold leading-tight tracking-tight md:text-5xl' style={typoStyles}>
        {text}
      </h2>
    );
  }
  return (
    <h2 className='text-2xl font-bold leading-tight tracking-tight md:text-3xl' style={typoStyles}>
      {text}
    </h2>
  );
}

export function HeadingBlock(): React.JSX.Element {
  const settings = useRequiredBlockSettings();

  const text = (settings['headingText'] as string) || 'Heading';
  const size = (settings['headingSize'] as string) || 'medium';
  const typoStyles = useMemo(() => getBlockTypographyStyles(settings), [settings]);

  return <Heading size={size} text={text} typoStyles={typoStyles} />;
}

'use client';

import React from 'react';
import Image from 'next/image';
import { useRequiredBlockRenderContext, useRequiredBlockSettings } from './BlockContext';
import {
  clampNumber,
  resolveObjectPosition,
  resolveGradientDirection,
  toBoolean,
} from './image-utils';

type ImageSettings = {
  src: string;
  alt: string;
  width: number;
  height: number;
  aspectRatio: string;
  objectFit: React.CSSProperties['objectFit'];
  objectPosition: string;
  opacity: number;
  blur: number;
  grayscale: number;
  brightness: number;
  contrast: number;
  scale: number;
  rotate: number;
  shape: string;
  borderRadius: number;
  borderWidth: number;
  borderStyle: string;
  borderColor: string;
  overlayType: string;
  overlayColor: string;
  overlayOpacity: number;
  overlayGradientFrom: string;
  overlayGradientTo: string;
  overlayGradientDirection: string;
  transparencyMode: string;
  transparencyDirection: string;
  transparencyStrength: number;
  clipOverflow: boolean;
};

const resolveImageSettings = (settings: Record<string, unknown>): ImageSettings => ({
  src: (settings['src'] as string) || '',
  alt: (settings['alt'] as string) || 'Image',
  width: (settings['width'] as number) || 100,
  height: (settings['height'] as number) || 0,
  aspectRatio: (settings['aspectRatio'] as string) || 'auto',
  objectFit: (settings['objectFit'] as React.CSSProperties['objectFit']) || 'cover',
  objectPosition: resolveObjectPosition((settings['objectPosition'] as string) || 'center'),
  opacity: clampNumber(settings['opacity'], 0, 100, 100),
  blur: clampNumber(settings['blur'], 0, 20, 0),
  grayscale: clampNumber(settings['grayscale'], 0, 100, 0),
  brightness: clampNumber(settings['brightness'], 0, 200, 100),
  contrast: clampNumber(settings['contrast'], 0, 200, 100),
  scale: clampNumber(settings['scale'], 50, 200, 100),
  rotate: clampNumber(settings['rotate'], -180, 180, 0),
  shape: (settings['shape'] as string) || 'none',
  borderRadius: (settings['borderRadius'] as number) || 0,
  borderWidth: (settings['borderWidth'] as number) || 0,
  borderStyle: (settings['borderStyle'] as string) || 'solid',
  borderColor: (settings['borderColor'] as string) || '#ffffff',
  overlayType: (settings['overlayType'] as string) || 'none',
  overlayColor: (settings['overlayColor'] as string) || '#000000',
  overlayOpacity: clampNumber(settings['overlayOpacity'], 0, 100, 0) / 100,
  overlayGradientFrom: (settings['overlayGradientFrom'] as string) || '#000000',
  overlayGradientTo: (settings['overlayGradientTo'] as string) || '#ffffff',
  overlayGradientDirection: (settings['overlayGradientDirection'] as string) || 'to-bottom',
  transparencyMode: (settings['transparencyMode'] as string) || 'none',
  transparencyDirection: (settings['transparencyDirection'] as string) || 'bottom',
  transparencyStrength: clampNumber(settings['transparencyStrength'], 0, 100, 0),
  clipOverflow: toBoolean(settings['clipOverflow'], false),
});

export function ImageElementBlock(): React.JSX.Element | null {
  const { mediaStyles, stretch } = useRequiredBlockRenderContext();
  const settings = useRequiredBlockSettings();
  const s = resolveImageSettings(settings);

  const wrapperStyles: React.CSSProperties = {
    ...(mediaStyles ?? {}),
    width: `${s.width}%`,
  };
  if (s.height > 0) wrapperStyles.height = `${s.height}px`;
  if (s.aspectRatio !== 'auto') wrapperStyles.aspectRatio = s.aspectRatio;
  if (stretch) {
    wrapperStyles.width = '100%';
    wrapperStyles.height = '100%';
  }
  if (s.borderWidth > 0 && s.borderStyle !== 'none') {
    wrapperStyles.borderWidth = `${s.borderWidth}px`;
    wrapperStyles.borderStyle = s.borderStyle;
    wrapperStyles.borderColor = s.borderColor;
  }
  if (s.shape === 'circle') {
    wrapperStyles.borderRadius = '9999px';
    wrapperStyles.overflow = 'hidden';
  } else if (s.shape === 'rounded' && s.borderRadius > 0) {
    wrapperStyles.borderRadius = `${s.borderRadius}px`;
    wrapperStyles.overflow = 'hidden';
  }
  if (s.clipOverflow) {
    wrapperStyles.overflow = 'hidden';
  }

  const filters: string[] = [];
  if (s.blur > 0) filters.push(`blur(${s.blur}px)`);
  if (s.grayscale > 0) filters.push(`grayscale(${s.grayscale / 100})`);
  if (s.brightness !== 100) filters.push(`brightness(${s.brightness / 100})`);
  if (s.contrast !== 100) filters.push(`contrast(${s.contrast / 100})`);

  const transforms: string[] = [];
  if (s.scale !== 100) transforms.push(`scale(${s.scale / 100})`);
  if (s.rotate !== 0) transforms.push(`rotate(${s.rotate}deg)`);

  const imageStyles: React.CSSProperties = {
    width: '100%',
    maxHeight: '100%',
    objectFit: s.objectFit,
    objectPosition: s.objectPosition,
    opacity: s.opacity / 100,
    filter: filters.length ? filters.join(' ') : undefined,
    transform: transforms.length ? transforms.join(' ') : undefined,
    display: 'block',
  };

  const overlayStyles: React.CSSProperties = {};
  if (s.overlayType === 'solid') {
    overlayStyles.backgroundColor = s.overlayColor;
    overlayStyles.opacity = s.overlayOpacity;
  } else if (s.overlayType === 'gradient') {
    overlayStyles.backgroundImage = `linear-gradient(${resolveGradientDirection(s.overlayGradientDirection)}, ${s.overlayGradientFrom}, ${s.overlayGradientTo})`;
    overlayStyles.opacity = s.overlayOpacity;
  }
  if (wrapperStyles.borderRadius) {
    overlayStyles.borderRadius = wrapperStyles.borderRadius as string;
  }

  if (!s.src) {
    return (
      <div
        className='cms-media cms-appearance-subtle-surface cms-appearance-muted-text flex items-center justify-center py-8 text-sm'
        style={wrapperStyles}
      >
        No image selected
      </div>
    );
  }

  const useFill = stretch || s.height > 0 || s.aspectRatio !== 'auto';

  return (
    <div className='relative' style={wrapperStyles}>
      {useFill ? (
        <Image src={s.src} alt={s.alt} fill style={imageStyles} />
      ) : (
        <Image
          src={s.src}
          alt={s.alt}
          width={1000}
          height={1000}
          style={{ ...imageStyles, height: 'auto' }}
        />
      )}
      {s.overlayType !== 'none' && (
        <div className='pointer-events-none absolute inset-0' style={overlayStyles} />
      )}
    </div>
  );
}

export function ImageBlock(): React.JSX.Element {
  const { mediaStyles, stretch } = useRequiredBlockRenderContext();
  const settings = useRequiredBlockSettings();
  const src = (settings['src'] as string) || '';
  const alt = (settings['alt'] as string) || '';
  const width = (settings['width'] as number) || 100;
  const borderRadius = (settings['borderRadius'] as number) || 0;
  const clipOverflow = toBoolean(settings['clipOverflow'], false);

  const resolvedStyles: React.CSSProperties = {
    ...(mediaStyles ?? {}),
    ...(borderRadius > 0 ? { borderRadius: `${borderRadius}px` } : {}),
  };

  if (!src) {
    return (
      <div
        className='cms-media cms-appearance-subtle-surface cms-appearance-muted-text flex items-center justify-center py-8 text-sm'
        style={{ width: `${width}%`, ...resolvedStyles }}
      >
        No image selected
      </div>
    );
  }

  const wrapperStyles: React.CSSProperties = {
    width: `${width}%`,
    ...(stretch ? { width: '100%', height: '100%' } : {}),
    ...resolvedStyles,
    ...(clipOverflow ? { overflow: 'hidden' } : {}),
  };

  const imageClassName = stretch
    ? 'block h-full w-full object-cover'
    : 'block h-auto w-full max-h-full object-cover';

  return (
    <div className='cms-media' style={wrapperStyles}>
      {stretch ? (
        <Image src={src} alt={alt} fill className={imageClassName} />
      ) : (
        <Image src={src} alt={alt} width={1000} height={1000} className={imageClassName} />
      )}
    </div>
  );
}

'use client';

import React, { useCallback, useEffect, useMemo, useState } from 'react';

import { Input } from '@/shared/ui/primitives.public';
import {
  resolveCmsRuntimeAction,
  useOptionalCmsRuntime,
} from '../CmsRuntimeContext';
import { useRequiredBlockSettings } from './BlockContext';

const resolveInputValue = (value: unknown): string => {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return '';
};

const resolveBoolean = (value: unknown): boolean => value === true || value === 'true';

type InputBlockResolvedSettings = {
  autoComplete: string;
  controlledValue: string;
  disabled: boolean;
  inputAriaLabel: string;
  inputType: string;
  maxLength: number | undefined;
  placeholder: string;
};

const resolveInputMaxLength = (value: unknown): number | undefined =>
  typeof value === 'number' && value > 0 ? Math.round(value) : undefined;

const resolveInputBlockSettings = (settings: Record<string, unknown>): InputBlockResolvedSettings => ({
  controlledValue: resolveInputValue(settings['inputValue']),
  placeholder: typeof settings['inputPlaceholder'] === 'string' ? settings['inputPlaceholder'] : '',
  inputAriaLabel: typeof settings['inputAriaLabel'] === 'string' ? (settings['inputAriaLabel']).trim() : '',
  inputType: typeof settings['inputType'] === 'string' ? settings['inputType'] : 'text',
  autoComplete: typeof settings['inputAutoComplete'] === 'string' ? (settings['inputAutoComplete']).trim() : '',
  maxLength: resolveInputMaxLength(settings['inputMaxLength']),
  disabled: resolveBoolean(settings['inputDisabled']),
});

function buildInputBlockCustomStyles(settings: Record<string, unknown>): React.CSSProperties {
  const customStyles: React.CSSProperties = {};
  const fontFamily = settings['fontFamily'] as string | undefined;
  const fontSize = settings['fontSize'] as number | undefined;
  const fontWeight = settings['fontWeight'] as string | undefined;
  const textColor = settings['textColor'] as string | undefined;
  const bgColor = settings['bgColor'] as string | undefined;
  const borderColor = settings['borderColor'] as string | undefined;
  const borderRadius = settings['borderRadius'] as number | undefined;
  const borderWidth = settings['borderWidth'] as number | undefined;
  const height = settings['height'] as number | undefined;

  if (fontFamily !== undefined) customStyles.fontFamily = fontFamily;
  if (typeof fontSize === 'number' && fontSize > 0) customStyles.fontSize = `${fontSize}px`;
  if (fontWeight !== undefined) customStyles.fontWeight = fontWeight;
  if (textColor !== undefined) customStyles.color = textColor;
  if (bgColor !== undefined) customStyles.backgroundColor = bgColor;
  if (borderColor !== undefined) customStyles.borderColor = borderColor;
  if (typeof borderRadius === 'number' && borderRadius > 0) customStyles.borderRadius = `${borderRadius}px`;
  if (typeof borderWidth === 'number' && borderWidth > 0) {
    customStyles.borderWidth = `${borderWidth}px`;
    customStyles.borderStyle = 'solid';
  }
  if (typeof height === 'number' && height > 0) customStyles.height = `${height}px`;

  return customStyles;
}

export function InputBlock(): React.JSX.Element {
  const settings = useRequiredBlockSettings();
  const runtime = useOptionalCmsRuntime();
  const { autoComplete, controlledValue, disabled, inputAriaLabel, inputType, maxLength, placeholder } =
    useMemo(() => resolveInputBlockSettings(settings), [settings]);

  const changeAction = useMemo(
    () => resolveCmsRuntimeAction(runtime, settings['inputChangeActionSource'] as string, settings['inputChangeActionPath'] as string),
    [runtime, settings]
  );
  const submitAction = useMemo(
    () => resolveCmsRuntimeAction(runtime, settings['inputSubmitActionSource'] as string, settings['inputSubmitActionPath'] as string),
    [runtime, settings]
  );

  const [value, setValue] = useState(controlledValue);

  useEffect(() => {
    setValue(controlledValue);
  }, [controlledValue]);

  const customStyles = useMemo(() => buildInputBlockCustomStyles(settings), [settings]);

  const handleChange = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>): void => {
      const nextValue = event.target.value;
      setValue(nextValue);
      changeAction?.(nextValue);
    },
    [changeAction]
  );

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent<HTMLInputElement>): void => {
      if (event.key !== 'Enter' || submitAction === null) {
        return;
      }

      event.preventDefault();
      submitAction(value);
    },
    [submitAction, value]
  );

  return (
    <Input
      type={inputType}
      value={value}
      placeholder={placeholder}
      autoComplete={autoComplete || undefined}
      maxLength={maxLength}
      disabled={disabled}
      aria-label={inputAriaLabel || placeholder || 'Input field'}
      className='cms-appearance-input w-full'
      style={customStyles}
      onChange={handleChange}
      onKeyDown={handleKeyDown}
      title={placeholder}
    />
  );
}

