import React from 'react';
import type { GsapAnimationConfig } from '@/features/gsap/public';
import type { CssAnimationConfig } from '@/shared/contracts/cms';
import type { SectionInstance } from '@/shared/contracts/cms';
import { EventEffectsWrapper } from '@/features/cms/components/shared/EventEffectsWrapper';
import { CssAnimationWrapper } from '../CssAnimationWrapper';
import { GsapAnimationWrapper } from '../GsapAnimationWrapper';
import { renderSectionRenderer } from '../CmsPageRendererBase';
import { isCmsSectionHidden } from '@/features/cms/utils/page-builder-normalization';
import { isCmsNodeVisible, type CmsRuntimeContextValue } from '../CmsRuntimeShared';

export const SectionSubtree = ({
  sectionId,
  depth,
  hierarchy,
  runtime,
}: {
  sectionId: string;
  depth: number;
  hierarchy: any;
  runtime: CmsRuntimeContextValue | null;
}): React.JSX.Element | null => {
  const section = hierarchy.nodeById.get(sectionId) as SectionInstance | undefined;
  if (!section || isCmsSectionHidden(section.settings['isHidden']) || !isCmsNodeVisible(section.settings, runtime)) return null;

  const childIds = hierarchy.childrenByParent.get(section.id) ?? [];

  return (
    <div key={section.id}>
      <GsapAnimationWrapper config={section.settings['gsapAnimation'] as Partial<GsapAnimationConfig> | undefined}>
        <CssAnimationWrapper config={section.settings['cssAnimation'] as CssAnimationConfig | undefined}>
          <EventEffectsWrapper settings={section.settings}>
            {renderSectionRenderer({
              type: section.type,
              sectionId: section.id,
              settings: section.settings,
              blocks: section.blocks,
              runtime,
            })}
          </EventEffectsWrapper>
        </CssAnimationWrapper>
      </GsapAnimationWrapper>
      {childIds.length > 0 ? (
        <div
          style={{ borderColor: 'var(--cms-appearance-page-border)' }}
          className={depth === 1 ? 'ml-4 border-l pl-3' : 'ml-5 border-l pl-3'}
        >
          {childIds.map((childId: string) => (
            <SectionSubtree key={childId} sectionId={childId} depth={depth + 1} hierarchy={hierarchy} runtime={runtime} />
          ))}
        </div>
      ) : null}
    </div>
  );
};

'use client';

import React, { useId, useState } from 'react';

import type { BlockInstance } from '@/features/cms/types/page-builder';
import { CompactEmptyState } from '@/shared/ui/navigation-and-layout.public';

import { FrontendBlockRenderer } from './FrontendBlockRenderer';
import { useSectionBlockData } from './SectionBlockContext';
import { useCmsPageContext } from '../CmsPageContext';
import { getSectionContainerClass, getSectionStyles } from '../theme-styles';


export function FrontendAccordionSection(): React.ReactNode {
  const { settings, blocks } = useSectionBlockData();
  const { colorSchemes, layout } = useCmsPageContext();
  const sectionStyles = getSectionStyles(settings, colorSchemes);

  // Group blocks into pairs: Heading + Text = one accordion item
  const items: { heading: BlockInstance; text?: BlockInstance }[] = [];
  let i = 0;
  while (i < blocks.length) {
    const current = blocks[i];
    if (!current) {
      i += 1;
      continue;
    }
    if (current.type === 'Heading') {
      const next = blocks[i + 1];
      if (next?.type === 'Text') {
        items.push({ heading: current, text: next });
        i += 2;
      } else {
        items.push({ heading: current });
        i += 1;
      }
    } else {
      i += 1;
    }
  }

  if (items.length === 0) {
    return (
      <section style={sectionStyles}>
        <div className={getSectionContainerClass({ fullWidth: layout?.fullWidth })}>
          <CompactEmptyState
            title='No accordion items'
            description='Add Heading and Text blocks to create accordion items.'
            className='bg-card/20 py-8'
           />
        </div>
      </section>
    );
  }

  return (
    <section style={sectionStyles}>
      <div
        className={getSectionContainerClass({
          fullWidth: layout?.fullWidth,
          maxWidthClass: 'max-w-3xl',
        })}
      >
        <div className='divide-y divide-gray-700/50'>
          {items.map((item: { heading: BlockInstance; text?: BlockInstance }, index: number) => (
            <AccordionItem key={item.heading.id} item={item} defaultOpen={index === 0} />
          ))}
        </div>
      </div>
    </section>
  );
}

function AccordionItem({
  item,
  defaultOpen,
}: {
  item: { heading: BlockInstance; text?: BlockInstance };
  defaultOpen: boolean;
}): React.ReactNode {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const buttonId = useId();
  const panelId = `${buttonId}-panel`;
  const headingBlock = item.heading;
  const textBlock = item.text;
  const headingLabel =
    typeof headingBlock.settings?.['headingText'] === 'string'
      ? headingBlock.settings['headingText']
      : 'Accordion section';
  return (
    <div className='py-4'>
      <button
        type='button'
        onClick={() => setIsOpen(!isOpen)}
        className='flex w-full items-center justify-between text-left'
        id={buttonId}
        aria-expanded={isOpen}
        aria-controls={panelId}
        aria-label={headingLabel}
      >
        <FrontendBlockRenderer block={headingBlock} />
        <span className='cms-appearance-muted-text ml-4 shrink-0 text-xl'>
          {isOpen ? '−' : '+'}
        </span>
      </button>
      {isOpen && textBlock && (
        <div className='mt-3' id={panelId} role='region' aria-labelledby={buttonId}>
          <FrontendBlockRenderer block={textBlock} />
        </div>
      )}
    </div>
  );
}

'use client';

import type { BlockInstance } from '@/features/cms/types/page-builder';
import { resolveAlignItems, resolveJustifyContent } from '@/features/cms/components/shared/layout-utils';
