import Image from 'next/image';
import React from 'react';

import {
  clampNumber,
  resolveObjectPosition,
  buildTransparencyMaskStyles,
  resolveGradientDirection,
} from './frontend-grid-utils';

function buildImageElementPresentation(settings: Record<string, unknown>): {
  wrapperStyles: React.CSSProperties;
  imageStyles: React.CSSProperties;
  overlayStyles: React.CSSProperties;
  hasOverlay: boolean;
  useFill: boolean;
} {
  const width = (settings['width'] as number) || 100;
  const height = (settings['height'] as number) || 0;
  const aspectRatio = (settings['aspectRatio'] as string) || 'auto';
  const objectFit = (settings['objectFit'] as React.CSSProperties['objectFit']) || 'cover';
  const objectPosition = resolveObjectPosition((settings['objectPosition'] as string) || 'center');
  const opacity = clampNumber(settings['opacity'], 0, 100, 100);
  const blur = clampNumber(settings['blur'], 0, 20, 0);
  const grayscale = clampNumber(settings['grayscale'], 0, 100, 0);
  const brightness = clampNumber(settings['brightness'], 0, 200, 100);
  const contrast = clampNumber(settings['contrast'], 0, 200, 100);
  const scale = clampNumber(settings['scale'], 50, 200, 100);
  const rotate = clampNumber(settings['rotate'], -180, 180, 0);
  const shape = (settings['shape'] as string) || 'none';
  const borderRadius = (settings['borderRadius'] as number) || 0;
  const borderWidth = (settings['borderWidth'] as number) || 0;
  const borderStyle = (settings['borderStyle'] as string) || 'solid';
  const borderColor = (settings['borderColor'] as string) || '#ffffff';
  const overlayType = (settings['overlayType'] as string) || 'none';
  const overlayColor = (settings['overlayColor'] as string) || '#000000';
  const overlayOpacity = clampNumber(settings['overlayOpacity'], 0, 100, 0) / 100;
  const overlayGradientFrom = (settings['overlayGradientFrom'] as string) || '#000000';
  const overlayGradientTo = (settings['overlayGradientTo'] as string) || '#ffffff';
  const overlayGradientDirection = (settings['overlayGradientDirection'] as string) || 'to-bottom';
  const transparencyMode = (settings['transparencyMode'] as string) || 'none';
  const transparencyDirection = (settings['transparencyDirection'] as string) || 'bottom';
  const transparencyStrength = clampNumber(settings['transparencyStrength'], 0, 100, 0);

  const wrapperStyles: React.CSSProperties = {
    width: `${width}%`,
  };
  if (height > 0) wrapperStyles.height = `${height}px`;
  if (aspectRatio !== 'auto') wrapperStyles.aspectRatio = aspectRatio;
  if (borderWidth > 0 && borderStyle !== 'none') {
    wrapperStyles.borderWidth = `${borderWidth}px`;
    wrapperStyles.borderStyle = borderStyle;
    wrapperStyles.borderColor = borderColor;
  }
  if (shape === 'circle') {
    wrapperStyles.borderRadius = '9999px';
    wrapperStyles.overflow = 'hidden';
  } else if (shape === 'rounded' && borderRadius > 0) {
    wrapperStyles.borderRadius = `${borderRadius}px`;
    wrapperStyles.overflow = 'hidden';
  }

  const shadow = settings['imageShadow'] as Record<string, unknown> | undefined;
  if (shadow) {
    const x = (shadow['x'] as number) ?? 0;
    const y = (shadow['y'] as number) ?? 0;
    const blurShadow = (shadow['blur'] as number) ?? 0;
    const spread = (shadow['spread'] as number) ?? 0;
    const color = shadow['color'] as string | undefined;
    if ((x || y || blurShadow || spread) && color) {
      wrapperStyles.boxShadow = `${x}px ${y}px ${blurShadow}px ${spread}px ${color}`;
    }
  }

  Object.assign(
    wrapperStyles,
    buildTransparencyMaskStyles(transparencyMode, transparencyDirection, transparencyStrength)
  );

  const filters: string[] = [];
  if (blur > 0) filters.push(`blur(${blur}px)`);
  if (grayscale > 0) filters.push(`grayscale(${grayscale / 100})`);
  if (brightness !== 100) filters.push(`brightness(${brightness / 100})`);
  if (contrast !== 100) filters.push(`contrast(${contrast / 100})`);

  const transforms: string[] = [];
  if (scale !== 100) transforms.push(`scale(${scale / 100})`);
  if (rotate !== 0) transforms.push(`rotate(${rotate}deg)`);

  const imageStyles: React.CSSProperties = {
    width: '100%',
    objectFit,
    objectPosition,
    opacity: opacity / 100,
    filter: filters.length ? filters.join(' ') : undefined,
    transform: transforms.length ? transforms.join(' ') : undefined,
  };

  const overlayStyles: React.CSSProperties = {};
  if (overlayType === 'solid') {
    overlayStyles.backgroundColor = overlayColor;
    overlayStyles.opacity = overlayOpacity;
  } else if (overlayType === 'gradient') {
    overlayStyles.backgroundImage = `linear-gradient(${resolveGradientDirection(overlayGradientDirection)}, ${overlayGradientFrom}, ${overlayGradientTo})`;
    overlayStyles.opacity = overlayOpacity;
  }
  if (wrapperStyles.borderRadius) {
    overlayStyles.borderRadius = wrapperStyles.borderRadius as string;
  }

  return {
    wrapperStyles,
    imageStyles,
    overlayStyles,
    hasOverlay: overlayType !== 'none',
    useFill: height > 0 || aspectRatio !== 'auto',
  };
}

export function BackgroundImageLayer({
  settings,
}: {
  settings?: Record<string, unknown>;
}): React.ReactNode {
  if (!settings) return null;
  const src = (settings['src'] as string) || '';
  if (!src) return null;
  const alt = (settings['alt'] as string) || '';
  const presentation = buildImageElementPresentation(settings);
  const wrapperStyles: React.CSSProperties = {
    ...presentation.wrapperStyles,
    position: 'absolute',
    inset: 0,
    width: '100%',
    height: '100%',
    pointerEvents: 'none',
  };
  delete (wrapperStyles as { aspectRatio?: string }).aspectRatio;
  const imageStyles: React.CSSProperties = {
    ...presentation.imageStyles,
    display: 'block',
  };
  delete (imageStyles as { height?: string | number }).height;
  delete (imageStyles as { width?: string | number }).width;

  return (
    <div className='absolute inset-0 z-0' style={wrapperStyles}>
      <Image src={src} alt={alt} fill style={imageStyles} />
      {presentation.hasOverlay && (
        <div className='pointer-events-none absolute inset-0' style={presentation.overlayStyles} />
      )}
    </div>
  );
}

import React from 'react';

import { getCustomCssSelector, buildScopedCustomCss } from '@/features/cms/utils/custom-css';
import type { BlockInstance } from '@/shared/contracts/cms';

import { BackgroundImageLayer } from './BackgroundImageLayer';
import {
  SECTION_BLOCK_TYPES,
  getBlockMinHeight,
  getGapClass,
  getGapStyle,
  resolveGapValue,
  resolveJustifyContent,
  resolveAlignItems,
} from './frontend-grid-utils';
import { SectionBlockRenderer } from './SectionBlockRenderer';
import { BlockRenderContext } from '../../blocks/BlockContext';
import { CssAnimationWrapper } from '../../CssAnimationWrapper';
import { GsapAnimationWrapper } from '../../GsapAnimationWrapper';
import { getSectionStyles, getTextAlign } from '../../theme-styles';
import { FrontendBlockRenderer, BlockSettingsContext } from '../FrontendBlockRenderer';
import { useSectionData } from '../SectionDataContext';
import { SectionLayoutProvider, useSectionLayout } from '../SectionLayoutContext';




export function ColumnRenderer({ column }: { column: BlockInstance }): React.ReactNode {
  const children = column.blocks ?? [];
  const { colorSchemes } = useSectionData();
  const { rowHeightMode, rowHeight } = useSectionLayout();

  const contentChildren = children;

  const isSingleBlock = contentChildren.length === 1;
  const columnHeightMode = (column.settings['heightMode'] as string) || 'inherit';
  const columnHeight = (column.settings['height'] as number) || 0;
  const shouldStretch =
    isSingleBlock && (columnHeightMode === 'fixed' || rowHeightMode === 'fixed');
  const columnBackgroundSettings = column.settings['backgroundImage'] as
    | Record<string, unknown>
    | undefined;
  const hasColumnBackgroundSetting = Boolean((columnBackgroundSettings?.['src'] as string) || '');
  const hasColumnBackground = hasColumnBackgroundSetting;
  const columnGapValue = resolveGapValue(column.settings?.['gap'], 'medium');
  const columnGapClass = shouldStretch ? '' : getGapClass(columnGapValue);
  const columnGapStyle = shouldStretch ? undefined : getGapStyle(column.settings?.['gapPx']);
  const columnJustify = resolveJustifyContent(column.settings?.['justifyContent']);
  const columnAlign = resolveAlignItems(column.settings?.['alignItems']);
  const columnSelector = getCustomCssSelector(column.id);
  const columnCustomCss = buildScopedCustomCss(column.settings?.['customCss'], columnSelector);
  const columnStyles = {
    ...getSectionStyles(column.settings ?? {}, colorSchemes),
    ...getTextAlign(column.settings?.['textAlign']),
  };
  const columnStyle: React.CSSProperties = {};
  if (columnHeightMode === 'fixed' && columnHeight > 0) {
    columnStyle.height = `${columnHeight}px`;
  } else if (rowHeightMode === 'fixed' && rowHeight && rowHeight > 0) {
    columnStyle.height = '100%';
  }

  return (
    <BlockRenderContext.Provider
      value={{ block: column, mediaStyles: null, stretch: shouldStretch }}
    >
      <BlockSettingsContext.Provider value={column.settings}>
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            <div
              className={`relative cms-node-${column.id} ${hasColumnBackground ? 'overflow-hidden' : ''}`}
              style={{ ...columnStyles, ...columnStyle }}
            >
              {columnCustomCss ? (
                <style data-cms-custom-css={column.id}>{columnCustomCss}</style>
              ) : null}
              {hasColumnBackgroundSetting && (
                <BackgroundImageLayer settings={columnBackgroundSettings} />
              )}
              <div
                className={`relative z-10 flex flex-col ${shouldStretch ? 'h-full' : columnGapClass}`}
                style={{
                  ...(columnGapStyle ?? {}),
                  ...(columnJustify ? { justifyContent: columnJustify } : {}),
                  ...(columnAlign ? { alignItems: columnAlign } : {}),
                }}
              >
                {contentChildren.map((block: BlockInstance, blockIndex: number) => {
                  const minHeight = getBlockMinHeight(block.type);
                  const wrapperStyle: React.CSSProperties = {
                    ...(shouldStretch ? { height: '100%' } : { minHeight: `${minHeight}px` }),
                    position: 'relative',
                    zIndex: contentChildren.length - blockIndex,
                  };
                  if (SECTION_BLOCK_TYPES.has(block.type)) {
                    return (
                      <div
                        key={block.id}
                        className={shouldStretch ? 'flex-1' : ''}
                        style={wrapperStyle}
                      >
                        <SectionLayoutProvider stretch={shouldStretch}>
                          <SectionBlockRenderer block={block} />
                        </SectionLayoutProvider>
                      </div>
                    );
                  }
                  return (
                    <div
                      key={block.id}
                      className={shouldStretch ? 'flex-1' : ''}
                      style={wrapperStyle}
                    >
                      <SectionLayoutProvider stretch={shouldStretch}>
                        <FrontendBlockRenderer block={block} />
                      </SectionLayoutProvider>
                    </div>
                  );
                })}
              </div>
            </div>
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      </BlockSettingsContext.Provider>
    </BlockRenderContext.Provider>
  );
}

'use client';

import React from 'react';

import { EventEffectsWrapper } from '@/features/cms/components/shared/EventEffectsWrapper';
import { getCustomCssSelector, buildScopedCustomCss } from '@/features/cms/utils/custom-css';
import type { BlockInstance } from '@/shared/contracts/cms';

import { BlockRenderContext } from '../../blocks/BlockContext';
import { CssAnimationWrapper } from '../../CssAnimationWrapper';
import { GsapAnimationWrapper } from '../../GsapAnimationWrapper';
import { getSectionStyles, getTextAlign } from '../../theme-styles';
import { FrontendBlockRenderer, BlockSettingsContext } from '../FrontendBlockRenderer';
import { FrontendCarousel } from '../FrontendCarousel';
import { FrontendHeroBlock } from '../FrontendHeroBlock';
import { FrontendImageWithTextBlock } from '../FrontendImageWithTextBlock';
import { FrontendSlideshowSection } from '../FrontendSlideshowSection';
import { SectionBlockProvider } from '../SectionBlockContext';
import { useSectionData } from '../SectionDataContext';
import { SectionLayoutProvider, useSectionLayout } from '../SectionLayoutContext';
import { resolveJustifyContent, resolveAlignItems } from './frontend-grid-utils';


export function SectionBlockRenderer({ block }: { block: BlockInstance }): React.ReactNode {
  const children = block.blocks ?? [];
  const { stretch = false } = useSectionLayout();
  const stretchClass = stretch ? 'h-full' : '';
  const stretchStyle = stretch ? { height: '100%' } : undefined;
  const { colorSchemes } = useSectionData();

  const wrapInline = (node: React.ReactNode): React.ReactNode => (
    <EventEffectsWrapper>{node}</EventEffectsWrapper>
  );
  const wrapEventsOnly = (node: React.ReactNode): React.ReactNode => (
    <EventEffectsWrapper>{node}</EventEffectsWrapper>
  );

  const content = ((): React.ReactNode => {
    if (block.type === 'ImageWithText') {
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div className={stretchClass} style={stretchStyle}>
                <FrontendImageWithTextBlock />
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'Hero') {
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div className={stretchClass} style={stretchStyle}>
                <FrontendHeroBlock />
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'RichText') {
      const sectionStyles = getSectionStyles(block.settings, colorSchemes);
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div style={{ ...sectionStyles, ...(stretchStyle ?? {}) }} className={stretchClass}>
                <div className='space-y-4'>
                  {children.length > 0 ? (
                    children.map((child: BlockInstance) => (
                      <SectionLayoutProvider key={child.id} stretch={false}>
                        <FrontendBlockRenderer block={child} />
                      </SectionLayoutProvider>
                    ))
                  ) : (
                    <p className='cms-appearance-muted-text'>Rich text section</p>
                  )}
                </div>
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'Block') {
      const sectionStyles = {
        ...getSectionStyles(block.settings, colorSchemes),
        ...getTextAlign(block.settings['contentAlignment']),
      };
      const alignment = (block.settings['contentAlignment'] as string) || 'left';
      const blockGap =
        typeof block.settings['blockGap'] === 'number' ? block.settings['blockGap'] : 0;
      const direction = (block.settings['layoutDirection'] as string) || 'row';
      const wrap = (block.settings['wrap'] as string) || 'wrap';
      const justifySetting = (block.settings['justifyContent'] as string) || 'inherit';
      const justifyContent =
        resolveJustifyContent(justifySetting === 'inherit' ? alignment : justifySetting) ??
        (alignment === 'center' ? 'center' : alignment === 'right' ? 'flex-end' : 'flex-start');
      const alignItems = resolveAlignItems(block.settings['alignItems']) ?? 'center';
      const flexDirClass = direction === 'column' ? 'flex-col' : 'flex-Allrow';
      const wrapClass =
        direction === 'column' ? '' : wrap === 'nowrap' ? 'flex-nowrap' : 'flex-wrap';
      const shouldStretchChildren = stretch && children.length === 1;
      const linkUrl = (block.settings['linkUrl'] as string) || '';
      const linkTarget = (block.settings['linkTarget'] as string) || '_self';
      const linkRel = linkTarget === '_blank' ? 'noopener noreferrer' : undefined;
      const blockSelector = getCustomCssSelector(block.id);
      const blockCustomCss = buildScopedCustomCss(block.settings['customCss'], blockSelector);
      const innerContent = (
        <div
          className={`flex ${flexDirClass} ${wrapClass}`}
          style={{ gap: `${blockGap}px`, justifyContent, alignItems }}
        >
          {children.map((child: BlockInstance) => (
            <SectionLayoutProvider key={child.id} stretch={shouldStretchChildren}>
              <FrontendBlockRenderer block={child} />
            </SectionLayoutProvider>
          ))}
        </div>
      );
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapEventsOnly(
              <div
                style={{ ...sectionStyles, ...(stretchStyle ?? {}) }}
                className={`${stretchClass} cms-node-${block.id}`.trim()}
              >
                {blockCustomCss ? (
                  <style data-cms-custom-css={block.id}>{blockCustomCss}</style>
                ) : null}
                {linkUrl ? (
                  <a
                    href={linkUrl}
                    target={linkTarget}
                    rel={linkRel}
                    className='block w-full'
                    aria-label={linkUrl}
                  >
                    {innerContent}
                  </a>
                ) : (
                  innerContent
                )}
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'TextAtom') {
      const text = (block.settings['text'] as string) || '';
      const alignment = (block.settings['alignment'] as string) || 'left';
      const letterGap = (block.settings['letterGap'] as number) || 0;
      const lineGap = (block.settings['lineGap'] as number) || 0;
      const wrap = (block.settings['wrap'] as string) || 'wrap';
      const letters = (block.blocks ?? []).length
        ? (block.blocks ?? [])
        : Array.from(text).map(
          (char: string, index: number): BlockInstance => ({
            id: `text-atom-${block.id}-${index}`,
            type: 'TextAtomLetter',
            settings: { textContent: char },
          })
        );

      const justifyContent =
        alignment === 'center' ? 'center' : alignment === 'right' ? 'flex-end' : 'flex-start';

      const containerStyle: React.CSSProperties = {
        display: 'flex',
        flexWrap: wrap === 'nowrap' ? 'nowrap' : 'wrap',
        justifyContent,
        alignItems: 'baseline',
        columnGap: letterGap,
        rowGap: lineGap,
        whiteSpace: wrap === 'nowrap' ? 'pre' : 'pre-wrap',
      };

      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div style={{ ...containerStyle, ...(stretchStyle ?? {}) }} className={stretchClass}>
                {letters.length > 0 ? (
                  letters.map((letter: BlockInstance) => (
                    <SectionLayoutProvider key={letter.id} stretch={false}>
                      <FrontendBlockRenderer block={letter} />
                    </SectionLayoutProvider>
                  ))
                ) : (
                  <span className='cms-appearance-muted-text text-sm'>Text atoms</span>
                )}
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'Carousel') {
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div className={stretchClass} style={stretchStyle}>
                <FrontendCarousel />
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }
    if (block.type === 'Slideshow') {
      return (
        <GsapAnimationWrapper>
          <CssAnimationWrapper>
            {wrapInline(
              <div className={stretchClass} style={stretchStyle}>
                <FrontendSlideshowSection layout={{ fullWidth: true }} />
              </div>
            )}
          </CssAnimationWrapper>
        </GsapAnimationWrapper>
      );
    }

    return null;
  })();
  const blockSettings = block.settings;
  const blockRenderContextValue = React.useMemo(
    () => ({
      block,
      mediaStyles: null,
      stretch,
    }),
    [block, stretch]
  );

  return (
    <BlockRenderContext.Provider value={blockRenderContextValue}>
      <BlockSettingsContext.Provider value={blockSettings}>
        <SectionBlockProvider settings={blockSettings} blocks={children}>
          {content}
        </SectionBlockProvider>
      </BlockSettingsContext.Provider>
    </BlockRenderContext.Provider>
  );
}

import type { ColorSchemeColors, ThemeSettings } from '@/shared/contracts/cms-theme';
import { isObjectRecord } from '@/shared/utils/object-utils';

import type React from 'react';


export type { ColorSchemeColors };

// ---------------------------------------------------------------------------
// Color scheme mapping
// ---------------------------------------------------------------------------

const COLOR_SCHEME_STYLES: Record<string, React.CSSProperties> = {
  'scheme-1': {},
  'scheme-2': { backgroundColor: 'rgba(59,130,246,0.06)' },
  'scheme-3': { backgroundColor: 'rgba(139,92,246,0.06)' },
  'scheme-4': { backgroundColor: 'rgba(34,197,94,0.06)' },
  'scheme-5': { backgroundColor: 'rgba(245,158,11,0.06)' },
};

function buildSchemeStyle(colors: ColorSchemeColors): React.CSSProperties {
  return {
    backgroundColor: colors.background,
    color: colors.text,
    borderColor: colors.border,
    ['--scheme-background' as keyof React.CSSProperties]: colors.background,
    ['--scheme-surface' as keyof React.CSSProperties]: colors.surface,
    ['--scheme-text' as keyof React.CSSProperties]: colors.text,
    ['--scheme-accent' as keyof React.CSSProperties]: colors.accent,
    ['--scheme-border' as keyof React.CSSProperties]: colors.border,
  };
}

export function getColorSchemeStyle(
  scheme: unknown,
  schemes?: Record<string, ColorSchemeColors>
): React.CSSProperties {
  if (typeof scheme === 'string') {
    if (scheme === 'none' || scheme.trim() === '') {
      return {};
    }
    if (schemes?.[scheme]) {
      return buildSchemeStyle(schemes[scheme]);
    }
    if (scheme in COLOR_SCHEME_STYLES) {
      return COLOR_SCHEME_STYLES[scheme] ?? {};
    }
  }
  return {};
}

// ---------------------------------------------------------------------------
// Hover effect vars
// ---------------------------------------------------------------------------

export function getHoverEffectVars(effect?: string, scale?: number): React.CSSProperties {
  if (!effect && !scale) return {};
  const normalized = effect === 'lift-3d' ? 'lift-3d' : 'vertical-lift';
  const safeScale = typeof scale === 'number' && scale > 0 ? scale : 1;
  const transform =
    normalized === 'lift-3d'
      ? `translateY(-6px) rotateX(6deg) rotateY(-4deg) scale(${safeScale})`
      : `translateY(-4px) scale(${safeScale})`;
  const shadow =
    normalized === 'lift-3d'
      ? '0 18px 30px rgba(0, 0, 0, 0.35)'
      : '0 12px 20px rgba(0, 0, 0, 0.25)';
  const perspective = normalized === 'lift-3d' ? '900px' : 'none';

  return {
    ['--cms-hover-transform' as keyof React.CSSProperties]: transform,
    ['--cms-hover-shadow' as keyof React.CSSProperties]: shadow,
    ['--cms-hover-perspective' as keyof React.CSSProperties]: perspective,
  };
}

// ---------------------------------------------------------------------------
// Media styles (global)
// ---------------------------------------------------------------------------

const clampNumber = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

const withOpacity = (hex: unknown, opacityPercent: unknown): string => {
  const safeHex = typeof hex === 'string' ? hex : '#000000';
  const safeOpacity =
    typeof opacityPercent === 'number' && Number.isFinite(opacityPercent) ? opacityPercent : 100;
  const normalized = safeHex.replace('#', '').trim();
  const expanded =
    normalized.length === 3
      ? normalized
        .split('')
        .map((c: string) => c + c)
        .join('')
      : normalized;
  if (expanded.length !== 6 || Number.isNaN(Number.parseInt(expanded, 16))) {
    return safeHex;
  }
  const r = Number.parseInt(expanded.slice(0, 2), 16);
  const g = Number.parseInt(expanded.slice(2, 4), 16);
  const b = Number.parseInt(expanded.slice(4, 6), 16);
  const alpha = clampNumber(safeOpacity, 0, 100) / 100;
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const buildMediaShadow = (theme: ThemeSettings): string => {
  const opacity =
    clampNumber(
      typeof theme.imageShadowOpacity === 'number' ? theme.imageShadowOpacity : 0,
      0,
      100
    ) / 100;
  if (opacity <= 0) return 'none';
  const x = theme.imageShadowX ?? 0;
  const y = theme.imageShadowY ?? 0;
  const blur = theme.imageShadowBlur ?? 0;
  return `${x}px ${y}px ${blur}px rgba(0, 0, 0, ${opacity})`;
};

export function getMediaStyleVars(theme: ThemeSettings): React.CSSProperties {
  const imageRadius = typeof theme.imageRadius === 'number' ? theme.imageRadius : 8;
  const imageBorderWidth = typeof theme.imageBorderWidth === 'number' ? theme.imageBorderWidth : 0;
  return {
    ['--cms-media-radius' as keyof React.CSSProperties]: `${imageRadius}px`,
    ['--cms-media-border-width' as keyof React.CSSProperties]: `${imageBorderWidth}px`,
    ['--cms-media-border-color' as keyof React.CSSProperties]: withOpacity(
      theme.imageBorderColor,
      theme.imageBorderOpacity
    ),
    ['--cms-media-shadow' as keyof React.CSSProperties]: buildMediaShadow(theme),
  };
}

export function getMediaInlineStyles(theme: ThemeSettings): React.CSSProperties {
  const imageRadius = typeof theme.imageRadius === 'number' ? theme.imageRadius : 8;
  const imageBorderWidth = typeof theme.imageBorderWidth === 'number' ? theme.imageBorderWidth : 0;
  return {
    borderRadius: `${imageRadius}px`,
    borderWidth: `${imageBorderWidth}px`,
    borderStyle: imageBorderWidth > 0 ? 'solid' : 'none',
    borderColor: withOpacity(theme.imageBorderColor, theme.imageBorderOpacity),
    boxShadow: buildMediaShadow(theme),
  };
}

// ---------------------------------------------------------------------------
// Section / block inline styles from settings
// ---------------------------------------------------------------------------

export function getSectionStyles(
  settings: Record<string, unknown>,
  schemes?: Record<string, ColorSchemeColors>
): React.CSSProperties {
  const styles: React.CSSProperties = {};

  const pt = settings['paddingTop'];
  const pb = settings['paddingBottom'];
  const pl = settings['paddingLeft'];
  const pr = settings['paddingRight'];
  if (typeof pt === 'number') styles.paddingTop = `${pt}px`;
  if (typeof pb === 'number') styles.paddingBottom = `${pb}px`;
  if (typeof pl === 'number') styles.paddingLeft = `${pl}px`;
  if (typeof pr === 'number') styles.paddingRight = `${pr}px`;

  const mt = settings['marginTop'];
  const mb = settings['marginBottom'];
  const ml = settings['marginLeft'];
  const mr = settings['marginRight'];
  if (typeof mt === 'number') styles.marginTop = `${mt}px`;
  if (typeof mb === 'number') styles.marginBottom = `${mb}px`;
  if (typeof ml === 'number') styles.marginLeft = `${ml}px`;
  if (typeof mr === 'number') styles.marginRight = `${mr}px`;

  const colorSchemeStyles = getColorSchemeStyle(settings['colorScheme'], schemes);
  Object.assign(styles, colorSchemeStyles);

  // Per-section style overrides
  Object.assign(styles, getBlockBorderStyles(settings));
  Object.assign(styles, getBlockShadowStyles(settings));
  Object.assign(styles, getBlockBackgroundStyles(settings));
  Object.assign(styles, getLayoutStyles(settings));

  return styles;
}

// ---------------------------------------------------------------------------
// Layout styles (shared)
// ---------------------------------------------------------------------------

const OVERFLOW_VALUES = new Set(['visible', 'hidden', 'scroll', 'auto', 'clip']);

export function getLayoutStyles(settings: Record<string, unknown>): React.CSSProperties {
  const styles: React.CSSProperties = {};

  const minHeight = settings['minHeight'];
  const maxWidth = settings['maxWidth'];
  const width = settings['width'];
  const overflow = settings['overflow'];
  const opacity = settings['opacity'];
  const zIndex = settings['zIndex'];

  if (typeof minHeight === 'number' && Number.isFinite(minHeight) && minHeight > 0) {
    styles.minHeight = `${minHeight}px`;
  }
  if (typeof maxWidth === 'number' && Number.isFinite(maxWidth) && maxWidth > 0) {
    styles.maxWidth = `${maxWidth}px`;
  }
  if (typeof width === 'number' && Number.isFinite(width) && width > 0) {
    styles.width = `${width}px`;
  }
  if (typeof overflow === 'string' && OVERFLOW_VALUES.has(overflow)) {
    styles.overflow = overflow;
  }
  if (typeof opacity === 'number' && Number.isFinite(opacity)) {
    styles.opacity = clampNumber(opacity, 0, 100) / 100;
  }
  if (typeof zIndex === 'number' && Number.isFinite(zIndex)) {
    styles.zIndex = zIndex;
  }

  return styles;
}

// ---------------------------------------------------------------------------
// Content alignment
// ---------------------------------------------------------------------------

export function getTextAlign(alignment: unknown): React.CSSProperties {
  if (alignment === 'center') return { textAlign: 'center' };
  if (alignment === 'right') return { textAlign: 'right' };
  return { textAlign: 'left' };
}

export function getVerticalAlign(position: unknown): string {
  if (position === 'top') return 'items-start';
  if (position === 'bottom') return 'items-end';
  return 'items-center';
}

// ---------------------------------------------------------------------------
// Per-block typography styles
// ---------------------------------------------------------------------------

export function getBlockTypographyStyles(settings: Record<string, unknown>): React.CSSProperties {
  const styles: React.CSSProperties = {};
  const fontFamily = settings['fontFamily'] as string | undefined;
  const fontWeight = settings['fontWeight'] as string | undefined;
  const fontStyle = settings['fontStyle'] as string | undefined;
  const fontSize = settings['fontSize'] as number | undefined;
  const lineHeight = settings['lineHeight'] as number | undefined;
  const letterSpacing = settings['letterSpacing'] as number | undefined;
  const textColor = settings['textColor'] as string | undefined;
  const textDecoration = settings['textDecoration'] as string | undefined;
  const textTransform = settings['textTransform'] as string | undefined;
  const textAlign = settings['textAlign'] as string | undefined;
  const wordSpacing = settings['wordSpacing'] as number | undefined;
  const textShadowX = settings['textShadowX'] as number | undefined;
  const textShadowY = settings['textShadowY'] as number | undefined;
  const textShadowBlur = settings['textShadowBlur'] as number | undefined;
  const textShadowColor = settings['textShadowColor'] as string | undefined;

  if (fontFamily) styles.fontFamily = fontFamily;
  if (fontWeight) styles.fontWeight = fontWeight;
  if (fontStyle) styles.fontStyle = fontStyle;
  if (fontSize && fontSize > 0) styles.fontSize = `${fontSize}px`;
  if (lineHeight && lineHeight > 0) styles.lineHeight = lineHeight;
  if (letterSpacing) styles.letterSpacing = `${letterSpacing}px`;
  if (textColor) styles.color = textColor;
  if (textDecoration && textDecoration !== 'none') styles.textDecoration = textDecoration;
  if (textTransform && textTransform !== 'none')
    styles.textTransform = textTransform as React.CSSProperties['textTransform'];
  if (textAlign && textAlign !== 'left')
    styles.textAlign = textAlign as React.CSSProperties['textAlign'];
  if (wordSpacing && wordSpacing !== 0) styles.wordSpacing = `${wordSpacing}px`;
  const hasShadow = textShadowX || textShadowY || textShadowBlur;
  if (hasShadow) {
    styles.textShadow = `${textShadowX ?? 0}px ${textShadowY ?? 0}px ${textShadowBlur ?? 0}px ${textShadowColor || '#000'}`;
  }

  return styles;
}

// ---------------------------------------------------------------------------
// Per-section border styles
// ---------------------------------------------------------------------------

export function getBlockBorderStyles(settings: Record<string, unknown>): React.CSSProperties {
  const styles: React.CSSProperties = {};
  const border = settings['sectionBorder'] as Record<string, unknown> | undefined;
  if (!border) return styles;

  const width = border['width'] as number | undefined;
  const borderStyle = border['style'] as string | undefined;
  const color = border['color'] as string | undefined;
  const radius = border['radius'] as number | undefined;

  if (width && width > 0 && borderStyle && borderStyle !== 'none') {
    styles.borderWidth = `${width}px`;
    styles.borderStyle = borderStyle;
    if (color) styles.borderColor = color;
  }
  if (radius && radius > 0) styles.borderRadius = `${radius}px`;

  return styles;
}

// ---------------------------------------------------------------------------
// Per-section shadow styles
// ---------------------------------------------------------------------------

export function getBlockShadowStyles(settings: Record<string, unknown>): React.CSSProperties {
  const styles: React.CSSProperties = {};
  const shadow = settings['sectionShadow'] as Record<string, unknown> | undefined;
  if (!shadow) return styles;

  const x = shadow['x'] as number | undefined;
  const y = shadow['y'] as number | undefined;
  const blur = shadow['blur'] as number | undefined;
  const spread = shadow['spread'] as number | undefined;
  const color = shadow['color'] as string | undefined;

  if ((x || y || blur || spread) && color) {
    styles.boxShadow = `${x ?? 0}px ${y ?? 0}px ${blur ?? 0}px ${spread ?? 0}px ${color}`;
  }

  return styles;
}

// ---------------------------------------------------------------------------
// Per-section background styles
// ---------------------------------------------------------------------------

export function getBlockBackgroundStyles(settings: Record<string, unknown>): React.CSSProperties {
  const styles: React.CSSProperties = {};

  const resolveColorWithOpacity = (color: unknown, opacityPercent: unknown): string => {
    if (typeof color !== 'string') return '';
    const trimmed = color.trim();
    if (!trimmed) return '';
    if (trimmed.toLowerCase() === 'transparent') return 'rgba(0, 0, 0, 0)';
    const opacity =
      typeof opacityPercent === 'number' && Number.isFinite(opacityPercent)
        ? clampNumber(opacityPercent, 0, 100)
        : 100;
    if (opacity >= 100) return trimmed;
    if (opacity <= 0) return 'rgba(0, 0, 0, 0)';
    return withOpacity(trimmed, opacity);
  };

  const background = settings['background'];
  let appliedBackground = false;
  if (isObjectRecord(background)) {
    const type = background['type'];
    if (typeof type === 'string') {
      if (type === 'none') {
        appliedBackground = true;
      } else if (type === 'solid') {
        const color = background['color'];
        const resolved = resolveColorWithOpacity(color, 100);
        if (resolved) {
          styles.backgroundColor = resolved;
        }
        appliedBackground = true;
      } else if (type === 'gradient') {
        const from = resolveColorWithOpacity(
          background['gradientFrom'],
          background['gradientFromOpacity']
        );
        const to = resolveColorWithOpacity(
          background['gradientTo'],
          background['gradientToOpacity']
        );
        const angleRaw = background['gradientAngle'];
        const angle =
          typeof angleRaw === 'number' && Number.isFinite(angleRaw)
            ? ((Math.round(angleRaw) % 360) + 360) % 360
            : 180;
        if (from || to) {
          styles.backgroundImage = `linear-gradient(${angle}deg, ${from || 'transparent'}, ${to || 'transparent'})`;
          styles.backgroundRepeat = 'no-repeat';
        }
        appliedBackground = true;
      } else if (type === 'image') {
        const url = typeof background['imageUrl'] === 'string' ? background['imageUrl'].trim() : '';
        if (url) {
          styles.backgroundImage = `url(${url})`;
          styles.backgroundRepeat = 'no-repeat';
          styles.backgroundSize = 'cover';
          styles.backgroundPosition = 'center';
        }
        appliedBackground = true;
      }
    }
  }

  if (!appliedBackground) {
    const bgColor = settings['backgroundColor'] as string | undefined;
    if (bgColor) {
      styles.backgroundColor = bgColor;
    }
  }

  return styles;
}

// ---------------------------------------------------------------------------
// Container helpers
// ---------------------------------------------------------------------------

export function getSectionContainerClass(options?: {
  fullWidth?: boolean | undefined;
  maxWidthClass?: string | undefined;
  paddingClass?: string | undefined;
}): string {
  const padding = options?.paddingClass ?? 'px-4 md:px-6';
  if (options?.fullWidth) {
    return `w-full ${padding}`;
  }
  const maxWidth = options?.maxWidthClass ? ` ${options.maxWidthClass}` : '';
  return `page-container${maxWidth} ${padding}`;
}

'use client';

import { Zap } from 'lucide-react';
import React from 'react';

import { DEFAULT_ANIMATION_CONFIG } from '@/features/gsap/public';
import type { AnimationPreset, AnimationTrigger } from '@/shared/contracts/gsap';
import { ANIMATION_PRESETS, ANIMATION_EASINGS } from '@/shared/contracts/gsap';
import { internalError } from '@/shared/errors/app-error';
import { Input, Label, RadioGroup, RadioGroupItem } from '@/shared/ui/primitives.public';
import { SelectSimple, FormField, ToggleRow } from '@/shared/ui/forms-and-actions.public';
import { SectionHeader } from '@/shared/ui/navigation-and-layout.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { AdvancedSection } from './animation/AdvancedSection';
import { AnimationConfigProvider } from './animation/AnimationConfigContext';
import { ParallaxSection } from './animation/ParallaxSection';
import { TimelineSection } from './animation/TimelineSection';
import { VisualEffectsSection } from './animation/VisualEffectsSection';
import {
  useComponentSettingsActions,
  useComponentSettingsState,
} from './context/ComponentSettingsContext';
import { useVectorOverlay } from '../../hooks/usePageBuilderContext';

export function AnimationConfigPanel(): React.JSX.Element {
  const { currentAnimationConfig: config } = useComponentSettingsState();
  const { handleAnimationChange: onChange } = useComponentSettingsActions();
  const { openVectorOverlay } = useVectorOverlay();
  const isEnabled =
    config.preset !== 'none' ||
    config.motionPathEnabled ||
    config.svgDrawEnabled ||
    config.parallaxPreset !== 'none';

  return (
    <div className='space-y-6 pb-20'>
      <SectionHeader
        title='Animations & FX'
        description='Configure GSAP-powered transitions and interactive effects.'
        icon={<Zap className='size-4 text-yellow-400' />}
      />

      <ToggleRow
        label='Enable Animations'
        description='Master switch for all animation effects on this component'
        checked={isEnabled}
        onCheckedChange={(checked: boolean) => {
          if (!checked) {
            onChange({ ...DEFAULT_ANIMATION_CONFIG, preset: 'none' });
          } else {
            onChange({ preset: 'fadeIn' });
          }
        }}
      />

      {isEnabled && (
        <>
          <FormField label='Animation Preset' description='Core entry transition style'>
            <SelectSimple
              options={ANIMATION_PRESETS}
              value={config.preset}
              onValueChange={(val) => onChange({ preset: val as AnimationPreset })}
             ariaLabel='Animation Preset' title='Animation Preset'/>
          </FormField>

          <div className='grid grid-cols-2 gap-4'>
            <FormField label='Duration (s)'>
              <Input
                type='number'
                min={0}
                max={10}
                step={0.1}
                value={config.duration}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const value = Number(e.target.value);
                  if (Number.isNaN(value)) {
                    logClientCatch(internalError('Invalid duration input'), {
                      source: 'cms.animation-panel',
                      action: 'updateDuration',
                      rawValue: e.target.value,
                    });
                    return;
                  }
                  onChange({ duration: value });
                }}
               aria-label='Duration (s)' title='Duration (s)'/>
            </FormField>
            <FormField label='Delay (s)'>
              <Input
                type='number'
                min={0}
                max={10}
                step={0.1}
                value={config.delay}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const value = Number(e.target.value);
                  if (Number.isNaN(value)) {
                    logClientCatch(internalError('Invalid delay input'), {
                      source: 'cms.animation-panel',
                      action: 'updateDelay',
                      rawValue: e.target.value,
                    });
                    return;
                  }
                  onChange({ delay: value });
                }}
               aria-label='Delay (s)' title='Delay (s)'/>
            </FormField>
          </div>

          <FormField label='Easing' description='The rhythm of the motion'>
            <SelectSimple
              options={ANIMATION_EASINGS}
              value={config.easing}
              onValueChange={(val) => onChange({ easing: val })}
             ariaLabel='Easing' title='Easing'/>
          </FormField>

          <FormField label='Trigger' description='When should the animation start?'>
            <RadioGroup
              value={config.trigger}
              onValueChange={(val) => onChange({ trigger: val as AnimationTrigger })}
              className='grid grid-cols-1 gap-2 mt-2'
            >
              <div className='flex items-center gap-2'>
                <RadioGroupItem value='load' id='trigger-load' />
                <Label htmlFor='trigger-load' className='text-sm text-gray-300 cursor-pointer'>
                  On page load
                </Label>
              </div>
              <div className='flex items-center gap-2'>
                <RadioGroupItem value='hover' id='trigger-hover' />
                <Label htmlFor='trigger-hover' className='text-sm text-gray-300 cursor-pointer'>
                  On mouse hover
                </Label>
              </div>
              <div className='flex items-center gap-2'>
                <RadioGroupItem value='scroll' id='trigger-scroll' />
                <Label htmlFor='trigger-scroll' className='text-sm text-gray-300 cursor-pointer'>
                  On scroll into view
                </Label>
              </div>
            </RadioGroup>
          </FormField>

          <AnimationConfigProvider
            value={{
              config,
              onChange,
              openVectorOverlay,
            }}
          >
            <TimelineSection />
            <ParallaxSection />
            <AdvancedSection />
            <VisualEffectsSection />
          </AnimationConfigProvider>
        </>
      )}
    </div>
  );
}

'use client';

import Link from 'next/link';
import React, { useCallback } from 'react';

import { APP_EMBED_OPTIONS } from '@/shared/lib/app-embeds';
import { AppEmbedsProvider, useAppEmbeds } from '@/shared/providers/AppEmbedsProvider';
import { Button, Checkbox, Label } from '@/shared/ui/primitives.public';
import { LoadingState, SectionHeader, UI_CENTER_ROW_CLASSNAME, UI_CENTER_ROW_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { SimpleSettingsList } from '@/shared/ui/templates.public';

export function AppEmbedsPanel({
  showHeader = true,
}: { showHeader?: boolean } = {}): React.JSX.Element {
  return (
    <AppEmbedsProvider>
      <AppEmbedsPanelContent showHeader={showHeader} />
    </AppEmbedsProvider>
  );
}

function AppEmbedsPanelContent({ showHeader }: { showHeader: boolean }): React.JSX.Element {
  const { enabled, toggleOption, save, isLoading, isSaving } = useAppEmbeds();

  const handleSave = useCallback((): void => {
    void save();
  }, [save]);

  if (isLoading) {
    return <LoadingState message='Loading app embeds...' className='h-full' />;
  }

  const items = APP_EMBED_OPTIONS.map((option) => ({
    id: option.id,
    title: option.label,
    description: option.description,
    original: option,
  }));

  return (
    <div className='flex min-h-0 flex-1 flex-col'>
      {showHeader && (
        <SectionHeader
          title='App embeds'
          subtitle='Enable apps you can embed into CMS layouts.'
          size='xs'
          className='p-3 border-b border-border'
        />
      )}
      <div className='flex-1 overflow-y-auto p-3'>
        <SimpleSettingsList
          items={items}
          renderActions={(item: typeof items[number]) => {
            const isEnabled = enabled.has(item.id);
            const checkboxId = `app-embed-enabled-${item.id}`;
            return (
              <div className={UI_CENTER_ROW_RELAXED_CLASSNAME}>
                <div className={`${UI_CENTER_ROW_CLASSNAME} text-xs text-gray-300`}>
                  <Checkbox
                    id={checkboxId}
                    checked={isEnabled}
                    onCheckedChange={(checked: boolean | 'indeterminate') =>
                      toggleOption(item.id, checked === true)
                    }
                  />
                  <Label htmlFor={checkboxId} className='cursor-pointer text-xs text-gray-300'>
                    Enabled
                  </Label>
                </div>
                <Link
                  href={item.original.settingsRoute}
                  className='text-xs text-blue-300 hover:text-blue-200 underline underline-offset-2'
                >
                  Settings
                </Link>
              </div>
            );
          }}
        />
      </div>
      <div className='border-t border-border px-4 py-3'>
        <Button
          onClick={handleSave}
          loading={isSaving}
          loadingText='Saving...'
          className='w-full'
        >
          Save Configuration
        </Button>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useMemo } from 'react';

import { Viewer3D, Asset3DPreviewModal } from '@/features/viewer3d/public';
import {
  useAssets3D,
  useAsset3DCategories,
  useAsset3DTags,
} from '@/features/viewer3d/public';
import type { EntityModalProps } from '@/shared/contracts/ui/modals';
import type { Asset3DListFilters, Asset3DRecord } from '@/shared/contracts/viewer3d';
import { FilterPanel } from '@/shared/ui/templates.public';
import { Button } from '@/shared/ui/primitives.public';
import { FormSection } from '@/shared/ui/forms-and-actions.public';
import { CompactEmptyState } from '@/shared/ui/navigation-and-layout.public';
import { DetailModal } from '@/shared/ui/templates/modals';
import type { FilterField } from '@/shared/contracts/ui/panels';

type Asset3DPickerModalProps = EntityModalProps<Asset3DRecord, Asset3DRecord> & {
  onSelectAsset: (assetId: string) => void;
};

const ALL_ASSET_CATEGORIES_OPTION = { value: '__all__', label: 'All categories' };

export function Asset3DPickerModal(props: Asset3DPickerModalProps): React.JSX.Element | null {
  const { isOpen, onClose, onSelectAsset } = props;

  const [previewAsset, setPreviewAsset] = useState<Asset3DRecord | null>(null);
  const [filters, setFilters] = useState({
    search: '',
    category: '__all__',
    tags: [] as string[],
    isPublicOnly: false,
  });

  const categoriesQuery = useAsset3DCategories();
  const tagsQuery = useAsset3DTags();

  const categories = categoriesQuery.data ?? [];
  const tags = tagsQuery.data ?? [];

  const categoryOptions = useMemo(
    () => [ALL_ASSET_CATEGORIES_OPTION, ...categories.map((cat: string) => ({ value: cat, label: cat }))],
    [categories]
  );
  const tagOptions = useMemo(
    () => tags.map((tag: string) => ({ value: tag, label: tag })),
    [tags]
  );

  const filterConfig = useMemo<FilterField[]>(
    () => [
      {
        key: 'category',
        label: 'Category',
        type: 'select',
        options: categoryOptions,
      },
      {
        key: 'tags',
        label: 'Tags',
        type: 'select',
        multi: true,
        options: tagOptions,
      },
      {
        key: 'isPublicOnly',
        label: 'Public only',
        type: 'checkbox',
      },
    ],
    [categoryOptions, tagOptions]
  );

  const apiFilters: Asset3DListFilters = {
    search: filters.search.trim() || undefined,
    categoryId: filters.category === '__all__' ? undefined : filters.category,
    tags: filters.tags,
    ...(filters.isPublicOnly ? { isPublic: true } : {}),
  };
  const assetsQuery = useAssets3D(apiFilters);
  const assets = assetsQuery.data ?? [];

  const handleFilterChange = (key: string, value: unknown) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  const handleReset = () => {
    setFilters({
      search: '',
      category: '__all__',
      tags: [],
      isPublicOnly: false,
    });
  };

  return (
    <>
      <DetailModal
        isOpen={isOpen}
        onClose={onClose}
        title='Select 3D asset'
        size='xl'
        footer={null}
      >
        <div className='space-y-4 text-sm text-gray-200'>
          <FilterPanel
            filters={filterConfig}
            values={filters}
            search={filters.search}
            searchPlaceholder='Search assets...'
            onFilterChange={handleFilterChange}
            onSearchChange={(search) => handleFilterChange('search', search)}
            onReset={handleReset}
            showHeader={false}
            compact
          />

          <div className='grid gap-3 md:grid-cols-[1fr_320px]'>
            <div className='space-y-2'>
              {assetsQuery.isLoading ? (
                <div className='text-xs text-gray-400'>Loading assets...</div>
              ) : assets.length === 0 ? (
                <CompactEmptyState
                  title='No 3D assets found'
                  description='Try adjusting your filters or upload new assets in the 3D Viewer admin.'
                  className='py-12'
                 />
              ) : (
                <div className='space-y-2'>
                  {assets.map((asset: Asset3DRecord) => (
                    <FormSection key={asset.id} variant='subtle' className='p-2'>
                      <div className='flex items-center justify-between gap-2'>
                        <div className='min-w-0'>
                          <div className='truncate text-sm text-gray-100'>
                            {asset.name || asset.filename}
                          </div>
                          <div className='text-[11px] text-gray-400'>
                            {asset.categoryId ? `${asset.categoryId} • ` : ''}
                            {asset.tags?.length ? asset.tags.join(', ') : 'No tags'}
                          </div>
                        </div>
                        <div className='flex items-center gap-2'>
                          <Button
                            type='button'
                            size='sm'
                            variant='outline'
                            onClick={() => setPreviewAsset(asset)}
                          >
                            Preview
                          </Button>
                          <Button
                            type='button'
                            size='sm'
                            onClick={() => {
                              onSelectAsset(asset.id);
                            }}
                          >
                            Select
                          </Button>
                        </div>
                      </div>
                    </FormSection>
                  ))}
                </div>
              )}
            </div>
            <FormSection title='Preview' variant='subtle' className='p-2'>
              {previewAsset ? (
                <div className='mt-2 h-56'>
                  <Viewer3D
                    modelUrl={`/api/assets3d/${previewAsset.id}/file`}
                    settings={{
                      backgroundColor: '#111827',
                      autoRotate: true,
                      autoRotateSpeed: 2,
                      environment: 'studio',
                      lighting: 'studio',
                      lightIntensity: 1,
                      enableShadows: true,
                      enableBloom: false,
                      bloomIntensity: 0.5,
                      exposure: 1,
                      showGround: false,
                      enableContactShadows: true,
                      enableVignette: false,
                    }}
                    autoFit
                    presentationMode={false}
                    className='h-full w-full'
                  />
                </div>
              ) : (
                <div className='mt-2 text-xs text-gray-500'>Pick an asset to preview.</div>
              )}
            </FormSection>
          </div>
        </div>
      </DetailModal>

      {previewAsset ? (
        <Asset3DPreviewModal
          isOpen={Boolean(previewAsset)}
          onClose={() => setPreviewAsset(null)}
          item={previewAsset}
        />
      ) : null}
    </>
  );
}

