            <TabsContent value='settings' className='flex-1 overflow-y-auto p-4 mt-0'>
              <SectionSettingsTab />
              <ColumnSettingsTab />
              <BlockSettingsTab />
            </TabsContent>
            <TabsContent value='animation' className='flex-1 overflow-y-auto p-4 mt-0'>
