            value={(value as string) ?? '#ffffff'}
            onChange={handleChange}
            disabled={isDisabled}
            ariaLabel={field.label}
            id={controlId}
          />
        </>
      )}

      {field.type === 'font-family' && (
        <>
          <Label
            className='text-xs font-medium uppercase tracking-wide text-gray-400'
            htmlFor={controlId}
          >
            {field.label}
          </Label>
          <SelectSimple
            size='sm'
            value={((): string => {
              const fallback =
                (typeof field.defaultValue === 'string' && field.defaultValue.trim().length > 0
                  ? field.defaultValue
                  : theme.bodyFont) || 'Inter, sans-serif';
              return typeof value === 'string' && value.trim().length > 0 ? value : fallback;
            })()}
            onValueChange={handleChange}
            options={FONT_FAMILY_OPTIONS}
            disabled={isDisabled}
            ariaLabel={field.label}
            id={controlId}
            triggerClassName='h-7 bg-card/40 text-xs mt-1'
           title={controlId}/>
        </>
      )}

      {field.type === 'font-weight' && (
        <>
          <Label
            className='text-xs font-medium uppercase tracking-wide text-gray-400'
            htmlFor={controlId}
          >
            {field.label}
          </Label>
          <SelectSimple
            size='sm'
            value={String((value as string | number) ?? '400')}
            onValueChange={handleChange}
            options={FONT_WEIGHT_OPTIONS}
            disabled={isDisabled}
            ariaLabel={field.label}
            id={controlId}
            triggerClassName='h-7 bg-card/40 text-xs mt-1'
           title={controlId}/>
        </>
      )}

      {field.type === 'spacing' && (
        <>
          <Label
            className='text-xs font-medium uppercase tracking-wide text-gray-400'
            id={`${controlId}-label`}
          >
            {field.label}
          </Label>
          <div role='group' aria-labelledby={`${controlId}-label`}>
            <CompositeFieldProvider
              value={value}
              onChange={handleChange}
              fieldLabel={field.label}
              fieldId={controlId}
