            {field.label}
          </Label>
          <div role='group' aria-labelledby={`${controlId}-label`}>
            <CompositeFieldProvider
              value={value}
              onChange={handleChange}
              fieldLabel={field.label}
              fieldId={controlId}
            >
              <BorderField />
            </CompositeFieldProvider>
          </div>
        </>
      )}

      {field.type === 'shadow' && (
        <>
          <Label
            className='text-xs font-medium uppercase tracking-wide text-gray-400'
            id={`${controlId}-label`}
          >
            {field.label}
          </Label>
          <div role='group' aria-labelledby={`${controlId}-label`}>
            <CompositeFieldProvider
              value={value}
              onChange={handleChange}
              fieldLabel={field.label}
              fieldId={controlId}
