    (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = parseFloat(e.target.value);
      if (!isNaN(val)) {
        onChange({ ...config, parallaxRotateTo: Math.max(-180, Math.min(180, val)) });
      }
    },
    [config, onChange]
  );

  const handleParallaxOpacityFromChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
