import { UI_GRID_RELAXED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';

import { useAnimationConfigActions, useAnimationConfigState } from './AnimationConfigContext';
import { RangeField, SelectField } from '../shared-fields';
import { ColorPickerField } from './ColorPickerField';
import {
  type VisualFilterType,
  type VisualClipType,
  type VisualShadowValues,
  FILTER_OPTIONS,
  FILTER_META,
  CLIP_OPTIONS,
  clampNumber,
  parseNumber,
  parseFilterString,
  buildFilterString,
  parseClipString,
  buildClipString,
  parseShadow,
  buildShadow,
} from './visual-effect-utils';

export function VisualEffectsSection(): React.ReactNode {
  const { config } = useAnimationConfigState();
  const { onChange } = useAnimationConfigActions();
  const visualFilterFromValue =
    config.visualFilterFrom ?? DEFAULT_ANIMATION_CONFIG.visualFilterFrom ?? '';
  const visualFilterToValue =
    config.visualFilterTo ?? DEFAULT_ANIMATION_CONFIG.visualFilterTo ?? '';
  const visualClipFromValue =
    config.visualClipFrom ?? DEFAULT_ANIMATION_CONFIG.visualClipFrom ?? '';
  const visualClipToValue = config.visualClipTo ?? DEFAULT_ANIMATION_CONFIG.visualClipTo ?? '';
  const visualRadiusFromValue =
    config.visualRadiusFrom ?? DEFAULT_ANIMATION_CONFIG.visualRadiusFrom ?? '';
  const visualRadiusToValue =
    config.visualRadiusTo ?? DEFAULT_ANIMATION_CONFIG.visualRadiusTo ?? '';
  const visualShadowFromValue =
    config.visualShadowFrom ?? DEFAULT_ANIMATION_CONFIG.visualShadowFrom ?? '';
  const visualShadowToValue =
    config.visualShadowTo ?? DEFAULT_ANIMATION_CONFIG.visualShadowTo ?? '';
  const visualBackgroundFromValue =
    config.visualBackgroundFrom ?? DEFAULT_ANIMATION_CONFIG.visualBackgroundFrom ?? '';
  const visualBackgroundToValue =
    config.visualBackgroundTo ?? DEFAULT_ANIMATION_CONFIG.visualBackgroundTo ?? '';

  const resolvedFilterFrom = parseFilterString(visualFilterFromValue);
  const resolvedFilterTo = parseFilterString(visualFilterToValue);
  const filterTypeValue = resolvedFilterFrom?.type ?? resolvedFilterTo?.type ?? 'none';
  const filterMeta = FILTER_META[filterTypeValue];
  const filterFromAmount = clampNumber(
    resolvedFilterFrom?.amount ?? filterMeta.defaultFrom,
    filterMeta.min,
    filterMeta.max
  );
  const filterToAmount = clampNumber(
    resolvedFilterTo?.amount ?? filterMeta.defaultTo,
    filterMeta.min,
    filterMeta.max
  );

  const resolvedClipFrom = parseClipString(visualClipFromValue);
  const resolvedClipTo = parseClipString(visualClipToValue);
  const clipTypeValue = resolvedClipFrom?.type ?? resolvedClipTo?.type ?? 'none';
  const clipFromAmount = clampNumber(resolvedClipFrom?.amount ?? 100, 0, 100);
  const clipToAmount = clampNumber(resolvedClipTo?.amount ?? 0, 0, 100);

  const radiusFromAmount = clampNumber(parseNumber(visualRadiusFromValue, 0), 0, 200);
  const radiusToAmount = clampNumber(parseNumber(visualRadiusToValue, 0), 0, 200);

  const shadowFromValues = parseShadow(visualShadowFromValue);
  const shadowToValues = parseShadow(visualShadowToValue);

  const handleVisualFilterTypeChange = useCallback(
    (value: string): void => {
      const type = value as VisualFilterType;
      if (type === 'none') {
        onChange({ ...config, visualFilterFrom: '', visualFilterTo: '' });
        return;
      }
      const meta = FILTER_META[type];
      const from = clampNumber(resolvedFilterFrom?.amount ?? meta.defaultFrom, meta.min, meta.max);
      const to = clampNumber(resolvedFilterTo?.amount ?? meta.defaultTo, meta.min, meta.max);
      onChange({
        ...config,
        visualFilterFrom: buildFilterString(type, from),
        visualFilterTo: buildFilterString(type, to),
      });
    },
    [config, onChange, resolvedFilterFrom, resolvedFilterTo]
  );

  const handleVisualFilterFromChange = useCallback(
    (value: number): void => {
      if (filterTypeValue === 'none') return;
      onChange({ ...config, visualFilterFrom: buildFilterString(filterTypeValue, value) });
    },
    [config, onChange, filterTypeValue]
  );

  const handleVisualFilterToChange = useCallback(
    (value: number): void => {
      if (filterTypeValue === 'none') return;
      onChange({ ...config, visualFilterTo: buildFilterString(filterTypeValue, value) });
    },
    [config, onChange, filterTypeValue]
  );

  const handleVisualClipTypeChange = useCallback(
    (value: string): void => {
      const type = value as VisualClipType;
      if (type === 'none') {
        onChange({ ...config, visualClipFrom: '', visualClipTo: '' });
        return;
      }
      onChange({
        ...config,
        visualClipFrom: buildClipString(type, clipFromAmount),
        visualClipTo: buildClipString(type, clipToAmount),
      });
    },
    [config, onChange, clipFromAmount, clipToAmount]
  );

  const handleVisualClipFromChange = useCallback(
    (value: number): void => {
      if (clipTypeValue === 'none') return;
      onChange({ ...config, visualClipFrom: buildClipString(clipTypeValue, value) });
    },
    [config, onChange, clipTypeValue]
  );

  const handleVisualClipToChange = useCallback(
    (value: number): void => {
      if (clipTypeValue === 'none') return;
      onChange({ ...config, visualClipTo: buildClipString(clipTypeValue, value) });
    },
    [config, onChange, clipTypeValue]
  );

  const handleVisualRadiusFromChange = useCallback(
    (value: number): void => {
      onChange({ ...config, visualRadiusFrom: `${clampNumber(value, 0, 200)}px` });
    },
    [config, onChange]
  );

  const handleVisualRadiusToChange = useCallback(
    (value: number): void => {
      onChange({ ...config, visualRadiusTo: `${clampNumber(value, 0, 200)}px` });
    },
    [config, onChange]
  );

  const updateShadowValue = useCallback(
    (target: 'from' | 'to', partial: Partial<VisualShadowValues>): void => {
      const current = target === 'from' ? shadowFromValues : shadowToValues;
      const next = { ...current, ...partial };
      const shadow = buildShadow(next);
      onChange({
        ...config,
        [target === 'from' ? 'visualShadowFrom' : 'visualShadowTo']: shadow,
      });
    },
    [config, onChange, shadowFromValues, shadowToValues]
  );

  const handleVisualBackgroundFromChange = useCallback(
    (value: string): void => {
      onChange({ ...config, visualBackgroundFrom: value });
    },
    [config, onChange]
  );

  const handleVisualBackgroundToChange = useCallback(
    (value: string): void => {
      onChange({ ...config, visualBackgroundTo: value });
    },
    [config, onChange]
  );

  return (
    <FormSection title='Visual FX' variant='subtle-compact' className='p-3 space-y-4'>
      <div className='space-y-3 mt-4'>
        <Card
          variant='subtle-compact'
          padding='sm'
          className='border-border/40 bg-card/30 space-y-3'
        >
          <FormField label='Filter type'>
            <SelectField
              label='Filter type'
              value={filterTypeValue}
              onChange={handleVisualFilterTypeChange}
              options={FILTER_OPTIONS}
            />
          </FormField>
          {filterTypeValue !== 'none' && (
            <div className='grid gap-3 sm:grid-cols-2'>
              <RangeField
                label='Filter from'
                value={filterFromAmount}
                onChange={handleVisualFilterFromChange}
                min={filterMeta.min}
                max={filterMeta.max}
                step={filterMeta.step}
                suffix={filterMeta.unit}
              />
              <RangeField
                label='Filter to'
                value={filterToAmount}
                onChange={handleVisualFilterToChange}
                min={filterMeta.min}
                max={filterMeta.max}
                step={filterMeta.step}
                suffix={filterMeta.unit}
              />
            </div>
          )}
        </Card>

        <Card
          variant='subtle-compact'
          padding='sm'
          className='border-border/40 bg-card/30 space-y-3'
        >
          <FormField label='Clip path'>
            <SelectField
              label='Clip path'
              value={clipTypeValue}
              onChange={handleVisualClipTypeChange}
              options={CLIP_OPTIONS}
            />
          </FormField>
          {clipTypeValue !== 'none' && (
            <div className='grid gap-3 sm:grid-cols-2'>
              <RangeField
                label='Clip from'
                value={clipFromAmount}
                onChange={handleVisualClipFromChange}
                min={0}
                max={100}
                step={1}
                suffix='%'
              />
              <RangeField
                label='Clip to'
                value={clipToAmount}
                onChange={handleVisualClipToChange}
                min={0}
                max={100}
                step={1}
                suffix='%'
              />
            </div>
          )}
        </Card>

        <Card
          variant='subtle-compact'
          padding='sm'
          className='border-border/40 bg-card/30 space-y-3'
        >
          <div className='grid gap-3 sm:grid-cols-2'>
            <RangeField
              label='Radius from'
              value={radiusFromAmount}
              onChange={handleVisualRadiusFromChange}
              min={0}
              max={200}
              step={1}
              suffix='px'
            />
            <RangeField
              label='Radius to'
              value={radiusToAmount}
              onChange={handleVisualRadiusToChange}
              min={0}
              max={200}
              step={1}
              suffix='px'
            />
          </div>
        </Card>

        <Card
          variant='subtle-compact'
          padding='sm'
          className='border-border/40 bg-card/30 space-y-3'
        >
          <FormSection title='Shadow' variant='subtle-compact' className='p-0'>
            <div className={`${UI_GRID_RELAXED_CLASSNAME} lg:grid-cols-2 mt-2`}>
              <div className='space-y-3'>
                <FormSection title='From' variant='subtle-compact' className='p-0'>
                  <div className='grid gap-3 sm:grid-cols-2 mt-2'>
                    <RangeField
                      label='Offset X'
                      value={shadowFromValues.x}
                      onChange={(value: number) => updateShadowValue('from', { x: value })}
                      min={-60}
                      max={60}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Offset Y'
                      value={shadowFromValues.y}
                      onChange={(value: number) => updateShadowValue('from', { y: value })}
                      min={-60}
                      max={60}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Blur'
                      value={shadowFromValues.blur}
                      onChange={(value: number) => updateShadowValue('from', { blur: value })}
                      min={0}
                      max={120}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Spread'
                      value={shadowFromValues.spread}
                      onChange={(value: number) => updateShadowValue('from', { spread: value })}
                      min={-40}
                      max={40}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Opacity'
                      value={shadowFromValues.opacity}
                      onChange={(value: number) => updateShadowValue('from', { opacity: value })}
                      min={0}
                      max={100}
                      step={1}
                      suffix='%'
                    />
                  </div>
                  <ColorPickerField
                    label='Color'
                    value={shadowFromValues.color}
                    onChange={(value: string) => updateShadowValue('from', { color: value })}
                  />
                </FormSection>
              </div>
              <div className='space-y-3'>
                <FormSection title='To' variant='subtle-compact' className='p-0'>
                  <div className='grid gap-3 sm:grid-cols-2 mt-2'>
                    <RangeField
                      label='Offset X'
                      value={shadowToValues.x}
                      onChange={(value: number) => updateShadowValue('to', { x: value })}
                      min={-60}
                      max={60}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Offset Y'
                      value={shadowToValues.y}
                      onChange={(value: number) => updateShadowValue('to', { y: value })}
                      min={-60}
                      max={60}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Blur'
                      value={shadowToValues.blur}
                      onChange={(value: number) => updateShadowValue('to', { blur: value })}
                      min={0}
                      max={120}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Spread'
                      value={shadowToValues.spread}
                      onChange={(value: number) => updateShadowValue('to', { spread: value })}
                      min={-40}
                      max={40}
                      step={1}
                      suffix='px'
                    />
                    <RangeField
                      label='Opacity'
                      value={shadowToValues.opacity}
                      onChange={(value: number) => updateShadowValue('to', { opacity: value })}
                      min={0}
                      max={100}
                      step={1}
                      suffix='%'
                    />
                  </div>
                  <ColorPickerField
                    label='Color'
                    value={shadowToValues.color}
                    onChange={(value: string) => updateShadowValue('to', { color: value })}
                  />
                </FormSection>
              </div>
            </div>
          </FormSection>
        </Card>

        <Card
          variant='subtle-compact'
          padding='sm'
          className='border-border/40 bg-card/30 space-y-3'
        >
          <div className='grid gap-3 sm:grid-cols-2'>
            <ColorPickerField
              label='Background from'
              value={visualBackgroundFromValue}
              onChange={handleVisualBackgroundFromChange}
            />
            <ColorPickerField
              label='Background to'
              value={visualBackgroundToValue}
              onChange={handleVisualBackgroundToChange}
            />
          </div>
        </Card>
      </div>
    </FormSection>
  );
}

'use client';

import React from 'react';

import { DEFAULT_ANIMATION_CONFIG, DRAG_AXES, type DragAxis } from '@/features/gsap/public';
import { Input, Checkbox } from '@/shared/ui/primitives.public';
import { SelectSimple, FormSection, FormField } from '@/shared/ui/forms-and-actions.public';

import { useAnimationConfigActions, useAnimationConfigState } from '../AnimationConfigContext';

export function AdvancedDraggableSection(): React.JSX.Element {
  const { config } = useAnimationConfigState();
  const { onChange } = useAnimationConfigActions();

  const draggableEnabledValue =
    config.draggableEnabled ?? DEFAULT_ANIMATION_CONFIG.draggableEnabled ?? false;
  const draggableTypeValue =
    config.draggableType ?? DEFAULT_ANIMATION_CONFIG.draggableType ?? 'x,y';
  const draggableBoundsValue =
    config.draggableBounds ?? DEFAULT_ANIMATION_CONFIG.draggableBounds ?? '';
  const draggableMomentumValue =
    config.draggableMomentum ?? DEFAULT_ANIMATION_CONFIG.draggableMomentum ?? false;
  const draggableMomentumFactorValue =
    config.draggableMomentumFactor ?? DEFAULT_ANIMATION_CONFIG.draggableMomentumFactor ?? 0.6;
  const draggableSnapValue = config.draggableSnap ?? DEFAULT_ANIMATION_CONFIG.draggableSnap ?? 0;
  const draggableCarouselValue =
    config.draggableCarousel ?? DEFAULT_ANIMATION_CONFIG.draggableCarousel ?? false;
  const draggableCarouselSelectorValue =
    config.draggableCarouselSelector ?? DEFAULT_ANIMATION_CONFIG.draggableCarouselSelector ?? '';
  const draggableCarouselSnapValue =
    config.draggableCarouselSnap ?? DEFAULT_ANIMATION_CONFIG.draggableCarouselSnap ?? true;

  return (
    <FormSection
      title='Draggable'
      variant='subtle-compact'
      actions={
        <Checkbox
          checked={draggableEnabledValue}
          onCheckedChange={(v: boolean) => onChange({ ...config, draggableEnabled: v === true })}
        />
      }
      className='p-3 space-y-4'
    >
      {draggableEnabledValue && (
        <div className='mt-4 space-y-4'>
          <FormField label='Axis'>
            <SelectSimple
              size='sm'
              value={draggableTypeValue}
              onValueChange={(v) => onChange({ ...config, draggableType: v as DragAxis })}
              options={DRAG_AXES}
             ariaLabel='Axis' title='Axis'/>
          </FormField>

          <FormField label='Bounds selector'>
            <Input
              value={draggableBoundsValue}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => onChange({ ...config, draggableBounds: e.target.value })}
              placeholder='e.g. .container'
              className='h-9'
             aria-label='e.g. .container' title='e.g. .container'/>
          </FormField>

          <div className='grid gap-3 sm:grid-cols-2'>
            <FormField label='Snap (px)'>
              <Input
                type='number'
                min={0}
                max={200}
                step={1}
                value={draggableSnapValue}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const val = parseFloat(e.target.value);
                  if (!isNaN(val))
                    onChange({ ...config, draggableSnap: Math.max(0, Math.min(200, val)) });
                }}
                className='h-9'
               aria-label='Snap (px)' title='Snap (px)'/>
            </FormField>
            <FormField label='Momentum factor'>
              <Input
                type='number'
                min={0.1}
                max={2}
                step={0.05}
                value={draggableMomentumFactorValue}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const val = parseFloat(e.target.value);
                  if (!isNaN(val))
                    onChange({
                      ...config,
                      draggableMomentumFactor: Math.max(0.1, Math.min(2, val)),
                    });
                }}
                className='h-9'
               aria-label='Momentum factor' title='Momentum factor'/>
            </FormField>
          </div>

          <div className='flex flex-wrap items-center gap-4'>
            <div className='flex items-center gap-2'>
              <Checkbox
                checked={draggableMomentumValue}
                onCheckedChange={(v: boolean) => onChange({ ...config, draggableMomentum: v === true })}
              />
              <span className='text-xs text-gray-300'>Enable momentum</span>
            </div>
            <div className='flex items-center gap-2'>
              <Checkbox
                checked={draggableCarouselValue}
                onCheckedChange={(v: boolean) => onChange({ ...config, draggableCarousel: v === true })}
              />
              <span className='text-xs text-gray-300'>Carousel mode</span>
            </div>
          </div>

          {draggableCarouselValue && (
            <div className='space-y-4 pl-2 border-l border-border/40'>
              <FormField label='Track selector'>
                <Input
                  value={draggableCarouselSelectorValue}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    onChange({ ...config, draggableCarouselSelector: e.target.value })
                  }
                  placeholder='e.g. .track'
                  className='h-9'
                 aria-label='e.g. .track' title='e.g. .track'/>
              </FormField>
              <div className='flex items-center gap-2'>
                <Checkbox
                  checked={draggableCarouselSnapValue}
                  onCheckedChange={(v: boolean) =>
                    onChange({ ...config, draggableCarouselSnap: v === true })
                  }
                />
                <span className='text-xs text-gray-300'>Snap to items</span>
              </div>
            </div>
          )}
        </div>
      )}
    </FormSection>
  );
}

'use client';

import { PenLine, Trash2 } from 'lucide-react';
import React from 'react';

import type { VectorOverlayResult } from '@/features/cms/hooks/usePageBuilderContext';
import { DEFAULT_ANIMATION_CONFIG } from '@/features/gsap/public';
import { type VectorShape } from '@/shared/contracts/vector';
import { DOCUMENTATION_MODULE_IDS } from '@/shared/contracts/documentation';
import { getDocumentationTooltip } from '@/shared/lib/documentation/tooltips';
import { Button, Checkbox, Input, Tooltip } from '@/shared/ui/primitives.public';
import { FormSection, FormField } from '@/shared/ui/forms-and-actions.public';

import { useAnimationConfigActions, useAnimationConfigState } from '../AnimationConfigContext';


const EMPTY_SHAPES: VectorShape[] = [];

export function AdvancedMotionPathSection(): React.JSX.Element {
  const { config } = useAnimationConfigState();
  const { onChange, openVectorOverlay } = useAnimationConfigActions();

  const drawPathTooltip =
    getDocumentationTooltip(DOCUMENTATION_MODULE_IDS.cms, 'animation_draw_path_canvas') ??
    'Draw path on canvas';
  const clearPathTooltip =
    getDocumentationTooltip(DOCUMENTATION_MODULE_IDS.cms, 'animation_clear_path_canvas') ??
    'Clear path';

  const motionPathEnabledValue =
    config.motionPathEnabled ?? DEFAULT_ANIMATION_CONFIG.motionPathEnabled ?? false;
  const motionPathPathValue =
    config.motionPathPath ?? DEFAULT_ANIMATION_CONFIG.motionPathPath ?? '';
  const motionPathAlignValue =
    config.motionPathAlign ?? DEFAULT_ANIMATION_CONFIG.motionPathAlign ?? true;
  const motionPathAutoRotateValue =
    config.motionPathAutoRotate ?? DEFAULT_ANIMATION_CONFIG.motionPathAutoRotate ?? true;
  const motionPathRotateOffsetValue =
    config.motionPathRotateOffset ?? DEFAULT_ANIMATION_CONFIG.motionPathRotateOffset ?? 0;
  const motionPathStartValue =
    config.motionPathStart ?? DEFAULT_ANIMATION_CONFIG.motionPathStart ?? 0;
  const motionPathEndValue = config.motionPathEnd ?? DEFAULT_ANIMATION_CONFIG.motionPathEnd ?? 1;
  const motionPathFollowValue =
    config.motionPathFollow ?? DEFAULT_ANIMATION_CONFIG.motionPathFollow ?? false;
  const motionPathSpacingValue =
    config.motionPathSpacing ?? DEFAULT_ANIMATION_CONFIG.motionPathSpacing ?? 0.08;
  const motionPathShapesValue =
    config.motionPathShapes ?? DEFAULT_ANIMATION_CONFIG.motionPathShapes ?? EMPTY_SHAPES;

  const handleEnabledChange = (checked: boolean | 'indeterminate') => {
    onChange({ ...config, motionPathEnabled: checked === true });
  };

  const handlePathChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange({ ...config, motionPathPath: e.target.value });
  };

  const handleDraw = (): void => {
    openVectorOverlay({
      title: 'Motion Path',
      description: 'Draw the motion path directly on the preview canvas.',
      initialShapes: motionPathShapesValue,
      onApply: ({ shapes, path }: VectorOverlayResult) => {
        onChange({
          ...config,
          motionPathEnabled: true,
          motionPathPath: path,
          motionPathShapes: shapes,
        });
      },
    });
  };

  const handleClear = (): void => {
    onChange({ ...config, motionPathPath: '', motionPathShapes: [] });
  };

  return (
    <FormSection
      title='Motion Path'
      variant='subtle-compact'
      actions={<Checkbox checked={motionPathEnabledValue} onCheckedChange={handleEnabledChange} />}
      className='p-3 space-y-4'
    >
      {motionPathEnabledValue && (
        <div className='mt-4 space-y-4'>
          <FormField label='Path / Selector'>
            <div className='flex items-center gap-2'>
              <Input
                value={motionPathPathValue}
                onChange={handlePathChange}
                placeholder='SVG path data or selector (#path)'
                className='flex-1 text-xs font-mono h-9'
               aria-label='SVG path data or selector (#path)' title='SVG path data or selector (#path)'/>
              <Tooltip content={drawPathTooltip}>
                <Button
                  type='button'
                  size='icon'
                  variant='outline'
                  aria-label='Draw motion path'
                  onClick={handleDraw}
                  className='h-9 w-9'
                  title={'Draw motion path'}>
                  <PenLine className='size-4' />
                </Button>
              </Tooltip>
              <Tooltip content={clearPathTooltip}>
                <Button
                  type='button'
                  size='icon'
                  variant='ghost'
                  aria-label='Clear motion path'
                  onClick={handleClear}
                  disabled={!motionPathPathValue && motionPathShapesValue.length === 0}
                  className='h-9 w-9'
                  title={'Clear motion path'}>
                  <Trash2 className='size-4' />
                </Button>
              </Tooltip>
            </div>
          </FormField>

          <div className='grid gap-3 sm:grid-cols-2'>
            <FormField label='Start (0-1)'>
              <Input
                type='number'
                min={0}
                max={1}
                step={0.01}
                value={motionPathStartValue}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const val = parseFloat(e.target.value);
                  if (!isNaN(val))
                    onChange({ ...config, motionPathStart: Math.max(0, Math.min(1, val)) });
                }}
                className='h-9'
               aria-label='Start (0-1)' title='Start (0-1)'/>
            </FormField>
            <FormField label='End (0-1)'>
              <Input
                type='number'
                min={0}
                max={1}
                step={0.01}
                value={motionPathEndValue}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const val = parseFloat(e.target.value);
                  if (!isNaN(val))
                    onChange({ ...config, motionPathEnd: Math.max(0, Math.min(1, val)) });
                }}
                className='h-9'
               aria-label='End (0-1)' title='End (0-1)'/>
            </FormField>
          </div>

          <div className='grid gap-3 sm:grid-cols-2'>
            <div className='flex items-center gap-2'>
              <Checkbox
                checked={motionPathAlignValue}
                onCheckedChange={(checked: boolean) =>
                  onChange({ ...config, motionPathAlign: checked === true })
                }
              />
              <span className='text-xs text-gray-300'>Align to path</span>
            </div>
            <div className='flex items-center gap-2'>
              <Checkbox
                checked={motionPathAutoRotateValue}
                onCheckedChange={(checked: boolean) =>
                  onChange({ ...config, motionPathAutoRotate: checked === true })
                }
              />
              <span className='text-xs text-gray-300'>Auto rotate</span>
            </div>
          </div>

          {motionPathAutoRotateValue && (
            <FormField label='Rotate offset (deg)'>
              <Input
                type='number'
                min={-360}
                max={360}
                step={1}
                value={motionPathRotateOffsetValue}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                  const val = parseFloat(e.target.value);
                  if (!isNaN(val))
                    onChange({
                      ...config,
