'use client';

import React, { createContext, useContext, useMemo, useCallback } from 'react';

import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { getEventEffectsConfig } from '@/features/cms/utils/event-effects';
import { DEFAULT_ANIMATION_CONFIG, type GsapAnimationConfig } from '@/features/gsap/public';
import {
  DEFAULT_CUSTOM_CSS_AI_CONFIG,
  type CustomCssAiConfig,
  type CssAnimationConfig,
} from '@/shared/contracts/cms';
import { internalError } from '@/shared/errors/app-error';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { getSectionDefinition, getBlockDefinition } from '../section-registry';

import type {
  ComponentSettingsActionsContextValue,
  ComponentSettingsStateContextValue,
  ConnectionSettings,
} from './ComponentSettingsContext.types';

export type {
  ComponentSettingsActionsContextValue,
  ComponentSettingsContextValue,
  ComponentSettingsStateContextValue,
  ConnectionSettings,
} from './ComponentSettingsContext.types';

const ComponentSettingsStateContext = createContext<ComponentSettingsStateContextValue | null>(
  null
);
const ComponentSettingsActionsContext = createContext<ComponentSettingsActionsContextValue | null>(
  null
);

export function useComponentSettingsState(): ComponentSettingsStateContextValue {
  const context = useContext(ComponentSettingsStateContext);
  if (!context) {
    throw internalError('useComponentSettingsState must be used within a ComponentSettingsProvider');
  }
  return context;
}

export function useComponentSettingsActions(): ComponentSettingsActionsContextValue {
  const context = useContext(ComponentSettingsActionsContext);
  if (!context) {
    throw internalError('useComponentSettingsActions must be used within a ComponentSettingsProvider');
  }
  return context;
}

export function ComponentSettingsProvider({
  children,
}: {
  children: React.ReactNode;
}): React.JSX.Element {
  const {
    selectedSection,
    selectedBlock,
    selectedColumn,
    selectedColumnParentSection,
    selectedParentSection,
    selectedParentColumn,
    selectedParentRow,
    selectedParentBlock,
    dispatch,
  } = usePageBuilder();

  const [activeTab, setActiveTab] = React.useState<string>('settings');

  const sectionDef = useMemo(
    () => (selectedSection ? getSectionDefinition(selectedSection.type) : null),
    [selectedSection]
  );
  const blockDef = useMemo(
    () => (selectedBlock ? getBlockDefinition(selectedBlock.type) : null),
    [selectedBlock]
  );

  const selectedLabel = useMemo(() => {
    if (selectedSection) return sectionDef?.label ?? selectedSection.type;
    if (selectedColumn) return 'Column';
    if (selectedBlock) return blockDef?.label ?? selectedBlock.type;
    return '';
  }, [selectedSection, selectedColumn, selectedBlock, sectionDef, blockDef]);

  const selectedTitle = useMemo(() => {
    if (selectedSection) return `Section: ${selectedLabel}`;
    if (selectedBlock) return `Block: ${selectedLabel}`;
    if (selectedColumn) return 'Column';
    return 'Settings';
  }, [selectedSection, selectedBlock, selectedColumn, selectedLabel]);

  const hasSelection = Boolean(selectedSection || selectedBlock || selectedColumn);

  // --- Handlers ---
  /**
   * Updates settings for a section and clears dependent properties.
   * Logs failures with detailed context (sectionId, key) to improve observability.
   */
  const handleSectionSettingChange = useCallback(
    (key: string, value: unknown): void => {
      if (!selectedSection) {
        logClientCatch(internalError('Cannot update section settings: no section selected'), {
          source: 'cms.settings-context',
          action: 'handleSectionSettingChange',
          key,
        });
        return;
      }
      dispatch({
        type: 'UPDATE_SECTION_SETTINGS',
        sectionId: selectedSection.id,
        settings: { [key]: value, ...(key === 'background' ? { backgroundColor: '' } : {}) },
      });
    },
    [selectedSection, dispatch]
  );

  /**
   * Updates settings for a block, dynamically routing to specific nest-level actions.
   * Logs failures with component/parent ID context to aid debugging.
   */
  const handleBlockSettingChange = useCallback(
    (key: string, value: unknown): void => {
      if (!selectedBlock || !selectedParentSection) {
        logClientCatch(
          internalError('Cannot update block settings: block or parent section not found'),
          {
            source: 'cms.settings-context',
            action: 'handleBlockSettingChange',
            key,
            blockId: selectedBlock?.id ?? null,
            sectionId: selectedParentSection?.id ?? null,
          }
        );
        return;
      }

      const next = {
        [key]: value,
        ...(key === 'background' ? { backgroundColor: '' } : {}),
        ...(selectedBlock.type === 'Row' && key === 'heightMode' && value === 'inherit'
          ? { height: 0 }
          : {}),
      };

      const actionType = (selectedParentBlock || selectedParentColumn || selectedParentRow)
          ? 'UPDATE_NESTED_BLOCK_SETTINGS'
          : 'UPDATE_BLOCK_SETTINGS';

      dispatch({
        type: actionType as any,
        sectionId: selectedParentSection.id,
        blockId: selectedBlock.id,
        settings: next,
      });
    },
    [
      selectedBlock,
      selectedParentSection,
      selectedParentColumn,
      selectedParentRow,
      selectedParentBlock,
      dispatch,
    ]
  );

  const handleColumnSettingChange = useCallback(
    (key: string, value: unknown): void => {
      if (!selectedColumn || !selectedColumnParentSection) return;
      const next = {
        [key]: value,
        ...(key === 'background' ? { backgroundColor: '' } : {}),
        ...(key === 'heightMode' && value === 'inherit' ? { height: 0 } : {}),
      };
      dispatch({
        type: 'UPDATE_NESTED_BLOCK_SETTINGS',
        sectionId: selectedColumnParentSection.id,
        blockId: selectedColumn.id,
        settings: next,
      });
    },
    [selectedColumn, selectedColumnParentSection, dispatch]
  );

  // --- Animation State ---
  const currentAnimationConfig = useMemo(
    () =>
      (selectedSection?.settings['gsapAnimation'] ??
        selectedColumn?.settings['gsapAnimation'] ??
        selectedBlock?.settings['gsapAnimation'] ??
        DEFAULT_ANIMATION_CONFIG) as GsapAnimationConfig,
    [selectedSection, selectedColumn, selectedBlock]
  );
  const currentCssAnimationConfig = useMemo(
    () =>
      (selectedSection?.settings['cssAnimation'] ??
        selectedColumn?.settings['cssAnimation'] ??
        selectedBlock?.settings['cssAnimation']) as CssAnimationConfig | undefined,
    [selectedSection, selectedColumn, selectedBlock]
  );

  const handleAnimationChange = useCallback(
    (updates: Partial<GsapAnimationConfig>): void => {
      const config = { ...currentAnimationConfig, ...updates };
      if (selectedSection && !selectedBlock && !selectedColumn)
        handleSectionSettingChange('gsapAnimation', config);
      else if (selectedColumn) handleColumnSettingChange('gsapAnimation', config);
      else if (selectedBlock) handleBlockSettingChange('gsapAnimation', config);
    },
    [
      currentAnimationConfig,
      selectedSection,
      selectedBlock,
      selectedColumn,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
    ]
  );

  const handleCssAnimationChange = useCallback(
    (updates: Partial<CssAnimationConfig>): void => {
      const config = { ...(currentCssAnimationConfig ?? {}), ...updates };
      if (selectedSection && !selectedBlock && !selectedColumn)
        handleSectionSettingChange('cssAnimation', config);
      else if (selectedColumn) handleColumnSettingChange('cssAnimation', config);
      else if (selectedBlock) handleBlockSettingChange('cssAnimation', config);
    },
    [
      currentCssAnimationConfig,
      selectedSection,
      selectedBlock,
      selectedColumn,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
    ]
  );

  // --- Custom CSS ---
  const customCssValue = useMemo((): string => {
    if (selectedSection) return (selectedSection.settings['customCss'] as string) || '';
    if (selectedColumn) return (selectedColumn.settings['customCss'] as string) || '';
    if (selectedBlock) return (selectedBlock.settings['customCss'] as string) || '';
    return '';
  }, [selectedSection, selectedColumn, selectedBlock]);

  const customCssAiRaw = useMemo((): CustomCssAiConfig | undefined => {
    if (selectedSection)
      return selectedSection.settings['customCssAi'] as CustomCssAiConfig | undefined;
    if (selectedColumn)
      return selectedColumn.settings['customCssAi'] as CustomCssAiConfig | undefined;
    if (selectedBlock)
      return selectedBlock.settings['customCssAi'] as CustomCssAiConfig | undefined;
    return undefined;
  }, [selectedSection, selectedColumn, selectedBlock]);

  const customCssAiConfig = useMemo(
    (): CustomCssAiConfig => ({ ...DEFAULT_CUSTOM_CSS_AI_CONFIG, ...(customCssAiRaw ?? {}) }),
    [customCssAiRaw]
  );

  const handleCustomCssChange = useCallback(
    (value: string): void => {
      if (selectedSection) handleSectionSettingChange('customCss', value);
      else if (selectedColumn) handleColumnSettingChange('customCss', value);
      else if (selectedBlock) handleBlockSettingChange('customCss', value);
    },
    [
      selectedSection,
      selectedColumn,
      selectedBlock,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
    ]
  );

  const handleCustomCssAiChange = useCallback(
    (patch: Partial<CustomCssAiConfig>): void => {
      const next = { ...customCssAiConfig, ...patch };
      if (selectedSection) handleSectionSettingChange('customCssAi', next);
      else if (selectedColumn) handleColumnSettingChange('customCssAi', next);
      else if (selectedBlock) handleBlockSettingChange('customCssAi', next);
    },
    [
      customCssAiConfig,
      selectedSection,
      selectedColumn,
      selectedBlock,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
    ]
  );

  // --- AI Settings ---
  const handleApplyAiSettings = useCallback(
    (patch: Record<string, unknown>): void => {
      Object.entries(patch).forEach(([key, value]) => {
        if (selectedSection && !selectedBlock && !selectedColumn) {
          if (key === 'columns' && selectedSection.type === 'Grid')
            dispatch({
              type: 'SET_GRID_COLUMNS',
              sectionId: selectedSection.id,
              columnCount: value as number,
            });
          else if (key === 'rows' && selectedSection.type === 'Grid')
            dispatch({
              type: 'SET_GRID_ROWS',
              sectionId: selectedSection.id,
              rowCount: value as number,
            });
          else handleSectionSettingChange(key, value);
        } else if (selectedColumn) handleColumnSettingChange(key, value);
        else if (selectedBlock) handleBlockSettingChange(key, value);
      });
    },
    [
      selectedSection,
      selectedBlock,
      selectedColumn,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
      dispatch,
    ]
  );

  const contentAiAllowedKeys = useMemo((): string[] => {
    const schema = selectedSection
      ? sectionDef?.settingsSchema
      : selectedBlock
        ? blockDef?.settingsSchema
        : null;
    return schema ? schema.map((f: { key: string }) => f.key) : [];
  }, [selectedSection, selectedBlock, sectionDef, blockDef]);

  // --- Connection Settings ---
  const connectionSettings = useMemo((): ConnectionSettings => {
    const raw = ((selectedSection?.settings ??
      selectedColumn?.settings ??
      selectedBlock?.settings ??
      null)?.['connection'] ?? {}) as Partial<ConnectionSettings>;
    return {
      enabled: raw.enabled ?? false,
      source: raw.source ?? '',
      path: raw.path ?? '',
      fallback: raw.fallback ?? '',
    };
  }, [selectedSection, selectedColumn, selectedBlock]);

  const updateConnectionSetting = useCallback(
    (patch: Partial<ConnectionSettings>): void => {
      const next = { ...connectionSettings, ...patch };
      if (selectedSection && !selectedBlock && !selectedColumn) {
        handleSectionSettingChange('connection', next);
      } else if (selectedColumn) {
        handleColumnSettingChange('connection', next);
      } else if (selectedBlock) {
        handleBlockSettingChange('connection', next);
      }
    },
    [
      connectionSettings,
      selectedSection,
      selectedBlock,
      selectedColumn,
      handleSectionSettingChange,
      handleColumnSettingChange,
      handleBlockSettingChange,
    ]
  );

  // --- Event Effects ---
  const eventSettingsSource = useMemo(
    () => selectedBlock?.settings ?? selectedSection?.settings ?? null,
    [selectedBlock, selectedSection]
  );
  const eventConfig = useMemo(
    () => (eventSettingsSource ? getEventEffectsConfig(eventSettingsSource) : null),
    [eventSettingsSource]
  );

  const handleEventSettingChange = useCallback(
    (key: string, value: unknown): void => {
      if (selectedBlock) {
        handleBlockSettingChange(key, value);
      } else if (selectedSection) {
        handleSectionSettingChange(key, value);
      }
    },
    [selectedBlock, selectedSection, handleBlockSettingChange, handleSectionSettingChange]
  );

  const stateValue = useMemo(
    (): ComponentSettingsStateContextValue => ({
      hasSelection,
      selectedLabel,
      selectedTitle,
      activeTab,
      currentAnimationConfig,
      currentCssAnimationConfig,
      customCssValue,
      customCssAiConfig,
      contentAiAllowedKeys,
      connectionSettings,
      eventConfig,
    }),
    [
      hasSelection,
      selectedLabel,
      selectedTitle,
      activeTab,
      currentAnimationConfig,
      currentCssAnimationConfig,
      customCssValue,
      customCssAiConfig,
      contentAiAllowedKeys,
      connectionSettings,
      eventConfig,
    ]
  );
  const actionsValue = useMemo(
    (): ComponentSettingsActionsContextValue => ({
      setActiveTab,
      handleAnimationChange,
      handleCssAnimationChange,
      handleCustomCssChange,
      handleCustomCssAiChange,
      handleApplyAiSettings,
      updateConnectionSetting,
      handleEventSettingChange,
      handleBlockSettingChange,
      handleSectionSettingChange,
      handleColumnSettingChange,
    }),
    [
      setActiveTab,
      handleAnimationChange,
      handleCssAnimationChange,
      handleCustomCssChange,
      handleCustomCssAiChange,
      handleApplyAiSettings,
      updateConnectionSetting,
      handleEventSettingChange,
      handleBlockSettingChange,
      handleSectionSettingChange,
      handleColumnSettingChange,
    ]
  );

  return (
    <ComponentSettingsActionsContext.Provider value={actionsValue}>
      <ComponentSettingsStateContext.Provider value={stateValue}>
        {children}
      </ComponentSettingsStateContext.Provider>
    </ComponentSettingsActionsContext.Provider>
  );
}

'use client';

import {
  useCallback,
  useMemo,
  useState,
  type Dispatch,
  type SetStateAction,
} from 'react';

import type { BlockInstance, SectionInstance } from '@/shared/contracts/cms';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import type { InspectorAiContextPreviewTab } from './InspectorAiContext.types';

const PAGE_CONTEXT_LIMIT = 6000;
const ELEMENT_CONTEXT_LIMIT = 2500;

interface BuilderStateSnapshot {
  currentPage?: {
    id: string;
    name: string;
    status?: string | null;
    themeId?: string | null;
    publishedAt?: string | null;
    slugs?: Array<string | { slug?: string | null }> | null;
  } | null;
  sections?: SectionInstance[] | null;
}

interface InspectorAiToastOptions {
  variant: 'success' | 'error' | 'info';
}

type InspectorAiToast = (message: string, options: InspectorAiToastOptions) => void;

interface UseInspectorAiContextPreviewArgs {
  state: BuilderStateSnapshot | null | undefined;
  selectedSection: SectionInstance | null | undefined;
  selectedBlock: BlockInstance | null | undefined;
  selectedColumn: BlockInstance | null | undefined;
  selectedColumnParentSection: SectionInstance | null | undefined;
  selectedParentSection: SectionInstance | null | undefined;
  selectedParentColumn: BlockInstance | null | undefined;
  selectedParentBlock: BlockInstance | null | undefined;
  toast: InspectorAiToast;
}

interface UseInspectorAiContextPreviewResult {
  buildPageContext: (limit?: number | null) => string;
  buildElementContext: (limit?: number | null) => string;
  contextPreviewOpen: boolean;
  setContextPreviewOpen: Dispatch<SetStateAction<boolean>>;
  contextPreviewTab: InspectorAiContextPreviewTab;
  setContextPreviewTab: Dispatch<SetStateAction<InspectorAiContextPreviewTab>>;
  contextPreviewFull: boolean;
  setContextPreviewFull: Dispatch<SetStateAction<boolean>>;
  contextPreviewNonce: number;
  setContextPreviewNonce: Dispatch<SetStateAction<number>>;
  pageContextPreview: string;
  elementContextPreview: string;
  copyContext: (value: string) => Promise<void>;
}

interface SerializedBlock {
  id: string;
  type: string;
  settings: Record<string, unknown>;
  blocks: SerializedBlock[];
}

function stringifyContext(value: unknown, limit?: number | null): string {
  try {
    const json = JSON.stringify(value, null, 2);
    if (limit == null) return json;
    if (json.length <= limit) return json;
    return `${json.slice(0, limit)}\n...truncated...`;
  } catch (error) {
    logClientError(error);
    const fallback =
      typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean'
        ? String(value)
        : '[complex value]';
    if (limit == null) return fallback;
    return fallback.length <= limit ? fallback : `${fallback.slice(0, limit)}...`;
  }
}

function serializeBlock(block: BlockInstance): SerializedBlock {
  return {
    id: block.id,
    type: block.type,
    settings: block.settings ?? {},
    blocks: (block.blocks ?? []).map((child: BlockInstance) => serializeBlock(child)),
  };
}

export function useInspectorAiContextPreview({
  state,
  selectedSection,
  selectedBlock,
  selectedColumn,
  selectedColumnParentSection,
  selectedParentSection,
  selectedParentColumn,
  selectedParentBlock,
  toast,
}: UseInspectorAiContextPreviewArgs): UseInspectorAiContextPreviewResult {
  const [contextPreviewOpen, setContextPreviewOpen] = useState(false);
  const [contextPreviewTab, setContextPreviewTab] =
    useState<InspectorAiContextPreviewTab>('page');
  const [contextPreviewFull, setContextPreviewFull] = useState(false);
  const [contextPreviewNonce, setContextPreviewNonce] = useState(0);

  const buildPageContext = useCallback(
    (limit?: number | null): string => {
      const resolvedLimit = limit === undefined ? PAGE_CONTEXT_LIMIT : limit;
      if (!state?.currentPage) return 'No page loaded.';
      return stringifyContext(
        {
          page: {
            id: state.currentPage.id,
            name: state.currentPage.name,
            status: state.currentPage.status ?? null,
            themeId: state.currentPage.themeId ?? null,
            publishedAt: state.currentPage.publishedAt ?? null,
            slugs: (state.currentPage.slugs ?? [])
              .map((slugEntry: string | { slug?: string | null }): string =>
                typeof slugEntry === 'string' ? slugEntry : slugEntry.slug?.trim() ?? ''
              )
              .filter((slug: string): boolean => slug.length > 0),
          },
          sections: (state.sections ?? []).map((section: SectionInstance) => ({
            id: section.id,
            type: section.type,
            zone: section.zone,
            settings: section.settings ?? {},
            blocks: (section.blocks ?? []).map((block: BlockInstance) => serializeBlock(block)),
          })),
        },
        resolvedLimit
      );
    },
    [state]
  );

  const selectedGridRow = useMemo<BlockInstance | null>(() => {
    if (selectedParentSection?.type !== 'Grid' || !selectedParentColumn) return null;
    return (
      selectedParentSection.blocks.find(
        (block: BlockInstance) =>
          block.type === 'Row' &&
          (block.blocks ?? []).some(
            (column: BlockInstance) => column.id === selectedParentColumn.id
          )
      ) ?? null
    );
  }, [selectedParentColumn, selectedParentSection]);

  const buildElementContext = useCallback(
    (limit?: number | null): string => {
      const resolvedLimit = limit === undefined ? ELEMENT_CONTEXT_LIMIT : limit;
      if (selectedSection && !selectedBlock && !selectedColumn) {
        return stringifyContext(
          {
            kind: 'section',
            id: selectedSection.id,
            type: selectedSection.type,
            zone: selectedSection.zone,
            settings: selectedSection.settings ?? {},
            blocks: (selectedSection.blocks ?? []).map((block: BlockInstance) =>
              serializeBlock(block)
            ),
          },
          resolvedLimit
        );
      }
      if (selectedColumn) {
        return stringifyContext(
          {
            kind: 'column',
            id: selectedColumn.id,
            sectionId: selectedColumnParentSection?.id,
            rowId: selectedGridRow?.id,
            settings: selectedColumn.settings ?? {},
            blocks: (selectedColumn.blocks ?? []).map((block: BlockInstance) =>
              serializeBlock(block)
            ),
          },
          resolvedLimit
        );
      }
      if (selectedBlock) {
        return stringifyContext(
          {
            kind: selectedBlock.type === 'Row' ? 'row' : 'block',
            id: selectedBlock.id,
            type: selectedBlock.type,
            sectionId: selectedParentSection?.id,
            columnId: selectedParentColumn?.id,
            parentBlockId: selectedParentBlock?.id,
            settings: selectedBlock.settings ?? {},
            blocks: (selectedBlock.blocks ?? []).map((block: BlockInstance) =>
              serializeBlock(block)
            ),
          },
          resolvedLimit
        );
      }
      return 'No element selected.';
    },
    [
      selectedBlock,
      selectedColumn,
      selectedColumnParentSection,
      selectedGridRow,
      selectedParentBlock,
      selectedParentColumn,
      selectedParentSection,
      selectedSection,
    ]
  );

  const pageContextPreview = useMemo((): string => {
    if (!contextPreviewOpen) return '';
    return buildPageContext(contextPreviewFull ? null : undefined);
  }, [buildPageContext, contextPreviewFull, contextPreviewNonce, contextPreviewOpen]);

  const elementContextPreview = useMemo((): string => {
    if (!contextPreviewOpen) return '';
    return buildElementContext(contextPreviewFull ? null : undefined);
  }, [buildElementContext, contextPreviewFull, contextPreviewNonce, contextPreviewOpen]);

  const copyContext = useCallback(
    async (value: string): Promise<void> => {
      try {
        await navigator.clipboard.writeText(value);
        toast('Context copied.', { variant: 'success' });
      } catch (error) {
        logClientError(error);
        toast('Failed to copy context.', { variant: 'error' });
        logClientError(error as Error, {
          context: { source: 'InspectorAiContext', action: 'copyContext' },
        });
      }
    },
    [toast]
  );

  return {
    buildPageContext,
    buildElementContext,
    contextPreviewOpen,
    setContextPreviewOpen,
    contextPreviewTab,
    setContextPreviewTab,
    contextPreviewFull,
    setContextPreviewFull,
    contextPreviewNonce,
    setContextPreviewNonce,
    pageContextPreview,
    elementContextPreview,
    copyContext,
  };
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';

import {
  extractCssFromResponse,
  extractJsonFromResponse,
} from '@/features/cms/components/page-builder/utils/ai-helpers';
import type { ContextRegistryConsumerEnvelope } from '@/shared/contracts/ai-context-registry';
import type { ChatMessage } from '@/shared/contracts/chatbot';
import type { CustomCssAiConfig } from '@/shared/contracts/cms';
import { useOptionalContextRegistryPageEnvelope } from '@/shared/lib/ai-context-registry/page-context';
import { ApiError } from '@/shared/lib/api-client';
import { logClientError } from '@/shared/utils/observability/client-error-logger';



interface InspectorAiToastOptions {
  variant: 'success' | 'error' | 'info';
}

type InspectorAiToast = (message: string, options: InspectorAiToastOptions) => void;

interface UseInspectorAiGenerationArgs {
  brainAiProvider: 'model' | 'agent';
  brainAiModelId: string;
  brainAiAgentId: string;
  buildPageContext: (limit?: number | null) => string;
  buildElementContext: (limit?: number | null) => string;
  contentAiAllowedKeys: string[];
  customCssAiConfig: CustomCssAiConfig;
  customCssValue: string;
  onUpdateCss: (css: string) => void;
  onUpdateSettings: (settings: Record<string, unknown>) => void;
  toast: InspectorAiToast;
}

interface UseInspectorAiGenerationResult {
  cssAiAppend: boolean;
  setCssAiAppend: (value: boolean) => void;
  cssAiAutoApply: boolean;
  setCssAiAutoApply: (value: boolean) => void;
  cssAiLoading: boolean;
  cssAiError: string | null;
  cssAiOutput: string;
  contentAiPrompt: string;
  setContentAiPrompt: (value: string) => void;
  contentAiLoading: boolean;
  contentAiError: string | null;
  contentAiOutput: string;
  contentAiPlaceholder: string;
  generateCss: () => Promise<void>;
  cancelCss: () => void;
  generateContent: () => Promise<void>;
  cancelContent: () => void;
  applyContent: () => void;
  applyCss: (mode: 'append' | 'replace') => void;
}

interface StreamInspectorAiResponseArgs {
  provider: 'model' | 'agent';
  modelId: string;
  agentId: string;
  prompt: string;
  sessionPrefix: string;
  systemPrompt: string;
  signal: AbortSignal;
  onDelta: (value: string) => void;
  contextRegistry?: ContextRegistryConsumerEnvelope | null;
}

const CMS_STREAM_ENDPOINT = '/api/cms/css-ai/stream';
const CONTENT_AI_PLACEHOLDER = '{{page_context}}\n{{element_context}}\n{{allowed_keys}}';

function getConfiguredTarget(
  provider: 'model' | 'agent',
  modelId: string,
  agentId: string
): { provider: 'model' | 'agent'; modelId: string; agentId: string } {
  if (provider === 'model' && !modelId) {
    throw new ApiError('Configure CMS CSS Stream in AI Brain first.', 400);
  }
  if (provider === 'agent' && !agentId) {
    throw new ApiError('Configure a CMS CSS Stream agent in AI Brain first.', 400);
  }
  return {
    provider,
    modelId: provider === 'model' ? modelId : '',
    agentId: provider === 'agent' ? agentId : '',
  };
}

async function streamInspectorAiResponse(
  args: StreamInspectorAiResponseArgs
): Promise<string> {
  const {
    provider,
    modelId,
    agentId,
    prompt,
    sessionPrefix,
    systemPrompt,
    signal,
    onDelta,
    contextRegistry,
  } = args;
  const timestamp = new Date().toISOString();
  const sessionId = `${sessionPrefix}-${Date.now()}`;
  const messages: ChatMessage[] = [
    {
      id: `sys-${Date.now()}`,
      sessionId,
      timestamp,
      role: 'system',
      content: systemPrompt,
    },
    {
      id: `user-${Date.now()}`,
      sessionId,
      timestamp,
      role: 'user',
      content: prompt,
    },
  ];

  const response = await fetch(CMS_STREAM_ENDPOINT, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    signal,
    body: JSON.stringify({ provider, modelId, agentId, messages, contextRegistry }),
  });

  if (!response.ok || !response.body) {
    const data = (await response.json().catch(() => null)) as { error?: string } | null;
    throw new ApiError(data?.error || 'Streaming request failed.', response.status);
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let buffer = '';
  let accumulated = '';
  let doneSignal = false;

  const processEvent = (raw: string): void => {
    const lines = raw.split('\n').map((line: string) => line.trim());
    const dataLine = lines.find((line: string) => line.startsWith('data:'));
    if (!dataLine) return;
    const payload = JSON.parse(dataLine.replace(/^data:\s*/, '')) as {
      delta?: string;
      done?: boolean;
      error?: string;
    };
    if (payload.error) {
      throw new ApiError(payload.error, 400);
    }
    if (payload.delta) {
      accumulated += payload.delta;
      onDelta(accumulated);
    }
    if (payload.done) {
      doneSignal = true;
    }
  };

  while (!doneSignal) {
    const { value, done } = await reader.read();
    if (done) break;
    if (!value) continue;
    buffer += decoder.decode(value, { stream: true });
    const chunks = buffer.split('\n\n');
    buffer = chunks.pop() ?? '';
    for (const chunk of chunks) {
      processEvent(chunk);
      if (doneSignal) break;
    }
  }

  if (buffer.trim() && !doneSignal) {
    processEvent(buffer);
  }

  if (doneSignal) {
    try {
      await reader.cancel();
    } catch (error) {
      logClientError(error);

      // ignore
    }
  }

  return accumulated;
}

export function useInspectorAiGeneration({
  brainAiProvider,
  brainAiModelId,
  brainAiAgentId,
  buildPageContext,
  buildElementContext,
  contentAiAllowedKeys,
  customCssAiConfig,
  customCssValue,
  onUpdateCss,
  onUpdateSettings,
  toast,
}: UseInspectorAiGenerationArgs): UseInspectorAiGenerationResult {
  const contextRegistry = useOptionalContextRegistryPageEnvelope();
  const [cssAiAppend, setCssAiAppend] = useState(true);
  const [cssAiAutoApply, setCssAiAutoApply] = useState(false);
  const [cssAiLoading, setCssAiLoading] = useState(false);
  const [cssAiError, setCssAiError] = useState<string | null>(null);
  const [cssAiOutput, setCssAiOutput] = useState('');
  const cssAiAbortRef = useRef<AbortController | null>(null);

  const [contentAiPrompt, setContentAiPrompt] = useState('');
  const [contentAiLoading, setContentAiLoading] = useState(false);
  const [contentAiError, setContentAiError] = useState<string | null>(null);
  const [contentAiOutput, setContentAiOutput] = useState('');
  const contentAiAbortRef = useRef<AbortController | null>(null);

  useEffect((): (() => void) => {
    return (): void => {
      cssAiAbortRef.current?.abort();
      contentAiAbortRef.current?.abort();
    };
  }, []);

  const buildCssAiPrompt = useCallback((): string => {
    const pageContext = buildPageContext();
    const elementContext = buildElementContext();
    const defaultPrompt =
      'Generate a CSS snippet for the selected element. Return only CSS without explanations.';
    const promptBody = (customCssAiConfig.prompt ?? '').trim() || defaultPrompt;
    const hasPagePlaceholder = /{{\s*page_context\s*}}/i.test(promptBody);
    const hasElementPlaceholder = /{{\s*element_context\s*}}/i.test(promptBody);
    const resolved = promptBody
      .replace(/{{\s*page_context\s*}}/gi, pageContext)
      .replace(/{{\s*element_context\s*}}/gi, elementContext);
    if (hasPagePlaceholder || hasElementPlaceholder) {
      return resolved;
    }
    return `${resolved}\n\nPage context:\n${pageContext}\n\nElement context:\n${elementContext}`;
  }, [buildElementContext, buildPageContext, customCssAiConfig.prompt]);

  const generateCss = useCallback(async (): Promise<void> => {
    if (cssAiLoading) return;
    setCssAiError(null);
    setCssAiLoading(true);
    setCssAiOutput('');
    try {
      const prompt = buildCssAiPrompt();
      if (!prompt.trim()) {
        throw new ApiError('Prompt is empty.', 400);
      }

      const controller = new AbortController();
      cssAiAbortRef.current = controller;
      const target = getConfiguredTarget(brainAiProvider, brainAiModelId, brainAiAgentId);
      const response = await streamInspectorAiResponse({
        ...target,
        prompt,
        sessionPrefix: 'css-ai',
        signal: controller.signal,
        systemPrompt:
          'You are a CSS assistant. Return only valid CSS without code fences or explanations.',
        onDelta: setCssAiOutput,
        contextRegistry,
      });
      const finalCss = extractCssFromResponse(response);
      if (!finalCss) {
        throw new ApiError('No CSS returned.', 400);
      }
      setCssAiOutput(finalCss);
      if (cssAiAutoApply) {
        const nextCss = cssAiAppend
          ? [customCssValue.trim(), finalCss].filter(Boolean).join('\n\n')
          : finalCss;
        onUpdateCss(nextCss);
        toast(`CSS generated and applied (${target.provider}).`, { variant: 'success' });
      } else {
        toast(`CSS generated from ${target.provider}.`, { variant: 'success' });
      }
    } catch (error) {
      logClientError(error);
      if ((error as Error)?.name === 'AbortError') {
        setCssAiError('Generation cancelled.');
        toast('Generation cancelled.', { variant: 'info' });
      } else {
        const message = error instanceof Error ? error.message : 'Failed to generate CSS.';
        setCssAiError(message);
        toast(message, { variant: 'error' });
      }
    } finally {
      setCssAiLoading(false);
      cssAiAbortRef.current = null;
    }
  }, [
    brainAiAgentId,
    brainAiModelId,
    brainAiProvider,
    buildCssAiPrompt,
    cssAiAppend,
    cssAiAutoApply,
    cssAiLoading,
    customCssValue,
    contextRegistry,
    onUpdateCss,
    toast,
  ]);

  const cancelCss = useCallback((): void => {
    cssAiAbortRef.current?.abort();
    cssAiAbortRef.current = null;
  }, []);

  const buildContentAiPrompt = useCallback((): string => {
    const promptBody =
      contentAiPrompt.trim() ||
      'Generate JSON settings for the selected element. Return only JSON.';
    const pageContext = buildPageContext();
    const elementContext = buildElementContext();
    const allowedKeys = contentAiAllowedKeys.length
      ? contentAiAllowedKeys.join(', ')
      : 'No schema keys available.';
    const withPlaceholders = promptBody
      .replace(/{{\s*page_context\s*}}/gi, pageContext)
      .replace(/{{\s*element_context\s*}}/gi, elementContext)
      .replace(/{{\s*allowed_keys\s*}}/gi, allowedKeys);
    const usesPlaceholders =
      /{{\s*page_context\s*}}/i.test(promptBody) ||
      /{{\s*element_context\s*}}/i.test(promptBody) ||
      /{{\s*allowed_keys\s*}}/i.test(promptBody);
    if (usesPlaceholders) {
      return withPlaceholders;
    }
    return `${withPlaceholders}\n\nAllowed keys:\n${allowedKeys}\n\nPage context:\n${pageContext}\n\nElement context:\n${elementContext}`;
  }, [buildElementContext, buildPageContext, contentAiAllowedKeys, contentAiPrompt]);

  const applyContentAiSettings = useCallback(
    (settingsPatch: Record<string, unknown>): void => {
      const allowed = new Set(contentAiAllowedKeys);
      const filtered =
        allowed.size > 0
          ? Object.entries(settingsPatch).reduce<Record<string, unknown>>(
            (accumulator: Record<string, unknown>, [key, value]: [string, unknown]) => {
              if (allowed.has(key)) {
                accumulator[key] = value;
              }
              return accumulator;
            },
            {}
          )
          : settingsPatch;
      if (Object.keys(filtered).length === 0) {
        setContentAiError('No valid settings keys found in AI output.');
        return;
      }
      onUpdateSettings(filtered);
      toast('AI settings applied.', { variant: 'success' });
    },
    [contentAiAllowedKeys, onUpdateSettings, toast]
  );

  const generateContent = useCallback(async (): Promise<void> => {
    if (contentAiLoading) return;
    setContentAiError(null);
    setContentAiOutput('');
    setContentAiLoading(true);
    try {
      const prompt = buildContentAiPrompt();
      if (!prompt.trim()) {
        throw new ApiError('Prompt is empty.', 400);
      }

      const controller = new AbortController();
      contentAiAbortRef.current = controller;
      const target = getConfiguredTarget(brainAiProvider, brainAiModelId, brainAiAgentId);
      const response = await streamInspectorAiResponse({
        ...target,
        prompt,
        sessionPrefix: 'content-ai',
        signal: controller.signal,
        systemPrompt:
          'You are a CMS content assistant. Return only JSON. If updating settings, output an object of key/value pairs matching allowed keys.',
        onDelta: setContentAiOutput,
        contextRegistry,
      });
      const parsed = extractJsonFromResponse(response);
      if (!parsed) {
        throw new ApiError('AI response did not include JSON.', 400);
      }
      setContentAiOutput(JSON.stringify(parsed, null, 2));
      toast(`AI output ready (${target.provider}).`, { variant: 'success' });
    } catch (error) {
      logClientError(error);
      if ((error as Error)?.name === 'AbortError') {
        setContentAiError('Generation cancelled.');
        toast('Generation cancelled.', { variant: 'info' });
      } else {
        const message = error instanceof Error ? error.message : 'Failed to generate AI output.';
        setContentAiError(message);
        toast(message, { variant: 'error' });
      }
    } finally {
      setContentAiLoading(false);
      contentAiAbortRef.current = null;
    }
  }, [
    brainAiAgentId,
    brainAiModelId,
    brainAiProvider,
    buildContentAiPrompt,
    contentAiLoading,
    contextRegistry,
    toast,
  ]);

  const cancelContent = useCallback((): void => {
    contentAiAbortRef.current?.abort();
    contentAiAbortRef.current = null;
  }, []);

  const applyContent = useCallback((): void => {
    if (!contentAiOutput.trim()) {
      setContentAiError('No AI output to apply.');
      return;
    }
    const parsed = extractJsonFromResponse(contentAiOutput);
    if (!parsed) {
      setContentAiError('AI output is not valid JSON.');
      return;
    }
    const settingsSource =
      typeof parsed['settings'] === 'object' && parsed['settings']
        ? (parsed['settings'] as Record<string, unknown>)
        : parsed;
    applyContentAiSettings(settingsSource);
  }, [applyContentAiSettings, contentAiOutput]);

  const applyCss = useCallback(
    (mode: 'append' | 'replace'): void => {
      if (!cssAiOutput) return;
      const nextCss =
        mode === 'append'
          ? [customCssValue.trim(), cssAiOutput].filter(Boolean).join('\n\n')
          : cssAiOutput;
      onUpdateCss(nextCss);
      toast(mode === 'append' ? 'CSS appended.' : 'CSS replaced.', { variant: 'success' });
    },
    [cssAiOutput, customCssValue, onUpdateCss, toast]
  );

  return {
    cssAiAppend,
    setCssAiAppend,
    cssAiAutoApply,
    setCssAiAutoApply,
    cssAiLoading,
    cssAiError,
    cssAiOutput,
    contentAiPrompt,
    setContentAiPrompt,
    contentAiLoading,
    contentAiError,
    contentAiOutput,
    contentAiPlaceholder: CONTENT_AI_PLACEHOLDER,
    generateCss,
    cancelCss,
    generateContent,
    cancelContent,
    applyContent,
    applyCss,
  };
}

import { cmsSectionInstanceSchema } from '@/shared/contracts/cms';

import type { SectionInstance } from '../../types/page-builder';

export const GRID_TEMPLATE_SETTINGS_KEY = 'cms_grid_templates.v2';

export type GridTemplateRecord = {
  id: string;
  name: string;
  description?: string;
  createdAt: string;
  section: SectionInstance;
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const normalizeRequiredString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const isValidIsoDate = (value: string): boolean => Number.isFinite(Date.parse(value));

export function normalizeGridTemplates(input: unknown): GridTemplateRecord[] {
  if (!Array.isArray(input)) return [];

  return input.flatMap((entry: unknown): GridTemplateRecord[] => {
    if (!isRecord(entry)) return [];

    const id = normalizeRequiredString(entry['id']);
    const name = normalizeRequiredString(entry['name']);
    const createdAt = normalizeRequiredString(entry['createdAt']);
    if (!id || !name || !createdAt || !isValidIsoDate(createdAt)) return [];

    const parsedSection = cmsSectionInstanceSchema.safeParse(entry['section']);
    if (!parsedSection.success) return [];
    if (parsedSection.data.type !== 'Grid') return [];

    const description = normalizeRequiredString(entry['description']) ?? '';

    return [
      {
        id,
        name,
        description,
        createdAt,
        section: parsedSection.data,
      },
    ];
  });
}

export function cloneGridTemplateSection(section: SectionInstance): SectionInstance {
  return structuredClone(section);
}

'use client';

import { useMemo } from 'react';

import type {
  BlockInstance,
  PageZone,
  SectionDefinition,
  SectionInstance,
} from '@/features/cms/types/page-builder';

import { cloneGridTemplateSection, type GridTemplateRecord } from '../grid-templates';
import { usePageBuilderPolicy } from '../PageBuilderPolicyContext';
import { getSectionTypesForZone } from '../section-registry';
import { cloneSectionTemplateSection, type SectionTemplateRecord } from '../section-template-store';
import { getTemplatesByCategory, type SectionTemplate } from '../section-templates';

const sectionContainsOnlyAllowedTypes = (
  section: SectionInstance,
  isSectionTypeAvailable: (sectionType: string) => boolean,
  isBlockTypeAvailable: (blockType: string) => boolean
): boolean => {
  if (!isSectionTypeAvailable(section.type)) {
    return false;
  }

  const traverseBlocks = (blocks: BlockInstance[]): boolean =>
    blocks.every(
      (block: BlockInstance) =>
        isBlockTypeAvailable(block.type) &&
        (!block.blocks || block.blocks.length === 0 || traverseBlocks(block.blocks))
    );

  return traverseBlocks(section.blocks);
};

export function useGroupedTemplates(
  zone: PageZone,
  savedGridTemplates: GridTemplateRecord[],
  savedSectionTemplates: SectionTemplateRecord[]
) {
  const policy = usePageBuilderPolicy();
  const sectionTypes = useMemo(
    () => policy.filterSectionDefinitions(getSectionTypesForZone(zone), { zone }),
    [policy, zone]
  );
  const primitiveTypes = useMemo(() => new Set(['Grid', 'Block']), []);
  const elementTypes = useMemo(
    () => new Set(['TextElement', 'TextAtom', 'ImageElement', 'Model3DElement', 'ButtonElement']),
    []
  );
  const gridAllowed = useMemo(
    () => sectionTypes.some((def: SectionDefinition) => def.type === 'Grid'),
    [sectionTypes]
  );

  const primitives = useMemo(
    () => sectionTypes.filter((def: SectionDefinition) => primitiveTypes.has(def.type)),
    [sectionTypes, primitiveTypes]
  );

  const elements = useMemo(
    () => sectionTypes.filter((def: SectionDefinition) => elementTypes.has(def.type)),
    [sectionTypes, elementTypes]
  );

  const templates = useMemo(
    () =>
      sectionTypes.filter(
        (def: SectionDefinition) => !primitiveTypes.has(def.type) && !elementTypes.has(def.type)
      ),
    [sectionTypes, primitiveTypes, elementTypes]
  );

  const groupedTemplates = useMemo(() => {
    const base = getTemplatesByCategory(zone);
    const result: Record<string, SectionTemplate[]> = {};
    const allowTemplateSection = (section: SectionInstance): boolean =>
      sectionContainsOnlyAllowedTypes(
        section,
        policy.isSectionTypeAvailable,
        policy.isBlockTypeAvailable
      );
    const allowedGridTemplates = savedGridTemplates.filter((record: GridTemplateRecord) =>
      allowTemplateSection(record.section)
    );
    const allowedSectionTemplates = savedSectionTemplates.filter((record: SectionTemplateRecord) =>
      allowTemplateSection(record.section)
    );

    if (gridAllowed && allowedGridTemplates.length > 0) {
      const savedGrids: SectionTemplate[] = allowedGridTemplates.map(
        (record: GridTemplateRecord) => ({
          name: record.name,
          description:
            record.description && record.description.length > 0
              ? record.description
              : 'Saved grid template',
          category: 'Saved grids',
          create: () => cloneGridTemplateSection(record.section),
        })
      );
      result['Saved grids'] = savedGrids;
    }

    if (allowedSectionTemplates.length > 0) {
      for (const record of allowedSectionTemplates) {
        const category = record.category || 'Saved sections';
        if (!result[category]) {
          result[category] = [];
        }
        result[category].push({
          name: record.name,
          description:
            record.description && record.description.length > 0
              ? record.description
              : `Saved ${record.sectionType} template`,
          category,
          create: () => cloneSectionTemplateSection(record.section),
        });
      }
    }

    return { ...base, ...result };
  }, [gridAllowed, policy, savedGridTemplates, savedSectionTemplates, zone]);

  return {
    sectionTypes,
    primitives,
    elements,
    templates,
    groupedTemplates,
  };
}

import { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import {
  CMS_MENU_SETTINGS_KEY,
  DEFAULT_MENU_SETTINGS,
  getCmsMenuSettingsKey,
  type MenuItem,
  type MenuSettings,
  normalizeMenuSettings,
} from '@/shared/contracts/cms-menu';
import { parseJsonSetting, serializeSetting } from '@/shared/utils/settings-json';

export function useMenuSettingsController() {
  const [openSections, setOpenSections] = useState<Set<string>>(new Set());
  const { activeDomainId, zoningEnabled } = useCmsDomainSelection();
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const persistTimerRef = useRef<number | null>(null);

  const [userMenuScopeId, setUserMenuScopeId] = useState<string | null>(null);
  const initialMenuScopeId = useMemo(() => zoningEnabled ? (activeDomainId || 'default') : 'default', [zoningEnabled, activeDomainId]);
  const menuScopeId = useMemo(() => zoningEnabled ? (userMenuScopeId ?? initialMenuScopeId) : 'default', [initialMenuScopeId, userMenuScopeId, zoningEnabled]);

  const menuKey = useMemo(() => (!zoningEnabled || menuScopeId === 'default') ? CMS_MENU_SETTINGS_KEY : getCmsMenuSettingsKey(menuScopeId), [menuScopeId, zoningEnabled]);

  const settingsReady = !settingsStore.isLoading && !settingsStore.error;
  const menuSettingsRaw = settingsStore.get(menuKey);
  const initialSettings = useMemo(() => settingsReady ? normalizeMenuSettings(parseJsonSetting(menuSettingsRaw, null)) : DEFAULT_MENU_SETTINGS, [settingsReady, menuSettingsRaw]);
  const [userSettings, setUserSettings] = useState<MenuSettings | null>(null);
  const settings = userSettings ?? initialSettings;

  const updateMenuItem = useCallback((id: string, field: keyof MenuItem, value: string) => {
    setUserSettings(prev => {
      const current = prev ?? initialSettings;
      return { ...current, items: current.items.map(item => item.id === id ? { ...item, [field]: value } : item) };
    });
  }, [initialSettings]);

  useEffect(() => {
    if (!userSettings) return;
    if (persistTimerRef.current) window.clearTimeout(persistTimerRef.current);
    persistTimerRef.current = window.setTimeout(() => updateSetting.mutate({ key: menuKey, value: serializeSetting(userSettings) }), 500);
    return () => { if (persistTimerRef.current) window.clearTimeout(persistTimerRef.current); };
  }, [menuKey, userSettings, updateSetting]);

  return {
    settings,
