export const InspectorHover = ({
  enabled: propEnabled,
  showTooltip: propShowTooltip,
  nodeId,
  onHover: propOnHover,
  fallbackNodeId,
  content,
  children,
  className,
}: {
  enabled?: boolean | undefined;
  showTooltip?: boolean | undefined;
  nodeId: string;
  onHover?: ((nodeId: string | null) => void) | undefined;
  fallbackNodeId?: string | null | undefined;
  content?: React.ReactNode | undefined;
  children: React.ReactNode;
  className?: string | undefined;
}): React.ReactNode => {
  const previewEditorState = useOptionalPreviewEditorState();
  const previewEditorActions = useOptionalPreviewEditorActions();

  const enabled = propEnabled ?? previewEditorState?.isInspecting ?? false;
  const showTooltip = propShowTooltip ?? previewEditorState?.inspectorSettings?.showTooltip ?? true;
  const onHover = propOnHover ?? previewEditorActions?.onHoverNode;

  const wrapperRef = useRef<HTMLDivElement | null>(null);
  const [open, setOpen] = useState(false);
  const [tooltipPos, setTooltipPos] = useState<{ top: number; left: number } | null>(null);
  const timerRef = useRef<number | null>(null);
  const reactId = useId();
  const tooltipId = `inspector-${reactId.replace(/:/g, '')}`;
  const isTooltipEnabled = enabled && showTooltip;
  const effectiveOpen = isTooltipEnabled ? open : false;

  const clearTimer = (): void => {
    if (timerRef.current) {
      window.clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  };

  const updateTooltipPosition = useCallback((): void => {
    const viewport =
      typeof document !== 'undefined'
        ? document.querySelector('[data-cms-canvas-viewport=\'true\']')
        : null;
    const canvas =
      typeof document !== 'undefined' ? document.querySelector('[data-cms-canvas=\'true\']') : null;
    const el = viewport ?? canvas ?? wrapperRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const margin = 12;
    const index = Math.max(0, getInspectorTooltipIndex(tooltipId));
    const offset = index * (INSPECTOR_TOOLTIP_WIDTH + INSPECTOR_TOOLTIP_GAP);
    const minRightEdge = margin + INSPECTOR_TOOLTIP_WIDTH;
    const rightEdge = rect.right - margin - offset;
    setTooltipPos({
      top: rect.bottom - margin,
      left: Math.max(minRightEdge, rightEdge),
    });
  }, [tooltipId]);

  useEffect((): void | (() => void) => {
    if (!isTooltipEnabled) {
      clearTimer();
      return undefined;
    }
    return (): void => {
      clearTimer();
    };
  }, [isTooltipEnabled]);

  const handleEnter = (): void => {
    if (!enabled) return;
    onHover?.(nodeId);
    clearTimer();
    if (showTooltip) {
      timerRef.current = window.setTimeout(() => {
        registerInspectorTooltip(tooltipId);
        updateTooltipPosition();
        setOpen(true);
      }, INSPECTOR_TOOLTIP_DELAY_MS);
    }
  };

  const handleLeave = (): void => {
    if (!enabled) return;
    onHover?.(fallbackNodeId ?? null);
    clearTimer();
    setOpen(false);
    unregisterInspectorTooltip(tooltipId);
  };

  useEffect((): void | (() => void) => {
    if (!open || !isTooltipEnabled) return undefined;
    const handleScroll = (): void => updateTooltipPosition();
    const handleResize = (): void => updateTooltipPosition();
    window.addEventListener('scroll', handleScroll, true);
    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('scroll', handleScroll, true);
      window.removeEventListener('resize', handleResize);
    };
  }, [open, isTooltipEnabled, updateTooltipPosition]);

  useEffect((): (() => void) => {
    return () => {
      unregisterInspectorTooltip(tooltipId);
    };
  }, [tooltipId]);

  return (
    <div
      ref={wrapperRef}
      className={`relative ${className ?? ''}`}
      onMouseEnter={handleEnter}
      onMouseLeave={handleLeave}
    >
      {children}
      {enabled &&
      showTooltip &&
      effectiveOpen &&
      content &&
      tooltipPos &&
      typeof document !== 'undefined'
        ? createPortal(
          <Card
            variant='subtle-compact'
            padding='sm'
            className='fixed z-[99999] -translate-x-full -translate-y-full border-gray-700 bg-gray-900/95 text-xs text-gray-200 shadow-lg pointer-events-none'
            style={{ left: tooltipPos.left, top: tooltipPos.top, width: INSPECTOR_TOOLTIP_WIDTH }}
          >
            {content}
          </Card>,
          document.body
        )
        : null}
    </div>
  );
};

