      {children.length > 0 ? (
        <BlockContextProvider value={CONTAINED_BLOCK_CONTEXT_VALUE}>
          {children.map((child: BlockInstance) => (
            <PreviewBlockItemProxy key={child.id} block={child} />
          ))}
        </BlockContextProvider>
      ) : showEditorChrome ? (
        <p className='text-gray-500'>Rich text section</p>
      ) : null}
    </div>
  );
}

