'use client';

import { Trash2 } from 'lucide-react';
import React, { useState, useCallback } from 'react';

import {
  usePageBuilderSelection,
  usePageBuilderDispatch,
} from '@/features/cms/hooks/usePageBuilderContext';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import { Button, Input, useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { parseJsonSetting, serializeSetting } from '@/shared/utils/settings-json';

import {
  appendRuntimeVisibilityFields,
  prependManagementFields,
  groupSettingsFields,
  renderFieldGroups,
} from './field-group-helpers';
import { SettingsFormProvider } from './SettingsFormContext';
import { usePageBuilderPolicy } from '../PageBuilderPolicyContext';
import { useComponentSettingsActions } from '../context/ComponentSettingsContext';
import { GRID_TEMPLATE_SETTINGS_KEY, normalizeGridTemplates } from '../grid-templates';
import { getSectionDefinition } from '../section-registry';
import {
  SECTION_TEMPLATE_SETTINGS_KEY,
  normalizeSectionTemplates,
  type SectionTemplateRecord,
} from '../section-template-store';



export function SectionSettingsTab(): React.JSX.Element | null {
  const dispatch = usePageBuilderDispatch();
  const policy = usePageBuilderPolicy();
  const { selectedSection } = usePageBuilderSelection();
  const { handleSectionSettingChange } = useComponentSettingsActions();
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();

  const [sectionTemplateName, setSectionTemplateName] = useState<string>('');
  const [sectionTemplateCategory, setSectionTemplateCategory] = useState<string>('');
  const runtimeVisibilityMode =
    (selectedSection?.settings?.['runtimeVisibilityMode'] as string) || 'always';

  const handleSectionSettingChangeWithGridColumns = useCallback(
    (key: string, value: unknown): void => {
      if (!selectedSection) return;
      if (key === 'columns' && selectedSection.type === 'Grid')
        dispatch({
          type: 'SET_GRID_COLUMNS',
          sectionId: selectedSection.id,
          columnCount: value as number,
        });
      else if (key === 'rows' && selectedSection.type === 'Grid')
        dispatch({
          type: 'SET_GRID_ROWS',
          sectionId: selectedSection.id,
          rowCount: value as number,
        });
      else handleSectionSettingChange(key, value);
    },
    [selectedSection, dispatch, handleSectionSettingChange]
  );

  const handleRemoveSection = useCallback(
    () => selectedSection && dispatch({ type: 'REMOVE_SECTION', sectionId: selectedSection.id }),
    [selectedSection, dispatch]
  );
  const handleCopySection = useCallback(
    () => selectedSection && dispatch({ type: 'COPY_SECTION', sectionId: selectedSection.id }),
    [selectedSection, dispatch]
  );
  const handleDuplicateSection = useCallback(
    () => selectedSection && dispatch({ type: 'DUPLICATE_SECTION', sectionId: selectedSection.id }),
    [selectedSection, dispatch]
  );

  const handleSaveSectionTemplate = useCallback(async (): Promise<void> => {
    if (!selectedSection) return;
    const sectionTemplates = normalizeSectionTemplates(
      parseJsonSetting(settingsStore.get(SECTION_TEMPLATE_SETTINGS_KEY), [])
    );
    const gridTemplates = normalizeGridTemplates(
      parseJsonSetting(settingsStore.get(GRID_TEMPLATE_SETTINGS_KEY), [])
    );
    const name =
      sectionTemplateName.trim() ||
      `${selectedSection.type} template ${sectionTemplates.length + 1}`;
    const category = sectionTemplateCategory.trim() || 'Saved sections';
    const sectionClone = structuredClone({ ...selectedSection, zone: 'template' as const });
    const nextRecord: SectionTemplateRecord = {
      id: `section-${Date.now()}`,
      name,
      description: '',
      category,
      sectionType: selectedSection.type,
      createdAt: new Date().toISOString(),
      section: sectionClone,
    };
    try {
      const promises = [
        updateSetting.mutateAsync({
          key: SECTION_TEMPLATE_SETTINGS_KEY,
          value: serializeSetting([...sectionTemplates, nextRecord]),
        }),
      ];
      if (selectedSection.type === 'Grid')
        promises.push(
          updateSetting.mutateAsync({
            key: GRID_TEMPLATE_SETTINGS_KEY,
            value: serializeSetting([
              ...gridTemplates,
              {
                id: `grid-${Date.now()}`,
                name,
                description: '',
                createdAt: new Date().toISOString(),
                section: sectionClone,
              },
            ]),
          })
        );
      await Promise.all(promises);
      setSectionTemplateName('');
      setSectionTemplateCategory('');
      toast('Section saved as template.', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'SectionSettingsTab',
        action: 'saveSectionTemplate',
      });
      toast('Failed to save section template.', { variant: 'error' });
    }
  }, [
    selectedSection,
    sectionTemplateName,
    sectionTemplateCategory,
    settingsStore,
    updateSetting,
    toast,
  ]);

  if (!selectedSection) return null;
  const sectionDef = getSectionDefinition(selectedSection.type);
  if (!sectionDef) return null;
  const visibleSettingsSchema = policy.filterSettingsFields(sectionDef.settingsSchema);

  return (
    <SettingsFormProvider
      values={selectedSection.settings}
      onChange={handleSectionSettingChangeWithGridColumns}
    >
      <div className='space-y-4'>
        <div className='grid grid-cols-2 gap-2'>
          <Button onClick={handleCopySection} variant='outline' size='sm' className='text-xs'>
            Copy
          </Button>
          <Button onClick={handleDuplicateSection} variant='outline' size='sm' className='text-xs'>
            Duplicate
          </Button>
        </div>
        {renderFieldGroups(
          groupSettingsFields(
            appendRuntimeVisibilityFields(
              selectedSection.type === 'Grid'
                ? prependManagementFields(visibleSettingsSchema)
                : visibleSettingsSchema
            )
          ),
          selectedSection.settings,
          handleSectionSettingChangeWithGridColumns,
          (field) => {
            if (
              runtimeVisibilityMode === 'always' &&
              (field.key === 'runtimeVisibilitySource' ||
                field.key === 'runtimeVisibilityPath' ||
                field.key === 'runtimeVisibilityValue')
            ) {
              return { ...field, disabled: true };
            }

            if (
              (runtimeVisibilityMode === 'truthy' || runtimeVisibilityMode === 'falsy') &&
              field.key === 'runtimeVisibilityValue'
            ) {
              return { ...field, disabled: true };
            }

            return field;
          }
        )}
        <div className='rounded border border-border/40 bg-gray-900/40 p-3'>
          <div className='flex gap-2'>
            <Input
              value={sectionTemplateName}
              onChange={(e) => setSectionTemplateName(e.target.value)}
              aria-label='Template name'
              placeholder='Name'
              className='h-8 text-xs'
             title='Name'/>
            <Input
              value={sectionTemplateCategory}
              onChange={(e) => setSectionTemplateCategory(e.target.value)}
              aria-label='Template category'
              placeholder='Cat'
              className='h-8 text-xs'
             title='Cat'/>
          </div>
          <Button
            onClick={() => void handleSaveSectionTemplate()}
            size='sm'
            className='mt-2 w-full h-8'
            disabled={updateSetting.isPending}
          >
            Save Template
          </Button>
        </div>
        <Button onClick={handleRemoveSection} variant='destructive' size='sm' className='w-full'>
          <Trash2 className='mr-2 size-4' />
          Remove Section
        </Button>
      </div>
    </SettingsFormProvider>
  );
}

'use client';

import React from 'react';

import type { CmsSettingsField } from '@/features/cms/types/page-builder';
import { Input, Label } from '@/shared/ui/primitives.public';

import { SettingsFieldRenderer } from '../SettingsFieldRenderer';


const PADDING_KEYS = new Set(['paddingTop', 'paddingRight', 'paddingBottom', 'paddingLeft']);
const MARGIN_KEYS = new Set(['marginTop', 'marginRight', 'marginBottom', 'marginLeft']);
const MANAGEMENT_FIELDS: CmsSettingsField[] = [
  { key: 'label', label: 'Label', type: 'text', defaultValue: '' },
  { key: 'notes', label: 'Internal notes', type: 'text', defaultValue: '' },
];
const RUNTIME_VISIBILITY_MODE_OPTIONS = [
  { label: 'Always render', value: 'always' },
  { label: 'Value equals', value: 'equals' },
  { label: 'Value does not equal', value: 'not-equals' },
  { label: 'Value is truthy', value: 'truthy' },
  { label: 'Value is falsy', value: 'falsy' },
];
const RUNTIME_VISIBILITY_FIELDS: CmsSettingsField[] = [
  {
    key: 'runtimeVisibilityMode',
    label: 'Runtime visibility',
    type: 'select',
    defaultValue: 'always',
    options: RUNTIME_VISIBILITY_MODE_OPTIONS,
  },
  {
    key: 'runtimeVisibilitySource',
    label: 'Runtime source',
    type: 'text',
    defaultValue: '',
  },
  {
    key: 'runtimeVisibilityPath',
    label: 'Runtime path',
    type: 'text',
    defaultValue: '',
  },
  {
    key: 'runtimeVisibilityValue',
    label: 'Expected value',
    type: 'text',
    defaultValue: '',
  },
];

function prependManagementFields(schema: CmsSettingsField[]): CmsSettingsField[] {
  const existing = new Set(schema.map((field: CmsSettingsField) => field.key));
  const extra = MANAGEMENT_FIELDS.filter((field: CmsSettingsField) => !existing.has(field.key));
  return extra.length ? [...extra, ...schema] : schema;
}

function appendRuntimeVisibilityFields(schema: CmsSettingsField[]): CmsSettingsField[] {
  const existing = new Set(schema.map((field: CmsSettingsField) => field.key));
  const extra = RUNTIME_VISIBILITY_FIELDS.filter(
    (field: CmsSettingsField) => !existing.has(field.key)
  );
  return extra.length ? [...schema, ...extra] : schema;
}

interface FieldGroup {
  kind: 'single' | 'padding' | 'margin';
  fields: CmsSettingsField[];
}

/** Groups consecutive padding / margin number fields so they render compactly. */
function groupSettingsFields(schema: CmsSettingsField[]): FieldGroup[] {
  const groups: FieldGroup[] = [];
  let paddingBuf: CmsSettingsField[] = [];
  let marginBuf: CmsSettingsField[] = [];

  const flushPadding = (): void => {
    if (paddingBuf.length) {
      groups.push({ kind: 'padding', fields: paddingBuf });
      paddingBuf = [];
    }
  };
  const flushMargin = (): void => {
    if (marginBuf.length) {
      groups.push({ kind: 'margin', fields: marginBuf });
      marginBuf = [];
    }
  };

  for (const field of schema) {
    if (PADDING_KEYS.has(field.key)) {
      flushMargin();
      paddingBuf.push(field);
    } else if (MARGIN_KEYS.has(field.key)) {
      flushPadding();
      marginBuf.push(field);
    } else {
      flushPadding();
      flushMargin();
      groups.push({ kind: 'single', fields: [field] });
    }
  }
  flushPadding();
  flushMargin();
  return groups;
}

function renderFieldGroups(
  groups: FieldGroup[],
  settings?: Record<string, unknown>,
  onChange?: (key: string, value: unknown) => void,
  resolveField?: (field: CmsSettingsField) => CmsSettingsField
): React.ReactNode[] {
  const effectiveSettings = settings ?? {};
  const effectiveOnChange = onChange;

  return groups.map((group: FieldGroup) => {
    if (group.kind === 'single') {
      const raw = group.fields[0]!;
      const field = resolveField ? resolveField(raw) : raw;
      return (
        <SettingsFieldRenderer
          key={field.key}
          field={field}
          value={effectiveSettings[field.key]}
          onChange={effectiveOnChange}
        />
      );
    }
    const label = group.kind === 'padding' ? 'Padding' : 'Margin';
    return (
      <div key={group.kind} className='space-y-1.5'>
        <Label className='text-xs text-gray-400'>{label}</Label>
        <div className='grid grid-cols-2 gap-2'>
          {group.fields.map((field: CmsSettingsField) => {
            const side = field.key.replace(/^(padding|margin)/, '');
            return (
              <div key={field.key} className='space-y-0.5'>
                <span className='text-[10px] text-gray-500 uppercase'>{side}</span>
                <Input
                  type='number'
                  value={(effectiveSettings[field.key] as number) ?? field.defaultValue ?? 0}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>): void => {
                    if (effectiveOnChange) {
                      effectiveOnChange(field.key, Number(e.target.value));
                    }
                  }}
                  className='text-xs h-7 px-1.5'
                  aria-label={`${label} ${side}`.trim()}
                 title='Input field'/>
              </div>
            );
          })}
        </div>
      </div>
    );
  });
}

