'use client';

import React, { useMemo, useState } from 'react';

import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import { useCmsSlugs, useUpdateSlug } from '@/features/cms/hooks/useCmsQueries';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import type { PageStatus, Slug } from '@/features/cms/types';
import { normalizePageSlugValues } from '@/features/cms/utils/slug-utils';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import { useUserPreferences, useUpdateUserPreferences } from '@/shared/hooks/useUserPreferences';
import { Button, Input, Label, Checkbox, Badge } from '@/shared/ui/primitives.public';
import { ToggleRow, SegmentedControl } from '@/shared/ui/forms-and-actions.public';

const STATUS_OPTIONS: Array<LabeledOptionDto<PageStatus>> = [
  { label: 'Draft', value: 'draft' },
  { label: 'Published', value: 'published' },
];

export function PageSettingsTabContent({ allSlugs }: { allSlugs: Slug[] }): React.JSX.Element {
  const { state, dispatch } = usePageBuilder();
  const page = state.currentPage!;
  const { activeDomainId } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const updateSlug = useUpdateSlug();
  const [search, setSearch] = useState('');
  const preferencesQuery = useUserPreferences();
  const userPreferences = preferencesQuery.data;
  const updatePreferencesMutation = useUpdateUserPreferences();
  const [userPreviewDraftsEnabled, setUserPreviewDraftsEnabled] = useState<boolean | null>(null);
  const [userPauseSlideshowOnHoverInEditor, setUserPauseSlideshowOnHoverInEditor] = useState<
    boolean | null
  >(null);
  const draftPreviewCheckboxId = 'cms-preview-drafts-enabled';
  const pauseHoverCheckboxId = 'cms-preview-pause-on-hover';

  const domainSlugs = useMemo((): Slug[] => slugsQuery.data ?? [], [slugsQuery.data]);
  const allSlugByValue = useMemo((): Map<string, Slug> => {
    const map = new Map<string, Slug>();
    allSlugs.forEach((slug: Slug) => map.set(slug.slug, slug));
    return map;
  }, [allSlugs]);

  const selectedSlugIds = useMemo((): string[] => {
    const pageSlugValues = normalizePageSlugValues(page.slugs);
    return pageSlugValues
      .map((value: string) => allSlugByValue.get(value)?.id)
      .filter((value: string | undefined): value is string => Boolean(value));
  }, [page.slugs, allSlugByValue]);

  const domainSlugIds = useMemo(
    (): Set<string> => new Set(domainSlugs.map((slug: Slug) => slug.id)),
    [domainSlugs]
  );
  const selectedSlugs = useMemo((): Slug[] => {
    const byId = new Map(allSlugs.map((slug: Slug) => [slug.id, slug]));
    return selectedSlugIds
      .map((idValue: string) => byId.get(idValue))
      .filter((value: Slug | undefined): value is Slug => Boolean(value));
  }, [allSlugs, selectedSlugIds]);

  const crossZoneSlugs = useMemo(
    (): Slug[] => selectedSlugs.filter((slug: Slug) => !domainSlugIds.has(slug.id)),
    [selectedSlugs, domainSlugIds]
  );
  const eligibleHomeSlugs = useMemo(
    (): Slug[] => selectedSlugs.filter((slug: Slug) => domainSlugIds.has(slug.id)),
    [selectedSlugs, domainSlugIds]
  );
  const currentHomeSlug = useMemo(
    (): Slug | null => domainSlugs.find((slug: Slug) => slug.isDefault) ?? null,
    [domainSlugs]
  );
  const pageHomeSlug = useMemo(
    (): Slug | null =>
      currentHomeSlug
        ? (eligibleHomeSlugs.find((slug: Slug) => slug.id === currentHomeSlug.id) ?? null)
        : null,
    [currentHomeSlug, eligibleHomeSlugs]
  );

  const filteredDomainSlugs = useMemo((): Slug[] => {
    const term = search.trim().toLowerCase();
    if (!term) return domainSlugs;
    return domainSlugs.filter((slug: Slug) => slug.slug.toLowerCase().includes(term));
  }, [domainSlugs, search]);

  const handleStatusChange = (status: PageStatus): void => {
    dispatch({ type: 'SET_PAGE_STATUS', status });
  };

  const handleMenuVisibilityChange = (checked: boolean): void => {
    dispatch({ type: 'SET_PAGE_MENU_VISIBILITY', showMenu: checked });
  };

  const showMenuValue = page.showMenu !== false;
  const previewDraftsEnabled =
    userPreviewDraftsEnabled ?? Boolean(userPreferences?.cmsPreviewEnabled);
  const pauseSlideshowOnHoverInEditor =
    userPauseSlideshowOnHoverInEditor ?? Boolean(userPreferences?.cmsSlideshowPauseOnHoverInEditor);

  const applySelectedSlugIds = (ids: string[]): void => {
    const selectedSlugsList = ids
      .map((idValue: string) => allSlugs.find((slug: Slug) => slug.id === idValue))
      .filter((value: Slug | undefined): value is Slug => Boolean(value));
    dispatch({
      type: 'UPDATE_PAGE_SLUGS',
      slugIds: ids,
      slugValues: selectedSlugsList.map((slug: Slug) => slug.slug),
    });
  };

  const handleToggleSlug = (slug: Slug): void => {
    const nextIds = selectedSlugIds.includes(slug.id)
      ? selectedSlugIds.filter((idValue: string) => idValue !== slug.id)
      : [...selectedSlugIds, slug.id];
    applySelectedSlugIds(nextIds);
  };

  const handleRemoveSlug = (slug: Slug): void => {
    applySelectedSlugIds(selectedSlugIds.filter((idValue: string) => idValue !== slug.id));
  };

  const handleSetHome = async (slug: Slug): Promise<void> => {
    await updateSlug.mutateAsync({
      id: slug.id,
      input: { slug: slug.slug, isDefault: true },
      domainId: activeDomainId,
    });
  };

  const handleDraftPreviewChange = (value: boolean | 'indeterminate'): void => {
    const next = value === true;
    setUserPreviewDraftsEnabled(next);
    updatePreferencesMutation.mutate({ cmsPreviewEnabled: next });
  };

  const handlePauseSlidesOnHoverChange = (value: boolean | 'indeterminate'): void => {
    const next = value === true;
    setUserPauseSlideshowOnHoverInEditor(next);
    updatePreferencesMutation.mutate({ cmsSlideshowPauseOnHoverInEditor: next });
  };

  return (
    <div className='space-y-4'>
      <div className='space-y-2'>
        <Label className='text-xs text-gray-400'>Status</Label>
        <SegmentedControl
          value={page.status}
          onChange={(value: string) => handleStatusChange(value as PageStatus)}
          options={STATUS_OPTIONS}
          size='sm'
          className='w-full'
          ariaLabel='Page status'
        />
        {page.publishedAt && page.status === 'published' && (
          <p className='text-[10px] text-gray-500'>
            Published: {new Date(page.publishedAt).toLocaleDateString()}
          </p>
        )}
      </div>

      <div className='space-y-2'>
        <ToggleRow
          variant='switch'
          label='Global Menu'
          description='Show the global navigation menu on this page.'
          checked={showMenuValue}
          onCheckedChange={handleMenuVisibilityChange}
          className='border-none p-0 bg-transparent hover:bg-transparent'
        />
      </div>

      <div className='space-y-2'>
        <Label className='text-xs text-gray-400'>Slugs for this zone</Label>
        <Input
          value={search}
          onChange={(e: React.ChangeEvent<HTMLInputElement>): void => setSearch(e.target.value)}
          aria-label='Search slugs'
          placeholder='Search slugs...'
          className='h-8 text-xs'
         title='Search slugs...'/>
        <div className='max-h-48 space-y-2 overflow-y-auto rounded border border-border/40 bg-gray-900/40 p-2'>
          {filteredDomainSlugs.length === 0 ? (
            <p className='py-4 text-center text-xs text-gray-500'>
              No slugs available for this zone.
            </p>
          ) : (
            filteredDomainSlugs.map((slug: Slug) => {
              const checked = selectedSlugIds.includes(slug.id);
              return (
                <label key={slug.id} className='flex items-center gap-2 text-xs text-gray-200'>
                  <Checkbox
                    checked={checked}
                    onCheckedChange={(): void => handleToggleSlug(slug)}
                  />
                  /{slug.slug}
                </label>
              );
            })
          )}
        </div>
        <p className='text-[10px] text-gray-500'>{selectedSlugIds.length} selected</p>
      </div>

      {crossZoneSlugs.length > 0 ? (
        <div className='rounded border border-amber-500/40 bg-amber-500/10 p-3'>
          <p className='text-[10px] font-semibold uppercase tracking-wide text-amber-200'>
            Cross-zone slugs
          </p>
          <p className='mt-1 text-[10px] text-amber-200/80'>
            These slugs are not part of the current zone. Remove them or switch zones.
          </p>
          <div className='mt-2 flex flex-wrap gap-1.5'>
            {crossZoneSlugs.map((slug: Slug) => (
              <Badge
                key={slug.id}
                variant='outline'
                className='h-auto border-amber-500/40 bg-amber-500/20 px-2 py-0.5 text-[10px] text-amber-200 cursor-pointer hover:bg-amber-500/30'
                onClick={(): void => handleRemoveSlug(slug)}
              >
                /{slug.slug} ×
              </Badge>
            ))}
          </div>
        </div>
      ) : null}

      <div className='space-y-2'>
        <Label className='text-xs text-gray-400'>Home page</Label>
        {eligibleHomeSlugs.length === 0 ? (
          <p className='text-xs text-gray-500'>
            Assign at least one slug in this zone to set this page as the home page.
          </p>
        ) : (
          <div className='space-y-2'>
            {eligibleHomeSlugs.map((slug: Slug) => {
              const isHome = currentHomeSlug?.id === slug.id;
              return (
                <div
                  key={slug.id}
                  className='flex items-center justify-between rounded border border-border/40 bg-gray-900/40 px-2.5 py-2 text-xs'
                >
                  <span className='text-gray-200'>/{slug.slug}</span>
                  {isHome ? (
                    <Badge
                      variant='success'
                      className='h-auto border-green-500/40 bg-green-500/10 px-2 py-0.5 text-[10px] text-green-300'
                    >
                      Home
                    </Badge>
                  ) : (
                    <Button
                      size='sm'
                      variant='outline'
                      disabled={updateSlug.isPending}
                      onClick={(): void => {
                        void handleSetHome(slug);
                      }}
                      className='h-6 px-2 text-[10px]'
                    >
                      Set as home
                    </Button>
                  )}
                </div>
              );
            })}
            {currentHomeSlug && !pageHomeSlug ? (
              <p className='text-[10px] text-gray-500'>
                Current home page: /{currentHomeSlug.slug}
              </p>
            ) : null}
          </div>
        )}
      </div>

      <p className='text-xs text-gray-500'>
        Select a section or block from the tree to edit its settings.
      </p>

      <div className='space-y-2 border-t border-border/40 pt-4'>
        <Label className='text-xs text-gray-400'>Preview options</Label>
        <div className='flex items-center justify-between rounded border border-border/40 bg-gray-900/40 px-3 py-2 text-xs text-gray-200'>
          <Label htmlFor={draftPreviewCheckboxId} className='cursor-pointer text-xs text-gray-200'>
            Draft Preview
          </Label>
          <Checkbox
            id={draftPreviewCheckboxId}
            checked={previewDraftsEnabled}
            onCheckedChange={handleDraftPreviewChange}
          />
        </div>
        <div className='flex items-center justify-between rounded border border-border/40 bg-gray-900/40 px-3 py-2 text-xs text-gray-200'>
          <Label htmlFor={pauseHoverCheckboxId} className='cursor-pointer text-xs text-gray-200'>
            Pause slides on hover
          </Label>
          <Checkbox
            id={pauseHoverCheckboxId}
            checked={pauseSlideshowOnHoverInEditor}
            onCheckedChange={handlePauseSlidesOnHoverChange}
          />
        </div>
      </div>
    </div>
  );
}

'use client';

import { useCallback, useMemo, useRef, useState } from 'react';

import {
  usePageBuilderState,
  usePageBuilderDispatch,
} from '@/features/cms/hooks/usePageBuilderContext';
import type { ChatMessageDto as ChatMessage } from '@/shared/contracts/chatbot';
import type { PageZone, SectionInstance } from '@/shared/contracts/cms';
import { useBrainAssignment } from '@/shared/lib/ai-brain/hooks/useBrainAssignment';
import { useOptionalContextRegistryPageEnvelope } from '@/shared/lib/ai-context-registry/page-context';
import { ApiError } from '@/shared/lib/api-client';
import { useMutationV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import { getSectionDefinition } from '../../section-registry';

export function usePageAiAssistant() {
  const state = usePageBuilderState();
  const dispatch = usePageBuilderDispatch();
  const page = state.currentPage;
  const { toast } = useToast();
  const brainAi = useBrainAssignment({
    capability: 'cms.css_stream',
  });

  const [pageAiPrompt, setPageAiPrompt] = useState<string>('');
  const [pageAiTask, setPageAiTask] = useState<'layout' | 'seo'>('layout');
  const [pageAiOutput, setPageAiOutput] = useState<string>('');
  const [pageAiError, setPageAiError] = useState<string | null>(null);
  const pageAiAbortRef = useRef<AbortController | null>(null);
  const pageAiProvider = brainAi.assignment.provider;
  const pageAiModelId = brainAi.assignment.modelId.trim();
  const pageAiAgentId = brainAi.assignment.agentId.trim();
  const contextRegistry = useOptionalContextRegistryPageEnvelope();

  const pageContext = useMemo((): string => {
    if (!page) return '';
    const sectionsData = state.sections;
    const contextSections = (sectionsData || []).map((section: SectionInstance) => {
      return {
        id: String(section.id || ''),
        type: String(section.type || ''),
        zone: String(section.zone || ''),
        blockCount: Array.isArray(section.blocks) ? section.blocks.length : 0,
      };
    });
    const firstSlug = Array.isArray(page.slugs) ? page.slugs[0] : null;
    const slugValue =
      typeof firstSlug === 'string'
        ? firstSlug
        : firstSlug && typeof firstSlug === 'object' && 'slug' in firstSlug
          ? (firstSlug as { slug: string }).slug
          : '';

    return JSON.stringify({
      pageId: page.id,
      title: page.name,
      slug: slugValue,
      sections: contextSections,
    });
  }, [page, state.sections]);

  const extractPageAiJson = useCallback((text: string): unknown => {
    try {
      const match = /```json\n([\s\S]*?)\n```/.exec(text);
      const jsonText = match?.[1] ? match[1] : text;
      return JSON.parse(jsonText);
    } catch (error) {
      logClientError(error);
      return null;
    }
  }, []);

  const buildPageAiMessages = useCallback((): ChatMessage[] => {
    const sessionId = `page-ai-${Date.now()}`;
    const timestamp = new Date().toISOString();
    const systemContent =
      pageAiTask === 'seo'
        ? 'You are a CMS SEO assistant. Return only valid JSON with concise SEO recommendations for this page. Do not use markdown or code fences.'
        : 'You are a CMS layout assistant. Return only valid JSON. The response must be an object with a "sections" array. Each section should use { "type": string, "zone": string, "settings"?: object }. Do not use markdown or code fences.';
    const userContent = [
      `Task: ${pageAiTask}`,
      pageAiPrompt.trim()
        ? `Prompt:\n${pageAiPrompt.trim()}`
        : 'Prompt:\nGenerate a useful result.',
      `Context:\n${pageContext}`,
    ].join('\n\n');

    return [
      {
        id: `sys-${Date.now()}`,
        sessionId,
        timestamp,
        role: 'system',
        content: systemContent,
      },
      {
        id: `user-${Date.now()}`,
        sessionId,
        timestamp,
        role: 'user',
        content: userContent,
      },
    ];
  }, [pageAiPrompt, pageAiTask, pageContext]);

  const generatePageAiMutation = useMutationV2<
    { accumulated: string; provider: 'model' | 'agent' },
    {
      messages: ChatMessage[];
    }
  >({
    mutationFn: async (variables) => {
      const { messages } = variables;
      const controller = new AbortController();
      pageAiAbortRef.current = controller;

      const response = await fetch('/api/cms/css-ai/stream', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          provider: pageAiProvider,
          modelId: pageAiModelId || undefined,
          agentId: pageAiAgentId || undefined,
          messages,
          contextRegistry,
        }),
        signal: controller.signal,
      });

      if (!response.ok) {
        const error = (await response.json().catch(() => null)) as Record<string, unknown> | null;
        throw new ApiError(
          String(error?.['message'] || error?.['error'] || 'Failed to generate AI output'),
          response.status
        );
      }

      if (response.headers.get('Content-Type')?.includes('text/event-stream')) {
        const reader = response.body?.getReader();
        if (!reader) throw new ApiError('Failed to read stream', 500);

        let accumulated = '';
        const decoder = new TextDecoder();
        let buffer = '';
        let doneSignal = false;

        const processEvent = (raw: string): void => {
          const lines = raw.split('\n').map((line: string) => line.trim());
          const dataLine = lines.find((line: string) => line.startsWith('data:'));
          if (!dataLine) return;
          const payload = JSON.parse(dataLine.replace(/^data:\s*/, '')) as {
            delta?: string;
            done?: boolean;
            error?: string;
            brainApplied?: unknown;
          };
          if (payload.error) {
            throw new ApiError(payload.error, 400);
          }
          if (payload.delta) {
            accumulated += payload.delta;
            setPageAiOutput(accumulated);
          }
          if (payload.done) {
            doneSignal = true;
          }
        };

        while (!doneSignal) {
          const { done, value } = await reader.read();
          if (done) break;
          if (!value) continue;
          buffer += decoder.decode(value, { stream: true });
          const chunks = buffer.split('\n\n');
          buffer = chunks.pop() ?? '';
          for (const chunk of chunks) {
            processEvent(chunk);
            if (doneSignal) break;
          }
        }
        if (buffer.trim() && !doneSignal) {
          processEvent(buffer);
        }
        if (doneSignal) {
          try {
            await reader.cancel();
          } catch (error) {
            logClientError(error);

            // ignore
          }
        }
        return { accumulated, provider: pageAiProvider };
      }

      const data = (await response.json()) as { output: string };
      setPageAiOutput(data.output);
      return { accumulated: data.output, provider: pageAiProvider };
    },
    mutationKey: QUERY_KEYS.cms.pages.all,
    meta: {
      source: 'cms.page-builder.ai-assistant',
      operation: 'action',
      resource: 'cms.pages.ai',
      domain: 'cms' as const,
      tags: ['cms', 'pages', 'ai'],
      description: 'Runs cms pages ai.'},
  });

  const handleGeneratePageAi = useCallback(async (): Promise<void> => {
    if (!page) return;
    setPageAiError(null);
    setPageAiOutput('');
    if (pageAiProvider === 'model' && !pageAiModelId) {
      const message = 'Configure CMS CSS Stream in AI Brain first.';
      setPageAiError(message);
      toast(message, { variant: 'error' });
      return;
    }
    if (pageAiProvider === 'agent' && !pageAiAgentId) {
      const message = 'Configure a CMS CSS Stream agent in AI Brain first.';
      setPageAiError(message);
      toast(message, { variant: 'error' });
      return;
    }

    try {
      const { accumulated, provider } = await generatePageAiMutation.mutateAsync({
        messages: buildPageAiMessages(),
      });

      const parsed = extractPageAiJson(accumulated) as Record<string, unknown> | null;
      if (!parsed) throw new ApiError('AI response did not include JSON.', 400);
      setPageAiOutput(JSON.stringify(parsed, null, 2));
      toast(`AI output ready (${provider}).`, { variant: 'success' });
    } catch (error) {
      logClientError(error);
      if (error instanceof Error && error.name === 'AbortError') return;
      logClientError(error, { context: { source: 'usePageAiAssistant', action: 'generate' } });
      const message = error instanceof Error ? error.message : 'Failed to generate AI output.';
      setPageAiError(message);
      toast(message, { variant: 'error' });
    } finally {
      pageAiAbortRef.current = null;
    }
  }, [
    page,
    pageAiProvider,
    pageAiModelId,
    pageAiAgentId,
    contextRegistry,
    pageAiTask,
    pageAiPrompt,
    buildPageAiMessages,
    generatePageAiMutation,
    extractPageAiJson,
    pageAiProvider,
    pageAiModelId,
    pageAiAgentId,
    toast,
  ]);

  const handleApplyPageAi = useCallback((): void => {
    const rawParsed = extractPageAiJson(pageAiOutput);
    if (!rawParsed || typeof rawParsed !== 'object') {
      setPageAiError('Invalid AI output format. Expected an object.');
      return;
    }
    const parsed = rawParsed as { sections?: unknown[] };
    if (!Array.isArray(parsed.sections)) {
      setPageAiError('Invalid AI output format. Expected sections array.');
      return;
    }

    let inserted = 0;
    const sections = parsed.sections as Array<Record<string, unknown>>;
    sections.forEach((section) => {
      const type = typeof section['type'] === 'string' ? section['type'] : '';
      const definition = getSectionDefinition(type);
      if (definition) {
        dispatch({
          type: 'ADD_SECTION',
          sectionType: type,
          zone: (section['zone'] || 'template') as PageZone,
          initialSettings: section['settings'] as Record<string, unknown>,
        });
        inserted += 1;
      }
    });

    if (inserted === 0) {
      setPageAiError('No valid templates or section types matched.');
      return;
    }
    toast(`Inserted ${inserted} section${inserted === 1 ? '' : 's'}.`, { variant: 'success' });
  }, [pageAiOutput, extractPageAiJson, dispatch, toast]);

  const handleCancelPageAi = useCallback((): void => {
    pageAiAbortRef.current?.abort();
    pageAiAbortRef.current = null;
  }, []);

  return {
    pageAiProvider,
    pageAiModelId,
    pageAiAgentId,
    pageAiPrompt,
    setPageAiPrompt,
    pageAiTask,
    setPageAiTask,
    pageAiOutput,
    pageAiError,
    generatePageAiMutation,
    handleGeneratePageAi,
    handleApplyPageAi,
    handleCancelPageAi,
  };
}

'use client';

import React, { useCallback, useMemo, useState } from 'react';

import { Viewer3D, Asset3DPreviewModal, useAsset3DById } from '@/features/viewer3d/public';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { ManagedImageSlot } from '@/shared/contracts/image-slots';
import type { ProductImageManagerController } from '@/shared/contracts/product-image-manager';
import type { Asset3DRecord } from '@/shared/contracts/viewer3d';
import { Input, Checkbox, Button, useToast } from '@/shared/ui/primitives.public';
import { SelectSimple, FormField } from '@/shared/ui/forms-and-actions.public';
import { ProductImageManager } from '@/shared/ui/media.public';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import {
  PRODUCT_IMAGES_EXTERNAL_BASE_URL_SETTING_KEY,
  DEFAULT_PRODUCT_IMAGES_EXTERNAL_BASE_URL,
} from '@/shared/lib/products/constants';
import { cn } from '@/shared/utils/ui-utils';

import { Asset3DPickerModal } from './Asset3DPickerModal';
import { MediaLibraryPanel } from './MediaLibraryPanel';
import { useUploadCmsMedia } from '../../hooks/useCmsQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


interface FieldProps<T> {
  label?: string;
  value: T;
  onChange: (value: T) => void;
  className?: string;
  disabled?: boolean;
  ariaLabel?: string;
  id?: string;
}

export function ImagePickerField(props: FieldProps<string>): React.JSX.Element {
  const { label, value, onChange, disabled } = props;

  const [open, setOpen] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const uploadMutation = useUploadCmsMedia();
  const { toast } = useToast();

  const managedSlot = useMemo<ManagedImageSlot>(() => {
    const src = value.trim();
    if (!src) return null;
    return {
      type: 'existing',
      data: {
        id: 'cms-image-slot-source',
        filepath: src,
      },
      previewUrl: src,
      slotId: 'cms-image-slot-0',
    };
  }, [value]);

  const uploadSingleFile = useCallback(
    async (file: File): Promise<void> => {
      if (disabled) return;
      try {
        setUploadError(null);
        const result = await uploadMutation.mutateAsync({ file });
        if (!result.filepath) {
          setUploadError('Upload completed without a media path.');
          toast('Upload completed without a media path.', { variant: 'error' });
          return;
        }
        onChange(result.filepath);
        toast('Image uploaded successfully.', { variant: 'success' });
      } catch (error) {
        logClientError(error);
        const message = error instanceof Error ? error.message : 'Upload failed';
        setUploadError(message);
        toast(message, { variant: 'error' });
      }
    },
    [disabled, onChange, toast, uploadMutation]
  );

  const controller = useMemo<ProductImageManagerController>(
    () => ({
      imageSlots: [managedSlot],
      imageLinks: [value],
      imageBase64s: [''],
      setImageLinkAt: (index: number, nextValue: string): void => {
        if (index !== 0 || disabled || uploadMutation.isPending) return;
        setUploadError(null);
        onChange(nextValue);
      },
      setImageBase64At: (): void => {
        // Base64 editing is not used in CMS field mode.
      },
      handleSlotImageChange: (file: File | null, index: number): void => {
        if (index !== 0 || disabled || uploadMutation.isPending || !file) return;
        void uploadSingleFile(file);
      },
      handleSlotDisconnectImage: async (index: number): Promise<void> => {
        if (index !== 0 || disabled || uploadMutation.isPending) return;
        setUploadError(null);
        onChange('');
      },
      setShowFileManager: (show: boolean): void => {
        if (!show || disabled || uploadMutation.isPending) return;
        setOpen(true);
      },
      setShowFileManagerForSlot: (index: number): void => {
        if (index !== 0 || disabled || uploadMutation.isPending) return;
        setOpen(true);
      },
      swapImageSlots: (): void => {
        // Single-slot picker: no reordering.
      },
      setImagesReordering: (): void => {
        // Single-slot picker: no reordering.
      },
      slotLabels: [''],
      uploadError,
      isSlotImageLocked: (): boolean => Boolean(disabled || uploadMutation.isPending),
      slotImageLockedReason: disabled ? 'Image field is disabled.' : 'Image upload is in progress.',
    }),
    [
      disabled,
      managedSlot,
      onChange,
      uploadError,
      uploadMutation.isPending,
      uploadSingleFile,
      value,
    ]
  );

  const settingsStore = useSettingsStore();
  const externalBaseUrl =
    settingsStore.get(PRODUCT_IMAGES_EXTERNAL_BASE_URL_SETTING_KEY) ??
    DEFAULT_PRODUCT_IMAGES_EXTERNAL_BASE_URL;

  return (
    <FormField label={label}>
      <div className='space-y-2 mt-1'>
        <ProductImageManager
          controller={controller}
          externalBaseUrl={externalBaseUrl}
          minimalUi
          showDragHandle={false}
          minimalSingleSlotAlign='left'
        />
        <MediaLibraryPanel
          open={open}
          onOpenChange={setOpen}
          selectionMode='single'
          onSelect={(filepaths: string[]): void => {
            if (disabled || uploadMutation.isPending) return;
            setUploadError(null);
            onChange(filepaths[0] ?? '');
          }}
        />
      </div>
    </FormField>
  );
}

export function Asset3DPickerField(props: FieldProps<string>): React.JSX.Element {
  const { label, value, onChange, disabled, ariaLabel } = props;

  const [open, setOpen] = useState(false);
  const [previewAsset, setPreviewAsset] = useState<Asset3DRecord | null>(null);

  const selectedAssetQuery = useAsset3DById(value || null);
  const selectedAsset = selectedAssetQuery.data ?? null;
  const modelUrl = selectedAsset ? `/api/assets3d/${selectedAsset.id}/file` : null;
  const closePickerModal = (): void => {
    setOpen(false);
  };

  return (
    <FormField label={label}>
      <div className='space-y-2 mt-1'>
        <div className='relative flex h-40 items-center justify-center overflow-hidden rounded border border-dashed border-border/50 bg-card/30'>
          {selectedAsset && modelUrl ? (
            <Viewer3D
              modelUrl={modelUrl}
              settings={{
                backgroundColor: '#111827',
                autoRotate: true,
                autoRotateSpeed: 2,
                environment: 'studio',
                lighting: 'studio',
                lightIntensity: 1,
                enableShadows: true,
                enableBloom: false,
                bloomIntensity: 0.5,
                exposure: 1,
                showGround: false,
                enableContactShadows: true,
                enableVignette: false,
              }}
              autoFit
              presentationMode={false}
              className='h-full w-full'
            />
          ) : (
            <span className='text-xs text-gray-500'>No 3D asset selected</span>
          )}
        </div>
        <div className='grid grid-cols-2 gap-2'>
          <Button
            type='button'
            size='sm'
            variant='outline'
            className='text-xs'
            onClick={(): void => setOpen(true)}
            disabled={disabled}
            aria-label={ariaLabel ? `${ariaLabel} browse 3D assets` : 'Browse 3D assets'}
          >
            Browse 3D assets
          </Button>
          <Button
            type='button'
            size='sm'
            variant='outline'
            className='text-xs'
            onClick={(): void => {
              if (selectedAsset) setPreviewAsset(selectedAsset);
            }}
            disabled={disabled || !selectedAsset}
            aria-label={ariaLabel ? `${ariaLabel} preview asset` : 'Preview 3D asset'}
          >
            Preview
          </Button>
        </div>
        {value ? (
          <Button
            type='button'
            size='sm'
            variant='ghost'
            className='w-full text-xs text-gray-400 hover:text-gray-200'
            onClick={(): void => onChange('')}
            disabled={disabled}
            aria-label={ariaLabel ? `Clear ${ariaLabel}` : 'Clear asset'}
          >
            Clear asset
          </Button>
        ) : null}
      </div>

      <Asset3DPickerModal
        isOpen={open}
        onClose={closePickerModal}
        onSuccess={() => {}}
        onSelectAsset={(assetId: string): void => {
          onChange(assetId);
          setOpen(false);
        }}
      />

      {previewAsset ? (
        <Asset3DPreviewModal
          isOpen={Boolean(previewAsset)}
          onClose={() => setPreviewAsset(null)}
          onSuccess={() => {}}
          item={previewAsset}
        />
      ) : null}
    </FormField>
  );
}

export function ColorField(props: FieldProps<string>): React.JSX.Element {
  const { label, value, onChange, className, disabled, ariaLabel, id } = props;
  const resolvedLabel = ariaLabel ?? label ?? 'Color';
  const generatedId = React.useId().replace(/:/g, '');
  const controlId = id ?? `color-field-${generatedId}`;

  return (
    <FormField label={label} className={className} controlId={controlId}>
      <div className='flex items-center gap-2 mt-1'>
        <div
          className={cn(
            'relative flex size-7 shrink-0 cursor-pointer items-center justify-center overflow-hidden rounded border border-border/50',
            disabled && 'cursor-not-allowed opacity-50'
          )}
        >
          <input
            type='color'
            aria-label={`${resolvedLabel} color picker`}
            value={value || '#ffffff'}
            onChange={(e: React.ChangeEvent<HTMLInputElement>): void => onChange(e.target.value)}
            className='absolute inset-0 size-full cursor-pointer opacity-0'
            disabled={disabled}
            id={`${controlId}-picker`}
          />
          <div className='size-full rounded' style={{ backgroundColor: value || '#ffffff' }} />
        </div>
        <Input
          id={controlId}
          value={value || '#ffffff'}
          onChange={(e: React.ChangeEvent<HTMLInputElement>): void => onChange(e.target.value)}
          className='h-7 flex-1 bg-card/40 text-xs font-mono'
          maxLength={7}
          disabled={disabled}
          aria-label={`${resolvedLabel} value`}
         title={label}/>
      </div>
    </FormField>
  );
}

export function NumberField(
  props: FieldProps<number> & {
    suffix?: string;
    min?: number;
    max?: number;
    step?: number;
  }
): React.JSX.Element {
  const { label, value, onChange, className, disabled, suffix, min, max, step, id } = props;
  const resolvedLabel = props.ariaLabel ?? label ?? 'Number value';
  const generatedId = React.useId().replace(/:/g, '');
  const controlId = id ?? `number-field-${generatedId}`;

  return (
    <FormField label={label} className={className} controlId={controlId}>
      <div className='flex items-center gap-1.5 mt-1'>
        <Input
          id={controlId}
          type='number'
          value={value ?? 0}
          min={min}
          max={max}
          step={step}
          onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
            onChange(Number(e.target.value))
          }
          className='h-7 flex-1 bg-card/40 text-xs'
          disabled={disabled}
          aria-label={resolvedLabel}
         title={label}/>
        {suffix && <span className='text-[10px] text-gray-500'>{suffix}</span>}
      </div>
    </FormField>
  );
}

export function RangeField(
  props: FieldProps<number> & {
    min: number;
    max: number;
    step?: number;
    suffix?: string;
  }
): React.JSX.Element {
  const { label, value, onChange, className, disabled, min, max, step, suffix, id } = props;
  const resolvedLabel = props.ariaLabel ?? label ?? 'Range value';
  const generatedId = React.useId().replace(/:/g, '');
  const controlId = id ?? `range-field-${generatedId}`;

  const safeValue = Number.isFinite(value) ? value : min;
  return (
    <FormField
      label={label}
      className={className}
      controlId={controlId}
      actions={
        <span className='text-[11px] text-gray-300'>
          {safeValue}
          {suffix}
        </span>
      }
    >
      <input
        id={controlId}
        type='range'
        min={min}
        max={max}
        step={step}
        value={safeValue}
        onChange={(e: React.ChangeEvent<HTMLInputElement>): void =>
          onChange(Number(e.target.value))
        }
        className={cn('w-full accent-blue-500 mt-1', disabled && 'opacity-50 cursor-not-allowed')}
        disabled={disabled}
        aria-label={resolvedLabel}
      />
    </FormField>
  );
}

export function SelectField(
  props: FieldProps<string> & {
    options: Array<LabeledOptionDto<string>>;
    placeholder?: string;
  }
): React.JSX.Element {
  const { label, value, onChange, options, className, disabled, placeholder, id } = props;
  const resolvedLabel = props.ariaLabel ?? label;
  const generatedId = React.useId().replace(/:/g, '');
  const controlId = id ?? `select-field-${generatedId}`;

  return (
    <FormField label={label} className={className} controlId={controlId}>
      <SelectSimple
        size='sm'
        value={value}
        onValueChange={onChange}
        disabled={disabled || false}
        options={options}
        placeholder={placeholder}
        ariaLabel={resolvedLabel}
        id={controlId}
        triggerClassName='h-7 bg-card/40 text-xs mt-1'
       title={placeholder}/>
    </FormField>
  );
}

export function CheckboxField(props: {
  label: string;
  checked: boolean;
  onChange: (checked: boolean) => void;
  className?: string;
  disabled?: boolean;
}): React.JSX.Element {
  const { label, checked, onChange, className, disabled } = props;

  return (
    <label
      className={cn(
        'flex items-center gap-2 cursor-pointer',
        disabled && 'cursor-not-allowed opacity-50',
        className
      )}
    >
      <Checkbox
        checked={checked}
        onCheckedChange={(v: boolean | 'indeterminate'): void => onChange(v === true)}
        disabled={disabled}
      />
      <span className='text-xs text-gray-300'>{label}</span>
    </label>
  );
}

export function TextField(props: FieldProps<string> & { placeholder?: string }): React.JSX.Element {
  const { label, value, onChange, className, disabled, placeholder, ariaLabel, id } = props;
  const resolvedLabel = ariaLabel ?? label;
  const generatedId = React.useId().replace(/:/g, '');
  const controlId = id ?? `text-field-${generatedId}`;

  return (
    <FormField label={label} className={className} controlId={controlId}>
      <Input
        id={controlId}
        value={value || ''}
        onChange={(e: React.ChangeEvent<HTMLInputElement>): void => onChange(e.target.value)}
        placeholder={placeholder}
        className='h-7 bg-card/40 text-xs mt-1'
        disabled={disabled}
        aria-label={resolvedLabel}
       title={placeholder}/>
    </FormField>
  );
}

