    setSchemeView,
    setEditingSchemeId,
    startAddScheme,
    startEditScheme,
    handleSaveScheme,
    setNewSchemeName,
    updateSchemeColor,
    toggleGlobalPalette,
  } = useThemeColorsActions();

  const updateSetting = useCallback(
    <K extends keyof ThemeSettings>(key: K) =>
      (value: ThemeSettings[K]) => {
        update(key, value);
      },
    [update]
