                          >
                            <div
                              className='h-1.5 w-10 rounded'
                              style={{ backgroundColor: scheme.colors.text, opacity: 0.75 }}
                            />
                            <div
                              className='h-1.5 w-6 rounded'
                              style={{ backgroundColor: scheme.colors.accent }}
