import type { CmsTheme } from '@/shared/contracts/cms';
import type { ColorSchemeColors, ThemeSettings } from '@/shared/contracts/cms-theme';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export const parseCssNumber = (value?: string | null): number | null => {
  if (!value) return null;
  const parsed = Number.parseFloat(value);
  return Number.isFinite(parsed) ? parsed : null;
};

export const normalizeAiString = (value: unknown): string | undefined => {
  if (typeof value !== 'string') return undefined;
  const trimmed = value.trim();
  return trimmed.length ? trimmed : undefined;
};

export const parseColorSchemePayload = (
  payload: unknown
): { name?: string; colors: Partial<ColorSchemeColors> } | null => {
  if (!payload || typeof payload !== 'object') return null;
  const raw = payload as Record<string, unknown>;
  const name = normalizeAiString(raw['name']);
  const colorsSource = raw['colors'] as Record<string, unknown>;

  if (!colorsSource || typeof colorsSource !== 'object') return null;

  const colors = colorsSource;
  const parsedRaw = {
    background: normalizeAiString(colors['background']),
    surface: normalizeAiString(colors['surface']),
    text: normalizeAiString(colors['text']),
    accent: normalizeAiString(colors['accent']),
    border: normalizeAiString(colors['border']),
  };
  const parsed: Partial<ColorSchemeColors> = {};
  (Object.entries(parsedRaw) as Array<[keyof ColorSchemeColors, string | undefined]>).forEach(
    ([key, val]: [keyof ColorSchemeColors, string | undefined]) => {
      if (val !== undefined) {
        parsed[key] = val;
      }
    }
  );

  if (!Object.values(parsed).some(Boolean) && !name) return null;
  return { ...(name ? { name } : {}), colors: parsed };
};

export const parseColorSchemeFromText = (
  text: string
): { name?: string; colors: Partial<ColorSchemeColors> } | null => {
  const trimmed = text.trim();
  if (!trimmed) return null;

  try {
    const payload = JSON.parse(trimmed) as unknown;
    return parseColorSchemePayload(payload);
  } catch (error) {
    logClientError(error);
    return null;
  }
};

export const applySavedThemePreset = (
  current: ThemeSettings,
  saved: CmsTheme,
  presetValue: string
): ThemeSettings => {
  const next = { ...current, themePreset: presetValue };

  const colors = saved.colors;
  if (colors) {
    if (colors.primary) next.primaryColor = colors.primary;
    if (colors.secondary) next.secondaryColor = colors.secondary;
    if (colors.accent) next.accentColor = colors.accent;
    if (colors.background) next.backgroundColor = colors.background;
    if (colors.surface) next.surfaceColor = colors.surface;
    if (colors.text) next.textColor = colors.text;
    if (colors.muted) next.mutedTextColor = colors.muted;
  }

  const typography = saved.typography;
  if (typography) {
    if (typography.headingFont) next.headingFont = typography.headingFont;
    if (typography.bodyFont) next.bodyFont = typography.bodyFont;
    if (Number.isFinite(typography.baseSize)) next.baseSize = typography.baseSize;
    if (Number.isFinite(typography.headingWeight))
      next.headingWeight = String(typography.headingWeight);
    if (Number.isFinite(typography.bodyWeight)) next.bodyWeight = String(typography.bodyWeight);
  }

  const spacing = saved.spacing;
  if (spacing) {
    const sectionSpacing = parseCssNumber(spacing.sectionPadding);
    if (sectionSpacing !== null) next.sectionSpacing = sectionSpacing;
    const maxWidth = parseCssNumber(spacing.containerMaxWidth);
    if (maxWidth !== null) next.maxContentWidth = maxWidth;
  }

  if (typeof saved.customCss === 'string') {
    next.customCss = saved.customCss;
  }

  return next;
};

export function sanitizeRichText(value: string | null | undefined): string {
  if (!value) return '';
  if (typeof value !== 'string') return '';
  const temp = document.createElement('div');
  temp.innerHTML = value;
  return temp.innerHTML;
}

'use client';

import { Box, Trash2, GripVertical } from 'lucide-react';
import React, { useMemo, useState } from 'react';

import { useDragStateExtract } from '@/features/cms/hooks/useDragStateExtract';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import { readBlockDragData, setBlockDragData } from '@/features/cms/utils/page-builder-dnd';
import type { TreeContextMenuItem } from '@/shared/contracts/ui/menus';
import { TreeRow, TreeActionButton, TreeActionSlot, TreeContextMenu } from '@/shared/ui/data-display.public';
import { DRAG_KEYS, hasDragType } from '@/shared/utils/drag-drop';

import { BLOCK_ICONS, resolveBlockLabel } from './tree-constants';
import { useOptionalTreeColumnId } from './TreeColumnContext';
import { useOptionalTreeParentBlockId } from './TreeParentBlockContext';
import { useOptionalTreeRowId } from './TreeRowContext';
import { useTreeSectionId } from './TreeSectionContext';

import type { BlockNodeItemProps } from './tree-types';

export function BlockNodeItem(props: BlockNodeItemProps): React.ReactNode {
  const { block, index, disableDrag = false } = props;

  const sectionId = useTreeSectionId();
  const columnId = useOptionalTreeColumnId();
  const rowId = useOptionalTreeRowId();
  const resolvedParentBlockId = useOptionalTreeParentBlockId();
  const { state: pbState } = usePageBuilder();
  const { selectNode, blockActions } = useTreeActions();

  const selectedNodeId = pbState.selectedNodeId;

  // Drag state from context
  const drag = useDragStateExtract();
  const { startBlockDrag, endBlockDrag } = drag.actions;

  const draggedBlockId = drag.block.id;
  const draggedBlockType = drag.block.type;
  const draggedFromSectionId = drag.block.fromSectionId;
  const draggedFromColumnId = drag.block.fromColumnId;
  const draggedFromParentBlockId = drag.block.fromParentBlockId;

  const isSelected = selectedNodeId === block.id;
  const Icon = BLOCK_ICONS[block.type] ?? Box;
  const [isDragOver, setIsDragOver] = useState(false);
  const isDragging = draggedBlockId === block.id;
  const blockLabel = resolveBlockLabel(block, block.type);
  const canNestOnDrop = Array.isArray(block.blocks);

  const canDrag = !disableDrag;

  const blockMenuItems: TreeContextMenuItem[] = useMemo(
    () => [
      {
        id: 'remove-block',
        label: 'Remove block',
        icon: <Trash2 className='size-3.5' />,
        tone: 'danger',
        onSelect: (): void => {
          blockActions.remove(sectionId, block.id, columnId, resolvedParentBlockId);
        },
      },
    ],
    [blockActions, sectionId, block.id, columnId, resolvedParentBlockId]
  );

  return (
    <TreeContextMenu items={blockMenuItems}>
      <TreeRow
        tone='none'
        draggable={canDrag}
        onDragStart={(e: React.DragEvent) => {
          if (!canDrag) return;
          setBlockDragData(e.dataTransfer, {
            id: block.id,
            type: block.type,
            fromSectionId: sectionId,
            fromColumnId: columnId ?? '',
            fromParentBlockId: resolvedParentBlockId ?? '',
          });
          // Defer state updates to prevent re-render from cancelling drag
          setTimeout(() => {
            startBlockDrag({
              id: block.id,
              type: block.type,
              fromSectionId: sectionId,
              fromColumnId: columnId ?? null,
              fromParentBlockId: resolvedParentBlockId ?? null,
            });
          }, 0);
        }}
        onDragEnd={() => {
          if (!canDrag) return;
          endBlockDrag();
        }}
        onDragOver={(e: React.DragEvent) => {
          if (disableDrag) return;
          const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
          const blockDrag = readBlockDragData(e.dataTransfer, {
            id: draggedBlockId,
            ...(draggedBlockType !== undefined ? { type: draggedBlockType } : {}),
          });
          const dragId = blockDrag.id;
          if ((!dragId && !hasBlockPayload) || draggedBlockId === block.id || dragId === block.id)
            return;
          e.preventDefault();
          e.stopPropagation();
          setIsDragOver(true);
        }}
        onDragLeave={(e: React.DragEvent) => {
          if (disableDrag) return;
          if (e.currentTarget.contains(e.relatedTarget as Node)) return;
          setIsDragOver(false);
        }}
        onDrop={(e: React.DragEvent) => {
          if (disableDrag) return;
          e.preventDefault();
          e.stopPropagation();
          setIsDragOver(false);
          const blockDrag = readBlockDragData(e.dataTransfer, {
            id: draggedBlockId,
            ...(draggedBlockType !== undefined ? { type: draggedBlockType } : {}),
            fromSectionId: draggedFromSectionId,
            ...(draggedFromColumnId !== undefined ? { fromColumnId: draggedFromColumnId } : {}),
            ...(draggedFromParentBlockId !== undefined
              ? { fromParentBlockId: draggedFromParentBlockId }
              : {}),
          });
          const dragId = blockDrag.id;
          if (!dragId || dragId === block.id) return;
          const fromSection = blockDrag.fromSectionId ?? sectionId;
          const fromColumn = blockDrag.fromColumnId;
          const fromParent = blockDrag.fromParentBlockId;
          if (columnId) {
            blockActions.dropToColumn(
              dragId,
              fromSection,
              fromColumn || undefined,
              sectionId,
              columnId,
              canNestOnDrop ? (block.blocks ?? []).length : index,
              fromParent || undefined,
              canNestOnDrop ? block.id : resolvedParentBlockId
            );
            endBlockDrag();
            return;
          }
          if (!fromSection) return;
          if (rowId) {
            blockActions.dropToRow(
              dragId,
              fromSection,
              fromColumn || undefined,
              sectionId,
              rowId,
              canNestOnDrop ? (block.blocks ?? []).length : index,
              fromParent || undefined,
              canNestOnDrop ? block.id : undefined
            );
          } else {
            blockActions.dropToSection(
              dragId,
              fromSection,
              fromColumn || undefined,
              sectionId,
              canNestOnDrop ? (block.blocks ?? []).length : index,
              fromParent || undefined,
              canNestOnDrop ? block.id : undefined
            );
          }
          endBlockDrag();
        }}
        className={`group flex w-full items-center gap-1.5 rounded px-2 py-1.5 text-sm transition ${'cursor-pointer'} ${
          isDragOver
            ? 'bg-emerald-600/30 text-emerald-200 ring-1 ring-emerald-500/50'
            : isSelected
              ? 'bg-blue-600/80 text-white'
              : isDragging
                ? 'opacity-40 text-gray-400'
                : 'text-gray-400 hover:bg-muted/40 hover:text-gray-300'
        }`}
      >
        {canDrag ? (
          <div
            draggable
            onDragStart={(e: React.DragEvent) => {
              if (!canDrag) return;
              e.stopPropagation();
              setBlockDragData(e.dataTransfer, {
                id: block.id,
                type: block.type,
                fromSectionId: sectionId,
                fromColumnId: columnId ?? '',
                fromParentBlockId: resolvedParentBlockId ?? '',
              });
              // Defer state updates to prevent re-render from cancelling drag
              setTimeout(() => {
                startBlockDrag({
                  id: block.id,
                  type: block.type,
                  fromSectionId: sectionId,
                  fromColumnId: columnId ?? null,
                  fromParentBlockId: resolvedParentBlockId ?? null,
                });
              }, 0);
            }}
            onDragEnd={() => {
              if (!canDrag) return;
              endBlockDrag();
            }}
            onMouseDown={(e: React.MouseEvent) => e.stopPropagation()}
            className='flex items-center justify-center opacity-0 group-hover:opacity-100 group-focus-within:opacity-100'
            aria-hidden='true'
          >
            <GripVertical className='size-3 shrink-0 text-gray-600 cursor-grab active:cursor-grabbing' />
          </div>
        ) : (
          <span className='size-3 shrink-0' />
        )}
        <button
          type='button'
          onClick={() => selectNode(block.id)}
          aria-pressed={isSelected}
          aria-label={`Select block ${blockLabel}`}
          className='flex min-w-0 flex-1 items-center gap-1.5 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
        >
          <Icon className='size-3.5 shrink-0' />
          <span className='min-w-0 flex-1 truncate'>{blockLabel}</span>
        </button>
        {/* Delete button - visible on hover when selected or always visible on hover */}
        {!isDragOver && (
          <TreeActionSlot show='hover' align='end'>
            <TreeActionButton
              tone='danger'
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                blockActions.remove(sectionId, block.id, columnId, resolvedParentBlockId);
              }}
              title='Remove block'
            >
              <Trash2 className='size-3' />
            </TreeActionButton>
          </TreeActionSlot>
        )}
      </TreeRow>
    </TreeContextMenu>
  );
}

'use client';

import { Columns, Minus } from 'lucide-react';
import React, { useMemo, useState } from 'react';

import { useDragStateExtract } from '@/features/cms/hooks/useDragStateExtract';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import type { BlockInstance } from '@/features/cms/types/page-builder';
import { readBlockDragData, readSectionDragData } from '@/features/cms/utils/page-builder-dnd';
import type { TreeContextMenuItem } from '@/shared/contracts/ui/menus';
import { TreeRow, TreeCaret, TreeActionButton, TreeActionSlot, TreeContextMenu } from '@/shared/ui/data-display.public';
import { DRAG_KEYS, hasDragType } from '@/shared/utils/drag-drop';


import { ColumnBlockPicker } from '../ColumnBlockPicker';
import { BlockNodeItem } from './BlockNodeItem';
import { SectionBlockNodeItem } from './SectionBlockNodeItem';
import { SECTION_BLOCK_TYPES, CONVERTIBLE_SECTION_TYPES, resolveNodeLabel } from './tree-constants';
import { TreeColumnProvider } from './TreeColumnContext';
import { useOptionalTreeRowId } from './TreeRowContext';
import { useTreeSectionId } from './TreeSectionContext';

import type { ColumnNodeItemProps } from './tree-types';


export function ColumnNodeItem(props: ColumnNodeItemProps): React.ReactNode {
  const { column, columnIndex, rowColumnCount } = props;

  const sectionId = useTreeSectionId();
  const rowId = useOptionalTreeRowId();
  const { state: pbState } = usePageBuilder();
  const { expandedIds, selectNode, toggleExpand, blockActions, sectionActions, gridActions } =
    useTreeActions();

  const selectedNodeId = pbState.selectedNodeId;

  // Drag state from context
  const drag = useDragStateExtract();
  const { endBlockDrag, endSectionDrag } = drag.actions;

  const draggedBlockId = drag.block.id;
  const draggedBlockType = drag.block.type;
  const draggedFromSectionId = drag.block.fromSectionId;
  const draggedFromColumnId = drag.block.fromColumnId;
  const draggedFromParentBlockId = drag.block.fromParentBlockId;
  const draggedSectionId = drag.section.id;
  const draggedSectionType = drag.section.type;

  const isSelected = selectedNodeId === column.id;
  const isExpanded = expandedIds.has(column.id);
  const hasBlocks = (column.blocks ?? []).length > 0;
  const [isDragOver, setIsDragOver] = useState(false);
  const canRemove = rowColumnCount === undefined ? true : rowColumnCount > 1;
  const columnLabel = resolveNodeLabel(`Column ${columnIndex + 1}`, column.settings['label']);

  const columnMenuItems: TreeContextMenuItem[] = useMemo(
    () => [
      {
        id: 'remove-column',
        label: 'Remove column',
        icon: <Minus className='size-3.5' />,
        tone: 'danger',
        disabled: !canRemove,
        onSelect: (): void => {
          if (canRemove) gridActions.removeColumn(sectionId, column.id, rowId);
        },
      },
    ],
    [canRemove, gridActions, sectionId, column.id, rowId]
  );

  const handleColumnDragOver = (e: React.DragEvent): void => {
    const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
    const blockDrag = readBlockDragData(e.dataTransfer, {
      id: draggedBlockId,
      type: draggedBlockType,
    });
    const dragId = blockDrag.id;
    const isSectionDrop =
      draggedSectionId &&
      draggedSectionId !== sectionId &&
      CONVERTIBLE_SECTION_TYPES.includes(draggedSectionType ?? '');
    if (!dragId && !hasBlockPayload && !isSectionDrop) return;
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(true);
  };

  const handleColumnDrop = (e: React.DragEvent): void => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);

    // Check if this is a section drop (section drag sets "sectionId" in dataTransfer)
    const sectionDrag = readSectionDragData(e.dataTransfer, {
      id: draggedSectionId,
      type: draggedSectionType,
    });
    const draggedSectionIdFromTransfer = sectionDrag.id;
    const draggedSectionTypeFromTransfer = sectionDrag.type;
    const isSectionDrag = Boolean(draggedSectionIdFromTransfer) || Boolean(draggedSectionId);

    if (isSectionDrag) {
      const sectionIdToDrop = draggedSectionId || draggedSectionIdFromTransfer;
      const sectionTypeToDrop = draggedSectionType || draggedSectionTypeFromTransfer;
      if (
        sectionIdToDrop &&
        sectionIdToDrop !== sectionId &&
        CONVERTIBLE_SECTION_TYPES.includes(sectionTypeToDrop ?? '')
      ) {
        sectionActions.dropToColumn(
          sectionIdToDrop,
          sectionId,
          column.id,
          (column.blocks ?? []).length
        );
        endSectionDrag();
      }
      return;
    }

    // Otherwise it's a block drop
    const blockDrag = readBlockDragData(e.dataTransfer, {
      id: draggedBlockId,
      type: draggedBlockType,
      fromSectionId: draggedFromSectionId,
      fromColumnId: draggedFromColumnId,
      fromParentBlockId: draggedFromParentBlockId,
    });
    const dragId = blockDrag.id;
    const fromSection = blockDrag.fromSectionId ?? sectionId;
    const fromColumn = blockDrag.fromColumnId;
    const fromParent = blockDrag.fromParentBlockId;
    if (dragId) {
      blockActions.dropToColumn(
        dragId,
        fromSection,
        fromColumn || undefined,
        sectionId,
        column.id,
        (column.blocks ?? []).length,
        fromParent || undefined
      );
      endBlockDrag();
    }
  };

  return (
    <TreeColumnProvider columnId={column.id}>
      <div
        draggable={false}
        onDragStart={(e: React.DragEvent) => {
          e.preventDefault();
          e.stopPropagation();
        }}
        onDragOver={handleColumnDragOver}
        onDragLeave={(e: React.DragEvent) => {
          if (e.currentTarget.contains(e.relatedTarget as Node)) return;
          setIsDragOver(false);
        }}
        onDrop={handleColumnDrop}
        className={`${isDragOver ? 'rounded ring-1 ring-emerald-500/30' : ''}`}
      >
        <TreeContextMenu items={columnMenuItems}>
          <TreeRow
            tone='none'
            onDragOver={handleColumnDragOver}
            onDragLeave={(e: React.DragEvent) => {
              if (e.currentTarget.contains(e.relatedTarget as Node)) return;
              setIsDragOver(false);
            }}
            onDrop={handleColumnDrop}
            className={`flex w-full items-center gap-1.5 rounded px-2 py-1.5 text-sm font-medium transition ${
              isDragOver
                ? 'bg-emerald-600/30 text-emerald-200 ring-1 ring-emerald-500/50'
                : isSelected
                  ? 'bg-blue-600/80 text-white'
                  : 'text-gray-200 hover:bg-muted/50'
            }`}
          >
            <TreeCaret
              isOpen={isExpanded}
              hasChildren={true}
              ariaLabel={isExpanded ? 'Collapse column' : 'Expand column'}
              onToggle={(): void => toggleExpand(column.id)}
              iconClassName='size-3'
              placeholderClassName='block size-3 shrink-0'
            />
            <button
              type='button'
              onClick={(e: React.MouseEvent<HTMLButtonElement>) => {
                e.stopPropagation();
                selectNode(column.id);
              }}
              aria-pressed={isSelected}
              aria-label={`Select ${columnLabel}`}
              className='flex min-w-0 flex-1 items-center gap-1.5 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
            >
              <Columns className='size-3.5 shrink-0' />
              <span className='min-w-0 flex-1 truncate text-left'>{columnLabel}</span>
            </button>
            <TreeActionSlot show='always' align='inline'>
              <TreeActionButton
                tone='danger'
                onClick={(e: React.MouseEvent) => {
                  e.stopPropagation();
                  if (!canRemove) return;
                  gridActions.removeColumn(sectionId, column.id, rowId);
                }}
                disabled={!canRemove}
                className='disabled:cursor-not-allowed disabled:opacity-40'
                title={canRemove ? 'Remove column' : 'At least one column is required'}
              >
                <Minus className='size-3' />
              </TreeActionButton>
              <ColumnBlockPicker
                onSelect={(blockType: string) =>
                  blockActions.addToColumn(sectionId, column.id, blockType)
                }
              />
            </TreeActionSlot>
          </TreeRow>
        </TreeContextMenu>

        {isExpanded && (
          <div
            className='ml-4 border-l border-border/30 pl-1'
            onDragOver={handleColumnDragOver}
            onDragLeave={(e: React.DragEvent) => {
              if (e.currentTarget.contains(e.relatedTarget as Node)) return;
              setIsDragOver(false);
            }}
            onDrop={handleColumnDrop}
          >
            {hasBlocks ? (
              (column.blocks ?? []).map((block: BlockInstance, index: number) =>
                SECTION_BLOCK_TYPES.includes(block.type) ? (
                  <SectionBlockNodeItem key={block.id} block={block} index={index} />
                ) : (
                  <BlockNodeItem key={block.id} block={block} index={index} />
                )
              )
            ) : (
              <div
                onDragOver={handleColumnDragOver}
                onDragLeave={(e: React.DragEvent) => {
                  if (e.currentTarget.contains(e.relatedTarget as Node)) return;
                  setIsDragOver(false);
                }}
                onDrop={handleColumnDrop}
                className={`mt-1 flex min-h-[36px] items-center gap-2 rounded border border-dashed px-2 py-1 text-[11px] transition ${
                  isDragOver
                    ? 'border-emerald-500/70 bg-emerald-500/10 text-emerald-200'
                    : 'border-border/30 text-gray-500'
                }`}
              >
                Drop blocks here
              </div>
            )}
          </div>
        )}
      </div>
    </TreeColumnProvider>
  );
}

'use client';

import React from 'react';

import type { FolderTreeViewportRenderNodeInput as ComponentTreeNodeRendererProps } from '@/shared/lib/foldertree/public';
import { Button } from '@/shared/ui/primitives.public';

import { useComponentTreeNodeRuntimeContext } from './ComponentTreeNodeRuntimeContext';
import { SectionDropTarget } from './SectionDropTarget';
import { SectionNodeItem } from './SectionNodeItem';
import { ZoneFooterNode } from './ZoneFooterNode';
import {
  CMS_ZONE_LABELS,
  fromCmsSectionNodeId,
  fromCmsZoneFooterNodeId,
  fromCmsZoneNodeId,
} from '../utils/cms-master-tree';

export type { ComponentTreeNodeRendererProps };

export function ComponentTreeNodeRenderer(
  props: ComponentTreeNodeRendererProps
): React.JSX.Element | null {
  const { node, depth, hasChildren, isExpanded, toggleExpand } = props;

  const { rootSectionsByZone, sectionById, sectionIndexById } =
    useComponentTreeNodeRuntimeContext();

  const zoneFromNode = fromCmsZoneNodeId(node.id);
  if (zoneFromNode) {
    const zoneSections = rootSectionsByZone[zoneFromNode];
    return (
      <div className='border-b border-border/50 px-4 py-2.5'>
        <Button
          variant='ghost'
          size='sm'
          onClick={toggleExpand}
          className='flex h-auto w-full items-center justify-start gap-1.5 p-0 text-xs font-semibold uppercase tracking-wider text-gray-400 transition hover:bg-transparent hover:text-gray-300 font-bold'
        >
          <span className='inline-block w-3.5 text-center'>{isExpanded ? '▾' : '▸'}</span>
          <span>{CMS_ZONE_LABELS[zoneFromNode]}</span>
          {zoneSections.length > 0 ? (
            <span className='ml-1 text-[10px] text-gray-500'>({zoneSections.length})</span>
          ) : null}
        </Button>
      </div>
    );
  }

  const sectionId = fromCmsSectionNodeId(node.id);
  if (sectionId) {
    const section = sectionById.get(sectionId);
    if (!section) return null;
    const sectionIndex = sectionIndexById.get(sectionId) ?? 0;
    const nestedOffset = Math.max(0, depth - 1) * 16;
    return (
      <div
        className='px-2'
        style={{ marginLeft: `${nestedOffset}px` }}
        data-cms-tree-depth={String(Math.max(0, depth - 1))}
      >
        <SectionDropTarget
          zone={section.zone}
          toParentSectionId={section.parentSectionId ?? null}
          toIndex={sectionIndex}
        />
        <SectionNodeItem
          section={section}
          sectionIndex={sectionIndex}
          hasTreeChildren={hasChildren}
          isTreeExpanded={isExpanded}
          toggleTreeExpand={toggleExpand}
        />
      </div>
    );
  }

  const zoneFromFooter = fromCmsZoneFooterNodeId(node.id);
  if (!zoneFromFooter) return null;
  return (
    <div className='px-2 pb-2'>
      <ZoneFooterNode
        zone={zoneFromFooter}
        sectionCount={rootSectionsByZone[zoneFromFooter].length}
      />
    </div>
  );
}

'use client';

import { Columns, Trash2, Plus, GripVertical } from 'lucide-react';
import React, { useMemo, useState } from 'react';

import { useDragStateExtract } from '@/features/cms/hooks/useDragStateExtract';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import type { BlockInstance } from '@/features/cms/types/page-builder';
import { readBlockDragData, readSectionDragData } from '@/features/cms/utils/page-builder-dnd';
import type { TreeContextMenuItem } from '@/shared/contracts/ui/menus';
import { TreeRow, TreeCaret, TreeActionButton, TreeActionSlot, TreeContextMenu } from '@/shared/ui/data-display.public';
import { DRAG_KEYS, hasDragType } from '@/shared/utils/drag-drop';

import { BlockNodeItem } from './BlockNodeItem';
import { ColumnNodeItem } from './ColumnNodeItem';
import { CONVERTIBLE_SECTION_TYPES, resolveNodeLabel } from './tree-constants';
import { TreeParentBlockProvider } from './TreeParentBlockContext';
import { TreeRowProvider } from './TreeRowContext';
import { useTreeSectionId } from './TreeSectionContext';

import type { RowNodeItemProps } from './tree-types';


export function RowNodeItem(props: RowNodeItemProps): React.ReactNode {
  const { row, rowIndex, rowCount } = props;

  const sectionId = useTreeSectionId();
  const { state: pbState } = usePageBuilder();
  const { expandedIds, selectNode, toggleExpand, blockActions, sectionActions, gridActions } =
    useTreeActions();

  const selectedNodeId = pbState.selectedNodeId;

  // Drag state from context
  const drag = useDragStateExtract();
  const { endBlockDrag, endSectionDrag } = drag.actions;

  const draggedBlockId = drag.block.id;
  const draggedBlockType = drag.block.type;
  const draggedFromSectionId = drag.block.fromSectionId;
  const draggedFromColumnId = drag.block.fromColumnId;
  const draggedFromParentBlockId = drag.block.fromParentBlockId;
  const draggedSectionId = drag.section.id;
  const draggedSectionType = drag.section.type;

  const isSelected = selectedNodeId === row.id;
  const isExpanded = expandedIds.has(row.id);
  const columns = (row.blocks ?? []).filter((b: BlockInstance) => b.type === 'Column');
  const canRemoveRow = rowCount > 1;
  const [isDragOver, setIsDragOver] = useState(false);
  const firstColumn = columns[0] ?? null;
  const rowLabel = resolveNodeLabel(`Row ${rowIndex + 1}`, row.settings['label']);

  const rowMenuItems: TreeContextMenuItem[] = useMemo(
    () => [
      {
        id: 'add-column',
        label: 'Add column',
        icon: <Columns className='size-3.5' />,
        onSelect: () => gridActions.addColumn(sectionId, row.id),
      },
      { id: 'separator-1', separator: true },
      {
        id: 'remove-row',
        label: 'Remove row',
        icon: <Trash2 className='size-3.5' />,
        tone: 'danger',
        disabled: !canRemoveRow,
        onSelect: (): void => {
          if (canRemoveRow) gridActions.removeRow(sectionId, row.id);
        },
      },
    ],
    [canRemoveRow, gridActions, row.id, sectionId]
  );

  return (
    <div>
      <TreeContextMenu items={rowMenuItems}>
        <TreeRow
          tone='none'
          onDragOver={(e: React.DragEvent) => {
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
            });
            const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
            const dragId = blockDrag.id;
            // Allow section drops (for convertible sections like ImageElement, TextElement, etc.)
            const isSectionDrop =
              draggedSectionId &&
              draggedSectionId !== sectionId &&
              CONVERTIBLE_SECTION_TYPES.includes(draggedSectionType ?? '');
            // Allow drops if we have a block or convertible section being dragged
            if (!dragId && !hasBlockPayload && !isSectionDrop) return;
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(true);
          }}
          onDragLeave={(e: React.DragEvent) => {
            if (e.currentTarget.contains(e.relatedTarget as Node)) return;
            setIsDragOver(false);
          }}
          onDrop={(e: React.DragEvent) => {
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(false);

            // Check if this is a section drop (section drag sets "sectionId" in dataTransfer)
            const sectionDrag = readSectionDragData(e.dataTransfer, {
              id: draggedSectionId,
              type: draggedSectionType,
            });
            const draggedSectionIdFromTransfer = sectionDrag.id;
            const draggedSectionTypeFromTransfer = sectionDrag.type;
            const isSectionDrag =
              Boolean(draggedSectionIdFromTransfer) || Boolean(draggedSectionId);

            if (isSectionDrag) {
              const sectionIdToDrop = draggedSectionId || draggedSectionIdFromTransfer;
              const sectionTypeToDrop = draggedSectionType || draggedSectionTypeFromTransfer;
              if (
                sectionIdToDrop &&
                sectionIdToDrop !== sectionId &&
                CONVERTIBLE_SECTION_TYPES.includes(sectionTypeToDrop ?? '')
              ) {
                // Route to first column if available
                if (firstColumn) {
                  sectionActions.dropToColumn(
                    sectionIdToDrop,
                    sectionId,
                    firstColumn.id,
                    (firstColumn.blocks ?? []).length
                  );
                }
                endSectionDrag();
              }
              return;
            }

            // Otherwise it's a block drop
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
              fromSectionId: draggedFromSectionId,
              fromColumnId: draggedFromColumnId,
              fromParentBlockId: draggedFromParentBlockId,
            });
            const dragId = blockDrag.id;
            if (!dragId) return;

            const fromSection = blockDrag.fromSectionId ?? sectionId;
            const fromColumn = blockDrag.fromColumnId;
            const fromParent = blockDrag.fromParentBlockId;
            if (!fromSection) return;

            // Get the block type being dragged
            const blockType = blockDrag.type ?? '';

            // If it's a Column type, route to first column (existing behavior)
            if (blockType === 'Column' && firstColumn) {
              blockActions.dropToColumn(
                dragId,
                fromSection,
                fromColumn || undefined,
                sectionId,
                firstColumn.id,
                (firstColumn.blocks ?? []).length,
                fromParent || undefined
              );
            } else {
              // For all other block types, drop directly into the Row
              const rowChildren = row.blocks ?? [];
              blockActions.dropToRow(
                dragId,
                fromSection,
                fromColumn || undefined,
                sectionId,
                row.id,
                rowChildren.length,
                fromParent || undefined
              );
            }

            endBlockDrag();
          }}
          className={`flex w-full items-center gap-1.5 rounded px-2 py-1.5 text-sm font-medium transition ${
            isDragOver
              ? 'bg-emerald-600/30 text-emerald-200 ring-1 ring-emerald-500/50'
              : isSelected
                ? 'bg-blue-600/80 text-white'
                : 'text-gray-300 hover:bg-muted/40'
          }`}
        >
          <GripVertical className='size-3.5 shrink-0' />
          <TreeCaret
            isOpen={isExpanded}
            hasChildren={true}
            ariaLabel={isExpanded ? 'Collapse row' : 'Expand row'}
            onToggle={(): void => toggleExpand(row.id)}
            iconClassName='size-3'
            placeholderClassName='block size-3 shrink-0'
          />
          <button
            type='button'
            onClick={(e: React.MouseEvent<HTMLButtonElement>) => {
              e.stopPropagation();
              selectNode(row.id);
            }}
            aria-pressed={isSelected}
            aria-label={`Select ${rowLabel}`}
            className='flex min-w-0 flex-1 items-center rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
          >
            <span className='min-w-0 flex-1 truncate text-left'>{rowLabel}</span>
          </button>
          <TreeActionSlot show='always' align='inline'>
            <TreeActionButton
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                gridActions.addColumn(sectionId, row.id);
              }}
              title='Add column'
            >
              <Plus className='size-3' />
            </TreeActionButton>
            <TreeActionButton
              tone='danger'
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                if (!canRemoveRow) return;
                gridActions.removeRow(sectionId, row.id);
              }}
              disabled={!canRemoveRow}
              className='disabled:cursor-not-allowed disabled:opacity-40'
              title={canRemoveRow ? 'Remove row' : 'At least one row is required'}
            >
              <Trash2 className='size-3' />
            </TreeActionButton>
          </TreeActionSlot>
        </TreeRow>
      </TreeContextMenu>

      {isExpanded && (row.blocks ?? []).length > 0 && (
        <div className='ml-4 border-l border-border/30 pl-1'>
          {/* Render all row children - both Columns and direct elements */}
          {(row.blocks ?? []).map((child: BlockInstance, childIndex: number) => {
            if (child.type === 'Column') {
              return (
                <TreeRowProvider key={child.id} rowId={row.id}>
                  <ColumnNodeItem
                    column={child}
                    columnIndex={childIndex}
                    rowColumnCount={columns.length}
                  />
                </TreeRowProvider>
              );
            }
            // Render direct element children (non-Column blocks in the Row)
            return (
              <TreeRowProvider key={child.id} rowId={row.id}>
                <TreeParentBlockProvider parentBlockId={row.id}>
                  <BlockNodeItem block={child} index={childIndex} />
                </TreeParentBlockProvider>
              </TreeRowProvider>
            );
          })}
        </div>
      )}
    </div>
  );
}

