import { BlockNodeItem } from './BlockNodeItem';
import { useTreeColumnId } from './TreeColumnContext';
import { TreeParentBlockProvider } from './TreeParentBlockContext';
import { useTreeSectionId } from './TreeSectionContext';

import type { SectionBlockNodeItemProps } from './tree-types';


export function SectionBlockNodeItem(props: SectionBlockNodeItemProps): React.ReactNode {
  const { block, index } = props;

  const sectionId = useTreeSectionId();
  const columnId = useTreeColumnId();
  const { state: pbState } = usePageBuilder();
  const { expandedIds, selectNode, toggleExpand, blockActions, sectionActions } = useTreeActions();

  const selectedNodeId = pbState.selectedNodeId;

  // Drag state from context
  const drag = useDragStateExtract();
  const { startBlockDrag, endBlockDrag, endSectionDrag } = drag.actions;

  const draggedBlockId = drag.block.id;
  const draggedBlockType = drag.block.type;
  const draggedFromSectionId = drag.block.fromSectionId;
  const draggedFromColumnId = drag.block.fromColumnId;
  const draggedFromParentBlockId = drag.block.fromParentBlockId;
  const draggedSectionId = drag.section.id;
  const draggedSectionType = drag.section.type;

  const isSelected = selectedNodeId === block.id;
  const isExpanded = expandedIds.has(block.id);
  const hasChildren = (block.blocks ?? []).length > 0;
  const Icon: LucideIcon = BLOCK_ICONS[block.type] ?? Box;
  const [isDragOver, setIsDragOver] = useState(false);
  const isDragging = draggedBlockId === block.id;
  const isTextAtom = block.type === 'TextAtom';
  const blockLabel = resolveBlockLabel(block, block.type);

  const sectionBlockMenuItems: TreeContextMenuItem[] = useMemo(
    () => [
      {
        id: 'remove-block',
        label: 'Remove block',
        icon: <Trash2 className='size-3.5' />,
        tone: 'danger',
        onSelect: (): void => {
          blockActions.remove(sectionId, block.id, columnId);
        },
      },
    ],
    [blockActions, sectionId, block.id, columnId]
  );

  return (
    <div className='group/sblock'>
      <TreeContextMenu items={sectionBlockMenuItems}>
        <TreeRow
          tone='none'
          draggable
          onDragStart={(e: React.DragEvent) => {
            setBlockDragData(e.dataTransfer, {
              id: block.id,
              type: block.type,
              fromSectionId: sectionId,
              fromColumnId: columnId ?? '',
              fromParentBlockId: '',
            });
            // Defer state updates to prevent re-render from cancelling drag
            setTimeout(() => {
              startBlockDrag({
                id: block.id,
                type: block.type,
                fromSectionId: sectionId,
                fromColumnId: columnId,
                fromParentBlockId: null,
              });
            }, 0);
          }}
          onDragEnd={() => {
            endBlockDrag();
          }}
          onDragOver={(e: React.DragEvent) => {
            const isSectionDrop =
              draggedSectionId &&
              draggedSectionId !== sectionId &&
              CONVERTIBLE_SECTION_TYPES.includes(draggedSectionType ?? '');
            const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
            const isBlockDrop = (draggedBlockId && draggedBlockId !== block.id) || hasBlockPayload;
            if (isTextAtom) {
              if (!isBlockDrop) return;
            } else if (!isBlockDrop && !isSectionDrop) {
              return;
            }
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(true);
          }}
          onDragLeave={(e: React.DragEvent) => {
            if (e.currentTarget.contains(e.relatedTarget as Node)) return;
            setIsDragOver(false);
          }}
          onDrop={(e: React.DragEvent) => {
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(false);
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
              fromSectionId: draggedFromSectionId,
              fromColumnId: draggedFromColumnId,
              fromParentBlockId: draggedFromParentBlockId,
            });
            const dragId = blockDrag.id;
            const fromSection = blockDrag.fromSectionId ?? sectionId;
            const fromColumn = blockDrag.fromColumnId;
            const fromParent = blockDrag.fromParentBlockId;
            if (isTextAtom) {
              if (!dragId || dragId === block.id) return;
              const draggedType = blockDrag.type ?? '';
              const shouldNest = draggedType === 'TextAtomLetter';
              blockActions.dropToColumn(
                dragId,
                fromSection,
                fromColumn || undefined,
                sectionId,
                columnId,
                shouldNest ? (block.blocks ?? []).length : index,
                fromParent || undefined,
                shouldNest ? block.id : undefined
              );
              endBlockDrag();
              return;
            }
            if (dragId && dragId !== block.id) {
              blockActions.dropToColumn(
                dragId,
                fromSection,
                fromColumn || undefined,
                sectionId,
                columnId,
                (block.blocks ?? []).length,
                fromParent || undefined,
                block.id
              );
              endBlockDrag();
            } else if (draggedSectionId && draggedSectionId !== sectionId) {
              sectionActions.dropToColumn(
                draggedSectionId,
                sectionId,
                columnId,
                (block.blocks ?? []).length,
                block.id
              );
              endSectionDrag();
            }
          }}
          className={`flex w-full cursor-pointer items-center gap-1.5 rounded px-2 py-1.5 text-sm font-medium transition ${
            isDragOver
              ? 'bg-emerald-600/30 text-emerald-200 ring-1 ring-emerald-500/50'
              : isSelected
                ? 'bg-blue-600/80 text-white'
                : isDragging
                  ? 'opacity-40 text-gray-400'
                  : 'text-gray-300 hover:bg-muted/40'
          }`}
        >
          <div
            draggable
            onDragStart={(e: React.DragEvent) => {
              e.stopPropagation();
              setBlockDragData(e.dataTransfer, {
                id: block.id,
                type: block.type,
                fromSectionId: sectionId,
                fromColumnId: columnId ?? '',
                fromParentBlockId: '',
              });
              // Defer state updates to prevent re-render from cancelling drag
              setTimeout(() => {
                startBlockDrag({
                  id: block.id,
                  type: block.type,
                  fromSectionId: sectionId,
                  fromColumnId: columnId,
                  fromParentBlockId: null,
                });
              }, 0);
            }}
            onDragEnd={() => {
              endBlockDrag();
            }}
            onMouseDown={(e: React.MouseEvent) => e.stopPropagation()}
            className='flex items-center justify-center opacity-0 group-hover/sblock:opacity-100 group-focus-within/sblock:opacity-100'
            aria-hidden='true'
          >
            <GripVertical className='size-3 shrink-0 text-gray-600 cursor-grab active:cursor-grabbing' />
          </div>
          <TreeCaret
            isOpen={isExpanded}
            hasChildren={true}
            ariaLabel={isExpanded ? 'Collapse block' : 'Expand block'}
            onToggle={(): void => toggleExpand(block.id)}
            iconClassName='size-3'
            placeholderClassName='block size-3 shrink-0'
          />
          <button
            type='button'
            onClick={() => selectNode(block.id)}
            aria-pressed={isSelected}
            aria-label={`Select block ${blockLabel}`}
            className='flex min-w-0 flex-1 items-center gap-1.5 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
          >
            <Icon className='size-3.5 shrink-0' />
            <span className='min-w-0 flex-1 truncate text-left'>{blockLabel}</span>
          </button>
          {!isTextAtom && (
            <TreeActionSlot show='always' align='inline'>
              <ColumnBlockPicker
                onSelect={(elemType: string) =>
                  blockActions.addElementToNestedBlock(sectionId, columnId, block.id, elemType)
                }
              />
            </TreeActionSlot>
          )}
          {/* Delete button for section-type blocks */}
          {!isDragOver && (
            <TreeActionSlot show='hover' align='inline'>
              <TreeActionButton
                tone='danger'
                onClick={(e: React.MouseEvent) => {
                  e.stopPropagation();
                  blockActions.remove(sectionId, block.id, columnId);
                }}
                title='Remove block'
              >
                <Trash2 className='size-3' />
              </TreeActionButton>
            </TreeActionSlot>
          )}
        </TreeRow>
      </TreeContextMenu>

      {isExpanded && hasChildren && (
        <div className='ml-5 border-l border-border/30 pl-1'>
          {(block.blocks ?? []).map((child: BlockInstance, childIndex: number) => (
            <TreeParentBlockProvider key={child.id} parentBlockId={block.id}>
              <BlockNodeItem block={child} index={childIndex} />
            </TreeParentBlockProvider>
          ))}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState } from 'react';

import { isCmsSectionSamePositionDrop } from '@/features/cms/components/page-builder/utils/cms-tree-external-drop';
import { useDragState } from '@/features/cms/hooks/useDragStateContext';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import { readSectionDragData } from '@/features/cms/utils/page-builder-dnd';
import type { PageZone } from '@/shared/contracts/cms';

import {
  useComponentTreePanelActions,
  useComponentTreePanelState,
} from './ComponentTreePanelContext';

const PROMOTABLE_BLOCK_TYPES = [
  'ImageElement',
  'TextElement',
  'ButtonElement',
  'Block',
  'TextAtom',
  'Model3DElement',
  'Slideshow',
];

interface SectionDropTargetProps {
  zone: PageZone;
  toParentSectionId?: string | null;
  toIndex: number;
}

export function SectionDropTarget({
  zone,
  toParentSectionId = null,
  toIndex,
}: SectionDropTargetProps): React.ReactNode {
  const {
    showExtractPlaceholder,
    showSectionDropPlaceholder,
    canDropSectionsAtRoot,
    canDropBlocksAtRoot,
    treePlaceholderClasses,
    draggedMasterSectionId,
  } = useComponentTreePanelState();
  const { moveSectionByMaster } = useComponentTreePanelActions();
  const [isOver, setIsOver] = useState(false);
  const { state: pbState } = usePageBuilder();
  const { state: dragState, endBlockDrag, endSectionDrag } = useDragState();
  const { sectionActions } = useTreeActions();

  const draggedBlockId = dragState.block.id;
  const draggedBlockType = dragState.block.type;
  const draggedFromSectionId = dragState.block.fromSectionId;
  const draggedFromColumnId = dragState.block.fromColumnId;
  const draggedFromParentBlockId = dragState.block.fromParentBlockId;
  const draggedSectionId = dragState.section.id ?? draggedMasterSectionId;
  const draggedSectionZone = dragState.section.zone;
  const draggedSectionIndex = dragState.section.index;
  const draggedSection = pbState.sections.find((section) => section.id === draggedSectionId);
  const draggedSectionParentId = draggedSection?.parentSectionId ?? null;
  const draggedSectionResolvedZone = draggedSectionZone ?? draggedSection?.zone ?? null;
  const draggedSectionResolvedIndex = React.useMemo((): number | null => {
    if (draggedSectionIndex !== null) return draggedSectionIndex;
    if (!draggedSectionId || !draggedSection) return null;
    const siblingSections = pbState.sections.filter(
      (section) =>
        section.zone === draggedSection.zone &&
        (section.parentSectionId ?? null) === draggedSectionParentId
    );
    const siblingIndex = siblingSections.findIndex((section) => section.id === draggedSectionId);
    return siblingIndex >= 0 ? siblingIndex : null;
  }, [
    draggedSection,
    draggedSectionId,
    draggedSectionIndex,
    draggedSectionParentId,
    pbState.sections,
  ]);

  const isDraggingBlock = Boolean(draggedBlockId);
  const isDraggingSection =
    showSectionDropPlaceholder && canDropSectionsAtRoot && Boolean(draggedSectionId);
  const canPromoteBlock =
    showExtractPlaceholder &&
    canDropBlocksAtRoot &&
    isDraggingBlock &&
    PROMOTABLE_BLOCK_TYPES.includes(draggedBlockType ?? '');
  const isDragging = isDraggingSection || canPromoteBlock;
  const isSameSectionPositionTarget =
    isDraggingSection &&
    draggedSectionParentId === toParentSectionId &&
    isCmsSectionSamePositionDrop({
      draggedZone: draggedSectionResolvedZone,
      draggedIndex: draggedSectionResolvedIndex,
      targetZone: zone,
      targetIndex: toIndex,
    });
  const shouldRenderSectionTarget = isDraggingSection && !isSameSectionPositionTarget;
  const shouldRenderTarget = canPromoteBlock || shouldRenderSectionTarget;

  if (!isDragging || !shouldRenderTarget) return null;

  return (
    <div
      data-cms-section-drop-target='sibling'
      data-cms-section-drop-zone={zone}
      data-cms-section-drop-parent={toParentSectionId ?? 'root'}
      data-cms-section-drop-index={String(toIndex)}
      onDragOver={(event: React.DragEvent<HTMLDivElement>): void => {
        if (shouldRenderSectionTarget) {
          const sectionDrag = readSectionDragData(event.dataTransfer, {
            id: draggedSectionId,
            zone: draggedSectionZone,
            index: draggedSectionIndex,
          });
          const dragSectionId = sectionDrag.id;
          if (!dragSectionId) return;
          const dragZone = sectionDrag.zone ?? null;
          const dragIndex = sectionDrag.index;
          const isSamePosition =
            draggedSectionParentId === toParentSectionId &&
            isCmsSectionSamePositionDrop({
              draggedZone: dragZone,
              draggedIndex: dragIndex,
              targetZone: zone,
              targetIndex: toIndex,
            });
          if (isSamePosition) return;
        }
        event.preventDefault();
        event.stopPropagation();
        setIsOver(true);
      }}
      onDragLeave={(event: React.DragEvent<HTMLDivElement>): void => {
        if (event.currentTarget.contains(event.relatedTarget as Node)) return;
        setIsOver(false);
      }}
      onDrop={(event: React.DragEvent<HTMLDivElement>): void => {
        event.preventDefault();
        event.stopPropagation();
        setIsOver(false);

        if (shouldRenderSectionTarget) {
          const sectionDrag = readSectionDragData(event.dataTransfer, {
            id: draggedSectionId,
            zone: draggedSectionZone,
            index: draggedSectionIndex,
          });
          const dragSectionId = sectionDrag.id;
          if (!dragSectionId) return;
          const dragZone = sectionDrag.zone ?? null;
          const dragIndex = sectionDrag.index;
          const isSamePosition =
            draggedSectionParentId === toParentSectionId &&
            isCmsSectionSamePositionDrop({
              draggedZone: dragZone,
              draggedIndex: dragIndex,
              targetZone: zone,
              targetIndex: toIndex,
            });
          if (isSamePosition) return;
          void moveSectionByMaster(dragSectionId, zone, toIndex, toParentSectionId).finally(() => {
            endSectionDrag();
          });
          return;
        }

        if (canPromoteBlock && draggedBlockId && draggedFromSectionId) {
          sectionActions.promoteBlockToSection(
            draggedBlockId,
            draggedFromSectionId,
            draggedFromColumnId ?? undefined,
            draggedFromParentBlockId ?? undefined,
            zone,
            toIndex
          );
          endBlockDrag();
        }
      }}
      className={`relative z-10 overflow-hidden transition-[height] ${isDragging ? 'h-8' : 'h-0'}`}
    >
      <div
        className={`absolute inset-x-1 top-1/2 flex -translate-y-1/2 items-center justify-center rounded border-2 border-dashed transition ${
          isOver
            ? canPromoteBlock
              ? 'border-emerald-500 bg-emerald-600/40 h-6'
              : `${treePlaceholderClasses.rootActive} h-4`
            : canPromoteBlock
              ? 'border-emerald-500/50 bg-emerald-600/20 h-5'
              : `${treePlaceholderClasses.rootIdle} h-3`
        }`}
      >
        {canPromoteBlock ? (
          <span
            className={`text-[9px] font-medium ${isOver ? 'text-emerald-200' : 'text-emerald-400'}`}
          >
            {isOver ? 'Release to extract' : 'Drop here to extract'}
          </span>
        ) : null}
      </div>
    </div>
  );
}

'use client';

import { Box, Eye, EyeOff, Trash2, Plus, GripVertical, type LucideIcon } from 'lucide-react';
import React from 'react';

import { isDescendant } from '@/features/cms/hooks/page-builder/section-hierarchy';
import { useDragStateExtract } from '@/features/cms/hooks/useDragStateExtract';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import { readSectionDragData, setSectionDragData } from '@/features/cms/utils/page-builder-dnd';
import { isCmsSectionHidden } from '@/features/cms/utils/page-builder-normalization';
import { setMasterTreeDragNodeData } from '@/shared/lib/foldertree/public';
import { Button, Badge } from '@/shared/ui/primitives.public';
import { TreeCaret } from '@/shared/ui/data-display.public';
import { cn } from '@/shared/utils/ui-utils';


import { BlockNodeItem } from './BlockNodeItem';
import {
  useComponentTreePanelActions,
  useComponentTreePanelState,
} from './ComponentTreePanelContext';
import { RowNodeItem } from './RowNodeItem';
import { SectionBlockNodeItem } from './SectionBlockNodeItem';
import { SlideshowFrameNodeItem } from './SlideshowFrameNodeItem';
import { TreeSectionProvider } from './TreeSectionContext';
import { renderTreeSectionPicker } from './TreeSectionPicker';
import { toCmsSectionNodeId } from '../utils/cms-master-tree';


import type { SectionNodeItemProps } from './tree-types';

export function SectionNodeItem(props: SectionNodeItemProps): React.JSX.Element {
  const {
    section,
    sectionIndex,
    hasTreeChildren = false,
    isTreeExpanded = false,
    toggleTreeExpand,
  } = props;

  const { draggedMasterSectionId } = useComponentTreePanelState();
  const { startSectionMasterDrag, endSectionMasterDrag, moveSectionByMaster } =
    useComponentTreePanelActions();
  const { state: pbState } = usePageBuilder();
  const allSections = pbState.sections ?? [];
  const [isInsideDropOver, setIsInsideDropOver] = React.useState(false);
  const drag = useDragStateExtract();
  const { startSectionDrag, endSectionDrag } = drag.actions;
  const { expandedIds, sectionActions, blockActions, selectNode, toggleExpand } = useTreeActions();

  const isExpanded = expandedIds.has(section.id);
  const isRowExpanded = isExpanded || isTreeExpanded;
  const isSelected = pbState.selectedNodeId === section.id;
  const isDragging = draggedMasterSectionId === section.id;
  const isHidden = isCmsSectionHidden(section.settings?.['isHidden']);
  const draggedSectionId = drag.section.id ?? draggedMasterSectionId;

  const resolveInsideDropSectionId = React.useCallback(
    (dataTransfer: DataTransfer): string | null => {
      const sectionDrag = readSectionDragData(dataTransfer, {
        id: draggedSectionId,
        type: drag.section.type,
        zone: drag.section.zone,
        index: drag.section.index,
      });
      const dragSectionId = sectionDrag.id;
      if (!dragSectionId || dragSectionId === section.id) return null;
      if (isDescendant(allSections, dragSectionId, section.id)) return null;

      const dragSection = allSections.find((candidate) => candidate.id === dragSectionId);
      if (dragSection?.parentSectionId === section.id) return null;
      return dragSectionId;
    },
    [
      allSections,
      drag.section.index,
      drag.section.type,
      drag.section.zone,
      draggedSectionId,
      section.id,
    ]
  );

  const SectionIcon: LucideIcon = Box;
  const rootRows = section.blocks.filter((block) => block.type === 'Row');
  const hasRowBlocks = rootRows.length > 0;
  const showSectionLevelBlockPicker = section.type !== 'Grid' && !hasRowBlocks;
  const rowIndexById = new Map<string, number>();
  rootRows.forEach((row, index) => {
    rowIndexById.set(row.id, index);
  });
  const childSectionCount = allSections.filter(
    (candidate) => candidate.parentSectionId === section.id
  ).length;
  const hasBlockChildren = section.blocks.length > 0;
  const hasAnyChildren = hasBlockChildren || hasTreeChildren;

  const handleSectionDragStart = React.useCallback(
    (event: React.DragEvent): void => {
      const target = event.target as HTMLElement | null;
      const isInteractiveTarget =
        target?.closest(
          'button,a,input,textarea,select,[role="button"],[data-no-section-drag="true"]'
        ) !== null;
      const isDragHandle = target?.closest('[data-cms-section-drag-handle="true"]') !== null;
      if (isInteractiveTarget && !isDragHandle) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }

      setSectionDragData(event.dataTransfer, {
        id: section.id,
        type: section.type,
        zone: section.zone,
        index: sectionIndex,
      });
      setMasterTreeDragNodeData(event.dataTransfer, toCmsSectionNodeId(section.id), section.id);
      // Defer state updates to avoid cancelling the browser drag session.
      setTimeout(() => {
        startSectionDrag({
          id: section.id,
          type: section.type,
          zone: section.zone,
          index: sectionIndex,
        });
        startSectionMasterDrag(section.id);
      }, 0);
    },
    [section.id, section.type, section.zone, sectionIndex, startSectionDrag, startSectionMasterDrag]
  );

  const handleSectionDragEnd = React.useCallback((): void => {
    endSectionDrag();
    setIsInsideDropOver(false);
    endSectionMasterDrag();
  }, [endSectionDrag, endSectionMasterDrag]);

  const handleToggleExpand = React.useCallback((): void => {
    const nextOpen = !isRowExpanded;
    if (isExpanded !== nextOpen) {
      toggleExpand(section.id);
    }
    if (toggleTreeExpand && isTreeExpanded !== nextOpen) {
      toggleTreeExpand();
    }
  }, [isExpanded, isRowExpanded, isTreeExpanded, section.id, toggleExpand, toggleTreeExpand]);

  const handleSectionRowDragOver = React.useCallback(
    (event: React.DragEvent): void => {
      const dragSectionId = resolveInsideDropSectionId(event.dataTransfer);
      if (!dragSectionId) return;
      event.preventDefault();
      event.stopPropagation();
      setIsInsideDropOver(true);
    },
    [resolveInsideDropSectionId]
  );

  const handleSectionRowDragLeave = React.useCallback((event: React.DragEvent): void => {
    if (event.currentTarget.contains(event.relatedTarget as Node)) return;
    setIsInsideDropOver(false);
  }, []);

  const handleSectionRowDrop = React.useCallback(
    (event: React.DragEvent): void => {
      event.preventDefault();
      event.stopPropagation();

      const dragSectionId = resolveInsideDropSectionId(event.dataTransfer);
      if (!dragSectionId) {
        setIsInsideDropOver(false);
        return;
      }

      setIsInsideDropOver(false);

      void moveSectionByMaster(dragSectionId, section.zone, childSectionCount, section.id).finally(
        () => {
          endSectionDrag();
        }
      );
    },
    [
      childSectionCount,
      endSectionDrag,
      moveSectionByMaster,
      resolveInsideDropSectionId,
      section.id,
      section.zone,
    ]
  );

  return (
    <TreeSectionProvider sectionId={section.id}>
      <div
        className={cn(
          'group mb-1 flex flex-col transition-all',
          isDragging ? 'opacity-40 grayscale' : 'opacity-100'
        )}
      >
        <div
          data-cms-section-row='true'
          data-cms-section-id={section.id}
          data-cms-section-zone={section.zone}
          className={cn(
            'flex items-center gap-2 rounded-md border py-1.5 pl-1 pr-2 transition',
            isInsideDropOver ? 'border-emerald-500/60 bg-emerald-500/10' : '',
            isSelected
              ? 'border-blue-500/50 bg-blue-500/10'
              : 'border-border/40 bg-card/20 hover:border-border/80 hover:bg-card/40'
          )}
          onDragOver={handleSectionRowDragOver}
          onDragLeave={handleSectionRowDragLeave}
          onDrop={handleSectionRowDrop}
        >
          <TreeCaret
            isOpen={isRowExpanded}
            hasChildren={hasAnyChildren}
            ariaLabel={isRowExpanded ? `Collapse ${section.type}` : `Expand ${section.type}`}
            onToggle={(event?: React.MouseEvent | React.KeyboardEvent): void => {
              event?.stopPropagation?.();
              handleToggleExpand();
            }}
            iconClassName='size-3'
            placeholderClassName='block size-3 shrink-0'
          />
          <button
            type='button'
            data-cms-section-drag-handle='true'
            draggable
            className='flex h-7 w-5 shrink-0 cursor-grab items-center justify-center rounded text-gray-600 hover:bg-black/10 hover:text-gray-400 active:cursor-grabbing'
            onDragStart={handleSectionDragStart}
            onDragEnd={handleSectionDragEnd}
            onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.preventDefault();
              event.stopPropagation();
            }}
            aria-label={`Drag ${section.type} section`}
            title={`Drag ${section.type} section`}
          >
            <GripVertical className='size-3.5' aria-hidden='true' />
          </button>

          <button
            type='button'
            className='flex min-w-0 flex-1 items-center gap-2 text-left'
            onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
              selectNode(section.id);
            }}
            aria-pressed={isSelected}
            aria-label={`Select ${section.type} section`}
          >
            <SectionIcon
              className={cn('size-4 shrink-0', isHidden ? 'text-gray-600' : 'text-sky-400/80')}
            />
            <span
              className={cn(
                'truncate text-sm font-medium',
                isHidden ? 'text-gray-500 line-through' : 'text-gray-200'
              )}
            >
              {section.type}
            </span>
          </button>
          {isHidden && (
            <Badge
              variant='neutral'
              className='bg-gray-800/50 text-[9px] uppercase tracking-wider text-gray-500 h-4 px-1'
            >
              Hidden
            </Badge>
          )}

          <div className='flex shrink-0 items-center gap-1 opacity-0 transition group-hover:opacity-100'>
            <Button
              variant='ghost'
              size='sm'
              onClick={(e: React.MouseEvent): void => {
                e.stopPropagation();
                sectionActions.toggleVisibility(section.id, !isHidden);
              }}
              data-no-section-drag='true'
              className='size-7 p-0 text-gray-500 hover:text-gray-200'
              title={isHidden ? 'Show section' : 'Hide section'}
              aria-label={isHidden ? 'Show section' : 'Hide section'}>
              {isHidden ? <EyeOff className='size-3.5' /> : <Eye className='size-3.5' />}
            </Button>
            <Button
              variant='ghost'
              size='sm'
              onClick={(e: React.MouseEvent): void => {
                e.stopPropagation();
                sectionActions.remove(section.id);
              }}
              data-no-section-drag='true'
              className='size-7 p-0 text-gray-500 hover:bg-red-500/10 hover:text-red-400'
              title='Delete section'
              aria-label={'Delete section'}>
              <Trash2 className='size-3.5' />
            </Button>
            <Button
              variant='ghost'
              size='sm'
              onClick={(e: React.MouseEvent): void => {
                e.stopPropagation();
                sectionActions.duplicate(section.id);
              }}
              data-no-section-drag='true'
              className='size-7 p-0 text-gray-500 hover:text-gray-200'
              title='Duplicate section'
              aria-label={'Duplicate section'}>
              <Plus className='size-3.5' />
            </Button>
          </div>
        </div>

        {isExpanded && (
          <div className='ml-4 mt-1 border-l-2 border-border/20 pl-2'>
            <div className='space-y-1'>
              {section.blocks.map((block, idx) => {
                if (block.type === 'Row') {
                  const rowIndex = rowIndexById.get(block.id) ?? idx;
                  return (
                    <RowNodeItem
                      key={block.id}
                      row={block}
                      rowIndex={rowIndex}
                      rowCount={rootRows.length}
                    />
                  );
                }
                if (block.type === 'SlideshowFrame') {
                  return <SlideshowFrameNodeItem key={block.id} frame={block} index={idx} />;
                }
                if (Array.isArray(block.blocks)) {
                  return <SectionBlockNodeItem key={block.id} block={block} index={idx} />;
                }
                return <BlockNodeItem key={block.id} block={block} index={idx} />;
              })}
            </div>
            {showSectionLevelBlockPicker ? (
              <div className='mt-2'>
                {renderTreeSectionPicker({
                  disabled: false,
                  variant: 'blocks',
                  sectionType: section.type,
                  onSelect: (blockType: string) => blockActions.add(section.id, blockType),
                })}
              </div>
            ) : null}
          </div>
        )}
      </div>
    </TreeSectionProvider>
  );
}

'use client';

import { Trash2, Frame, GripVertical, type LucideIcon } from 'lucide-react';
import React, { useMemo, useState } from 'react';

import { useDragStateExtract } from '@/features/cms/hooks/useDragStateExtract';
import { usePageBuilder } from '@/features/cms/hooks/usePageBuilderContext';
import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import type { BlockInstance } from '@/features/cms/types/page-builder';
import {
  readBlockDragData,
  readSectionDragData,
  setBlockDragData,
} from '@/features/cms/utils/page-builder-dnd';
import type { TreeContextMenuItem } from '@/shared/contracts/ui/menus';
import { TreeRow, TreeCaret, TreeActionButton, TreeActionSlot, TreeContextMenu } from '@/shared/ui/data-display.public';
import { DRAG_KEYS, hasDragType } from '@/shared/utils/drag-drop';


import { ColumnBlockPicker } from '../ColumnBlockPicker';
import { getBlockDefinition } from '../section-registry';
import { BlockNodeItem } from './BlockNodeItem';
import { BLOCK_ICONS, CONVERTIBLE_SECTION_TYPES, resolveBlockLabel } from './tree-constants';
import { TreeParentBlockProvider } from './TreeParentBlockContext';
import { useTreeSectionId } from './TreeSectionContext';

import type { SlideshowFrameNodeItemProps } from './tree-types';


export function SlideshowFrameNodeItem(props: SlideshowFrameNodeItemProps): React.ReactNode {
  const { frame, index } = props;

  const sectionId = useTreeSectionId();
  const { state: pbState } = usePageBuilder();
  const { expandedIds, selectNode, toggleExpand, blockActions, sectionActions } = useTreeActions();

  const selectedNodeId = pbState.selectedNodeId;

  // Drag state from context
  const drag = useDragStateExtract();
  const { startBlockDrag, endBlockDrag, endSectionDrag } = drag.actions;

  const draggedBlockId = drag.block.id;
  const draggedBlockType = drag.block.type;
  const draggedFromSectionId = drag.block.fromSectionId;
  const draggedFromColumnId = drag.block.fromColumnId;
  const draggedFromParentBlockId = drag.block.fromParentBlockId;
  const draggedSectionId = drag.section.id;
  const draggedSectionType = drag.section.type;
  const isSelected = selectedNodeId === frame.id;
  const isExpanded = expandedIds.has(frame.id);
  const hasChildren = (frame.blocks ?? []).length > 0;
  const Icon: LucideIcon = BLOCK_ICONS[frame.type] ?? Frame;
  const [isDragOver, setIsDragOver] = useState(false);
  const isDragging = draggedBlockId === frame.id;
  const blockLabel = resolveBlockLabel(frame, 'Frame');
  const frameAllowedTypes = getBlockDefinition('SlideshowFrame')?.allowedBlockTypes ?? [];
  const frameMenuItems: TreeContextMenuItem[] = useMemo(
    () => [
      {
        id: 'remove-frame',
        label: 'Remove frame',
        icon: <Trash2 className='size-3.5' />,
        tone: 'danger',
        onSelect: (): void => {
          blockActions.remove(sectionId, frame.id);
        },
      },
    ],
    [blockActions, sectionId, frame.id]
  );

  return (
    <div className='group/frame'>
      <TreeContextMenu items={frameMenuItems}>
        <TreeRow
          tone='none'
          onDragOver={(e: React.DragEvent) => {
            const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
            });
            const dragId = blockDrag.id;
            // Check for section drag (for convertible sections like Block, TextElement, etc.)
            const isSectionDrag =
              draggedSectionId &&
              draggedSectionId !== sectionId &&
              CONVERTIBLE_SECTION_TYPES.includes(draggedSectionType ?? '');
            // Accept block drag OR section drag
            if (!dragId && !hasBlockPayload && !isSectionDrag) return;
            if (dragId === frame.id) return; // Don't allow dropping on self
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(true);
          }}
          onDragLeave={(e: React.DragEvent) => {
            if (e.currentTarget.contains(e.relatedTarget as Node)) return;
            setIsDragOver(false);
          }}
          onDrop={(e: React.DragEvent) => {
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(false);

            // First check for section drag data
            const sectionDrag = readSectionDragData(e.dataTransfer, {
              id: draggedSectionId,
              type: draggedSectionType,
            });
            const sectionIdToDrop = sectionDrag.id;
            const sectionTypeToDrop = sectionDrag.type;

            // Handle section drop (convert section to block in frame)
            if (
              sectionIdToDrop &&
              sectionIdToDrop !== sectionId &&
              CONVERTIBLE_SECTION_TYPES.includes(sectionTypeToDrop ?? '')
            ) {
              // Convert the section to a block inside the frame
              sectionActions.dropToSlideshowFrame(
                sectionIdToDrop,
                sectionId,
                frame.id,
                (frame.blocks ?? []).length
              );
              endSectionDrag();
              return;
            }

            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
              fromSectionId: draggedFromSectionId,
              fromColumnId: draggedFromColumnId,
              fromParentBlockId: draggedFromParentBlockId,
            });
            const dragType = blockDrag.type ?? '';
            const dragId = blockDrag.id;

            if (!dragId) return;

            // Handle SlideshowFrame reordering
            if (dragType === 'SlideshowFrame') {
              if (dragId === frame.id) return;
              const fromSection = blockDrag.fromSectionId ?? sectionId;
              blockActions.drop(dragId, fromSection, sectionId, index);
            }
            // Handle dropping allowed block types INTO the frame
            else if (frameAllowedTypes.includes(dragType)) {
              const fromSection = blockDrag.fromSectionId ?? sectionId;
              const fromColumn = blockDrag.fromColumnId ?? undefined;
              const fromParentBlock = blockDrag.fromParentBlockId ?? undefined;
              const frameBlockCount = (frame.blocks ?? []).length;
              blockActions.dropToSlideshowFrame(
                dragId,
                fromSection,
                fromColumn,
                fromParentBlock,
                sectionId,
                frame.id,
                frameBlockCount
              );
            } else {
              return;
            }

            endBlockDrag();
          }}
          className={`flex w-full cursor-pointer items-center gap-1.5 rounded px-2 py-1.5 text-sm font-medium transition ${
            isDragOver
              ? 'bg-emerald-600/30 text-emerald-200 ring-1 ring-emerald-500/50'
              : isSelected
                ? 'bg-blue-600/80 text-white'
                : isDragging
                  ? 'opacity-40 text-gray-400'
                  : 'text-gray-300 hover:bg-muted/40'
          }`}
        >
          <div
            draggable
            onDragStart={(e: React.DragEvent) => {
              e.stopPropagation();
              setBlockDragData(e.dataTransfer, {
                id: frame.id,
                type: frame.type,
                fromSectionId: sectionId,
                fromColumnId: '',
                fromParentBlockId: '',
              });
              setTimeout(() => {
                startBlockDrag({
                  id: frame.id,
                  type: frame.type,
                  fromSectionId: sectionId,
                  fromColumnId: null,
                  fromParentBlockId: null,
                });
              }, 0);
            }}
            onDragEnd={() => {
              endBlockDrag();
            }}
            onMouseDown={(e: React.MouseEvent) => e.stopPropagation()}
            className='flex items-center justify-center opacity-0 group-hover/frame:opacity-100 group-focus-within/frame:opacity-100'
            aria-hidden='true'
          >
            <GripVertical className='size-3 shrink-0 text-gray-600 cursor-grab active:cursor-grabbing' />
          </div>
          <TreeCaret
            isOpen={isExpanded}
            hasChildren={true}
            ariaLabel={isExpanded ? 'Collapse frame' : 'Expand frame'}
            onToggle={(): void => toggleExpand(frame.id)}
            iconClassName='size-3'
            placeholderClassName='block size-3 shrink-0'
          />
          <button
            type='button'
            onClick={() => selectNode(frame.id)}
            aria-pressed={isSelected}
            aria-label={`Select block ${blockLabel}`}
            className='flex min-w-0 flex-1 items-center gap-1.5 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
          >
            <Icon className='size-3.5 shrink-0' />
            <span className='min-w-0 flex-1 truncate text-left'>{blockLabel}</span>
          </button>
          <TreeActionSlot show='always' align='inline'>
            <ColumnBlockPicker
              onSelect={(elemType: string) =>
                blockActions.addElementToSectionBlock(sectionId, frame.id, elemType)
              }
              allowedBlockTypes={frameAllowedTypes}
            />
          </TreeActionSlot>
          {!isDragOver && (
            <TreeActionSlot show='hover' align='inline'>
              <TreeActionButton
                tone='danger'
                onClick={(e: React.MouseEvent) => {
                  e.stopPropagation();
                  blockActions.remove(sectionId, frame.id);
                }}
                title='Remove frame'
              >
                <Trash2 className='size-3' />
              </TreeActionButton>
            </TreeActionSlot>
          )}
        </TreeRow>
      </TreeContextMenu>

      {isExpanded && (
        <div
          className='ml-5 border-l border-border/30 pl-1'
          onDragOver={(e: React.DragEvent) => {
            const hasBlockPayload = hasDragType(e.dataTransfer, [DRAG_KEYS.BLOCK_ID]);
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
            });
            const dragId = blockDrag.id;
            if (!dragId && !hasBlockPayload) return;
            if (dragId === frame.id) return;
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(true);
          }}
          onDragLeave={(e: React.DragEvent) => {
            if (e.currentTarget.contains(e.relatedTarget as Node)) return;
            setIsDragOver(false);
          }}
          onDrop={(e: React.DragEvent) => {
            e.preventDefault();
            e.stopPropagation();
            setIsDragOver(false);
            const blockDrag = readBlockDragData(e.dataTransfer, {
              id: draggedBlockId,
              type: draggedBlockType,
              fromSectionId: draggedFromSectionId,
              fromColumnId: draggedFromColumnId,
              fromParentBlockId: draggedFromParentBlockId,
            });
            const dragType = blockDrag.type ?? '';
            const dragId = blockDrag.id;
            if (!dragId) return;
            // Handle dropping allowed block types INTO the frame
            if (frameAllowedTypes.includes(dragType)) {
              const fromSection = blockDrag.fromSectionId ?? sectionId;
              const fromColumn = blockDrag.fromColumnId ?? undefined;
              const fromParentBlock = blockDrag.fromParentBlockId ?? undefined;
              const frameBlockCount = (frame.blocks ?? []).length;
              blockActions.dropToSlideshowFrame(
                dragId,
                fromSection,
                fromColumn,
                fromParentBlock,
                sectionId,
                frame.id,
                frameBlockCount
              );
            }
            endBlockDrag();
          }}
        >
          {hasChildren ? (
            (frame.blocks ?? []).map((child: BlockInstance, childIndex: number) => (
              <div
                key={child.id}
                draggable
                onDragStart={(e: React.DragEvent) => {
                  setBlockDragData(e.dataTransfer, {
                    id: child.id,
                    type: child.type,
                    fromSectionId: sectionId,
                    fromColumnId: '',
                    fromParentBlockId: frame.id,
                  });
                  setTimeout(() => {
                    startBlockDrag({
                      id: child.id,
                      type: child.type,
                      fromSectionId: sectionId,
                      fromColumnId: null,
                      fromParentBlockId: frame.id,
                    });
                  }, 0);
                }}
                onDragEnd={() => {
                  endBlockDrag();
                }}
              >
                <TreeParentBlockProvider parentBlockId={frame.id}>
                  <BlockNodeItem block={child} index={childIndex} disableDrag />
                </TreeParentBlockProvider>
              </div>
            ))
          ) : (
            <div
              className={`mt-1 flex min-h-[36px] items-center gap-2 rounded border border-dashed px-2 py-1 text-[11px] transition ${
                isDragOver
                  ? 'border-emerald-500/70 bg-emerald-500/10 text-emerald-200'
                  : 'border-border/30 text-gray-500'
              }`}
            >
              {isDragOver ? 'Drop here' : 'Add elements to this frame'}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { createContext, useContext, useMemo } from 'react';

import { internalError } from '@/shared/errors/app-error';

type TreeColumnContextValue = {
  columnId: string;
};

const TreeColumnContext = createContext<TreeColumnContextValue | null>(null);

type TreeColumnProviderProps = {
  columnId: string;
  children: React.ReactNode;
};

export function TreeColumnProvider({
  columnId,
  children,
}: TreeColumnProviderProps): React.JSX.Element {
  const value = useMemo<TreeColumnContextValue>(() => ({ columnId }), [columnId]);
  return <TreeColumnContext.Provider value={value}>{children}</TreeColumnContext.Provider>;
}

export function useOptionalTreeColumnId(explicitColumnId?: string): string | undefined {
  if (typeof explicitColumnId === 'string' && explicitColumnId.trim().length > 0) {
    return explicitColumnId;
  }
  const context = useContext(TreeColumnContext);
  return context?.columnId;
}

export function useTreeColumnId(explicitColumnId?: string): string {
  const columnId = useOptionalTreeColumnId(explicitColumnId);
  if (!columnId) {
    throw internalError(
      'useTreeColumnId must be used within TreeColumnProvider or receive a columnId prop'
    );
  }
  return columnId;
}

