'use client';

import React, { useCallback } from 'react';

import { useTreeActions } from '@/features/cms/hooks/useTreeActionsContext';
import type { PageZone } from '@/features/cms/types/page-builder';

import { BlockPicker } from '../BlockPicker';
import { SectionPicker as BaseSectionPicker } from '../SectionPicker';


type SectionVariantProps = {
  disabled?: boolean;
  zone: PageZone;
  onSelect?: (sectionType: string) => void;
  variant?: 'sections';
  sectionType?: never;
};

type BlockVariantProps = {
  disabled?: boolean;
  sectionType: string;
  onSelect: (blockType: string) => void;
  variant: 'blocks';
  zone?: never;
};

export type TreeSectionPickerProps = SectionVariantProps | BlockVariantProps;

function TreeBlockPicker(props: {
  disabled?: boolean;
  sectionType: string;
  onSelect: (value: string) => void;
}): React.ReactNode {
  const { disabled, sectionType, onSelect } = props;
  if (disabled) return null;
  return <BlockPicker sectionType={sectionType} onSelect={onSelect} />;
}

function TreeZoneSectionPicker(props: {
  disabled?: boolean;
  zone: PageZone;
  onSelect?: (value: string) => void;
}): React.ReactNode {
  const { disabled, zone, onSelect } = props;
  const { sectionActions } = useTreeActions();
  const handleSelect = useCallback(
    (sectionType: string): void => {
      if (onSelect) {
        onSelect(sectionType);
        return;
      }
      sectionActions.add(sectionType, zone);
    },
    [onSelect, sectionActions, zone]
  );
  return <BaseSectionPicker disabled={disabled} zone={zone} onSelect={handleSelect} />;
}

export function renderTreeSectionPicker(props: TreeSectionPickerProps): React.ReactNode {
  if (props.variant === 'blocks') {
    return (
      <TreeBlockPicker
        disabled={props.disabled}
        sectionType={props.sectionType}
        onSelect={props.onSelect}
      />
    );
  }

  return (
    <TreeZoneSectionPicker
      disabled={props.disabled}
      zone={props.zone}
      onSelect={props.onSelect}
    />
  );
}

'use client';

import React, { useState } from 'react';

import { useDragState } from '@/features/cms/hooks/useDragStateContext';
import type { PageZone } from '@/shared/contracts/cms';
import { Button } from '@/shared/ui/primitives.public';
import { cn } from '@/shared/utils/ui-utils';

import {
  useComponentTreePanelActions,
  useComponentTreePanelState,
} from './ComponentTreePanelContext';
import { renderTreeSectionPicker } from './TreeSectionPicker';


export function ZoneFooterNode({
  zone,
  sectionCount,
}: {
  zone: PageZone;
  sectionCount: number;
}): React.JSX.Element {
  const {
    currentPage,
    showSectionDropPlaceholder,
    canDropSectionsAtRoot,
    treePlaceholderClasses,
    treeRootDropLabel,
    draggedMasterSectionId,
  } = useComponentTreePanelState();
  const { moveSectionByMaster } = useComponentTreePanelActions();
  const { state: dragState, endSectionDrag } = useDragState();
  const [isDropTarget, setIsDropTarget] = useState(false);

  const draggedSectionId = dragState.section.id ?? draggedMasterSectionId;
  const canDropHere =
    showSectionDropPlaceholder && canDropSectionsAtRoot && Boolean(draggedSectionId);
  const pickerZone = zone;

  return (
    <>
      {canDropHere && (
        <div
          onDragOver={(e: React.DragEvent): void => {
            e.preventDefault();
            setIsDropTarget(true);
          }}
          onDragLeave={(e: React.DragEvent): void => {
            if (e.currentTarget.contains(e.relatedTarget as Node)) return;
            setIsDropTarget(false);
          }}
          onDrop={(e: React.DragEvent): void => {
            e.preventDefault();
            setIsDropTarget(false);
            if (!draggedSectionId) return;
            void moveSectionByMaster(draggedSectionId, zone, sectionCount).finally(() => {
              endSectionDrag();
            });
          }}
          className={cn(
            'mb-1.5 flex h-6 items-center justify-center rounded border-2 border-dashed text-[9px] font-medium transition',
            isDropTarget ? treePlaceholderClasses.rootActive : treePlaceholderClasses.rootIdle
          )}
        >
          {treeRootDropLabel}
        </div>
      )}
      <div className='flex items-center justify-center py-2'>
        {sectionCount === 0 ? (
          <Button
            variant='ghost'
            size='sm'
            className='text-[10px] uppercase tracking-wider text-gray-500 hover:text-gray-300 h-auto py-1 font-semibold'
            disabled
          >
            Empty Zone
          </Button>
        ) : null}
        {renderTreeSectionPicker({ disabled: !currentPage, zone: pickerZone })}
      </div>
    </>
  );
}

