// ---------------------------------------------------------------------------
// Label Utilities
// ---------------------------------------------------------------------------

/**
 * Resolves a node label, using the provided value if it's a non-empty string,
 * otherwise falling back to the default.
 */
export const resolveNodeLabel = (fallback: string, value: unknown): string => {
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (trimmed.length > 0) return trimmed;
  }
  return fallback;
};

/**
 * Resolves a block label, with special handling for TextAtomLetter blocks
 * which display their text content directly.
 */
export const resolveBlockLabel = (block: BlockInstance, fallback: string): string => {
  if (block.type === 'TextAtomLetter') {
    const raw = block.settings?.['textContent'];
    if (typeof raw === 'string') {
      return raw.trim().length === 0 ? 'space' : raw;
    }
  }
  return resolveNodeLabel(fallback, block.settings?.['label']);
};

import { logClientError } from '@/shared/utils/observability/client-error-logger';
/**
 * Utility functions for AI generation in the CMS inspector.
 */

const extractFencedCodeBlock = (raw: string, language?: string): string | null => {
  const languagePattern = language ? `(?:${language})?` : '(?:[a-z]+)?';
  const fenceMatch = raw.match(new RegExp(String.raw`^\`\`\`${languagePattern}\s*([\s\S]*?)\`\`\`$`, 'i'));
  return fenceMatch?.[1]?.trim() ?? null;
};

const stripMarkdownCodeFences = (raw: string): string => raw.replace(/```/g, '').trim();

const trimAiResponse = (raw: string): string => raw.trim();

const resolveCodeBlockContent = (raw: string, language: string): string | null =>
  extractFencedCodeBlock(raw, language) ?? stripMarkdownCodeFences(raw);

const extractJsonCandidateText = (raw: string): string =>
  extractFencedCodeBlock(raw, 'json') ?? raw;

const resolveJsonObjectText = (candidate: string): string => {
  const first = candidate.indexOf('{');
  const last = candidate.lastIndexOf('}');
  return first >= 0 && last > first ? candidate.slice(first, last + 1) : candidate;
};

const parseJsonObjectText = (jsonText: string): Record<string, unknown> | null => {
  const parsed = JSON.parse(jsonText) as unknown;
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed)
    ? (parsed as Record<string, unknown>)
    : null;
};

const pushDiffLine = (
  lines: Array<{ type: 'add' | 'remove' | 'same'; text: string }>,
  type: 'add' | 'remove' | 'same',
  text: string | undefined
): void => {
  if (text !== undefined) {
    lines.push({ type, text });
  }
};

const appendDiffLinePair = (args: {
  lines: Array<{ type: 'add' | 'remove' | 'same'; text: string }>;
  prevLine: string | undefined;
  nextLine: string | undefined;
}): void => {
  if (args.prevLine === args.nextLine) {
    pushDiffLine(args.lines, 'same', args.prevLine);
    return;
  }

  pushDiffLine(args.lines, 'remove', args.prevLine);
  pushDiffLine(args.lines, 'add', args.nextLine);
};

export function extractCssFromResponse(raw: string): string {
  const trimmed = trimAiResponse(raw);
  if (!trimmed) return '';

  return resolveCodeBlockContent(trimmed, 'css') ?? '';
}

export function extractJsonFromResponse(raw: string): Record<string, unknown> | null {
  const trimmed = trimAiResponse(raw);
  if (!trimmed) return null;
  try {
    return parseJsonObjectText(resolveJsonObjectText(extractJsonCandidateText(trimmed)));
  } catch (error) {
    logClientError(error);
    return null;
  }
}

export function buildDiffLines(
  prev: string,
  next: string,
  limit: number = 220
): { lines: Array<{ type: 'add' | 'remove' | 'same'; text: string }>; truncated: boolean } {
  const prevLines = prev.split('\n');
  const nextLines = next.split('\n');
  const max = Math.max(prevLines.length, nextLines.length);
  const lines: Array<{ type: 'add' | 'remove' | 'same'; text: string }> = [];
  let truncated = false;
  for (let index = 0; index < max; index += 1) {
    appendDiffLinePair({ lines, prevLine: prevLines[index], nextLine: nextLines[index] });
    if (lines.length >= limit) {
      truncated = true;
      break;
    }
  }
  return { lines, truncated };
}

import type { PageZone } from '@/features/cms/types/page-builder';
import { createMasterFolderTreeAdapterV3 } from '@/shared/lib/foldertree/public';
import type { MasterTreeNode } from '@/shared/utils/master-folder-tree-contract';

import { decodeCmsMasterNodeId, fromCmsSectionNodeId, fromCmsZoneNodeId } from './cms-master-tree';


export const createCmsMasterTreeAdapter = (
  applySectionMoveInTree: (
    sectionId: string,
    toZone: PageZone,
    toParentSectionId: string | null,
    toIndex: number
  ) => void
) =>
  createMasterFolderTreeAdapterV3({
    decodeNodeId: decodeCmsMasterNodeId,
    handlers: {
      onMove: ({ operation, context, node, targetParent }): void => {
        if (node.entity !== 'section' || !targetParent) return;
        if (targetParent.entity !== 'zone' && targetParent.entity !== 'section') return;

        const nextSections = context.nextNodes
          .filter(
            (entry: MasterTreeNode): boolean =>
              entry.parentId === targetParent.nodeId && entry.kind === 'section'
          )
          .sort((left: MasterTreeNode, right: MasterTreeNode) => left.sortOrder - right.sortOrder);
        const derivedIndex = nextSections.findIndex(
          (entry: MasterTreeNode): boolean => entry.id === node.nodeId
        );
        const targetIndex = operation.targetIndex ?? derivedIndex;
        if (targetIndex < 0) return;

        if (targetParent.entity === 'zone') {
          const targetZone = extractPageZone(targetParent.id);
          if (!targetZone) return;
          applySectionMoveInTree(node.id, targetZone, null, targetIndex);
          return;
        }

        const parentSectionId = targetParent.id;
        const targetZone = resolveZoneForParentNode(context.nextNodes, targetParent.nodeId);
        if (!targetZone) return;
        applySectionMoveInTree(node.id, targetZone, parentSectionId, targetIndex);
      },
      onReorder: ({ operation, context, node, target }): void => {
        if (node.entity !== 'section' || target.entity !== 'section') return;
        const targetNode = context.previousNodes.find(
          (entry: MasterTreeNode): boolean => entry.id === operation.targetId
        );
        if (!targetNode?.parentId) return;

        const currentSections = context.previousNodes
          .filter(
            (entry: MasterTreeNode): boolean =>
              entry.parentId === targetNode.parentId && entry.kind === 'section'
          )
          .sort((left: MasterTreeNode, right: MasterTreeNode) => left.sortOrder - right.sortOrder);
        const targetIndex = currentSections.findIndex(
          (entry: MasterTreeNode): boolean => entry.id === target.nodeId
        );
        if (targetIndex < 0) return;

        const dropIndex = operation.position === 'after' ? targetIndex + 1 : targetIndex;
        const parentZone = fromCmsZoneNodeId(targetNode.parentId);
        if (parentZone) {
          applySectionMoveInTree(node.id, parentZone, null, dropIndex);
          return;
        }

        const parentSectionId = fromCmsSectionNodeId(targetNode.parentId);
        if (!parentSectionId) return;
        const targetZone = resolveZoneForParentNode(context.previousNodes, targetNode.parentId);
        if (!targetZone) return;
        applySectionMoveInTree(node.id, targetZone, parentSectionId, dropIndex);
      },
    },
  });

const resolveZoneForParentNode = (
  nodes: MasterTreeNode[],
  parentNodeId: string
): PageZone | null => {
  const zoneFromId = fromCmsZoneNodeId(parentNodeId);
  if (zoneFromId) return zoneFromId;

  const parentNode = nodes.find((entry: MasterTreeNode): boolean => entry.id === parentNodeId);
  if (!parentNode) return null;
  const metadataZone = extractPageZone(parentNode.metadata?.['zone']);
  if (metadataZone) return metadataZone;

  const pathRoot = parentNode.path.split('/')[0] ?? '';
  return extractPageZone(pathRoot);
};

const extractPageZone = (value: unknown): PageZone | null => {
  if (value === 'header' || value === 'template' || value === 'footer') return value;
  return null;
};

import { buildHierarchyIndexes } from '@/features/cms/hooks/page-builder/section-hierarchy';
import type { PageZone, SectionInstance } from '@/features/cms/types/page-builder';
import type { MasterTreeNode } from '@/shared/utils/master-folder-tree-contract';

const CMS_ZONE_NODE_PREFIX = 'cms-zone:';
const CMS_SECTION_NODE_PREFIX = 'cms-section:';
const CMS_ZONE_FOOTER_NODE_PREFIX = 'cms-zone-footer:';

export const CMS_ZONE_LABELS: Record<PageZone, string> = {
  header: 'Header',
  template: 'Template',
  footer: 'Footer',
};

export const CMS_ZONE_ORDER: PageZone[] = ['header', 'template', 'footer'];

export type CmsMasterNodeRef =
  | {
      entity: 'zone';
      id: PageZone;
      nodeId: string;
    }
  | {
      entity: 'section';
      id: string;
      nodeId: string;
    };

export const toCmsZoneNodeId = (zone: PageZone): string => `${CMS_ZONE_NODE_PREFIX}${zone}`;

export const toCmsSectionNodeId = (sectionId: string): string =>
  `${CMS_SECTION_NODE_PREFIX}${sectionId}`;

export const toCmsZoneFooterNodeId = (zone: PageZone): string =>
  `${CMS_ZONE_FOOTER_NODE_PREFIX}${zone}`;

export const fromCmsSectionNodeId = (value: string): string | null =>
  value.startsWith(CMS_SECTION_NODE_PREFIX) ? value.slice(CMS_SECTION_NODE_PREFIX.length) : null;

export const fromCmsZoneNodeId = (value: string): PageZone | null => {
  if (!value.startsWith(CMS_ZONE_NODE_PREFIX)) return null;
  const zone = value.slice(CMS_ZONE_NODE_PREFIX.length);
  return CMS_ZONE_ORDER.includes(zone as PageZone) ? (zone as PageZone) : null;
};

export const fromCmsZoneFooterNodeId = (value: string): PageZone | null => {
  if (!value.startsWith(CMS_ZONE_FOOTER_NODE_PREFIX)) return null;
  const zone = value.slice(CMS_ZONE_FOOTER_NODE_PREFIX.length);
  return CMS_ZONE_ORDER.includes(zone as PageZone) ? (zone as PageZone) : null;
};

export const decodeCmsMasterNodeId = (value: string): CmsMasterNodeRef | null => {
  const zone = fromCmsZoneNodeId(value);
  if (zone) {
    return {
      entity: 'zone',
      id: zone,
      nodeId: value,
    };
  }

  const sectionId = fromCmsSectionNodeId(value);
  if (sectionId) {
    return {
      entity: 'section',
      id: sectionId,
      nodeId: value,
    };
  }

  return null;
};

const getSectionNodeLabel = (section: SectionInstance): string => {
  const settings =
    section.settings && typeof section.settings === 'object' ? section.settings : null;
  const customLabel = settings?.['label'];
  if (typeof customLabel === 'string' && customLabel.trim().length > 0) {
    return customLabel.trim();
  }
  return section.type;
};

export const buildCmsMasterNodes = (sections: SectionInstance[]): MasterTreeNode[] => {
  const nodes: MasterTreeNode[] = [];
  const hierarchy = buildHierarchyIndexes(sections);

  CMS_ZONE_ORDER.forEach((zone: PageZone, zoneIndex: number) => {
    const zoneNodeId = toCmsZoneNodeId(zone);
    const zoneLabel = CMS_ZONE_LABELS[zone];
    const rootSectionIds = (hierarchy.childrenByParent.get(null) ?? []).filter(
      (sectionId: string) => {
        const section = hierarchy.nodeById.get(sectionId);
        return section?.zone === zone;
      }
    );

    nodes.push({
      id: zoneNodeId,
      type: 'folder',
      kind: 'zone',
      parentId: null,
      name: zoneLabel,
      path: zone,
      sortOrder: zoneIndex,
      metadata: { entity: 'zone', zone },
    });

    const pushSectionNode = (
      sectionId: string,
      parentNodeId: string,
      parentPath: string,
      sortOrder: number
    ): void => {
      const section = hierarchy.nodeById.get(sectionId);
      if (!section) return;
      const sectionNodeId = toCmsSectionNodeId(section.id);

      nodes.push({
        id: sectionNodeId,
        type: 'folder',
        kind: 'section',
        parentId: parentNodeId,
        name: getSectionNodeLabel(section),
        path: `${parentPath}/${section.id}`,
        sortOrder,
        metadata: {
          entity: 'section',
          zone: section.zone,
          sectionId: section.id,
          parentSectionId: section.parentSectionId ?? null,
        },
      });

      const childIds = hierarchy.childrenByParent.get(section.id) ?? [];
      childIds.forEach((childId: string, childIndex: number) => {
        pushSectionNode(childId, sectionNodeId, `${parentPath}/${section.id}`, childIndex);
      });
    };

    rootSectionIds.forEach((sectionId: string, sectionIndex: number) => {
      pushSectionNode(sectionId, zoneNodeId, zone, sectionIndex);
    });

    nodes.push({
      id: toCmsZoneFooterNodeId(zone),
      type: 'file',
      kind: 'zone_footer',
      parentId: zoneNodeId,
      name: `${zoneLabel} controls`,
      path: `${zone}/controls`,
      sortOrder: rootSectionIds.length,
      metadata: { entity: 'zone_footer', zone },
    });
  });

  return nodes;
};

'use client';

import React, { useCallback, useMemo, useContext } from 'react';

import { buildScopedCustomCss, getCustomCssSelector } from '@/features/cms/utils/custom-css';
import {
  getEventClassName,
  getEventEffectsConfig,
  getEventHoverStyle,
  isEventClickEnabled,
} from '@/features/cms/utils/event-effects';
import type { CmsEventEffectsConfig } from '@/shared/contracts/cms';
import { cn } from '@/shared/utils/ui-utils';
import { getMotionSafeScrollBehavior } from '@/shared/utils/motion-accessibility';

import { BlockRenderContext, BlockSettingsContext } from '../frontend/blocks/BlockContext';

interface EventEffectsWrapperProps {
  settings?: Record<string, unknown>;
  disableClick?: boolean;
  nodeId?: string;
  customCss?: unknown;
  children: React.ReactNode;
}

const INTERACTIVE_TAGS = new Set(['a', 'button', 'input', 'select', 'textarea', 'label']);

const isInteractiveElement = (element: React.ReactNode): boolean => {
  if (!React.isValidElement(element)) return false;
  return typeof element.type === 'string' && INTERACTIVE_TAGS.has(element.type);
};

const isInteractiveTarget = (target: EventTarget | null): boolean => {
  if (!target || !(target instanceof HTMLElement)) return false;
  return Boolean(target.closest('a,button,input,select,textarea,label'));
};

const normalizeScrollTarget = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed) return '';
  return trimmed.startsWith('#') ? trimmed : `#${trimmed}`;
};

export function EventEffectsWrapper({
  settings: settingsProp,
  disableClick = false,
  nodeId: nodeIdProp,
  customCss: customCssProp,
  children,
}: EventEffectsWrapperProps): React.ReactNode {
  const blockSettings = useContext(BlockSettingsContext);
  const blockRender = useContext(BlockRenderContext);

  const settings = settingsProp ?? blockSettings ?? {};
  const nodeId = nodeIdProp ?? blockRender?.block.id;
  const customCss = customCssProp ?? settings['customCss'];

  const config = useMemo<CmsEventEffectsConfig>(() => getEventEffectsConfig(settings), [settings]);
  const hoverStyle = useMemo(() => getEventHoverStyle(config), [config]);
  const eventClassName = useMemo(
    () => getEventClassName(config, { disableClick }),
    [config, disableClick]
  );
  const customCssSelector = nodeId ? getCustomCssSelector(nodeId) : null;
  const scopedCustomCss = useMemo(
    () => buildScopedCustomCss(customCss, customCssSelector),
    [customCss, customCssSelector]
  );
  const customClassName = nodeId ? `cms-node-${nodeId}` : '';
  const clickEnabled = isEventClickEnabled(config, disableClick);
  const childIsInteractive = isInteractiveElement(children);

  const runClickAction = useCallback(
    (event: {
      target: EventTarget | null;
      preventDefault: () => void;
      stopPropagation: () => void;
    }): void => {
      if (!clickEnabled) return;
      if (isInteractiveTarget(event.target)) return;

      if (config.clickAction === 'navigate') {
        const url = config.clickUrl.trim();
        if (!url) return;
        event.preventDefault();
        event.stopPropagation();
        if (config.clickTarget === '_blank') {
          window.open(url, '_blank', 'noopener,noreferrer');
        } else {
          window.location.assign(url);
        }
        return;
      }

      if (config.clickAction === 'scroll') {
        const target = normalizeScrollTarget(config.clickScrollTarget);
        if (!target) return;
        event.preventDefault();
        event.stopPropagation();
        const el = document.querySelector(target);
        if (el) {
          el.scrollIntoView({
            behavior: getMotionSafeScrollBehavior(config.clickScrollBehavior),
            block: 'start',
          });
        }
      }
    },
    [clickEnabled, config]
  );

  const handleClick = useCallback(
    (event: React.MouseEvent): void => {
      runClickAction(event);
    },
    [runClickAction]
  );

  const handleKeyDown = useCallback(
    (event: React.KeyboardEvent): void => {
      if (!clickEnabled) return;
      if (event.key !== 'Enter' && event.key !== ' ') return;
      event.preventDefault();
      runClickAction({
        target: event.target,
        preventDefault: () => event.preventDefault(),
        stopPropagation: () => event.stopPropagation(),
      });
    },
    [clickEnabled, runClickAction]
  );

  if (children === null || children === undefined) return children;

  if (!React.isValidElement(children)) {
    if (
      !eventClassName &&
      Object.keys(hoverStyle).length === 0 &&
      !scopedCustomCss &&
      !customClassName
    ) {
      return children;
    }

    return (
      <>
        {scopedCustomCss ? <style data-cms-custom-css={nodeId}>{scopedCustomCss}</style> : null}
        <div
          className={cn(eventClassName, customClassName)}
          style={hoverStyle}
          onClick={clickEnabled ? handleClick : undefined}
          onKeyDown={clickEnabled ? handleKeyDown : undefined}
          role={clickEnabled ? 'button' : undefined}
          tabIndex={clickEnabled ? 0 : undefined}
        >
          {children}
        </div>
      </>
    );
  }

  const existingClassName = (children.props as { className?: string }).className;
  const existingStyle = (children.props as { style?: React.CSSProperties }).style;
  const isFragment = children.type === React.Fragment;
  const mergedClassName = cn(existingClassName, eventClassName, customClassName);
  const mergedStyle = Object.keys(hoverStyle).length
    ? { ...(existingStyle ?? {}), ...hoverStyle }
    : existingStyle;

  const nextProps: Record<string, unknown> = isFragment
    ? {}
    : {
      className: mergedClassName,
      style: mergedStyle,
    };

  if (clickEnabled && !isFragment) {
    const existingOnClick = (children.props as { onClick?: (event: React.MouseEvent) => void })
      .onClick;
    const existingOnKeyDown = (
      children.props as { onKeyDown?: (event: React.KeyboardEvent) => void }
    ).onKeyDown;
    nextProps['onClick'] = (event: React.MouseEvent): void => {
      existingOnClick?.(event);
      if (!event.defaultPrevented) handleClick(event);
    };
    nextProps['onKeyDown'] = (event: React.KeyboardEvent): void => {
      existingOnKeyDown?.(event);
      if (!event.defaultPrevented) handleKeyDown(event);
    };
    if (!childIsInteractive) {
      nextProps['role'] = 'button';
      nextProps['tabIndex'] = 0;
    }
  }

  if (isFragment) {
    return (
      <>
        {scopedCustomCss ? <style data-cms-custom-css={nodeId}>{scopedCustomCss}</style> : null}
        <div
          className={cn(eventClassName, customClassName)}
          style={hoverStyle}
          onClick={clickEnabled ? handleClick : undefined}
          onKeyDown={clickEnabled ? handleKeyDown : undefined}
          role={clickEnabled ? 'button' : undefined}
          tabIndex={clickEnabled ? 0 : undefined}
        >
          {children}
        </div>
      </>
    );
  }

  return (
    <>
      {scopedCustomCss ? <style data-cms-custom-css={nodeId}>{scopedCustomCss}</style> : null}
      {React.cloneElement(children, nextProps)}
    </>
  );
}

'use client';

import React, { useMemo, useState } from 'react';

import type { Slug } from '@/shared/contracts/cms';
import type { EntityModalProps } from '@/shared/contracts/ui/modals';
import { FormModal, FormField } from '@/shared/ui/forms-and-actions.public';
import { LoadingState, UI_CENTER_ROW_SPACED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { SearchableList } from '@/shared/ui/data-display.public';
import { Button } from '@/shared/ui/primitives.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


interface AttachSlugModalProps extends EntityModalProps<Slug, Slug> {
  onAttach: (selectedIds: string[]) => Promise<void>;
  alreadyAssignedIds: Set<string>;
}

export function AttachSlugModal({
  isOpen,
  onClose,
  items: allSlugs = [],
  loading = false,
  onAttach,
  alreadyAssignedIds,
}: AttachSlugModalProps): React.JSX.Element | null {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [error, setError] = useState('');
  const [isAttaching, setIsAttaching] = useState(false);

  const availableSlugs = useMemo(() => {
    return allSlugs.filter((slug) => !alreadyAssignedIds.has(slug.id));
  }, [allSlugs, alreadyAssignedIds]);

  const toggleSelection = (slugId: string): void => {
    setSelectedIds((prev) =>
      prev.includes(slugId) ? prev.filter((id) => id !== slugId) : [...prev, slugId]
    );
  };

  const selectAllVisible = (): void => {
    const visibleIds = availableSlugs.map((slug) => slug.id);
    setSelectedIds((prev) => Array.from(new Set([...prev, ...visibleIds])));
  };

  const clearSelection = (): void => {
    setSelectedIds([]);
  };

  const handleAttach = async (): Promise<void> => {
    if (!selectedIds.length) {
      setError('Select at least one slug to attach.');
      return;
    }
    setError('');
    setIsAttaching(true);
    try {
      await onAttach(selectedIds);
      setSelectedIds([]);
      onClose();
    } catch (_err) {
      logClientError(_err);
      setError('Failed to attach slugs. Please try again.');
    } finally {
      setIsAttaching(false);
    }
  };

  const handleClose = (): void => {
    setSelectedIds([]);
    setError('');
    onClose();
  };

  return (
    <FormModal
      open={isOpen}
      onClose={handleClose}
      title='Attach Existing Slug'
      onSave={() => void handleAttach()}
      isSaving={isAttaching}
      saveText={`Attach ${selectedIds.length > 0 ? `(${selectedIds.length})` : ''}`}
      isSaveDisabled={selectedIds.length === 0}
      size='md'
    >
      <div className='space-y-4'>
        <FormField
          label='Route Assignment'
          description='Select global routes that are not yet assigned to this zone.'
        >
          {loading ? (
            <LoadingState message='Fetching global slug index...' className='py-8' size='sm' />
          ) : (
            <SearchableList
              items={availableSlugs}
              selectedIds={selectedIds}
              onToggle={toggleSelection}
              getId={(s) => s.id}
              getLabel={(s) => s.slug}
              searchPlaceholder='Filter slugs...'
              maxHeight='max-h-60'
              extraActions={
                <div className={`${UI_CENTER_ROW_SPACED_CLASSNAME} text-[10px] uppercase font-bold`}>
                  <Button
                    variant='link'
                    className='h-auto p-0 text-[10px] uppercase font-bold text-primary hover:text-primary/80 transition-colors'
                    onClick={selectAllVisible}
                  >
                    Select All
                  </Button>
                  <Button
                    variant='link'
                    className='h-auto p-0 text-[10px] uppercase font-bold text-muted-foreground hover:text-foreground transition-colors'
                    onClick={clearSelection}
                  >
                    Clear
                  </Button>
                </div>
              }
              renderItem={(slug) => (
                <div className='flex flex-col'>
                  <span className='text-sm font-medium text-gray-200 group-hover:text-white transition-colors'>
                    /{slug.slug}
                  </span>
                  <span className='text-[10px] text-muted-foreground font-mono'>{slug.id}</span>
                </div>
              )}
            />
          )}
        </FormField>
        {error && <p className='text-xs text-destructive font-medium px-1'>{error}</p>}
      </div>
    </FormModal>
  );
}

