import { getBlockDefinition } from '../../components/page-builder/section-registry';

import type { SectionInstance, BlockInstance } from '../../types/page-builder';

// ---------------------------------------------------------------------------
// ID generation
// ---------------------------------------------------------------------------

export const GLOBAL_ID_KEY = '__cmsNextId';

export function getNextId(): number {
  const globalScope = globalThis as { [GLOBAL_ID_KEY]?: number };
  const nextId = globalScope[GLOBAL_ID_KEY];
  if (typeof nextId !== 'number') {
    globalScope[GLOBAL_ID_KEY] = 1000;
    return 1000;
  }
  return nextId;
}

export function bumpNextId(target: number): void {
  const globalScope = globalThis as { [GLOBAL_ID_KEY]?: number };
  const nextId = globalScope[GLOBAL_ID_KEY];
  if (typeof nextId !== 'number' || nextId < target) {
    globalScope[GLOBAL_ID_KEY] = target;
  }
}

export function uid(): string {
  const current = getNextId();
  bumpNextId(current + 1);
  return `node-${current}`;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

export const NODE_ID_REGEX = /node-(\d+)/;
export const TEXT_ATOM_BLOCK_TYPE = 'TextAtom';
export const TEXT_ATOM_LETTER_TYPE = 'TextAtomLetter';
export const CONTAINER_BLOCK_TYPES = new Set([
  'ImageWithText',
  'Hero',
  'RichText',
  'Block',
  TEXT_ATOM_BLOCK_TYPE,
  'Carousel',
  'CarouselFrame',
  'Slideshow',
  'SlideshowFrame',
]);

// ---------------------------------------------------------------------------
// Sync & normalize helpers
// ---------------------------------------------------------------------------

export function syncNextIdFromSections(sections: SectionInstance[]): void {
  let maxId = 999;
  const stack: Array<SectionInstance | BlockInstance> = [...sections];
  while (stack.length) {
    const item = stack.pop();
    if (!item) continue;
    const id = typeof item.id === 'string' ? item.id : '';
    const match = NODE_ID_REGEX.exec(id);
    if (match) {
      const value = Number(match[1]);
      if (Number.isFinite(value)) {
        maxId = Math.max(maxId, value);
      }
    }
    const blocks = 'blocks' in item ? item.blocks : undefined;
    if (blocks && blocks.length > 0) {
      stack.push(...blocks);
    }
  }
  bumpNextId(maxId + 1);
}

export function normalizeTextAtomText(value: unknown): string {
  return typeof value === 'string' ? value : '';
}

export function buildTextAtomLetterBlocks(
  text: string,
  existing: BlockInstance[] | undefined,
  seen?: Set<string>
): BlockInstance[] {
  const def = getBlockDefinition(TEXT_ATOM_LETTER_TYPE);
  const letters = Array.from(text ?? '');
  return letters.map((char: string, index: number): BlockInstance => {
    const existingBlock = existing?.[index];
    const baseSettings = def?.defaultSettings ?? {};
    const nextSettings = {
      ...baseSettings,
      ...(existingBlock?.settings ?? {}),
      textContent: char,
    };
    const candidateId = existingBlock?.id ?? uid();
    const id = seen ? ensureUniqueId(candidateId, seen) : candidateId;
    return {
      id,
      type: TEXT_ATOM_LETTER_TYPE,
      settings: nextSettings,
    };
  });
}

export function applyTextAtomSettings(
  block: BlockInstance,
  nextSettings: Record<string, unknown>,
  seen?: Set<string>
): BlockInstance {
  if (block.type !== TEXT_ATOM_BLOCK_TYPE) {
    return { ...block, settings: nextSettings };
  }
  const text = normalizeTextAtomText(nextSettings['text']);
  const nextBlocks = buildTextAtomLetterBlocks(text, block.blocks, seen);
  return { ...block, settings: nextSettings, blocks: nextBlocks };
}

export function isContainerBlockType(type: string): boolean {
  return CONTAINER_BLOCK_TYPES.has(type);
}

// ---------------------------------------------------------------------------
// Block/section creation
// ---------------------------------------------------------------------------

export function createBlockInstance(type: string): BlockInstance | null {
  const def = getBlockDefinition(type);
  if (!def) return null;
  const baseSettings = { ...def.defaultSettings };
  if (type === TEXT_ATOM_BLOCK_TYPE) {
    const text = normalizeTextAtomText(baseSettings['text']);
    return {
      id: uid(),
      type,
      settings: baseSettings,
      blocks: buildTextAtomLetterBlocks(text, undefined),
    };
  }
  return {
    id: uid(),
    type,
    settings: baseSettings,
    ...(isContainerBlockType(type) ? { blocks: [] } : {}),
  };
}

export function ensureUniqueId(id: unknown, seen: Set<string>): string {
  let nextId = typeof id === 'string' && id.length > 0 ? id : uid();
  if (!seen.has(nextId)) {
    seen.add(nextId);
    return nextId;
  }
  do {
    nextId = uid();
  } while (seen.has(nextId));
  seen.add(nextId);
  return nextId;
}

export function createColumnBlock(): BlockInstance {
  const colDef = getBlockDefinition('Column');
  return {
    id: uid(),
    type: 'Column',
    settings: colDef ? { ...colDef.defaultSettings } : {},
    blocks: [],
  };
}

export function createRowBlock(columnCount: number): BlockInstance {
  const rowDef = getBlockDefinition('Row');
  const defaultSettings = rowDef ? { ...rowDef.defaultSettings } : {};
  return {
    id: uid(),
    type: 'Row',
    settings: defaultSettings,
    blocks: Array.from({ length: Math.max(1, columnCount) }, () => createColumnBlock()),
  };
}

// ---------------------------------------------------------------------------
// Grid operations
// ---------------------------------------------------------------------------

export function splitGridBlocks(blocks: BlockInstance[]): {
  rows: BlockInstance[];
  extras: BlockInstance[];
} {
  const rows: BlockInstance[] = [];
  const extras: BlockInstance[] = [];
  for (const block of blocks) {
    if (block.type === 'Row') {
      rows.push(block);
    } else {
      extras.push(block);
    }
  }
  return { rows, extras };
}

export function getCanonicalGridStructure(section: SectionInstance): {
  rows: BlockInstance[];
  extras: BlockInstance[];
  columnsPerRow: number;
} | null {
  if (section.type !== 'Grid') return null;
  const { rows, extras } = splitGridBlocks(section.blocks);
  if (rows.length === 0) return null;

  let columnsPerRow = 0;
  for (const row of rows) {
    const rowBlocks = row.blocks ?? [];
    if (rowBlocks.length === 0) return null;
    if (!rowBlocks.every((block: BlockInstance) => block.type === 'Column')) {
      return null;
    }
    columnsPerRow = Math.max(columnsPerRow, rowBlocks.length);
  }

  if (columnsPerRow <= 0) return null;
  return { rows, extras, columnsPerRow };
}

export function updateColumnBlocks(
  blocks: BlockInstance[],
  columnId: string,
  updater: (column: BlockInstance) => BlockInstance
): BlockInstance[] {
  return blocks.map((block: BlockInstance) => {
    if (block.type === 'Column') {
      return block.id === columnId ? updater(block) : block;
    }
    if (block.type === 'Row' && block.blocks) {
      return { ...block, blocks: updateColumnBlocks(block.blocks, columnId, updater) };
    }
    return block;
  });
}

export function updateRowBlocks(
  blocks: BlockInstance[],
  rowId: string,
  updater: (row: BlockInstance) => BlockInstance
): BlockInstance[] {
  return blocks.map((block: BlockInstance) => {
    if (block.type === 'Row') {
      return block.id === rowId ? updater(block) : block;
    }
    return block;
  });
}

// ---------------------------------------------------------------------------
// Block manipulation
// ---------------------------------------------------------------------------

export function removeColumnFromRows(
  blocks: BlockInstance[],
  columnId: string,
  rowId?: string
): { blocks: BlockInstance[]; removed: boolean } {
  let removed = false;
  const nextBlocks = blocks.map((block: BlockInstance) => {
    if (block.type !== 'Row') return block;
    const rowBlocks = block.blocks ?? [];
    const columns = rowBlocks.filter((b: BlockInstance) => b.type === 'Column');
    const isTargetRow = rowId
      ? block.id === rowId
      : rowBlocks.some((b: BlockInstance) => b.id === columnId);
    if (!isTargetRow) return block;
    if (columns.length <= 1) return block;
    const nextRowBlocks = rowBlocks.filter((b: BlockInstance) => b.id !== columnId);
    if (nextRowBlocks.length === rowBlocks.length) return block;
    removed = true;
    return { ...block, blocks: nextRowBlocks };
  });
  return { blocks: nextBlocks, removed };
}

export function removeBlockFromColumnBlocks(
  blocks: BlockInstance[],
  columnId: string,
  blockId: string,
  fromParentBlockId?: string
): { blocks: BlockInstance[]; moved?: BlockInstance } {
  let moved: BlockInstance | undefined;
  const nextBlocks = blocks.map((block: BlockInstance) => {
    if (block.type === 'Row' && block.blocks) {
      const result = removeBlockFromColumnBlocks(
        block.blocks,
        columnId,
        blockId,
        fromParentBlockId
      );
      if (result.moved) moved = result.moved;
      return { ...block, blocks: result.blocks };
    }
    if (block.type === 'Column' && block.id === columnId) {
      if (fromParentBlockId) {
        return {
          ...block,
          blocks: (block.blocks ?? []).map((pb: BlockInstance) => {
            if (pb.id !== fromParentBlockId) return pb;
            const found = (pb.blocks ?? []).find((eb: BlockInstance) => eb.id === blockId);
            if (found) moved = found;
            return {
              ...pb,
              blocks: (pb.blocks ?? []).filter((eb: BlockInstance) => eb.id !== blockId),
            };
          }),
        };
      }
      const found = (block.blocks ?? []).find((cb: BlockInstance) => cb.id === blockId);
      if (found) moved = found;
      return {
        ...block,
        blocks: (block.blocks ?? []).filter((cb: BlockInstance) => cb.id !== blockId),
      };
    }
    return block;
  });
  return { blocks: nextBlocks, ...(moved && { moved }) };
}

export function insertBlockIntoColumnBlocks(
  blocks: BlockInstance[],
  columnId: string,
  block: BlockInstance,
  toIndex: number,
  toParentBlockId?: string
): BlockInstance[] {
  return blocks.map((blockItem: BlockInstance) => {
    if (blockItem.type === 'Row' && blockItem.blocks) {
      return {
        ...blockItem,
        blocks: insertBlockIntoColumnBlocks(
          blockItem.blocks,
          columnId,
          block,
          toIndex,
          toParentBlockId
        ),
      };
    }
    if (blockItem.type === 'Column' && blockItem.id === columnId) {
      if (toParentBlockId) {
        return {
          ...blockItem,
          blocks: (blockItem.blocks ?? []).map((pb: BlockInstance) => {
            if (pb.id !== toParentBlockId) return pb;
            const newBlocks = [...(pb.blocks ?? [])];
            newBlocks.splice(toIndex, 0, block);
            return { ...pb, blocks: newBlocks };
          }),
        };
      }
      const newBlocks = [...(blockItem.blocks ?? [])];
      newBlocks.splice(toIndex, 0, block);
      return { ...blockItem, blocks: newBlocks };
    }
    return blockItem;
  });
}

export function updateSectionNestedBlocks(
  blocks: BlockInstance[],
  parentBlockId: string,
  updater: (block: BlockInstance) => BlockInstance
): BlockInstance[] {
  return blocks.map((block: BlockInstance) => {
    if (block.id === parentBlockId) {
      return updater(block);
    }
    if (block.blocks && block.blocks.length > 0) {
      return { ...block, blocks: updateSectionNestedBlocks(block.blocks, parentBlockId, updater) };
    }
    return block;
  });
}

// ---------------------------------------------------------------------------
// Lookups
// ---------------------------------------------------------------------------

export function findSection(sections: SectionInstance[], nodeId: string): SectionInstance | null {
  for (const s of sections) {
    if (s.id === nodeId) return s;
  }
  return null;
}

export function findBlock(
  sections: SectionInstance[],
  nodeId: string
): {
  block: BlockInstance;
  section: SectionInstance;
  parentColumn?: BlockInstance;
  parentBlock?: BlockInstance;
  parentRow?: BlockInstance;
} | null {
  const searchBlocks = (
    blocks: BlockInstance[],
    section: SectionInstance,
    parentColumn?: BlockInstance,
    parentBlock?: BlockInstance,
    parentRow?: BlockInstance
  ): {
    block: BlockInstance;
    section: SectionInstance;
    parentColumn?: BlockInstance;
    parentBlock?: BlockInstance;
    parentRow?: BlockInstance;
  } | null => {
    for (const b of blocks) {
      if (b.id === nodeId)
        return {
          block: b,
          section,
          ...(parentColumn && { parentColumn }),
          ...(parentBlock && { parentBlock }),
          ...(parentRow && { parentRow }),
        };
      if (!b.blocks || b.blocks.length === 0) continue;
      if (b.type === 'Column') {
        for (const cb of b.blocks ?? []) {
          if (cb.id === nodeId)
            return { block: cb, section, parentColumn: b, ...(parentRow && { parentRow }) };
          if (cb.blocks) {
            for (const eb of cb.blocks) {
              if (eb.id === nodeId)
                return {
                  block: eb,
                  section,
                  parentColumn: b,
                  parentBlock: cb,
                  ...(parentRow && { parentRow }),
                };
            }
          }
        }
        continue;
      }
      if (b.type === 'Row') {
        // Search inside Row - pass the Row as parentRow
        const nested = searchBlocks(b.blocks ?? [], section, parentColumn, parentBlock, b);
        if (nested) return nested;
        continue;
      }
      const nested = searchBlocks(b.blocks ?? [], section, parentColumn, b, parentRow);
      if (nested) return nested;
    }
    return null;
  };

  for (const s of sections) {
    const result = searchBlocks(s.blocks ?? [], s);
    if (result) return result;
  }
  return null;
}

export function findColumn(
  sections: SectionInstance[],
  nodeId: string
): { column: BlockInstance; section: SectionInstance } | null {
  const searchColumns = (
    blocks: BlockInstance[],
    section: SectionInstance
  ): { column: BlockInstance; section: SectionInstance } | null => {
    for (const b of blocks) {
      if (b.type === 'Column' && b.id === nodeId) return { column: b, section };
      if (b.blocks) {
        const nested = searchColumns(b.blocks, section);
        if (nested) return nested;
      }
    }
    return null;
  };
  for (const s of sections) {
    const result = searchColumns(s.blocks ?? [], s);
    if (result) return result;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Clone
// ---------------------------------------------------------------------------

export function cloneBlock(block: BlockInstance): BlockInstance {
  return {
    id: uid(),
    type: block.type,
    settings: { ...block.settings },
    ...(block.blocks ? { blocks: block.blocks.map(cloneBlock) } : {}),
  };
}

export function cloneSection(section: SectionInstance): SectionInstance {
  return {
    id: uid(),
    type: section.type,
    zone: section.zone,
    parentSectionId: section.parentSectionId ?? null,
    settings: { ...section.settings },
    blocks: section.blocks.map(cloneBlock),
  };
}

import {
  cloneBlock,
  uid,
  findSection,
  findBlock,
  insertBlockIntoColumnBlocks,
} from './block-helpers';
import { reduceBlockActions } from './page-builder-reducer/block-actions';
import { reduceComplexActions } from './page-builder-reducer/complex-actions';
import { reduceGridActions } from './page-builder-reducer/grid-actions';
import { reducePageActions } from './page-builder-reducer/page-actions';
import { reduceSectionActions } from './page-builder-reducer/section-actions';
import { reducePageBuilderMoveActions } from './page-builder-reducer-move-actions';
import {
  buildHierarchyIndexes,
  cloneSectionSubtree,
  moveSectionSubtree,
} from './section-hierarchy';
import { internalError } from '@/shared/errors/app-error';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import type {
  PageBuilderState,
  PageBuilderAction,
  SectionInstance,
} from '../../types/page-builder';

export function reducePageBuilderStateCore(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState {
  const moveActionResult = reducePageBuilderMoveActions(state, action);
  if (moveActionResult) {
    return moveActionResult;
  }

  const pageResult = reducePageActions(state, action);
  if (pageResult) return pageResult;

  const sectionResult = reduceSectionActions(state, action);
  if (sectionResult) return sectionResult;

  const blockResult = reduceBlockActions(state, action);
  if (blockResult) return blockResult;

  const gridResult = reduceGridActions(state, action);
  if (gridResult) return gridResult;

  const complexResult = reduceComplexActions(state, action);
  if (complexResult) return complexResult;

  switch (action.type) {
    case 'SET_PAGE_STATUS': {
      if (!state.currentPage) return state;
      return { ...state, currentPage: { ...state.currentPage, status: action.status } };
    }

    case 'SET_PAGE_NAME': {
      if (!state.currentPage) return state;
      return { ...state, currentPage: { ...state.currentPage, name: action.name } };
    }

    case 'UPDATE_SEO': {
      if (!state.currentPage) return state;
      return { ...state, currentPage: { ...state.currentPage, ...action.seo } };
    }

    case 'UPDATE_PAGE_SLUGS': {
      if (!state.currentPage) return state;
      const nextSlugs = state.currentPage.slugs.map((slug, index) => ({
        ...slug,
        ...(action.slugIds[index] ? { slugId: action.slugIds[index] } : {}),
        ...(action.slugValues[index] ? { slug: action.slugValues[index] } : {}),
      }));
      return { ...state, currentPage: { ...state.currentPage, slugs: nextSlugs } };
    }

    case 'SET_PAGE_MENU_VISIBILITY': {
      if (!state.currentPage) return state;
      return { ...state, currentPage: { ...state.currentPage, showMenu: action.showMenu } };
    }

    case 'SET_PAGE_THEME': {
      if (!state.currentPage) return state;
      return { ...state, currentPage: { ...state.currentPage, themeId: action.themeId } };
    }

    case 'TOGGLE_INSPECTOR':
      return { ...state, inspectorEnabled: !state.inspectorEnabled };

    case 'UPDATE_INSPECTOR_SETTINGS':
      return {
        ...state,
        inspectorSettings: { ...state.inspectorSettings, ...action.settings },
      };

    case 'SET_PREVIEW_MODE':
      return { ...state, previewMode: action.mode };

    case 'TOGGLE_LEFT_PANEL':
      return { ...state, leftPanelCollapsed: !state.leftPanelCollapsed };

    case 'TOGGLE_RIGHT_PANEL':
      return { ...state, rightPanelCollapsed: !state.rightPanelCollapsed };

    case 'COPY_SECTION': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;
      const hierarchy = buildHierarchyIndexes(state.sections);
      const subtree: SectionInstance[] = [];
      const visit = (sectionId: string): void => {
        const node = hierarchy.nodeById.get(sectionId);
        if (!node) return;
        subtree.push(node);
        const childIds = hierarchy.childrenByParent.get(sectionId) ?? [];
        childIds.forEach((childId: string) => visit(childId));
      };
      visit(section.id);
      return {
        ...state,
        clipboard: {
          type: 'section_hierarchy',
          data: {
            rootSectionId: section.id,
            sections: subtree,
          },
        },
      };
    }

    case 'PASTE_SECTION': {
      let sourceSections: SectionInstance[] = [];
      let sourceRootId: string | null = null;
      if (state.clipboard?.type === 'section_hierarchy') {
        sourceSections = state.clipboard.data.sections;
        sourceRootId = state.clipboard.data.rootSectionId ?? null;
      } else if (state.clipboard?.type === 'section') {
        const source = state.clipboard.data;
        sourceSections = [source];
        sourceRootId = source.id;
      } else {
        return state;
      }

      if (!sourceRootId || sourceSections.length === 0) return state;

      const clonedSubtree = cloneSectionSubtree(sourceSections, sourceRootId, uid);
      const clonedRoot = clonedSubtree[0];
      if (!clonedRoot) return state;
      const sectionsWithClone = [...state.sections, ...clonedSubtree];
      const moveResult = moveSectionSubtree(sectionsWithClone, {
        sectionId: clonedRoot.id,
        toZone: action.zone,
        toParentSectionId: null,
        toIndex: Number.MAX_SAFE_INTEGER,
      });

      return {
        ...state,
        sections: moveResult.ok ? moveResult.sections : sectionsWithClone,
        selectedNodeId: clonedRoot.id,
      };
    }

    case 'COPY_BLOCK': {
      const located = findBlock(state.sections, action.blockId);
      if (!located) return state;
      return {
        ...state,
        clipboard: {
          type: 'block',
          data: located.block,
        },
      };
    }

    case 'PASTE_BLOCK': {
      if (state.clipboard?.type !== 'block') return state;
      const nextBlock = cloneBlock(state.clipboard.data);
      const nextSections = state.sections.map((section) => {
        if (section.id !== action.sectionId) return section;
        if (action.columnId) {
          return {
            ...section,
            blocks: insertBlockIntoColumnBlocks(
              section.blocks,
              action.columnId,
              nextBlock,
              Number.MAX_SAFE_INTEGER,
              action.parentBlockId ?? undefined
            ),
          };
        }
        return {
          ...section,
          blocks: [...section.blocks, nextBlock],
        };
      });
      return {
        ...state,
        sections: nextSections,
        selectedNodeId: nextBlock.id,
      };
    }

    default:
      logClientCatch(internalError(`Unhandled page builder action: ${action.type}`), {
        source: 'cms.page-builder',
        action: 'reducePageBuilderStateCore',
        actionType: action.type,
      });
      return state;
  }
}

import {
  uid,
  normalizeTextAtomText,
  buildTextAtomLetterBlocks,
  removeBlockFromColumnBlocks,
  insertBlockIntoColumnBlocks,
  updateSectionNestedBlocks,
  findBlock,
  TEXT_ATOM_BLOCK_TYPE,
} from './block-helpers';
import { moveSectionSubtree } from './section-hierarchy';
import { getBlockDefinition } from '../../components/page-builder/section-registry';

import type {
  PageBuilderAction,
  PageBuilderState,
  BlockInstance,
  SectionInstance,
} from '../../types/page-builder';

export function reducePageBuilderMoveActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  const hasChildSections = (sectionId: string): boolean =>
    state.sections.some((section: SectionInstance) => section.parentSectionId === sectionId);

  switch (action.type) {
    case 'MOVE_BLOCK_TO_COLUMN': {
      // Remove block from source (section direct, column, row, or nested inside a parent block)
      const removeFromSource = (
        sections: SectionInstance[],
        fromSectionId: string,
        fromColumnId?: string,
        fromParentBlockId?: string,
        _fromRowId?: string
      ): { sections: SectionInstance[]; moved: BlockInstance | null } => {
        let moved: BlockInstance | null = null;
        const nextSections = sections.map((s: SectionInstance) => {
          if (s.id !== fromSectionId) return s;
          if (fromColumnId) {
            const result = removeBlockFromColumnBlocks(
              s.blocks,
              fromColumnId,
              action.blockId,
              fromParentBlockId
            );
            if (result.moved) moved = result.moved;
            return { ...s, blocks: result.blocks };
          }
          // Remove from section's direct blocks (could be from a row)
          const removeFromBlocks = (blocks: BlockInstance[]): BlockInstance[] => {
            return blocks.reduce<BlockInstance[]>((next: BlockInstance[], b: BlockInstance) => {
              if (b.id === action.blockId) {
                moved = b;
                return next;
              }
              if (b.type === 'Row' && b.blocks) {
                const idx = b.blocks.findIndex((rb: BlockInstance) => rb.id === action.blockId);
                if (idx !== -1) {
                  const foundBlock = b.blocks[idx];
                  if (foundBlock) moved = foundBlock;
                  next.push({
                    ...b,
                    blocks: b.blocks.filter((rb: BlockInstance) => rb.id !== action.blockId),
                  });
                  return next;
                }
              }
              if (b.blocks) {
                next.push({ ...b, blocks: removeFromBlocks(b.blocks) });
                return next;
              }
              next.push(b);
              return next;
            }, []);
          };
          return { ...s, blocks: removeFromBlocks(s.blocks) };
        });
        return { sections: nextSections, moved };
      };

      let removal = removeFromSource(
        state.sections,
        action.fromSectionId,
        action.fromColumnId,
        action.fromParentBlockId ?? undefined
      );
      if (!removal.moved) {
        const found = findBlock(state.sections, action.blockId);
        if (!found) return state;
        removal = removeFromSource(
          state.sections,
          found.section.id,
          found.parentColumn?.id,
          found.parentBlock?.id,
          found.parentRow?.id
        );
      }
      if (!removal.moved) return state;
      const movedBlock = removal.moved;
      // Insert into target (column direct or inside a parent block in a column)
      const sectionsAfterInsert = removal.sections.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        const insertInRequestedTarget = (): BlockInstance[] =>
          insertBlockIntoColumnBlocks(
            s.blocks,
            action.toColumnId,
            movedBlock,
            action.toIndex,
            action.toParentBlockId ?? undefined
          );
        const hasMovedBlock = (blocks: BlockInstance[]): boolean =>
          Boolean(
            findBlock(
              [
                {
                  ...s,
                  blocks,
                },
              ],
              movedBlock.id
            )
          );
        const requestedBlocks = insertInRequestedTarget();
        if (action.toParentBlockId && !hasMovedBlock(requestedBlocks)) {
          return {
            ...s,
            blocks: insertBlockIntoColumnBlocks(
              s.blocks,
              action.toColumnId,
              movedBlock,
              action.toIndex
            ),
          };
        }
        return {
          ...s,
          blocks: requestedBlocks,
        };
      });
      return { ...state, sections: sectionsAfterInsert };
    }

    case 'MOVE_BLOCK_TO_ROW': {
      // Remove block from source (section direct, column, or nested inside a parent block in a column)
      const removeFromSource = (
        sections: SectionInstance[],
        fromSectionId: string,
        fromColumnId?: string,
        fromParentBlockId?: string
      ): { sections: SectionInstance[]; moved: BlockInstance | null } => {
        let moved: BlockInstance | null = null;
        const nextSections = sections.map((s: SectionInstance) => {
          if (s.id !== fromSectionId) return s;
          if (fromColumnId) {
            const result = removeBlockFromColumnBlocks(
              s.blocks,
              fromColumnId,
              action.blockId,
              fromParentBlockId
            );
            if (result.moved) moved = result.moved;
            return { ...s, blocks: result.blocks };
          }
          // Remove from section's direct blocks (could be from a row)
          const removeFromBlocks = (blocks: BlockInstance[]): BlockInstance[] => {
            return blocks.reduce<BlockInstance[]>((next: BlockInstance[], b: BlockInstance) => {
              if (b.id === action.blockId) {
                moved = b;
                return next;
              }
              if (b.type === 'Row' && b.blocks) {
                const idx = b.blocks.findIndex((rb: BlockInstance) => rb.id === action.blockId);
                if (idx !== -1) {
                  const foundBlock = b.blocks[idx];
                  if (foundBlock) moved = foundBlock;
                  next.push({
                    ...b,
                    blocks: b.blocks.filter((rb: BlockInstance) => rb.id !== action.blockId),
                  });
                  return next;
                }
              }
              if (b.blocks) {
                next.push({ ...b, blocks: removeFromBlocks(b.blocks) });
                return next;
              }
              next.push(b);
              return next;
            }, []);
          };
          return { ...s, blocks: removeFromBlocks(s.blocks) };
        });
        return { sections: nextSections, moved };
      };

      let removal = removeFromSource(
        state.sections,
        action.fromSectionId,
        action.fromColumnId,
        action.fromParentBlockId ?? undefined
      );
      if (!removal.moved) {
        const found = findBlock(state.sections, action.blockId);
        if (!found) return state;
        removal = removeFromSource(
          state.sections,
          found.section.id,
          found.parentColumn?.id,
          found.parentBlock?.id
        );
      }
      if (!removal.moved) return state;
      const movedBlock = removal.moved;

      // Insert into target row
      const sectionsAfterInsert = removal.sections.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        let nestedInserted = false;
        const insertIntoRow = (blocks: BlockInstance[]): BlockInstance[] => {
          return blocks.map((b: BlockInstance) => {
            if (b.id === action.toRowId && b.type === 'Row') {
              if (action.toParentBlockId) {
                const updatedRowBlocks = updateSectionNestedBlocks(
                  b.blocks ?? [],
                  action.toParentBlockId,
                  (parent: BlockInstance) => {
                    nestedInserted = true;
                    const nextBlocks = [...(parent.blocks ?? [])];
                    nextBlocks.splice(action.toIndex, 0, movedBlock);
                    return { ...parent, blocks: nextBlocks };
                  }
                );
                if (nestedInserted) {
                  return { ...b, blocks: updatedRowBlocks };
                }
              }
              const nextBlocks = [...(b.blocks ?? [])];
              nextBlocks.splice(action.toIndex, 0, movedBlock);
              return { ...b, blocks: nextBlocks };
            }
            if (b.blocks) {
              return { ...b, blocks: insertIntoRow(b.blocks) };
            }
            return b;
          });
        };
        return { ...s, blocks: insertIntoRow(s.blocks) };
      });
      return { ...state, sections: sectionsAfterInsert };
    }

    case 'MOVE_BLOCK_TO_SECTION': {
      const removeFromSource = (
        sections: SectionInstance[],
        fromSectionId: string,
        fromColumnId?: string,
        fromParentBlockId?: string
      ): { sections: SectionInstance[]; moved: BlockInstance | null } => {
        let moved: BlockInstance | null = null;
        const nextSections = sections.map((s: SectionInstance) => {
          if (s.id !== fromSectionId) return s;
          if (fromColumnId) {
            const result = removeBlockFromColumnBlocks(
              s.blocks,
              fromColumnId,
              action.blockId,
              fromParentBlockId
            );
            if (result.moved) moved = result.moved;
            return { ...s, blocks: result.blocks };
          }
          // Remove from section's direct blocks (could be from a row)
          const removeFromBlocks = (blocks: BlockInstance[]): BlockInstance[] => {
            return blocks.reduce<BlockInstance[]>((next: BlockInstance[], b: BlockInstance) => {
              if (b.id === action.blockId) {
                moved = b;
                return next;
              }
              if (b.type === 'Row' && b.blocks) {
                const idx = b.blocks.findIndex((rb: BlockInstance) => rb.id === action.blockId);
                if (idx !== -1) {
                  const foundBlock = b.blocks[idx];
                  if (foundBlock) moved = foundBlock;
                  next.push({
                    ...b,
                    blocks: b.blocks.filter((rb: BlockInstance) => rb.id !== action.blockId),
                  });
                  return next;
                }
              }
              if (b.blocks) {
                next.push({ ...b, blocks: removeFromBlocks(b.blocks) });
                return next;
              }
              next.push(b);
              return next;
            }, []);
          };
          return { ...s, blocks: removeFromBlocks(s.blocks) };
        });
        return { sections: nextSections, moved };
      };

      let removal = removeFromSource(
        state.sections,
        action.fromSectionId,
        action.fromColumnId,
        action.fromParentBlockId ?? undefined
      );
      if (!removal.moved) {
        const found = findBlock(state.sections, action.blockId);
        if (!found) return state;
        removal = removeFromSource(
          state.sections,
          found.section.id,
          found.parentColumn?.id,
          found.parentBlock?.id
        );
      }
      if (!removal.moved) return state;
      const movedBlock = removal.moved;
      const sectionsAfterInsert = removal.sections.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        if (action.toParentBlockId) {
          let nestedInserted = false;
          const nextBlocks = updateSectionNestedBlocks(
            s.blocks,
            action.toParentBlockId,
            (parent: BlockInstance) => {
              nestedInserted = true;
              const childBlocks = [...(parent.blocks ?? [])];
              childBlocks.splice(action.toIndex, 0, movedBlock);
              return { ...parent, blocks: childBlocks };
            }
          );
          if (nestedInserted) {
            return { ...s, blocks: nextBlocks };
          }
        }
        const nextBlocks = [...s.blocks];
        nextBlocks.splice(action.toIndex, 0, movedBlock);
        return { ...s, blocks: nextBlocks };
      });
      return { ...state, sections: sectionsAfterInsert };
    }

    case 'MOVE_BLOCK_TO_SLIDESHOW_FRAME': {
      // Remove block from source (similar to MOVE_BLOCK_TO_SECTION)
      const removeFromSource = (
        sections: SectionInstance[],
        fromSectionId: string,
        fromColumnId?: string,
        fromParentBlockId?: string
      ): { sections: SectionInstance[]; moved: BlockInstance | null } => {
        let moved: BlockInstance | null = null;
        const nextSections = sections.map((s: SectionInstance) => {
          if (s.id !== fromSectionId) return s;
          if (fromColumnId) {
            const result = removeBlockFromColumnBlocks(
              s.blocks,
              fromColumnId,
              action.blockId,
              fromParentBlockId
            );
            if (result.moved) moved = result.moved;
            return { ...s, blocks: result.blocks };
          }
          // Remove from section's direct blocks (including from SlideshowFrames)
          const removeFromBlocks = (blocks: BlockInstance[]): BlockInstance[] => {
            return blocks.reduce<BlockInstance[]>((next: BlockInstance[], b: BlockInstance) => {
              if (b.id === action.blockId) {
                moved = b;
                return next;
              }
              if (b.blocks) {
                const idx = b.blocks.findIndex((rb: BlockInstance) => rb.id === action.blockId);
                if (idx !== -1) {
                  const foundBlock = b.blocks[idx];
                  if (foundBlock) moved = foundBlock;
                  next.push({
                    ...b,
                    blocks: b.blocks.filter((rb: BlockInstance) => rb.id !== action.blockId),
                  });
                  return next;
                }
                next.push({ ...b, blocks: removeFromBlocks(b.blocks) });
                return next;
              }
              next.push(b);
              return next;
            }, []);
          };
          return { ...s, blocks: removeFromBlocks(s.blocks) };
        });
        return { sections: nextSections, moved };
      };

      let removal = removeFromSource(
        state.sections,
        action.fromSectionId,
        action.fromColumnId,
        action.fromParentBlockId ?? undefined
      );
      if (!removal.moved) {
        const found = findBlock(state.sections, action.blockId);
        if (!found) return state;
        removal = removeFromSource(
          state.sections,
          found.section.id,
          found.parentColumn?.id,
          found.parentBlock?.id
        );
      }
      if (!removal.moved) return state;
      const movedBlock = removal.moved;

      // Insert into target SlideshowFrame
      const sectionsAfterInsert = removal.sections.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        return {
          ...s,
          blocks: s.blocks.map((b: BlockInstance) => {
            if (b.id !== action.toFrameId) return b;
            const frameBlocks = [...(b.blocks ?? [])];
            frameBlocks.splice(action.toIndex, 0, movedBlock);
            return { ...b, blocks: frameBlocks };
          }),
        };
      });
      return { ...state, sections: sectionsAfterInsert };
    }

    case 'MOVE_SECTION_TO_SLIDESHOW_FRAME': {
      const CONVERTIBLE_TYPES = [
        'ImageWithText',
        'RichText',
        'Hero',
        'Block',
        'TextElement',
        'ImageElement',
        'TextAtom',
        'ButtonElement',
        'Model3DElement',
        'Slideshow',
      ];
      const sourceSection = state.sections.find((s: SectionInstance) => s.id === action.sectionId);
      if (!sourceSection) return state;
      if (!CONVERTIBLE_TYPES.includes(sourceSection.type)) return state;
      if (hasChildSections(action.sectionId)) return state;
      // Prevent dropping into its own frames
      if (action.sectionId === action.toSectionId) return state;

      const resolvedBlockType =
        sourceSection.type === 'ButtonElement' ? 'Button' : sourceSection.type;
      const convertedBlock: BlockInstance = {
        id: uid(),
        type: resolvedBlockType,
        settings: { ...sourceSection.settings },
        blocks: sourceSection.blocks.length > 0 ? [...sourceSection.blocks] : [],
      };

      // Remove section from sections array
      const remaining = state.sections.filter((s: SectionInstance) => s.id !== action.sectionId);

      // Insert the converted block into the target SlideshowFrame
      const updatedSections = remaining.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        return {
          ...s,
          blocks: s.blocks.map((b: BlockInstance) => {
            if (b.id !== action.toFrameId) return b;
            const frameBlocks = [...(b.blocks ?? [])];
            frameBlocks.splice(action.toIndex, 0, convertedBlock);
            return { ...b, blocks: frameBlocks };
          }),
        };
      });

      return { ...state, sections: updatedSections, selectedNodeId: convertedBlock.id };
    }

    case 'CONVERT_BLOCK_TO_SECTION': {
      const located = findBlock(state.sections, action.blockId);
      if (!located) return state;
      const blockTypeToSectionType: Record<string, string> = {
        TextElement: 'TextElement',
        TextAtom: 'TextAtom',
        ImageElement: 'ImageElement',
        Button: 'ButtonElement',
        Block: 'Block',
        Model3DElement: 'Model3DElement',
        Slideshow: 'Slideshow',
      };
      const sectionType = blockTypeToSectionType[located.block.type];
      if (!sectionType) return state;

      let didRemove = false;
      const sectionsAfterRemove = state.sections.map((s: SectionInstance) => {
        if (s.id !== located.section.id) return s;
        if (located.parentColumn) {
          const result = removeBlockFromColumnBlocks(
            s.blocks,
            located.parentColumn.id,
            action.blockId,
            located.parentBlock?.id
          );
          if (result.moved) didRemove = true;
          return { ...s, blocks: result.blocks };
        }
        // Handle blocks inside a Row (but not in a Column)
        if (located.parentRow) {
          const parentRowId = located.parentRow.id;
          const updatedBlocks = s.blocks.map((block: BlockInstance) => {
            if (block.id !== parentRowId) return block;
            const hasBlockInRow = (block.blocks ?? []).some(
              (b: BlockInstance) => b.id === action.blockId
            );
            if (hasBlockInRow) didRemove = true;
            return {
              ...block,
              blocks: (block.blocks ?? []).filter((b: BlockInstance) => b.id !== action.blockId),
            };
          });
          return { ...s, blocks: updatedBlocks };
        }
        // Handle blocks inside a parent block (e.g., SlideshowFrame, Carousel, etc.)
        if (located.parentBlock) {
          const parentBlockId = located.parentBlock.id;
          const updatedBlocks = s.blocks.map((block: BlockInstance) => {
            if (block.id !== parentBlockId) return block;
            const hasBlockInParent = (block.blocks ?? []).some(
              (b: BlockInstance) => b.id === action.blockId
            );
            if (hasBlockInParent) didRemove = true;
            return {
              ...block,
              blocks: (block.blocks ?? []).filter((b: BlockInstance) => b.id !== action.blockId),
            };
          });
          return { ...s, blocks: updatedBlocks };
        }
        const hasBlock = s.blocks.some((b: BlockInstance) => b.id === action.blockId);
        if (hasBlock) didRemove = true;
        return { ...s, blocks: s.blocks.filter((b: BlockInstance) => b.id !== action.blockId) };
      });

      if (!didRemove) return state;

      const baseSettings = { ...(located.block.settings ?? {}) };
      const resolvedBlocks =
        located.block.type === TEXT_ATOM_BLOCK_TYPE
          ? buildTextAtomLetterBlocks(
            normalizeTextAtomText(baseSettings['text']),
            located.block.blocks
          )
          : located.block.blocks
            ? [...located.block.blocks]
            : [];
      const newSection: SectionInstance = {
        id: uid(),
        type: sectionType,
        zone: action.toZone,
        parentSectionId: null,
        settings: baseSettings,
        blocks: resolvedBlocks,
      };
      const sectionsWithNew = [...sectionsAfterRemove, newSection];
      const moveResult = moveSectionSubtree(sectionsWithNew, {
        sectionId: newSection.id,
        toZone: action.toZone,
        toParentSectionId: null,
        toIndex: action.toIndex,
      });
      if (!moveResult.ok)
        return { ...state, sections: sectionsWithNew, selectedNodeId: newSection.id };
      return { ...state, sections: moveResult.sections, selectedNodeId: newSection.id };
    }

    case 'CONVERT_SECTION_TO_BLOCK': {
      if (action.sectionId === action.toSectionId) return state;
      const sourceSection = state.sections.find((s: SectionInstance) => s.id === action.sectionId);
      if (!sourceSection) return state;
      if (hasChildSections(action.sectionId)) return state;
      if (
        sourceSection.type !== 'TextElement' &&
        sourceSection.type !== 'ImageElement' &&
        sourceSection.type !== 'ButtonElement' &&
        sourceSection.type !== TEXT_ATOM_BLOCK_TYPE
      )
        return state;
      const targetSection = state.sections.find(
        (s: SectionInstance) => s.id === action.toSectionId
      );
      if (!targetSection) return state;

      const resolvedBlockType =
        sourceSection.type === 'ButtonElement' ? 'Button' : sourceSection.type;
      const blockDef = getBlockDefinition(resolvedBlockType);
      const baseSettings = {
        ...(blockDef?.defaultSettings ?? {}),
        ...sourceSection.settings,
      };
      const textAtomBlocks =
        sourceSection.type === TEXT_ATOM_BLOCK_TYPE
          ? buildTextAtomLetterBlocks(
            normalizeTextAtomText(baseSettings['text']),
            sourceSection.blocks
          )
          : undefined;
      const convertedBlock: BlockInstance = {
        id: uid(),
        type: resolvedBlockType,
        settings: baseSettings,
        ...(textAtomBlocks ? { blocks: textAtomBlocks } : {}),
      };

      const remaining = state.sections.filter((s: SectionInstance) => s.id !== action.sectionId);
      const updatedSections = remaining.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        const nextBlocks = [...s.blocks];
        nextBlocks.splice(action.toIndex, 0, convertedBlock);
        return { ...s, blocks: nextBlocks };
      });

      return { ...state, sections: updatedSections, selectedNodeId: convertedBlock.id };
    }

    case 'MOVE_SECTION_TO_COLUMN': {
      const CONVERTIBLE_TYPES = [
        'ImageWithText',
        'RichText',
        'Hero',
        'Block',
        'TextElement',
        'ImageElement',
        'TextAtom',
        'ButtonElement',
        'Model3DElement',
        'Slideshow',
      ];
      const sourceSection = state.sections.find((s: SectionInstance) => s.id === action.sectionId);
      if (!sourceSection) return state;
      if (!CONVERTIBLE_TYPES.includes(sourceSection.type)) return state;
      if (hasChildSections(action.sectionId)) return state;
      // Prevent dropping a Grid into its own columns
      if (action.sectionId === action.toSectionId) return state;

      const resolvedBlockType =
        sourceSection.type === 'ButtonElement' ? 'Button' : sourceSection.type;
      const convertedBlock: BlockInstance = {
        id: uid(),
        type: resolvedBlockType,
        settings: { ...sourceSection.settings },
        blocks: sourceSection.blocks.length > 0 ? [...sourceSection.blocks] : [],
      };

      // Remove section from sections array
      const remaining = state.sections.filter((s: SectionInstance) => s.id !== action.sectionId);

      // Insert the converted block into the target column
      const updatedSections = remaining.map((s: SectionInstance) => {
        if (s.id !== action.toSectionId) return s;
        return {
          ...s,
          blocks: insertBlockIntoColumnBlocks(
            s.blocks,
            action.toColumnId,
            convertedBlock,
            action.toIndex,
            action.toParentBlockId ?? undefined
          ),
        };
      });

      return { ...state, sections: updatedSections, selectedNodeId: convertedBlock.id };
    }

    case 'MOVE_SECTION_TO_ZONE': {
      const moveResult = moveSectionSubtree(state.sections, {
        sectionId: action.sectionId,
        toZone: action.toZone,
        toParentSectionId: null,
        toIndex: action.toIndex,
      });
      if (!moveResult.ok) return state;
      return { ...state, sections: moveResult.sections };
    }

    case 'MOVE_SECTION_IN_TREE': {
      const moveResult = moveSectionSubtree(state.sections, {
        sectionId: action.sectionId,
        toZone: action.toZone,
        toParentSectionId: action.toParentSectionId ?? null,
        toIndex: action.toIndex,
      });
      if (!moveResult.ok) return state;
      return { ...state, sections: moveResult.sections };
    }

    default:
      return null;
  }
}

import { reducePageBuilderStateCore } from './page-builder-reducer-core';

import type {
  PageBuilderAction,
  PageBuilderSnapshot,
  PageBuilderState,
} from '../../types/page-builder';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

const HISTORY_LIMIT = 50;

const HISTORY_IGNORED_ACTIONS = new Set<PageBuilderAction['type']>([
  'SET_PAGES',
  'CLEAR_CURRENT_PAGE',
  'SELECT_NODE',
  'TOGGLE_LEFT_PANEL',
  'TOGGLE_RIGHT_PANEL',
  'COPY_SECTION',
  'COPY_BLOCK',
  'UPDATE_PAGE_SLUGS',
  'TOGGLE_INSPECTOR',
  'UPDATE_INSPECTOR_SETTINGS',
  'SET_PREVIEW_MODE',
]);

function makeSnapshot(state: PageBuilderState): PageBuilderSnapshot {
  return {
    currentPage: state.currentPage,
    sections: state.sections,
  };
}

export function pageBuilderReducer(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState {
  try {
    if (action.type === 'UNDO') {
      if (state.history.past.length === 0) return state;
      const previous = state.history.past[state.history.past.length - 1]!;
      const past = state.history.past.slice(0, -1);
      const future = [makeSnapshot(state), ...state.history.future];
      return {
        ...state,
        currentPage: previous.currentPage,
        sections: previous.sections,
        selectedNodeId: null,
        history: { past, future },
      };
    }

    if (action.type === 'REDO') {
      if (state.history.future.length === 0) return state;
      const next = state.history.future[0]!;
      const future = state.history.future.slice(1);
      const past = [...state.history.past, makeSnapshot(state)].slice(-HISTORY_LIMIT);
      return {
        ...state,
        currentPage: next.currentPage,
        sections: next.sections,
        selectedNodeId: null,
        history: { past, future },
      };
    }

    const nextState = reducePageBuilderStateCore(state, action);

    if (nextState === state) return state;

    if (action.type === 'SET_CURRENT_PAGE') {
      return {
        ...nextState,
        history: { past: [], future: [] },
      };
    }

    if (HISTORY_IGNORED_ACTIONS.has(action.type)) {
      return {
        ...nextState,
        history: state.history,
      };
    }

    const past = [...state.history.past, makeSnapshot(state)].slice(-HISTORY_LIMIT);
    return {
      ...nextState,
      history: { past, future: [] },
    };
  } catch (error) {
    logClientCatch(error, {
      source: 'cms.page-builder',
      action: 'pageBuilderReducer',
      actionType: action.type,
    });
    throw error;
  }
}

import type {
  PageBuilderState,
  PageBuilderAction,
  SectionInstance,
  BlockInstance,
} from '@/features/cms/types/page-builder';

import {
  applyTextAtomSettings,
  createBlockInstance,
  createRowBlock,
  getCanonicalGridStructure,
} from '../block-helpers';

export function reduceBlockActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  switch (action.type) {
    case 'ADD_BLOCK': {
      if (action.blockType === 'Row') {
        const updatedSections = state.sections.map((s: SectionInstance) => {
          if (s.id !== action.sectionId) return s;
          if (s.type !== 'Grid') return s;
          const canonical = getCanonicalGridStructure(s);
          if (!canonical) return s;
          const { rows, extras, columnsPerRow } = canonical;
          const nextRows = [...rows, createRowBlock(columnsPerRow)];
          return {
            ...s,
            blocks: [...nextRows, ...extras],
            settings: { ...s.settings, rows: nextRows.length, columns: columnsPerRow },
          };
        });
        return { ...state, sections: updatedSections };
      }
      const newBlock = createBlockInstance(action.blockType);
      if (!newBlock) return state;
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId) return s;
        return { ...s, blocks: [...s.blocks, newBlock] };
      });
      return {
        ...state,
        sections: updatedSections,
        selectedNodeId: newBlock.id,
      };
    }

    case 'REMOVE_BLOCK': {
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId
          ? {
            ...s,
            blocks: s.blocks.filter((b: BlockInstance) => b.id !== action.blockId),
          }
          : s
      );
      return {
        ...state,
        sections: updatedSections,
        selectedNodeId: state.selectedNodeId === action.blockId ? null : state.selectedNodeId,
      };
    }

    case 'UPDATE_BLOCK_SETTINGS': {
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId
          ? {
            ...s,
            blocks: s.blocks.map((b: BlockInstance) =>
              b.id === action.blockId
                ? applyTextAtomSettings(b, { ...b.settings, ...action.settings })
                : b
            ),
          }
          : s
      );
      return { ...state, sections: updatedSections };
    }

    case 'MOVE_BLOCK': {
      let movedBlock: BlockInstance | null = null;
      const sectionsAfterRemove = state.sections.map((s: SectionInstance) => {
        if (s.id === action.fromSectionId) {
          const block = s.blocks.find((b: BlockInstance) => b.id === action.blockId);
          if (block) movedBlock = block;
          return {
            ...s,
            blocks: s.blocks.filter((b: BlockInstance) => b.id !== action.blockId),
          };
        }
        return s;
      });
      if (!movedBlock) return state;
      const movedBlockValue = movedBlock;
      const sectionsAfterInsert = sectionsAfterRemove.map((s: SectionInstance) => {
        if (s.id === action.toSectionId) {
          const newBlocks = [...s.blocks];
          newBlocks.splice(action.toIndex, 0, movedBlockValue);
          return { ...s, blocks: newBlocks };
        }
        return s;
      });
      return { ...state, sections: sectionsAfterInsert };
    }

    case 'REORDER_BLOCKS': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId) return s;
        const newBlocks = [...s.blocks];
        const [moved] = newBlocks.splice(action.fromIndex, 1);
        if (!moved) return s;
        newBlocks.splice(action.toIndex, 0, moved);
        return { ...s, blocks: newBlocks };
      });
      return { ...state, sections: updatedSections };
    }

    default:
      return null;
  }
}

import type {
  PageBuilderState,
  PageBuilderAction,
  SectionInstance,
  BlockInstance,
} from '@/features/cms/types/page-builder';

import {
  uid,
  findSection,
  findBlock,
  createBlockInstance,
  removeColumnFromRows,
  updateSectionNestedBlocks,
} from '../block-helpers';
import {
  buildHierarchyIndexes,
  cloneSectionSubtree,
  moveSectionSubtree,
} from '../section-hierarchy';

export function reduceComplexActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  switch (action.type) {
    case 'DUPLICATE_SECTION': {
      const section = state.sections.find((s: SectionInstance) => s.id === action.sectionId);
      if (!section) return state;
      const duplicates = cloneSectionSubtree(state.sections, section.id, uid);
      if (duplicates.length === 0) return state;
      const duplicatedRoot = duplicates[0];
      if (!duplicatedRoot) return state;

      const hierarchy = buildHierarchyIndexes(state.sections);
      const siblings = section.parentSectionId
        ? (hierarchy.childrenByParent.get(section.parentSectionId) ?? [])
        : (hierarchy.childrenByParent.get(null) ?? []).filter((id: string) => {
          const node = hierarchy.nodeById.get(id);
          return node?.zone === section.zone;
        });
      const sourceIndex = siblings.indexOf(section.id);
      const targetIndex = sourceIndex >= 0 ? sourceIndex + 1 : siblings.length;

      const sectionsWithDuplicate = [...state.sections, ...duplicates];
      const moveResult = moveSectionSubtree(sectionsWithDuplicate, {
        sectionId: duplicatedRoot.id,
        toZone: section.zone,
        toParentSectionId: section.parentSectionId ?? null,
        toIndex: targetIndex,
      });

      return {
        ...state,
        sections: moveResult.ok ? moveResult.sections : sectionsWithDuplicate,
        selectedNodeId: duplicatedRoot.id,
      };
    }

    case 'REMOVE_COLUMN_FROM_ROW': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId || s.type !== 'Grid') return s;
        const result = removeColumnFromRows(s.blocks, action.columnId, action.rowId);
        if (!result.removed) return s;
        const rows = result.blocks.filter((block: BlockInstance) => block.type === 'Row');
        const nextColumnCount = Math.max(
          1,
          ...rows.map(
            (row: BlockInstance) =>
              (row.blocks ?? []).filter((block: BlockInstance) => block.type === 'Column').length
          )
        );
        return {
          ...s,
          blocks: result.blocks,
          settings: { ...s.settings, columns: nextColumnCount },
        };
      });
      return { ...state, sections: updatedSections };
    }

    case 'UPDATE_NESTED_BLOCK_SETTINGS': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;
      const located = findBlock([section], action.blockId);
      if (!located) return state;

      const nextBlocks = updateSectionNestedBlocks(
        section.blocks,
        action.blockId,
        (current: BlockInstance) => ({
          ...current,
          settings: { ...located.block.settings, ...action.settings },
        })
      );
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId ? { ...s, blocks: nextBlocks } : s
      );
      return { ...state, sections: updatedSections };
    }

    case 'ADD_ELEMENT_TO_NESTED_BLOCK': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;
      if (!findBlock([section], action.parentBlockId)) return state;
      const newBlock = createBlockInstance(action.elementType);
      if (!newBlock) return state;

      const nextBlocks = updateSectionNestedBlocks(
        section.blocks,
        action.parentBlockId,
        (block: BlockInstance) => ({
          ...block,
          blocks: [...(block.blocks ?? []), newBlock],
        })
      );
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId ? { ...s, blocks: nextBlocks } : s
      );
      return { ...state, sections: updatedSections, selectedNodeId: newBlock.id };
    }

    case 'REMOVE_ELEMENT_FROM_NESTED_BLOCK': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;

      const nextBlocks = updateSectionNestedBlocks(
        section.blocks,
        action.parentBlockId,
        (parent: BlockInstance) => ({
          ...parent,
          blocks: (parent.blocks ?? []).filter((b: BlockInstance) => b.id !== action.elementId),
        })
      );
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId ? { ...s, blocks: nextBlocks } : s
      );
      return {
        ...state,
        sections: updatedSections,
        selectedNodeId: state.selectedNodeId === action.elementId ? null : state.selectedNodeId,
      };
    }

    case 'ADD_ELEMENT_TO_SECTION_BLOCK': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;
      if (!findBlock([section], action.parentBlockId)) return state;
      const newBlock = createBlockInstance(action.elementType);
      if (!newBlock) return state;

      const nextBlocks = updateSectionNestedBlocks(
        section.blocks,
        action.parentBlockId,
        (block: BlockInstance) => ({
          ...block,
          blocks: [...(block.blocks ?? []), newBlock],
        })
      );
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId ? { ...s, blocks: nextBlocks } : s
      );
      return { ...state, sections: updatedSections, selectedNodeId: newBlock.id };
    }

    case 'REMOVE_ELEMENT_FROM_SECTION_BLOCK': {
      const section = findSection(state.sections, action.sectionId);
      if (!section) return state;

      const nextBlocks = updateSectionNestedBlocks(
        section.blocks,
        action.parentBlockId,
        (parent: BlockInstance) => ({
          ...parent,
          blocks: (parent.blocks ?? []).filter((b: BlockInstance) => b.id !== action.elementId),
        })
      );
      const updatedSections = state.sections.map((s: SectionInstance) =>
        s.id === action.sectionId ? { ...s, blocks: nextBlocks } : s
      );
      return {
        ...state,
        sections: updatedSections,
        selectedNodeId: state.selectedNodeId === action.elementId ? null : state.selectedNodeId,
      };
    }

    default:
      return null;
  }
}

import type {
  PageBuilderState,
  PageBuilderAction,
  SectionInstance,
  BlockInstance,
} from '@/features/cms/types/page-builder';

import { createColumnBlock, createRowBlock, getCanonicalGridStructure } from '../block-helpers';

export function reduceGridActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  switch (action.type) {
    case 'SET_GRID_COLUMNS': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId || s.type !== 'Grid') return s;
        const canonical = getCanonicalGridStructure(s);
        if (!canonical) return s;
        const { rows, extras } = canonical;
        const targetCols = Math.max(1, action.columnCount);
        const nextRows = rows.map((row: BlockInstance) => {
          const cols = (row.blocks ?? []).filter((b: BlockInstance) => b.type === 'Column');
          if (cols.length < targetCols) {
            const newCols = Array.from({ length: targetCols - cols.length }, () =>
              createColumnBlock()
            );
            return { ...row, blocks: [...cols, ...newCols] };
          }
          return { ...row, blocks: cols.slice(0, targetCols) };
        });
        return {
          ...s,
          blocks: [...nextRows, ...extras],
          settings: { ...s.settings, columns: targetCols, rows: nextRows.length },
        };
      });
      return { ...state, sections: updatedSections };
    }

    case 'SET_GRID_ROWS': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId || s.type !== 'Grid') return s;
        const canonical = getCanonicalGridStructure(s);
        if (!canonical) return s;
        const { rows, extras, columnsPerRow } = canonical;
        const targetRows = Math.max(1, action.rowCount);
        if (rows.length < targetRows) {
          const newRows = Array.from({ length: targetRows - rows.length }, () =>
            createRowBlock(columnsPerRow)
          );
          return {
            ...s,
            blocks: [...rows, ...newRows, ...extras],
            settings: { ...s.settings, rows: targetRows, columns: columnsPerRow },
          };
        }
        const nextRows = rows.slice(0, targetRows);
        return {
          ...s,
          blocks: [...nextRows, ...extras],
          settings: { ...s.settings, rows: targetRows, columns: columnsPerRow },
        };
      });
      return { ...state, sections: updatedSections };
    }

    case 'ADD_GRID_ROW': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId || s.type !== 'Grid') return s;
        const canonical = getCanonicalGridStructure(s);
        if (!canonical) return s;
        const { rows, extras, columnsPerRow } = canonical;
        const nextRows = [...rows, createRowBlock(columnsPerRow)];
        return {
          ...s,
          blocks: [...nextRows, ...extras],
          settings: { ...s.settings, rows: nextRows.length, columns: columnsPerRow },
        };
      });
      return { ...state, sections: updatedSections };
    }

    default:
      return null;
  }
}

import type {
  PageBuilderState,
  PageBuilderAction,
  SectionInstance,
} from '@/features/cms/types/page-builder';

import { syncNextIdFromSections } from '../block-helpers';

export function reducePageActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  switch (action.type) {
    case 'SET_PAGES':
      return { ...state, pages: action.pages };

    case 'SET_CURRENT_PAGE': {
      const page = action.page;
      const sections: SectionInstance[] = (page?.components ?? []).map(
        (comp): SectionInstance => {
          const content = comp.content;
          return {
            id: content.sectionId,
            type: comp.type,
            zone: content.zone,
            parentSectionId: content.parentSectionId,
            settings: content.settings,
            blocks: content.blocks,
          };
        }
      );
      syncNextIdFromSections(sections);
      return {
        ...state,
        currentPage: page,
        sections,
        selectedNodeId: null,
      };
    }

    case 'CLEAR_CURRENT_PAGE':
      return {
        ...state,
        currentPage: null,
        sections: [],
        selectedNodeId: null,
      };

    default:
      return null;
  }
}

import {
  getSectionDefinition,
  getBlockDefinition,
} from '@/features/cms/components/page-builder/section-registry';
import type {
  PageBuilderState,
  PageBuilderAction,
  PageZone,
  SectionInstance,
  BlockInstance,
} from '@/features/cms/types/page-builder';

import {
  uid,
  normalizeTextAtomText,
  buildTextAtomLetterBlocks,
  applyTextAtomSettings,
  createRowBlock,
  TEXT_ATOM_BLOCK_TYPE,
} from '../block-helpers';
import { moveSectionSubtree, removeSectionSubtree } from '../section-hierarchy';

export function reduceSectionActions(
  state: PageBuilderState,
  action: PageBuilderAction
): PageBuilderState | null {
  switch (action.type) {
    case 'SELECT_NODE':
      return { ...state, selectedNodeId: action.nodeId };

    case 'ADD_SECTION': {
      const sectionType = action.sectionType;
      const def = getSectionDefinition(sectionType);
      if (!def) return state;

      const settings = {
        ...def.defaultSettings,
        ...(action.initialSettings ?? {}),
      };
      let initialBlocks: BlockInstance[] = [];
      if (sectionType === 'Grid') {
        const rows = (settings['rows'] as number) ?? 1;
        const colCount = (settings['columns'] as number) ?? 2;
        initialBlocks = Array.from({ length: Math.max(1, rows) }, () => createRowBlock(colCount));
      } else if (sectionType === TEXT_ATOM_BLOCK_TYPE) {
        initialBlocks = buildTextAtomLetterBlocks(
          normalizeTextAtomText(settings['text']),
          undefined
        );
      } else if (sectionType === 'Slideshow') {
        const frameDef = getBlockDefinition('SlideshowFrame');
        if (frameDef) {
          initialBlocks = [
            {
              id: uid(),
              type: 'SlideshowFrame',
              settings: { ...frameDef.defaultSettings },
              blocks: [],
            },
          ];
        }
      }

      const newSection: SectionInstance = {
        id: uid(),
        type: sectionType,
        zone: action.zone,
        parentSectionId: null,
        settings,
        blocks: initialBlocks,
      };
      return {
        ...state,
        sections: [...state.sections, newSection],
        selectedNodeId: newSection.id,
      };
    }

    case 'REMOVE_SECTION': {
      const filtered = removeSectionSubtree(state.sections, action.sectionId);
      return {
        ...state,
        sections: filtered,
        selectedNodeId: state.selectedNodeId === action.sectionId ? null : state.selectedNodeId,
      };
    }

    case 'UPDATE_SECTION_SETTINGS': {
      const updatedSections = state.sections.map((s: SectionInstance) => {
        if (s.id !== action.sectionId) return s;
        const nextSettings = { ...s.settings, ...action.settings };
        if (s.type === TEXT_ATOM_BLOCK_TYPE) {
          const updatedBlock = applyTextAtomSettings(
            {
              id: s.id,
              type: TEXT_ATOM_BLOCK_TYPE,
              settings: s.settings,
              blocks: s.blocks,
            },
            nextSettings
          );
          return { ...s, settings: updatedBlock.settings, blocks: updatedBlock.blocks ?? [] };
        }
        return { ...s, settings: nextSettings };
      });
      return { ...state, sections: updatedSections };
    }

    case 'REORDER_SECTION_IN_ZONE':
    case 'REORDER_SECTIONS': {
      const zone: PageZone = action.zone;
      const rootSectionsInZone = state.sections.filter(
        (section: SectionInstance) => section.zone === zone && !section.parentSectionId
      );
      const fromIndex = action.fromIndex;
      const toIndex = action.toIndex;
      const moved = rootSectionsInZone[fromIndex] ?? null;
      if (!moved) return state;
      const result = moveSectionSubtree(state.sections, {
        sectionId: moved.id,
        toZone: zone,
        toParentSectionId: null,
        toIndex,
      });
      if (!result.ok) return state;
      return { ...state, sections: result.sections };
    }

    default:
      return null;
  }
}

import type {
  PageZone,
  SectionInstance as PageBuilderSectionInstance,
} from '../../types/page-builder';

type SectionInstance = PageBuilderSectionInstance & {
  parentSectionId?: string | null;
};

const ZONE_ORDER: PageZone[] = ['header', 'template', 'footer'];

export type HierarchyIndexes = {
  nodeById: Map<string, SectionInstance>;
  childrenByParent: Map<string | null, string[]>;
  depthById: Map<string, number>;
};

export type MoveSectionSubtreeInput = {
  sectionId: string;
  toZone: PageZone;
  toParentSectionId?: string | null;
  toIndex: number;
  maxDepth?: number | undefined;
};

export type MoveSectionSubtreeResult = {
  ok: boolean;
  sections: SectionInstance[];
  reason?:
    | 'SECTION_NOT_FOUND'
    | 'PARENT_NOT_FOUND'
    | 'TARGET_IS_SELF'
    | 'TARGET_IN_SUBTREE'
    | 'DEPTH_LIMIT_EXCEEDED'
    | undefined;
};

const clampIndex = (value: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, value));

const listFor = (map: Map<string | null, string[]>, key: string | null): string[] => {
  const list = map.get(key);
  if (list) return list;
  const next: string[] = [];
  map.set(key, next);
  return next;
};

const pushChild = (
  map: Map<string | null, string[]>,
  parentId: string | null,
  childId: string
): void => {
  const list = listFor(map, parentId);
  list.push(childId);
};

const createNodeMap = (sections: SectionInstance[]): Map<string, SectionInstance> => {
  const nodeById = new Map<string, SectionInstance>();
  sections.forEach((section: SectionInstance) => {
    if (nodeById.has(section.id)) return;
    nodeById.set(section.id, section);
  });
  return nodeById;
};

const buildChildrenByParentFromNodes = (
  nodes: Iterable<SectionInstance>
): Map<string | null, string[]> => {
  const childrenByParent = new Map<string | null, string[]>();
  childrenByParent.set(null, []);

  for (const section of nodes) {
    const parentId = section.parentSectionId ?? null;
    if (parentId && !childrenByParent.has(parentId)) {
      childrenByParent.set(parentId, []);
    }
    pushChild(childrenByParent, parentId, section.id);
  }

  return childrenByParent;
};

const computeDepths = (
  nodeById: Map<string, SectionInstance>,
  childrenByParent: Map<string | null, string[]>
): Map<string, number> => {
  const depthById = new Map<string, number>();

  const visit = (nodeId: string, depth: number): void => {
    depthById.set(nodeId, depth);
    const children = childrenByParent.get(nodeId) ?? [];
    children.forEach((childId: string) => {
      if (!nodeById.has(childId)) return;
      visit(childId, depth + 1);
    });
  };

  const roots = childrenByParent.get(null) ?? [];
  roots.forEach((rootId: string) => {
    if (!nodeById.has(rootId)) return;
    visit(rootId, 1);
  });

  return depthById;
};

const ensureNoCyclesAndInvalidParents = (sections: SectionInstance[]): SectionInstance[] => {
  const byId = createNodeMap(sections);

  const sanitized = sections.map((section: SectionInstance) => {
    const parentId = section.parentSectionId ?? null;
    if (!parentId || !byId.has(parentId) || parentId === section.id) {
      return { ...section, parentSectionId: null };
    }

    // Check ancestry chain for cycles
    let cursor: string | null = parentId;
    const seen = new Set<string>([section.id]);
    while (cursor) {
      if (seen.has(cursor)) {
        return { ...section, parentSectionId: null };
      }
      seen.add(cursor);
      const cursorNode = byId.get(cursor);
      if (!cursorNode) {
        return { ...section, parentSectionId: null };
      }
      cursor = cursorNode.parentSectionId ?? null;
    }

    return {
      ...section,
      parentSectionId: parentId,
    };
  });

  return sanitized;
};

const rebuildRootOrderByZone = (
  rootIds: string[],
  nodes: Map<string, SectionInstance>
): string[] => {
  const byZone: Record<PageZone, string[]> = { header: [], template: [], footer: [] };
  rootIds.forEach((id: string) => {
    const node = nodes.get(id);
    if (!node) return;
    byZone[node.zone].push(id);
  });
  return ZONE_ORDER.flatMap((zone: PageZone) => byZone[zone]);
};

const getSubtreeIds = (
  sectionId: string,
  childrenByParent: Map<string | null, string[]>
): Set<string> => {
  const ids = new Set<string>();
  const stack = [sectionId];
  while (stack.length > 0) {
    const current = stack.pop();
    if (!current || ids.has(current)) continue;
    ids.add(current);
    const children = childrenByParent.get(current) ?? [];
    children.forEach((child: string) => stack.push(child));
  }
  return ids;
};

const getSubtreeHeight = (
  sectionId: string,
  childrenByParent: Map<string | null, string[]>
): number => {
  const children = childrenByParent.get(sectionId) ?? [];
  if (children.length === 0) return 1;
  return (
    1 + Math.max(...children.map((childId: string) => getSubtreeHeight(childId, childrenByParent)))
  );
};

const cloneBlockTree = (
  blocks: SectionInstance['blocks'],
  uidFactory: () => string
): SectionInstance['blocks'] =>
  blocks.map((block) => ({
    ...block,
    id: uidFactory(),
    settings: block.settings ? { ...block.settings } : {},
    ...(Array.isArray(block.blocks) ? { blocks: cloneBlockTree(block.blocks, uidFactory) } : {}),
  }));

const flattenWithStructure = (
  nodeById: Map<string, SectionInstance>,
  childrenByParent: Map<string | null, string[]>
): SectionInstance[] => {
  const ordered: SectionInstance[] = [];

  const visit = (nodeId: string): void => {
    const node = nodeById.get(nodeId);
    if (!node) return;
    ordered.push(node);
    const children = childrenByParent.get(nodeId) ?? [];
    children.forEach((childId: string) => visit(childId));
  };

  const roots = childrenByParent.get(null) ?? [];
  const rootsByZone: Record<PageZone, string[]> = { header: [], template: [], footer: [] };
  roots.forEach((rootId: string) => {
    const node = nodeById.get(rootId);
    if (!node) return;
    rootsByZone[node.zone].push(rootId);
  });

  ZONE_ORDER.forEach((zone: PageZone) => {
    rootsByZone[zone].forEach((rootId: string) => visit(rootId));
  });

  return ordered;
};

const reindexDepths = (
  nodeById: Map<string, SectionInstance>,
  childrenByParent: Map<string | null, string[]>
): Map<string, number> => computeDepths(nodeById, childrenByParent);

export const sanitizeSectionHierarchy = (
  sections: SectionInstance[],
  maxDepth = 5
): SectionInstance[] => {
  const sanitizedInput = ensureNoCyclesAndInvalidParents(sections);
  const nodeById = createNodeMap(sanitizedInput);

  const childrenByParent = buildChildrenByParentFromNodes(nodeById.values());

  // Enforce zone inheritance down the tree.
  const applyZoneInheritance = (nodeId: string, inheritedZone: PageZone): void => {
    const node = nodeById.get(nodeId);
    if (!node) return;
    node.zone = inheritedZone;
    const children = childrenByParent.get(nodeId) ?? [];
    children.forEach((childId: string) => applyZoneInheritance(childId, inheritedZone));
  };

  const rootIds = childrenByParent.get(null) ?? [];
  rootIds.forEach((rootId: string) => {
    const root = nodeById.get(rootId);
    if (!root) return;
    applyZoneInheritance(rootId, root.zone);
  });

  // Enforce max depth by detaching overflowing nodes to root.
  let depthById = reindexDepths(nodeById, childrenByParent);
  const overflow = Array.from(depthById.entries())
    .filter(([, depth]) => depth > maxDepth)
    .sort((left, right) => right[1] - left[1]);

  overflow.forEach(([nodeId]: [string, number]) => {
    const node = nodeById.get(nodeId);
    if (!node) return;
    const oldParent = node.parentSectionId ?? null;
    if (oldParent) {
      const oldSiblings = listFor(childrenByParent, oldParent).filter(
        (id: string) => id !== nodeId
      );
      childrenByParent.set(oldParent, oldSiblings);
    }
    node.parentSectionId = null;
    pushChild(childrenByParent, null, nodeId);
    depthById = reindexDepths(nodeById, childrenByParent);
  });

  childrenByParent.set(null, rebuildRootOrderByZone(childrenByParent.get(null) ?? [], nodeById));

  return flattenWithStructure(nodeById, childrenByParent);
};

export const buildHierarchyIndexes = (sections: SectionInstance[]): HierarchyIndexes => {
  const sanitized = sanitizeSectionHierarchy(sections);
  const nodeById = createNodeMap(sanitized);
  const childrenByParent = buildChildrenByParentFromNodes(nodeById.values());
  childrenByParent.set(null, rebuildRootOrderByZone(childrenByParent.get(null) ?? [], nodeById));
  const depthById = computeDepths(nodeById, childrenByParent);
  return { nodeById, childrenByParent, depthById };
};

export const flattenByZonePreorder = (sections: SectionInstance[]): SectionInstance[] => {
  const { nodeById, childrenByParent } = buildHierarchyIndexes(sections);
  return flattenWithStructure(nodeById, childrenByParent);
};

export const isDescendant = (
  sections: SectionInstance[],
  ancestorId: string,
  candidateId: string
): boolean => {
  if (!ancestorId || !candidateId || ancestorId === candidateId) return false;
  const { childrenByParent } = buildHierarchyIndexes(sections);
  const stack = [...(childrenByParent.get(ancestorId) ?? [])];
  while (stack.length > 0) {
    const current = stack.pop();
    if (!current) continue;
    if (current === candidateId) return true;
    const children = childrenByParent.get(current) ?? [];
    children.forEach((childId: string) => stack.push(childId));
  }
  return false;
};

export const moveSectionSubtree = (
  sections: SectionInstance[],
  { sectionId, toZone, toParentSectionId = null, toIndex, maxDepth = 5 }: MoveSectionSubtreeInput
): MoveSectionSubtreeResult => {
  const sanitized = sanitizeSectionHierarchy(sections, maxDepth);
  const { nodeById, childrenByParent, depthById } = buildHierarchyIndexes(sanitized);
  const movingNode = nodeById.get(sectionId);
  if (!movingNode) {
    return { ok: false, reason: 'SECTION_NOT_FOUND', sections: sanitized };
  }

  if (toParentSectionId === sectionId) {
    return { ok: false, reason: 'TARGET_IS_SELF', sections: sanitized };
  }

  if (toParentSectionId && !nodeById.has(toParentSectionId)) {
    return { ok: false, reason: 'PARENT_NOT_FOUND', sections: sanitized };
  }

  if (toParentSectionId && isDescendant(sanitized, sectionId, toParentSectionId)) {
    return { ok: false, reason: 'TARGET_IN_SUBTREE', sections: sanitized };
  }

  const subtreeHeight = getSubtreeHeight(sectionId, childrenByParent);
  const targetDepth = toParentSectionId ? (depthById.get(toParentSectionId) ?? 0) + 1 : 1;
  if (targetDepth + subtreeHeight - 1 > maxDepth) {
    return { ok: false, reason: 'DEPTH_LIMIT_EXCEEDED', sections: sanitized };
  }

  // Remove from old siblings.
  const previousParentId = movingNode.parentSectionId ?? null;
  const previousSiblings = (childrenByParent.get(previousParentId) ?? []).filter(
    (id: string) => id !== sectionId
  );
  childrenByParent.set(previousParentId, previousSiblings);

  // Insert into target siblings.
  if (toParentSectionId) {
    const targetSiblings = [...(childrenByParent.get(toParentSectionId) ?? [])].filter(
      (id: string) => id !== sectionId
    );
    const insertAt = clampIndex(toIndex, 0, targetSiblings.length);
    targetSiblings.splice(insertAt, 0, sectionId);
    childrenByParent.set(toParentSectionId, targetSiblings);
  } else {
    const roots = [...(childrenByParent.get(null) ?? [])].filter((id: string) => id !== sectionId);
    const zoneRoots = roots.filter((id: string) => {
      const node = nodeById.get(id);
      return node?.zone === toZone;
    });
    const otherRootsByZone: Record<PageZone, string[]> = { header: [], template: [], footer: [] };
    roots.forEach((id: string) => {
      const node = nodeById.get(id);
      if (!node || node.zone === toZone) return;
      otherRootsByZone[node.zone].push(id);
    });
    const insertAt = clampIndex(toIndex, 0, zoneRoots.length);
    zoneRoots.splice(insertAt, 0, sectionId);
    const rebuiltRoots: string[] = [];
    ZONE_ORDER.forEach((zone: PageZone) => {
      if (zone === toZone) {
        rebuiltRoots.push(...zoneRoots);
      } else {
        rebuiltRoots.push(...otherRootsByZone[zone]);
      }
    });
    childrenByParent.set(null, rebuiltRoots);
  }

  const targetParentZone = toParentSectionId ? nodeById.get(toParentSectionId)?.zone : null;
  if (toParentSectionId && !targetParentZone) {
    return { ok: false, reason: 'PARENT_NOT_FOUND', sections: sanitized };
  }
  const resolvedZone = targetParentZone ?? toZone;

  movingNode.parentSectionId = toParentSectionId ?? null;

  // Update moved subtree zone to satisfy inheritance constraints.
  const subtreeIds = getSubtreeIds(sectionId, childrenByParent);
  subtreeIds.forEach((id: string) => {
    const node = nodeById.get(id);
    if (!node) return;
    node.zone = resolvedZone;
  });

  const flattened = flattenWithStructure(nodeById, childrenByParent);
  return { ok: true, sections: flattened };
};

export const removeSectionSubtree = (
  sections: SectionInstance[],
  sectionId: string
): SectionInstance[] => {
  const { nodeById, childrenByParent } = buildHierarchyIndexes(sections);
  if (!nodeById.has(sectionId)) return sections;
  const subtreeIds = getSubtreeIds(sectionId, childrenByParent);
  const nextSections = sections.filter((section: SectionInstance) => !subtreeIds.has(section.id));
  return sanitizeSectionHierarchy(nextSections);
};

export const cloneSectionSubtree = (
  sections: SectionInstance[],
  sectionId: string,
  uidFactory: () => string
): SectionInstance[] => {
  const sanitized = sanitizeSectionHierarchy(sections);
  const { nodeById, childrenByParent } = buildHierarchyIndexes(sanitized);
  if (!nodeById.has(sectionId)) return [];

  const clones: SectionInstance[] = [];
  const idMap = new Map<string, string>();

  const visit = (nodeId: string, parentCloneId: string | null): void => {
    const node = nodeById.get(nodeId);
    if (!node) return;
    const clonedId = uidFactory();
    idMap.set(nodeId, clonedId);
    const clone: SectionInstance = {
      ...node,
      id: clonedId,
      parentSectionId: parentCloneId,
      blocks: cloneBlockTree(node.blocks ?? [], uidFactory),
      settings: node.settings ? { ...node.settings } : {},
    };
    clones.push(clone);
    const children = childrenByParent.get(nodeId) ?? [];
    children.forEach((childId: string) => visit(childId, clonedId));
  };

  visit(sectionId, null);
  return clones;
};

'use client';

import { useEffect } from 'react';

import { usePageBuilder } from './usePageBuilderContext';

import type { PageBuilderAction } from '../types/page-builder';

function isEditableTarget(target: EventTarget | null): boolean {
  if (!(target instanceof HTMLElement)) return false;
  if (target.isContentEditable) return true;
  const tag = target.tagName.toLowerCase();
  return tag === 'input' || tag === 'textarea' || tag === 'select';
}

export function useBuilderKeyboardShortcuts(): void {
  const {
    state,
    dispatch,
    selectedSection,
    selectedBlock,
    selectedParentSection,
    selectedParentColumn,
    selectedParentBlock,
    selectedColumn,
    selectedColumnParentSection,
  } = usePageBuilder();

  useEffect((): (() => void) => {
    const handleKeyDown = (event: KeyboardEvent): void => {
      if (isEditableTarget(event.target)) return;

      const key = event.key.toLowerCase();
      const isMod = event.metaKey || event.ctrlKey;

      if (isMod && key === 'z') {
        event.preventDefault();
        dispatch({ type: event.shiftKey ? 'REDO' : 'UNDO' });
        return;
      }

      if (isMod && key === 'y') {
        event.preventDefault();
        dispatch({ type: 'REDO' });
        return;
      }

      if (isMod && key === 'c') {
        if (selectedSection) {
          event.preventDefault();
          dispatch({ type: 'COPY_SECTION', sectionId: selectedSection.id });
          return;
        }
        if (selectedBlock && selectedParentSection) {
          event.preventDefault();
          dispatch({
            type: 'COPY_BLOCK',
            sectionId: selectedParentSection.id,
            blockId: selectedBlock.id,
            ...(selectedParentColumn?.id && { columnId: selectedParentColumn.id }),
            ...(selectedParentBlock?.id && { parentBlockId: selectedParentBlock.id }),
          });
        }
        return;
      }

      if (isMod && key === 'v') {
        if (!state.clipboard) return;
        event.preventDefault();
        if (state.clipboard.type === 'section' || state.clipboard.type === 'section_hierarchy') {
          const zone = selectedSection?.zone ?? 'template';
          dispatch({ type: 'PASTE_SECTION', zone });
          return;
        }
        if (state.clipboard.type === 'block') {
          const targetSectionId =
            selectedParentSection?.id ?? selectedColumnParentSection?.id ?? selectedSection?.id;
          if (!targetSectionId) return;

          const columnId = selectedParentColumn?.id ?? selectedColumn?.id;
          const parentBlockId = selectedParentBlock?.id;

          const pasteAction: PageBuilderAction = {
            type: 'PASTE_BLOCK',
            sectionId: targetSectionId,
            ...(columnId && { columnId }),
            ...(parentBlockId && { parentBlockId }),
          };
          dispatch(pasteAction);
        }
        return;
      }

      if (event.key === 'Escape') {
        if (state.selectedNodeId) {
          event.preventDefault();
          dispatch({ type: 'SELECT_NODE', nodeId: null });
        }
        return;
      }

      if (event.key === 'Delete' || event.key === 'Backspace') {
        if (selectedSection) {
          event.preventDefault();
          dispatch({ type: 'REMOVE_SECTION', sectionId: selectedSection.id });
          return;
        }

        if (selectedBlock && selectedParentSection) {
          event.preventDefault();
          if (selectedParentColumn && selectedParentBlock) {
            dispatch({
              type: 'REMOVE_ELEMENT_FROM_NESTED_BLOCK',
              sectionId: selectedParentSection.id,
              columnId: selectedParentColumn.id,
              parentBlockId: selectedParentBlock.id,
              elementId: selectedBlock.id,
            });
            return;
          }

          if (selectedParentColumn) {
            dispatch({
              type: 'REMOVE_BLOCK_FROM_COLUMN',
              sectionId: selectedParentSection.id,
              columnId: selectedParentColumn.id,
              blockId: selectedBlock.id,
            });
            return;
          }

          dispatch({
            type: 'REMOVE_BLOCK',
            sectionId: selectedParentSection.id,
            blockId: selectedBlock.id,
          });
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return (): void => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [
    dispatch,
    selectedSection,
    selectedBlock,
    selectedParentSection,
    selectedParentColumn,
    selectedParentBlock,
    selectedColumn,
    selectedColumnParentSection,
    state.clipboard,
    state.selectedNodeId,
  ]);
}

