const appendOptionalUploadField = (
  formData: FormData,
  key: string,
  value: string | null | undefined
): void => {
  const trimmed = value?.trim() ?? '';
  if (trimmed.length > 0) {
    formData.append(key, trimmed);
  }
};

export function useUploadCmsMedia(): CreateMutation<
  ImageFileRecord,
  {
    file: File;
    onProgress?: (loaded: number, total?: number) => void;
    folder?: string | null;
    storageProfile?: FileStorageProfile;
  }
  > {
  return useMutationV2({
    mutationFn: async ({
      file,
      onProgress,
      folder,
      storageProfile,
    }: {
      file: File;
      onProgress?: (loaded: number, total?: number) => void;
      folder?: string | null;
      storageProfile?: FileStorageProfile;
    }): Promise<ImageFileRecord> => {
      const formData = new FormData();
      formData.append('file', file);
      appendOptionalUploadField(formData, 'folder', folder);
      appendOptionalUploadField(
        formData,
        'storageProfile',
        storageProfile !== 'default' ? storageProfile : undefined
      );
      const { uploadWithProgress } = await import('@/shared/utils/upload-with-progress');
      const result = await uploadWithProgress<ImageFileRecord>('/api/cms/media', {
        formData,
        onProgress,
      });
      if (!result.ok) {
        const data = result.data as { error?: string };
        throw new Error(data.error ?? 'Upload failed');
      }
      return result.data;
    },
    mutationKey: cmsKeys.mutation('upload-media'),
    meta: {
      source: 'cms.hooks.useUploadCmsMedia',
      operation: 'upload',
      resource: 'cms.media',
      domain: 'cms',

      tags: ['cms', 'media', 'upload'],
      description: 'Uploads cms media.'},
    invalidate: async (queryClient) => {
      await invalidateFiles(queryClient);
    },
  });
}

'use client';

import { useCallback } from 'react';

import {
  COLUMN_ALLOWED_BLOCK_TYPES,
  ROW_ALLOWED_BLOCK_TYPES,
  getSectionDefinition,
  getBlockDefinition,
} from '../components/page-builder/section-registry';

export interface DropValidationResult {
  isValid: boolean;
  reason?: string;
}

// Block types that can be nested inside other blocks (container blocks)
const CONTAINER_BLOCK_TYPES = new Set([
  'ImageWithText',
  'Hero',
  'RichText',
  'Block',
  'TextAtom',
  'Carousel',
  'CarouselFrame',
  'Slideshow',
  'SlideshowFrame',
]);

// Section types that can be converted to blocks
const CONVERTIBLE_SECTION_TYPES = new Set([
  'ImageWithText',
  'Hero',
  'RichText',
  'Block',
  'TextElement',
  'ImageElement',
  'TextAtom',
  'ButtonElement',
  'Model3DElement',
  'Slideshow',
]);

/**
 * Hook for validating drag-and-drop operations in the CMS page builder.
 * Provides functions to check if a block can be dropped in various targets.
 */
export function useDropValidation(): {
  canDropInRow: (blockType: string) => DropValidationResult;
  canDropInColumn: (blockType: string) => DropValidationResult;
  canDropInSection: (blockType: string, sectionType: string) => DropValidationResult;
  canDropInNestedBlock: (blockType: string, parentBlockType: string) => DropValidationResult;
  canConvertSectionToBlock: (sectionType: string) => DropValidationResult;
  isContainerBlock: (blockType: string) => boolean;
  } {
  /**
   * Check if a block type can be dropped directly into a Row
   */
  const canDropInRow = useCallback((blockType: string): DropValidationResult => {
    if (ROW_ALLOWED_BLOCK_TYPES.includes(blockType)) {
      return { isValid: true };
    }
    return {
      isValid: false,
      reason: `"${blockType}" cannot be placed directly in a Row. Allowed types: Column, TextElement, ImageElement, Button, etc.`,
    };
  }, []);

  /**
   * Check if a block type can be dropped into a Column
   */
  const canDropInColumn = useCallback((blockType: string): DropValidationResult => {
    if (COLUMN_ALLOWED_BLOCK_TYPES.includes(blockType)) {
      return { isValid: true };
    }
    return {
      isValid: false,
      reason: `"${blockType}" cannot be placed in a Column. Allowed types: Heading, Text, TextElement, ImageElement, Button, etc.`,
    };
  }, []);

  /**
   * Check if a block type can be dropped into a specific section type
   */
  const canDropInSection = useCallback(
    (blockType: string, sectionType: string): DropValidationResult => {
      const sectionDef = getSectionDefinition(sectionType);
      if (!sectionDef) {
        return { isValid: false, reason: `Unknown section type: ${sectionType}` };
      }

      if (sectionDef.allowedBlockTypes.includes(blockType)) {
        return { isValid: true };
      }

      return {
        isValid: false,
        reason: `"${blockType}" cannot be placed in "${sectionDef.label}" section.`,
      };
    },
    []
  );

  /**
   * Check if a block type can be dropped into a nested block (container block)
   */
  const canDropInNestedBlock = useCallback(
    (blockType: string, parentBlockType: string): DropValidationResult => {
      // First check if the parent is a container block
      if (!CONTAINER_BLOCK_TYPES.has(parentBlockType)) {
        return {
          isValid: false,
          reason: `"${parentBlockType}" is not a container block and cannot hold child elements.`,
        };
      }

      // Check the block definition for allowed types
      const blockDef = getBlockDefinition(parentBlockType);
      if (!blockDef) {
        return { isValid: false, reason: `Unknown block type: ${parentBlockType}` };
      }

      // For blocks that use the section definition's allowed types
      const sectionDef = getSectionDefinition(parentBlockType);
      if (sectionDef?.allowedBlockTypes.includes(blockType)) {
        return { isValid: true };
      }

      // For TextAtom, only TextAtomLetter is allowed
      if (parentBlockType === 'TextAtom') {
        if (blockType === 'TextAtomLetter') {
          return { isValid: true };
        }
        return {
          isValid: false,
          reason: 'TextAtom can only contain TextAtomLetter elements.',
        };
      }

      // Default container block types allow common elements
      const commonAllowed = [
        'Heading',
        'Text',
        'TextElement',
        'ImageElement',
        'Button',
        'AppEmbed',
      ];
      if (commonAllowed.includes(blockType)) {
        return { isValid: true };
      }

      return {
        isValid: false,
        reason: `"${blockType}" cannot be placed inside "${parentBlockType}".`,
      };
    },
    []
  );

  /**
   * Check if a section can be converted to a block (for dropping sections into columns)
   */
  const canConvertSectionToBlock = useCallback((sectionType: string): DropValidationResult => {
    if (CONVERTIBLE_SECTION_TYPES.has(sectionType)) {
      return { isValid: true };
    }
    return {
      isValid: false,
      reason: `"${sectionType}" sections cannot be converted to blocks.`,
    };
  }, []);

  /**
   * Check if a block type is a container that can hold other blocks
   */
  const isContainerBlock = useCallback((blockType: string): boolean => {
    return CONTAINER_BLOCK_TYPES.has(blockType);
  }, []);

  return {
    canDropInRow,
    canDropInColumn,
    canDropInSection,
    canDropInNestedBlock,
    canConvertSectionToBlock,
    isContainerBlock,
  };
}

'use client';

import React, { useReducer, useMemo, useState, useCallback, type ReactNode } from 'react';

import type {
  PageBuilderState,
  PageBuilderAction,
  InspectorSettings,
} from '@/shared/contracts/cms';

import { usePageBuilderPolicy } from '@/features/cms/components/page-builder/PageBuilderPolicyContext';

import { findSection, findBlock, findColumn } from './page-builder/block-helpers';
import { pageBuilderReducer } from './page-builder/page-builder-reducer';
import { PageDispatchContext, usePageBuilderDispatch } from './page-builder/PageDispatchContext';
import {
  PageSelectionContext,
  type PageSelectionValue,
  usePageBuilderSelection,
} from './page-builder/PageSelectionContext';
import { PageStateContext, usePageBuilderState } from './page-builder/PageStateContext';
import {
  VectorOverlayContext,
  type VectorOverlayRequest,
  type VectorOverlayValue,
  useVectorOverlay,
  type VectorOverlayResult,
} from './page-builder/VectorOverlayContext';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

export { pageBuilderReducer } from './page-builder/page-builder-reducer';
export { usePageBuilderState, usePageBuilderDispatch, usePageBuilderSelection, useVectorOverlay };
export type { VectorOverlayResult, VectorOverlayRequest };

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

const DEFAULT_INSPECTOR_SETTINGS: InspectorSettings = {
  showTooltip: true,
  showStyleSettings: true,
  showStructureInfo: true,
  showIdentifiers: false,
  showVisibilityInfo: true,
  showConnectionInfo: true,
  showEditorChrome: true,
  showLayoutGuides: true,
  pauseAnimations: false,
};

export const initialState: PageBuilderState = {
  pages: [],
  currentPage: null,
  sections: [],
  selectedNodeId: null,
  inspectorEnabled: false,
  inspectorSettings: DEFAULT_INSPECTOR_SETTINGS,
  previewMode: 'desktop',
  leftPanelCollapsed: false,
  rightPanelCollapsed: false,
  clipboard: null,
  history: { past: [], future: [] },
};

export interface PageBuilderContextValue extends PageSelectionValue, VectorOverlayValue {
  state: PageBuilderState;
  dispatch: React.Dispatch<PageBuilderAction>;
}

export function PageBuilderProvider({
  children,
  initialState: customInitialState = initialState,
}: {
  children: ReactNode;
  initialState?: PageBuilderState;
}): React.ReactNode {
  const policy = usePageBuilderPolicy();
  const [state, rawDispatch] = useReducer(
    (currentState: PageBuilderState, action: PageBuilderAction): PageBuilderState =>
      policy.sanitizeState(pageBuilderReducer(currentState, action)),
    customInitialState,
    policy.sanitizeState
  );

  const dispatch = useCallback((action: PageBuilderAction): void => {
    try {
      rawDispatch(action);
    } catch (error) {
      logClientCatch(error, {
        source: 'cms.page-builder',
        action: 'dispatch',
        actionType: action.type,
      });
      throw error;
    }
  }, [rawDispatch]);

  const [vectorOverlay, setVectorOverlay] = useState<VectorOverlayRequest | null>(null);

  const openVectorOverlay = useCallback((request: VectorOverlayRequest): void => {
    setVectorOverlay(request);
  }, []);

  const closeVectorOverlay = useCallback((): void => {
    setVectorOverlay(null);
  }, []);

  const selectionValue = useMemo((): PageSelectionValue => {
    const empty: PageSelectionValue = {
      selectedSection: null,
      selectedBlock: null,
      selectedParentSection: null,
      selectedColumn: null,
      selectedColumnParentSection: null,
      selectedParentColumn: null,
      selectedParentRow: null,
      selectedParentBlock: null,
    };
    if (!state.selectedNodeId) return empty;

    // Check if it's a section
    const section = findSection(state.sections, state.selectedNodeId);
    if (section) {
      return { ...empty, selectedSection: section };
    }

    // Check if it's a column
    const colResult = findColumn(state.sections, state.selectedNodeId);
    if (colResult) {
      return {
        ...empty,
        selectedColumn: colResult.column,
        selectedColumnParentSection: colResult.section,
      };
    }

    // Check if it's a block (including blocks inside columns and nested blocks)
    const blockResult = findBlock(state.sections, state.selectedNodeId);
    if (blockResult) {
      return {
        ...empty,
        selectedBlock: blockResult.block,
        selectedParentSection: blockResult.section,
        selectedParentColumn: blockResult.parentColumn ?? null,
        selectedParentRow: blockResult.parentRow ?? null,
        selectedParentBlock: blockResult.parentBlock ?? null,
      };
    }

    return empty;
  }, [state.sections, state.selectedNodeId]);

  const vectorOverlayValue = useMemo(
    (): VectorOverlayValue => ({
      vectorOverlay,
      openVectorOverlay,
      closeVectorOverlay,
    }),
    [vectorOverlay, openVectorOverlay, closeVectorOverlay]
  );

  return (
    <PageStateContext.Provider value={state}>
      <PageDispatchContext.Provider value={dispatch}>
        <PageSelectionContext.Provider value={selectionValue}>
          <VectorOverlayContext.Provider value={vectorOverlayValue}>
            {children}
          </VectorOverlayContext.Provider>
        </PageSelectionContext.Provider>
      </PageDispatchContext.Provider>
    </PageStateContext.Provider>
  );
}

export function usePageBuilder(): PageBuilderContextValue {
  const state = usePageBuilderState();
  const dispatch = usePageBuilderDispatch();
  const selection = usePageBuilderSelection();
  const vectorOverlay = useVectorOverlay();

  return useMemo(
    () => ({
      state,
      dispatch,
      ...selection,
      ...vectorOverlay,
    }),
    [state, dispatch, selection, vectorOverlay]
  );
}

