'use client';

import { useCallback, type Dispatch } from 'react';

import type { PageBuilderAction } from '@/shared/contracts/cms';

import type { TreeActionsActionsContextValue } from './useTreeActionsContext.types';
import type { PageZone, SectionInstance } from '../types/page-builder';

export function useTreeSectionActions({
  dispatch,
  autoExpand,
  sections,
}: {
  dispatch: Dispatch<PageBuilderAction>;
  autoExpand: TreeActionsActionsContextValue['autoExpand'];
  sections: SectionInstance[];
}) {
  const addSection = useCallback(
    (sectionType: string, zone: PageZone) => {
      dispatch({ type: 'ADD_SECTION', sectionType, zone });
    },
    [dispatch]
  );

  const removeSection = useCallback(
    (sectionId: string) => {
      dispatch({ type: 'REMOVE_SECTION', sectionId });
    },
    [dispatch]
  );

  const duplicateSection = useCallback(
    (sectionId: string) => {
      dispatch({ type: 'DUPLICATE_SECTION', sectionId });
    },
    [dispatch]
  );

  const toggleSectionVisibility = useCallback(
    (sectionId: string, isHidden: boolean) => {
      dispatch({ type: 'UPDATE_SECTION_SETTINGS', sectionId, settings: { isHidden } });
    },
    [dispatch]
  );

  const dropSectionInZone = useCallback(
    (droppedSectionId: string, zone: PageZone, toIndex: number) => {
      const section = sections.find((item: SectionInstance) => item.id === droppedSectionId);
      if (!section) {
        return;
      }

      if (section.zone === zone) {
        const zoneSections = sections.filter((item: SectionInstance) => item.zone === zone);
        const fromIndex = zoneSections.findIndex(
          (item: SectionInstance) => item.id === droppedSectionId
        );
        if (fromIndex === -1 || fromIndex === toIndex) {
          return;
        }

        dispatch({ type: 'REORDER_SECTIONS', zone, fromIndex, toIndex });
      } else {
        dispatch({
          type: 'MOVE_SECTION_TO_ZONE',
          sectionId: droppedSectionId,
          toZone: zone,
          toIndex,
        });
      }
    },
    [dispatch, sections]
  );

  const dropSectionToColumn = useCallback(
    (
      sectionId: string,
      toSectionId: string,
      toColumnId: string,
      toIndex: number,
      toParentBlockId?: string
    ) => {
      dispatch({
        type: 'MOVE_SECTION_TO_COLUMN',
        sectionId,
        toSectionId,
        toColumnId,
        ...(toParentBlockId && { toParentBlockId }),
        toIndex,
      });
      autoExpand(toSectionId, toColumnId, toParentBlockId);
    },
    [dispatch, autoExpand]
  );

  const dropSectionToSlideshowFrame = useCallback(
    (sectionId: string, toSectionId: string, toFrameId: string, toIndex: number) => {
      dispatch({
        type: 'MOVE_SECTION_TO_SLIDESHOW_FRAME',
        sectionId,
        toSectionId,
        toFrameId,
        toIndex,
      });
      autoExpand(toSectionId, toFrameId);
    },
    [dispatch, autoExpand]
  );

  const convertSectionToBlock = useCallback(
    (sectionId: string, toSectionId: string, toIndex: number) => {
      dispatch({ type: 'CONVERT_SECTION_TO_BLOCK', sectionId, toSectionId, toIndex });
      autoExpand(toSectionId);
    },
    [dispatch, autoExpand]
  );

  const promoteBlockToSection = useCallback(
    (
      blockId: string,
      fromSectionId: string,
      fromColumnId: string | undefined,
      fromParentBlockId: string | undefined,
      toZone: PageZone,
      toIndex: number
    ) => {
      dispatch({
        type: 'CONVERT_BLOCK_TO_SECTION',
        blockId,
        fromSectionId,
        ...(fromColumnId && { fromColumnId }),
        ...(fromParentBlockId && { fromParentBlockId }),
        toZone,
        toIndex,
      });
    },
    [dispatch]
  );

  const pasteSection = useCallback(
    (zone: PageZone) => {
      dispatch({ type: 'PASTE_SECTION', zone });
    },
    [dispatch]
  );

  return {
    addSection,
    removeSection,
    duplicateSection,
    toggleSectionVisibility,
    dropSectionInZone,
    dropSectionToColumn,
    dropSectionToSlideshowFrame,
    convertSectionToBlock,
    promoteBlockToSection,
    pasteSection,
  };
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { useMemo, useState, startTransition } from 'react';

import { CmsDomainSelector } from '@/features/cms/components/CmsDomainSelector';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import { useCmsAllSlugs, useCmsSlugs, useCreatePage } from '@/features/cms/hooks/useCmsQueries';
import { cmsPageCreateSchema } from '@/features/cms/validations/api';
import type { CmsPageCreateRequestDto, Slug } from '@/shared/contracts/cms';
import { AdminCmsBreadcrumbs } from '@/shared/ui/admin.public';
import { Alert, Input } from '@/shared/ui/primitives.public';
import { FormActions, FormField, FormSection, ToggleRow } from '@/shared/ui/forms-and-actions.public';
import { SectionHeader } from '@/shared/ui/navigation-and-layout.public';
import { StatusBadge, SearchableList } from '@/shared/ui/data-display.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { validateFormData } from '@/shared/validations/form-validation';

export default function CreatePagePage(): React.JSX.Element {
  const [name, setName] = useState('');
  const [slugIds, setSlugIds] = useState<string[]>([]);
  const router = useRouter();
  const { activeDomainId } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const [includeAllZones, setIncludeAllZones] = useState(false);
  const allSlugsQuery = useCmsAllSlugs(includeAllZones);
  const createPage = useCreatePage();
  const [error, setError] = useState<string | null>(null);
  const nameInputRef = (node: HTMLInputElement | null): void => {
    node?.focus();
  };

  const domainSlugs = useMemo(() => slugsQuery.data ?? [], [slugsQuery.data]);
  const allSlugs = allSlugsQuery.data ?? [];
  const domainSlugIds = useMemo(
    (): Set<string> => new Set(domainSlugs.map((slug: Slug) => slug.id)),
    [domainSlugs]
  );
  const visibleSlugs = includeAllZones ? allSlugs : domainSlugs;

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>): Promise<void> => {
    e.preventDefault();
    const validation = validateFormData(
      cmsPageCreateSchema,
      { name, slugIds },
      'Page form is invalid.'
    );
    if (!validation.success) {
      setError(validation.firstError);
      return;
    }

    setError(null);
    try {
      const input: CmsPageCreateRequestDto = {
        ...validation.data,
        slugIds: validation.data.slugIds ?? [],
      };
      await createPage.mutateAsync(input);
      startTransition(() => { router.push('/admin/cms/pages'); });
    } catch (submitError: unknown) {
      logClientCatch(submitError, {
        source: 'CreatePagePage',
        action: 'createPage',
        name,
      });
      setError(submitError instanceof Error ? submitError.message : 'Failed to create page.');
    }
  };

  return (
    <div className='page-section max-w-3xl space-y-6'>
      <SectionHeader
        title='Create Page'
        description='Provision a new content page and map it to URL routes.'
        eyebrow={
          <AdminCmsBreadcrumbs
            parent={{ label: 'Pages', href: '/admin/cms/pages' }}
            current='Create'
            className='mb-2'
          />
        }
        actions={<CmsDomainSelector />}
      />

      <form
        onSubmit={(e: React.FormEvent<HTMLFormElement>): void => {
          void handleSubmit(e);
        }}
      >
        <div className='space-y-6'>
          {error && (
            <Alert variant='error' className='mb-6'>
              {error}
            </Alert>
          )}
          <FormSection title='General Information' className='p-6'>
            <FormField label='Page Name' error={error} required>
              <Input
                ref={nameInputRef}
                id='name'
                value={name}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setName(e.target.value)}
                placeholder='e.g. Summer Collection 2026'
                className='h-9'
               aria-label='e.g. Summer Collection 2026' title='e.g. Summer Collection 2026'/>
            </FormField>
          </FormSection>

          <FormSection
            title='Route Mapping'
            description='Select which URL paths should resolve to this page.'
            actions={
              <ToggleRow
                label='Show all zones'
                checked={includeAllZones}
                onCheckedChange={setIncludeAllZones}
                className='bg-transparent border-none p-0 hover:bg-transparent'
                labelClassName='text-[10px] uppercase font-bold text-gray-500'
              />
            }
            className='p-6'
          >
            <SearchableList
              items={visibleSlugs}
              selectedIds={slugIds}
              onToggle={(id) => {
                setSlugIds((prev) =>
                  prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id]
                );
              }}
              getId={(s: Slug) => s.id}
              getLabel={(s: Slug) => s.slug}
              searchPlaceholder='Filter available routes...'
              renderItem={(slug: Slug) => (
                <div className='flex flex-1 items-center justify-between'>
                  <span className='text-sm text-gray-300'>/{slug.slug}</span>
                  {includeAllZones && !domainSlugIds.has(slug.id) && (
                    <StatusBadge
                      status='Cross-Zone'
                      variant='warning'
                      size='sm'
                      className='font-bold'
                    />
                  )}
                </div>
              )}
            />
          </FormSection>

          <FormActions
            onCancel={() => router.back()}
            saveText='Create Page'
            isSaving={createPage.isPending}
            className='pt-4'
          />
        </div>
      </form>
    </div>
  );
}

