function EditPageContent({
  initialPage,
  pageId,
}: {
  initialPage: Page;
  pageId: string;
}): React.JSX.Element {
  const page = initialPage;
  const { activeDomainId } = useCmsDomainSelection();
  const slugsQuery = useCmsSlugs(activeDomainId);
  const allSlugsQuery = useCmsAllSlugs(true);
  const [includeAllZones, setIncludeAllZones] = useState(false);
  const [manualSelectedSlugIds, setManualSelectedSlugIds] = useState<string[] | null>(null);
  const router = useRouter();
  const updatePage = useUpdatePage();
  const [error, setError] = useState<string | null>(null);

  const allSlugs = useMemo((): Slug[] => allSlugsQuery.data ?? [], [allSlugsQuery.data]);
  const domainSlugs = useMemo((): Slug[] => slugsQuery.data ?? [], [slugsQuery.data]);
  const allSlugByValue = useMemo((): Map<string, { id: string; slug: string }> => {
    const map = new Map<string, { id: string; slug: string }>();
    allSlugs.forEach((slug: Slug): void => {
      map.set(slug.slug, { id: slug.id, slug: slug.slug });
    });
    return map;
  }, [allSlugs]);

  const initialSelectedSlugIds = useMemo((): string[] => {
    if (!allSlugs.length) return [];
    const pageSlugValues = normalizePageSlugValues(initialPage.slugs);
    return pageSlugValues
      .map((value: string) => allSlugByValue.get(value)?.id)
      .filter((value: string | undefined): value is string => Boolean(value));
  }, [allSlugs.length, allSlugByValue, initialPage.slugs]);

  const selectedSlugIds = manualSelectedSlugIds ?? initialSelectedSlugIds;

  const domainSlugIds = useMemo(
    (): Set<string> => new Set(domainSlugs.map((slug: Slug) => slug.id)),
    [domainSlugs]
  );
  const selectedSlugs = useMemo((): Slug[] => {
    const byId = new Map(allSlugs.map((slug: Slug) => [slug.id, slug]));
    const isSlug = (value: Slug | undefined): value is Slug => Boolean(value);
    return selectedSlugIds.map((idValue: string) => byId.get(idValue)).filter(isSlug);
  }, [allSlugs, selectedSlugIds]);

  const crossZoneSlugs = useMemo(
    (): Slug[] => selectedSlugs.filter((slug: Slug) => !domainSlugIds.has(slug.id)),
    [selectedSlugs, domainSlugIds]
  );

  const visibleSlugs = includeAllZones ? allSlugs : domainSlugs;
  const handleToggleSlug = useCallback(
    (slugId: string): void => {
      setManualSelectedSlugIds((previousSlugIds) => {
        const currentSlugIds = previousSlugIds ?? selectedSlugIds;
        return currentSlugIds.includes(slugId)
          ? currentSlugIds.filter((value: string) => value !== slugId)
          : [...currentSlugIds, slugId];
      });
    },
    [selectedSlugIds]
  );

  const handleSave = async (): Promise<void> => {
    if (!page) return;

    const validation = validateFormData(
      cmsPageUpdateSchema,
      {
        name: page.name,
        status: page.status,
        publishedAt: page.publishedAt ?? null,
        seoTitle: page.seoTitle ?? null,
        seoDescription: page.seoDescription ?? null,
        seoOgImage: page.seoOgImage ?? null,
        seoCanonical: page.seoCanonical ?? null,
        robotsMeta: page.robotsMeta ?? null,
        themeId: page.themeId ?? null,
        showMenu: page.showMenu ?? true,
        components: page.components,
        slugIds: selectedSlugIds,
      },
      'Page form is invalid.'
    );
    if (!validation.success) {
      setError(validation.firstError);
      return;
    }

    setError(null);
    await updatePage.mutateAsync({
      id: pageId,
      input: validation.data,
    });
    startTransition(() => { router.push('/admin/cms/pages'); });
  };

  return (
    <CmsEditorLayout>
      <div className='mx-auto flex w-full max-w-3xl flex-col gap-6 py-10'>
        <SectionHeader
          title={page.name}
          description='Map content to URL routes and manage cross-zone availability.'
          eyebrow={
            <AdminCmsBreadcrumbs
              parent={{ label: 'Pages', href: '/admin/cms/pages' }}
              current='Edit'
              className='mb-2'
            />
          }
          actions={
            <FormActions
              onCancel={(): void => {
                startTransition(() => { router.push('/admin/cms/pages'); });
              }}
              cancelText='Back'
              onSave={(): void => {
                void handleSave();
              }}
              saveText='Save Changes'
              isSaving={updatePage.isPending}
            />
          }
        />

        {error && (
          <Alert variant='error' className='mb-6'>
            {error}
          </Alert>
        )}

        <div className='space-y-6'>
          <FormSection title='Context Selector' className='p-6'>
            <CmsDomainSelector />
          </FormSection>

          <FormSection
            title='Route Configuration'
            description='Select which URL paths should resolve to this page.'
            actions={
              <ToggleRow
                label='Show all zones'
                checked={includeAllZones}
                onCheckedChange={setIncludeAllZones}
                className='bg-transparent border-none p-0 hover:bg-transparent'
                labelClassName='text-[10px] uppercase font-bold text-gray-500'
              />
            }
            className='p-6'
          >
            <EditPageRouteList
              visibleSlugs={visibleSlugs}
              selectedSlugIds={selectedSlugIds}
              domainSlugIds={domainSlugIds}
              onToggleSlug={handleToggleSlug}
            />
          </FormSection>

          {crossZoneSlugs.length > 0 && (
            <FormSection
              title='External Assignments'
              description='Routes from other zones currently pointing to this page.'
              className='p-6'
            >
              <div className='flex flex-wrap gap-2'>
                {crossZoneSlugs.map((slug) => (
                  <Button
                    key={slug.id}
                    variant='ghost'
                    size='sm'
                    onClick={() =>
                      setManualSelectedSlugIds((prev) => {
                        const current = prev ?? selectedSlugIds;
                        return current.filter((id) => id !== slug.id);
                      })
                    }
                    className='h-auto p-0 hover:bg-transparent'
                    aria-label={`Remove external assignment /${slug.slug}`}
                    title='Remove external assignment'
                  >
                    <StatusBadge
                      status={`/${  slug.slug  } ×`}
                      variant='warning'
                      className='cursor-pointer hover:opacity-80 transition-opacity font-mono'
                    />
                  </Button>
                ))}
              </div>
            </FormSection>
          )}
        </div>
      </div>
    </CmsEditorLayout>
  );
}

'use client';

import { Eye, Plus } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'nextjs-toploader/app';
import { useMemo, useState, startTransition } from 'react';

import { CmsDomainSelector } from '@/features/cms/components/CmsDomainSelector';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import { useCmsPages, useCmsSlugs, useDeletePage } from '@/features/cms/hooks/useCmsQueries';
import {
  normalizePageSlugLinks,
  type NormalizedPageSlugLink,
} from '@/features/cms/utils/slug-utils';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { PageStatus, PageSummary, Slug } from '@/shared/contracts/cms';
import { useAdminLayoutActions } from '@/shared/providers/AdminLayoutProvider';
import { AdminCmsPageLayout } from '@/shared/ui/admin.public';
import { Button, Badge, DropdownMenuItem, DropdownMenuSeparator } from '@/shared/ui/primitives.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { SelectSimple, ActionMenu } from '@/shared/ui/forms-and-actions.public';
import { StandardDataTablePanel, FilterPanel } from '@/shared/ui/templates.public';
import { ConfirmModal } from '@/shared/ui/templates/modals/ConfirmModal';
import type { FilterField } from '@/shared/contracts/ui/panels';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import type { ColumnDef } from '@tanstack/react-table';


type StatusFilter = PageStatus | 'all';
type StatusFilterOption = LabeledOptionDto<StatusFilter>;

const STATUS_FILTERS: StatusFilterOption[] = [
  { label: 'All', value: 'all' },
  { label: 'Draft', value: 'draft' },
  { label: 'Published', value: 'published' },
  { label: 'Scheduled', value: 'scheduled' },
];

const buildZoneSlugOptions = (zoneSlugs: string[]): Array<LabeledOptionDto<string>> =>
  zoneSlugs.map((slug) => ({ value: slug, label: `/${slug}` }));

export default function PagesPage(): React.ReactNode {
  const { setIsMenuCollapsed, setIsProgrammaticallyCollapsed } = useAdminLayoutActions();
  const router = useRouter();
  const { activeDomainId, activeDomain } = useCmsDomainSelection();
  const pagesQuery = useCmsPages(activeDomainId);
  const slugsQuery = useCmsSlugs(activeDomainId);
  const deletePage = useDeletePage();
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('all');
  const [search, setSearch] = useState('');
  const [previewSelections, setPreviewSelections] = useState<Record<string, string>>({});
  const [pageToDelete, setPageToDelete] = useState<PageSummary | null>(null);

  const pages = useMemo((): PageSummary[] => pagesQuery.data ?? [], [pagesQuery.data]);
  const domainSlugs = useMemo((): Slug[] => slugsQuery.data ?? [], [slugsQuery.data]);
  const domainSlugSet = useMemo((): Set<string> | null => {
    if (!domainSlugs.length) return null;
    const values = domainSlugs
      .map((slug: Slug): string => (typeof slug.slug === 'string' ? slug.slug.trim() : ''))
      .filter((slugValue: string): boolean => slugValue.length > 0);
    return values.length ? new Set(values) : null;
  }, [domainSlugs]);

  const filteredPages = useMemo((): PageSummary[] => {
    let result = pages;
    if (statusFilter !== 'all') {
      result = result.filter((page: PageSummary) => (page.status ?? 'draft') === statusFilter);
    }
    if (search.trim()) {
      const q = search.toLowerCase().trim();
      result = result.filter((page: PageSummary) => page.name.toLowerCase().includes(q));
    }
    return result;
  }, [pages, statusFilter, search]);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!pageToDelete) return;
    try {
      await deletePage.mutateAsync(pageToDelete.id);
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'PagesPage.handleConfirmDelete',
        pageId: pageToDelete.id,
      });
    } finally {
      setPageToDelete(null);
    }
  };

  const handleCreatePage = (): void => {
    setIsMenuCollapsed(true);
    setIsProgrammaticallyCollapsed(true);
    startTransition(() => { router.push('/admin/cms/pages/create'); });
  };

  const handlePreview = (slug: string): void => {
    if (typeof window === 'undefined') return;
    const protocol = window.location.protocol;
    const currentHost = window.location.host;
    const currentHostname = window.location.hostname;
    const targetHost = activeDomain?.domain ?? currentHostname;
    const resolvedHost = targetHost === currentHostname ? currentHost : targetHost;
    const path = slug.startsWith('/') ? slug : `/${slug}`;
    window.open(`${protocol}//${resolvedHost}${path}`, '_blank', 'noopener,noreferrer');
  };

  const columns = useMemo<ColumnDef<PageSummary>[]>(
    () => [
      {
        accessorKey: 'name',
        header: 'Page Name',
        cell: ({ row }) => (
          <div className='flex flex-col gap-1'>
            <Link
              href={`/admin/cms/builder?pageId=${row.original.id}`}
              className='font-medium text-gray-200 hover:text-blue-300 transition-colors'
            >
              {row.original.name}
            </Link>
            <div className='flex flex-wrap gap-1'>
              {normalizePageSlugLinks(row.original.slugs).map((s: NormalizedPageSlugLink) => {
                const isOutOfZone = domainSlugSet && !domainSlugSet.has(s.slug);
                return (
                  <Badge
                    key={s.id}
                    variant='outline'
                    className={`text-[9px] px-1 py-0 ${isOutOfZone ? 'border-amber-500/30 text-amber-400 bg-amber-500/5' : 'text-gray-500'}`}
                  >
                    /{s.slug}
                  </Badge>
                );
              })}
            </div>
          </div>
        ),
      },
      {
        accessorKey: 'status',
        header: 'Status',
        cell: ({ row }) => (
          <StatusBadge status={row.original.status ?? 'draft'} className='text-[10px]' />
        ),
        size: 100,
      },
      {
        id: 'preview',
        header: 'Live Preview',
        cell: ({ row }) => {
          const page = row.original;
          const slugValues = normalizePageSlugLinks(page.slugs).map(
            (slugLink: NormalizedPageSlugLink): string => slugLink.slug
          );
          const zoneSlugs = domainSlugSet
            ? slugValues.filter((value: string) => domainSlugSet.has(value))
            : [];
          const selectedSlugCandidate = previewSelections[page.id];
          const previewSlug = zoneSlugs.length
            ? selectedSlugCandidate && zoneSlugs.includes(selectedSlugCandidate)
              ? selectedSlugCandidate
              : zoneSlugs[0]
            : null;

          if (!previewSlug)
            return <span className='text-[10px] text-gray-600 uppercase font-bold'>No route</span>;

          return (
            <div className='flex items-center gap-2'>
              {zoneSlugs.length > 1 ? (
                <SelectSimple
                  size='xs'
                  value={previewSlug}
                  onValueChange={(val) =>
                    setPreviewSelections((prev) => ({ ...prev, [page.id]: val }))
                  }
                  options={buildZoneSlugOptions(zoneSlugs)}
                  className='h-7 w-28 text-[10px]'
                 ariaLabel='Select option' title='Select option'/>
              ) : (
                <span className='text-[10px] text-blue-400 font-mono'>/{previewSlug}</span>
              )}
              <Button
                variant='ghost'
                size='xs'
                className='h-7 w-7 p-0'
                onClick={() => handlePreview(previewSlug)}
                title={`Preview on ${activeDomain?.domain ?? 'current'}`}
                aria-label={`Preview on ${activeDomain?.domain ?? 'current'}`}>
                <Eye className='size-3.5' />
              </Button>
            </div>
          );
        },
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => (
          <div className='flex justify-end'>
            <ActionMenu ariaLabel={`Actions for page ${row.original.name}`}>
              <DropdownMenuItem
                onSelect={(event: Event): void => {
                  event.preventDefault();
                  startTransition(() => { router.push(`/admin/cms/builder?pageId=${row.original.id}`); });
                }}
              >
                Open in Builder
              </DropdownMenuItem>
              <DropdownMenuItem
                onSelect={(event: Event): void => {
                  event.preventDefault();
                  startTransition(() => { router.push(`/admin/cms/pages/${row.original.id}/edit`); });
                }}
              >
                Edit Settings
              </DropdownMenuItem>
              <DropdownMenuSeparator />
              <DropdownMenuItem
                className='text-destructive focus:text-destructive'
                onSelect={(event: Event): void => {
                  event.preventDefault();
                  setPageToDelete(row.original);
                }}
              >
                Delete
              </DropdownMenuItem>
            </ActionMenu>
          </div>
        ),
      },
    ],
    [domainSlugSet, previewSelections, activeDomain]
  );

  const filterConfig: FilterField[] = useMemo(
    () => [
      {
        key: 'status',
        label: 'Status',
        type: 'select',
        options: STATUS_FILTERS,
      },
    ],
    []
  );

  const filters = (
    <FilterPanel
      filters={filterConfig}
      values={{ status: statusFilter }}
      search={search}
      searchPlaceholder='Search pages by name...'
      onFilterChange={(key, value) => {
        if (key === 'status') setStatusFilter(value as StatusFilter);
      }}
      onSearchChange={setSearch}
      onReset={() => {
        setStatusFilter('all');
        setSearch('');
      }}
      showHeader={false}
      compact
    />
  );

  return (
    <AdminCmsPageLayout
      title='Content Pages'
      current='Pages'
      description='Manage layouts and routes for your marketplace domains.'
      headerActions={
        <div className='flex gap-2'>
          <CmsDomainSelector />
          <Button size='xs' className='h-8' onClick={handleCreatePage}>
            <Plus className='size-3.5 mr-2' />
            Create Page
          </Button>
        </div>
      }
    >
      <StandardDataTablePanel
        filters={filters}
        variant='flat'
        columns={columns}
        data={filteredPages}
        isLoading={pagesQuery.isLoading}
      />

      <ConfirmModal
        isOpen={Boolean(pageToDelete)}
        onClose={() => setPageToDelete(null)}
        onConfirm={() => {
          void handleConfirmDelete();
        }}
        title='Permanently Delete Page?'
        message={`This will destroy "${pageToDelete?.name}" and all its block configurations. This cannot be undone.`}
        confirmText='Destroy Page'
        isDangerous
      />
    </AdminCmsPageLayout>
  );
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { useSearchParams } from 'next/navigation';
import { useMemo, useState, startTransition } from 'react';

import { SlugForm, type SlugFormSubmitData } from '@/features/cms/components/SlugForm';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import {
  useCmsDomains,
  useCreateSlug,
  useUpdateSlugDomains,
} from '@/features/cms/hooks/useCmsQueries';
import { AdminCmsPageLayout } from '@/shared/ui/admin.public';
import { Alert, useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

export default function CreateSlugPage(): React.JSX.Element {
  const { toast } = useToast();
  const [error, setError] = useState<string | null>(null);
  const router = useRouter();
  const searchParams = useSearchParams();
  const domainId = searchParams.get('domainId') ?? undefined;
  const createSlug = useCreateSlug();
  const updateSlugDomains = useUpdateSlugDomains();
  const domainsQuery = useCmsDomains();
  const { zoningEnabled } = useCmsDomainSelection();

  const domains = useMemo(() => domainsQuery.data ?? [], [domainsQuery.data]);

  const handleSubmit = async (data: SlugFormSubmitData): Promise<void> => {
    setError(null);

    try {
      const createData: { slug: string; domainId?: string | null } = { slug: data.slug };
      if (domainId) createData.domainId = domainId;

      const newSlug = await createSlug.mutateAsync(createData);

      if (zoningEnabled && data.domainIds.length > 0) {
        await updateSlugDomains.mutateAsync({ id: newSlug.id, domainIds: data.domainIds });
      }

      toast('Route path created successfully.', { variant: 'success' });
      const next = domainId
        ? `/admin/cms/slugs?domainId=${encodeURIComponent(domainId)}`
        : '/admin/cms/slugs';
      startTransition(() => { router.push(next); });
    } catch (err: unknown) {
      logClientCatch(err, {
        source: 'CreateSlugPage',
        action: 'createSlug',
        slug: data.slug,
        domainId,
      });
      setError(err instanceof Error ? err.message : 'An unexpected error occurred.');
    }
  };

  return (
    <AdminCmsPageLayout
      title='Create Route'
      current='Create'
      parent={{ label: 'Slugs', href: '/admin/cms/slugs' }}
      description='Register a new URL path for your content.'
      containerClassName='page-section max-w-2xl space-y-6'
    >

      {error && (
        <Alert variant='error' className='mb-6'>
          {error}
        </Alert>
      )}

      <SlugForm
        onSubmit={handleSubmit}
        isSaving={createSlug.isPending || updateSlugDomains.isPending}
        onCancel={() => router.back()}
        submitText='Create Path'
        domains={domains}
        initialData={domainId ? { slug: '', isDefault: false, domainIds: [domainId] } : undefined}
      />
    </AdminCmsPageLayout>
  );
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { useParams, useSearchParams } from 'next/navigation';
import { useMemo, useState, startTransition } from 'react';

import { SlugForm, type SlugFormSubmitData } from '@/features/cms/components/SlugForm';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import {
  useCmsDomains,
  useCmsSlug,
  useCmsSlugDomains,
  useUpdateSlug,
  useUpdateSlugDomains,
} from '@/features/cms/hooks/useCmsQueries';
import { cmsSlugDomainsUpdateSchema, cmsSlugUpdateSchema } from '@/features/cms/validations/api';
import type { IdInputDto } from '@/shared/contracts/base';
import type { Slug } from '@/shared/contracts/cms';
import { AdminCmsPageLayout } from '@/shared/ui/admin.public';
import { Alert, useToast } from '@/shared/ui/primitives.public';
import { LoadingState } from '@/shared/ui/navigation-and-layout.public';
import { validateFormData } from '@/shared/validations/form-validation';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export default function EditSlugPageLoader(): React.JSX.Element {
  const params = useParams();
  const id = params['id'] as string;
  const searchParams = useSearchParams();
  const domainId = searchParams.get('domainId') ?? undefined;
  const slugQuery = useCmsSlug(id, domainId);

  if (slugQuery.isLoading || !slugQuery.data) {
    return <LoadingState message='Loading route configuration...' className='py-12' />;
  }

  return <EditSlugForm initialSlug={slugQuery.data} id={id} {...(domainId && { domainId })} />;
}

function EditSlugForm({
  initialSlug,
  id,
  domainId,
}: {
  initialSlug: Slug;
  id: string;
  domainId?: string;
}): React.JSX.Element {
  const { toast } = useToast();
  const { zoningEnabled } = useCmsDomainSelection();
  const domainsQuery = useCmsDomains();
  const slugDomainsQuery = useCmsSlugDomains(id);
  const updateSlugDomains = useUpdateSlugDomains();
  const router = useRouter();
  const updateSlug = useUpdateSlug();
  const [error, setError] = useState<string | null>(null);

  const domains = useMemo(() => domainsQuery.data ?? [], [domainsQuery.data]);
  const initialDomainIds = useMemo(
    () => slugDomainsQuery.data?.domainIds ?? [],
    [slugDomainsQuery.data]
  );
  const slugFormInitialData = useMemo(
    () => ({
      slug: initialSlug.slug,
      isDefault: Boolean(initialSlug.isDefault),
      domainIds: initialDomainIds,
    }),
    [initialSlug, initialDomainIds]
  );

  const handleSubmit = async (data: SlugFormSubmitData): Promise<void> => {
    setError(null);

    const slugValidation = validateFormData(
      cmsSlugUpdateSchema,
      {
        slug: data.slug,
        isDefault: data.isDefault,
      },
      'Slug form is invalid.'
    );
    if (!slugValidation.success) {
      setError(slugValidation.firstError);
      return;
    }

    if (zoningEnabled) {
      const domainsValidation = validateFormData(
        cmsSlugDomainsUpdateSchema,
        { domainIds: data.domainIds },
        'Assign this slug to at least one zone.'
      );
      if (!domainsValidation.success) {
        setError(domainsValidation.firstError);
        return;
      }
    }

    const updateData: IdInputDto<Partial<Slug>> & { domainId?: string | null } = {
      id,
      input: slugValidation.data as Partial<Slug>,
    };
    if (domainId) updateData.domainId = domainId;

    try {
      await updateSlug.mutateAsync(updateData);
      if (zoningEnabled) {
        await updateSlugDomains.mutateAsync({ id, domainIds: data.domainIds });
      }
      toast('Route path updated successfully.', { variant: 'success' });
      const next = domainId
        ? `/admin/cms/slugs?domainId=${encodeURIComponent(domainId)}`
        : '/admin/cms/slugs';
      startTransition(() => { router.push(next); });
    } catch (err) {
      logClientError(err);
      setError(err instanceof Error ? err.message : 'Update failed.');
    }
  };

  return (
    <AdminCmsPageLayout
      title='Edit Route'
      current='Edit'
      parent={{ label: 'Slugs', href: '/admin/cms/slugs' }}
      description='Configure path behavior and cross-domain assignments.'
      containerClassName='page-section max-w-2xl space-y-6'
    >

      {error && (
        <Alert variant='error' className='mb-6'>
          {error}
        </Alert>
      )}

      <SlugForm
        initialData={slugFormInitialData}
        onSubmit={handleSubmit}
        isSaving={updateSlug.isPending || updateSlugDomains.isPending}
        onCancel={() => router.back()}
        submitText='Save Changes'
        domains={domains}
      />
    </AdminCmsPageLayout>
  );
}

'use client';

import { Link2 } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'nextjs-toploader/app';
import { usePathname, useSearchParams } from 'next/navigation';
import { useMemo, useState, useCallback, startTransition } from 'react';

import { AttachSlugModal } from '@/features/cms/components/slugs/AttachSlugModal';
import { useCmsDomainSelection } from '@/features/cms/hooks/useCmsDomainSelection';
import {
  useCmsAllSlugs,
  useCmsSlugs,
  useCreateSlug,
  useDeleteSlug,
} from '@/features/cms/hooks/useCmsQueries';
import type { LabeledOptionWithDescriptionDto } from '@/shared/contracts/base';
import type { CmsDomain, Slug } from '@/shared/contracts/cms';
import { CMS_DOMAIN_SETTINGS_KEY, normalizeCmsDomainSettings } from '@/shared/contracts/cms';
import { useUpdateSetting } from '@/shared/hooks/use-settings';
import { useSettingsStore } from '@/shared/providers/SettingsStoreProvider';
import { AdminCmsPageLayout } from '@/shared/ui/admin.public';
import { Button, DropdownMenuItem } from '@/shared/ui/primitives.public';
import { StandardDataTablePanel, FilterPanel } from '@/shared/ui/templates.public';
import { ToggleRow, SelectSimple, ActionMenu } from '@/shared/ui/forms-and-actions.public';
import { EmptyState, UI_CENTER_ROW_SPACED_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { ConfirmModal } from '@/shared/ui/templates/modals';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';
import { parseJsonSetting, serializeSetting } from '@/shared/utils/settings-json';

import type { ColumnDef } from '@tanstack/react-table';

export default function SlugsPage(): React.JSX.Element {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const domainIdParam = searchParams.get('domainId') ?? undefined;
  const {
    domains,
    activeDomainId,
    hostDomainId,
    canonicalDomain,
    sharedWithDomains,
    setActiveDomainId,
    zoningEnabled,
  } = useCmsDomainSelection({ initialDomainId: domainIdParam ?? null });
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();
  const domainSettingsRaw = settingsStore.get(CMS_DOMAIN_SETTINGS_KEY);
  const domainSettings = useMemo(
    () => normalizeCmsDomainSettings(parseJsonSetting(domainSettingsRaw, null)),
    [domainSettingsRaw]
  );
  const zoningToggleValue = domainSettings.zoningEnabled;
  const [attachOpen, setAttachOpen] = useState(false);
  const [slugToDelete, setSlugToDelete] = useState<Slug | null>(null);
  const [search, setSearch] = useState('');
  const slugsQuery = useCmsSlugs(activeDomainId);
  const allSlugsQuery = useCmsAllSlugs(attachOpen);
  const createSlug = useCreateSlug();
  const deleteSlug = useDeleteSlug();
  const slugs = useMemo((): Slug[] => slugsQuery.data ?? [], [slugsQuery.data]);
  const allSlugs = useMemo((): Slug[] => allSlugsQuery.data ?? [], [allSlugsQuery.data]);
  const domainSelectOptions = useMemo<Array<LabeledOptionWithDescriptionDto<string>>>(
    () =>
      domains.map((domain: CmsDomain) => ({
        value: domain.id,
        label: domain.domain,
        description: hostDomainId === domain.id ? 'host' : undefined,
      })),
    [domains, hostDomainId]
  );

  const filteredSlugs = useMemo((): Slug[] => {
    if (!search.trim()) return slugs;
    const q = search.toLowerCase().trim().replace(/^\//, '');
    return slugs.filter((s) => s.slug.toLowerCase().includes(q));
  }, [slugs, search]);

  const handleDomainChange = (value: string): void => {
    if (value === (activeDomainId ?? '')) return;
    const params = new URLSearchParams(searchParams.toString());
    if (value) {
      params.set('domainId', value);
    } else {
      params.delete('domainId');
    }
    const next = params.toString();
    startTransition(() => { router.replace(next ? `${pathname}?${next}` : pathname); });
    setActiveDomainId(value || null);
  };

  const handleZoningToggle = (checked: boolean): void => {
    const next = normalizeCmsDomainSettings({ ...domainSettings, zoningEnabled: checked });
    updateSetting.mutate({ key: CMS_DOMAIN_SETTINGS_KEY, value: serializeSetting(next) });
  };

  const buildDomainHref = useMemo((): ((href: string) => string) => {
    return (href: string): string =>
      activeDomainId ? `${href}?domainId=${encodeURIComponent(activeDomainId)}` : href;
  }, [activeDomainId]);

  const handleDelete = useCallback((slug: Slug): void => {
    setSlugToDelete(slug);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!slugToDelete) return;
    try {
      await deleteSlug.mutateAsync({ id: slugToDelete.id, domainId: activeDomainId });
    } catch (error) {
      logClientCatch(error, {
        source: 'slugs-page',
        action: 'deleteSlug',
        slugId: slugToDelete.id,
      });
    } finally {
      setSlugToDelete(null);
    }
  };

  const columns = useMemo<ColumnDef<Slug>[]>(
    () => [
      {
        accessorKey: 'slug',
        header: 'Route Path',
        cell: ({ row }) => (
          <div className='flex flex-col gap-1'>
            <Link
              href={buildDomainHref(`/admin/cms/slugs/${row.original.id}/edit`)}
              className='font-medium text-gray-200 hover:text-blue-300 transition-colors'
            >
              /{row.original.slug}
            </Link>
            <div className='flex items-center gap-2'>
              {row.original.isDefault && (
                <StatusBadge status='Default' variant='info' size='sm' className='font-bold' />
              )}
              {(canonicalDomain || sharedWithDomains.length > 0) && (
                <StatusBadge status='Shared' variant='active' size='sm' className='font-bold' />
              )}
            </div>
          </div>
        ),
      },
      {
        id: 'sharing',
        header: 'Sharing Status',
        cell: ({ row: _row }) => {
          if (canonicalDomain)
            return (
              <span className='text-xs text-gray-500'>Inherited from {canonicalDomain.domain}</span>
            );
          if (sharedWithDomains.length > 0)
            return (
              <span className='text-xs text-gray-500'>
                Pushed to {sharedWithDomains.length} domains
              </span>
            );
          return <span className='text-xs text-gray-600 italic'>Local only</span>;
        },
      },
      {
        id: 'actions',
        header: () => <div className='text-right'>Actions</div>,
        cell: ({ row }) => (
          <div className='flex justify-end'>
            <ActionMenu ariaLabel={`Actions for slug /${row.original.slug}`}>
              <DropdownMenuItem
                onSelect={(event: Event): void => {
                  event.preventDefault();
                  startTransition(() => { router.push(buildDomainHref(`/admin/cms/slugs/${row.original.id}/edit`)); });
                }}
              >
                Edit Settings
              </DropdownMenuItem>
              <DropdownMenuItem
                className='text-destructive focus:text-destructive'
                onSelect={(event: Event): void => {
                  event.preventDefault();
                  handleDelete(row.original);
                }}
              >
                Detach from Zone
              </DropdownMenuItem>
            </ActionMenu>
          </div>
        ),
      },
    ],
    [buildDomainHref, canonicalDomain, sharedWithDomains, handleDelete]
  );

  return (
    <AdminCmsPageLayout
      title='Slugs'
      current='Slugs'
      description={
        zoningEnabled
          ? 'Manage unique paths assigned to the active domain. These control how pages are resolved.'
          : 'Global route management. Domain zoning is currently disabled.'
      }
      headerActions={
        <div className={UI_CENTER_ROW_SPACED_CLASSNAME}>
          <ToggleRow
            label='Zoning'
            checked={zoningToggleValue}
            onCheckedChange={handleZoningToggle}
            disabled={updateSetting.isPending}
            className='bg-black/20 border-border/60 px-3 py-1.5'
            labelClassName='text-[10px] uppercase font-bold text-gray-500'
          />
          {zoningEnabled ? (
            <SelectSimple
              value={activeDomainId || ''}
              onValueChange={handleDomainChange}
              options={domainSelectOptions}
              placeholder='Select domain...'
              ariaLabel='Domain'
              className='w-[200px]'
              size='sm'
             title='Select domain...'/>
          ) : null}
          <div className='flex gap-2'>
            {zoningEnabled && (
              <Button
                variant='outline'
                size='xs'
                className='h-8'
                onClick={() => setAttachOpen(true)}
              >
                <Link2 className='size-3.5 mr-2' />
                Attach Existing
              </Button>
            )}
            <Button size='xs' className='h-8' asChild>
              <Link href={buildDomainHref('/admin/cms/slugs/create')}>Create New Slug</Link>
            </Button>
          </div>
        </div>
      }
    >
      <StandardDataTablePanel
        variant='flat'
        columns={columns}
        data={filteredSlugs}
        filters={
          <FilterPanel
            filters={[]}
            values={{}}
            search={search}
            searchPlaceholder='Search routes by path...'
            onFilterChange={() => {}}
            onSearchChange={setSearch}
            onReset={() => setSearch('')}
            showHeader={false}
            compact
          />
        }
        isLoading={slugsQuery.isLoading}
        emptyState={
          <EmptyState
            title='No routes defined'
            description='This domain currently has no assigned slugs. Pages will not be reachable until a route is mapped.'
            action={
              <div className='flex gap-2'>
                <Button onClick={() => setAttachOpen(true)} variant='outline' size='sm'>
                  Attach Existing
                </Button>
                <Button asChild size='sm'>
                  <Link href={buildDomainHref('/admin/cms/slugs/create')}>Create First Slug</Link>
                </Button>
              </div>
            }
          />
        }
      />

      <AttachSlugModal
        isOpen={attachOpen}
        onClose={() => setAttachOpen(false)}
        onSuccess={() => setAttachOpen(false)}
        items={allSlugs}
        loading={allSlugsQuery.isLoading}
        alreadyAssignedIds={new Set(slugs.map((s) => s.id))}
        onAttach={async (selectedIds) => {
          const selected = allSlugs.filter((item: Slug) => selectedIds.includes(item.id));
          for (const slug of selected) {
            await createSlug.mutateAsync({ slug: slug.slug, domainId: activeDomainId });
          }
          setAttachOpen(false);
        }}
      />

      <ConfirmModal
        isOpen={Boolean(slugToDelete)}
        onClose={() => setSlugToDelete(null)}
        onConfirm={handleConfirmDelete}
        title='Remove Slug from Zone'
        message='This route will be detached from the current domain. It will remain active in other domains if previously assigned.'
        confirmText='Detach Route'
        isDangerous={true}
      />
    </AdminCmsPageLayout>
  );
}

'use client';

import { useRouter } from 'nextjs-toploader/app';
import React, { useState, startTransition } from 'react';

import { ThemeForm, type ThemeFormSubmitData } from '@/features/cms/components/ThemeForm';
import { useCreateTheme } from '@/features/cms/hooks/useCmsQueries';
